const QUESTIONS_CCSP = [
// ─── DOMAIN 1: Cloud Concepts, Architecture and Design ───────────────────────
{id:1,domain:1,level:1,question:"According to NIST SP 800-145, which of the following is NOT one of the five essential characteristics of cloud computing?",options:["A. On-demand self-service","B. Broad network access","C. Dedicated hardware allocation","D. Measured service"],correct:2,explanation:"NIST defines five essential characteristics: on-demand self-service, broad network access, resource pooling, rapid elasticity, and measured service. Dedicated hardware allocation contradicts the shared/pooled nature of cloud."},
{id:2,domain:1,level:1,question:"Which cloud service model gives the customer the MOST control over the underlying infrastructure?",options:["A. SaaS","B. PaaS","C. IaaS","D. FaaS"],correct:2,explanation:"In IaaS the customer manages OS, middleware, applications, and data. PaaS abstracts the OS and below; SaaS abstracts everything. IaaS therefore provides the most control."},
{id:3,domain:1,level:1,question:"A group of organizations in the same regulated industry shares a cloud environment built around their common compliance requirements. Which deployment model is this?",options:["A. Public cloud","B. Private cloud","C. Hybrid cloud","D. Community cloud"],correct:3,explanation:"Community cloud is provisioned for exclusive use by a specific community of consumers from organizations with shared concerns such as mission, security, policy, or compliance."},
{id:4,domain:1,level:1,question:"What does 'rapid elasticity' mean in cloud computing?",options:["A. Data can be compressed elastically","B. Resources can be rapidly scaled up or down to match demand","C. The provider can quickly relocate physical hardware","D. Network bandwidth expands automatically"],correct:1,explanation:"Rapid elasticity is the ability to provision and release capabilities quickly—sometimes automatically—so that resources appear unlimited and can be acquired in any quantity at any time."},
{id:5,domain:1,level:1,question:"A development team wants to deploy custom applications without managing servers or the underlying OS. Which service model is most appropriate?",options:["A. IaaS","B. PaaS","C. SaaS","D. DaaS"],correct:1,explanation:"PaaS provides a platform allowing customers to develop, run, and manage applications without the complexity of managing infrastructure."},
{id:6,domain:1,level:1,question:"In the shared responsibility model for IaaS, which item is the CUSTOMER's responsibility?",options:["A. Physical security of data centers","B. Hypervisor security","C. Guest operating system patching","D. Core network infrastructure"],correct:2,explanation:"In IaaS the customer owns everything from the OS upward: OS patching, middleware, applications, and data. The provider secures physical facilities, hypervisor, and network infrastructure."},
{id:7,domain:1,level:1,question:"What does 'measured service' mean under NIST's cloud definition?",options:["A. SLA performance is measured by a third party","B. Resource usage is monitored, controlled, and billed on a pay-per-use basis","C. Customers measure their satisfaction monthly","D. Latency is measured continuously"],correct:1,explanation:"Measured service means cloud systems automatically control and optimize resource use through metering, providing transparency for both provider and consumer."},
{id:8,domain:1,level:1,question:"What is the PRIMARY purpose of a Cloud Access Security Broker (CASB)?",options:["A. To physically secure cloud data centers","B. To act as a security policy enforcement point between users and cloud services","C. To provide backup and recovery for SaaS applications","D. To replace traditional firewalls"],correct:1,explanation:"A CASB sits between users and cloud services, enforcing security policies. It provides visibility, compliance monitoring, data security, and threat protection."},
{id:9,domain:1,level:1,question:"Which cloud deployment model combines two or more distinct cloud infrastructures bound together by standardized technology?",options:["A. Community cloud","B. Multi-cloud","C. Hybrid cloud","D. Federated cloud"],correct:2,explanation:"Hybrid cloud combines private, community, or public clouds that remain unique entities but are bound together enabling data and application portability (e.g., cloud bursting)."},
{id:10,domain:1,level:1,question:"Which of the following is an example of SaaS?",options:["A. Amazon EC2","B. Microsoft Azure Virtual Machines","C. Google Workspace (Gmail, Docs)","D. AWS Elastic Kubernetes Service"],correct:2,explanation:"SaaS delivers software applications over the internet managed by the provider. Google Workspace is SaaS. EC2 and Azure VMs are IaaS; EKS is PaaS/IaaS."},
{id:11,domain:1,level:2,question:"A financial institution needs to keep sensitive customer data under its direct control while leveraging public cloud for analytics workloads. Which approach BEST addresses both goals?",options:["A. Deploy all workloads on a public cloud with encryption","B. Implement a hybrid cloud keeping sensitive data on-premises","C. Use a community cloud shared with peer institutions","D. Avoid cloud adoption until regulations change"],correct:1,explanation:"Hybrid cloud lets the institution maintain sensitive data on-premises or in a private cloud (regulatory compliance) while using public cloud for non-sensitive analytics (cost/scalability)."},
{id:12,domain:1,level:2,question:"What is 'cloud bursting'?",options:["A. A DDoS attack targeting cloud infrastructure","B. Failure of cloud services during peak load","C. Overflow of workloads from private to public cloud when demand spikes","D. Migrating all workloads from on-premises to public cloud"],correct:2,explanation:"Cloud bursting is a hybrid configuration where an application runs in a private cloud and automatically bursts into a public cloud when computing demand exceeds private cloud capacity."},
{id:13,domain:1,level:2,question:"What is the KEY security risk introduced by hypervisor-based virtualization in cloud?",options:["A. Increased power consumption","B. A hypervisor compromise could expose all VMs on that host","C. Network bandwidth becomes the primary bottleneck","D. Physical access controls become irrelevant"],correct:1,explanation:"A hypervisor compromise (VM escape) gives an attacker access to all virtual machines on the host, making the hypervisor the most critical attack surface in virtualized cloud environments."},
{id:14,domain:1,level:2,question:"Cloud 'portability' refers to which of the following?",options:["A. Accessing cloud services from mobile devices","B. Moving applications and data between cloud providers","C. Physically relocating cloud servers","D. Converting monolithic apps to microservices"],correct:1,explanation:"Cloud portability is the ability to move workloads between different cloud environments. It is achieved through open standards and APIs and is the opposite of vendor lock-in."},
{id:15,domain:1,level:2,question:"What is the PRIMARY purpose of a cloud Service Level Agreement (SLA)?",options:["A. Define the technical architecture","B. Specify all security controls the provider must implement","C. Define expected performance, availability, and remedies for non-compliance","D. Set the pricing model for the service"],correct:2,explanation:"An SLA is a contractual commitment defining the expected service levels (uptime, performance, support) and the remedies (credits, penalties) if the provider fails to meet them."},
{id:16,domain:1,level:2,question:"What is the MOST significant security concern with public APIs in cloud environments?",options:["A. APIs increase infrastructure costs","B. Insecure APIs can expose sensitive data and functionality to unauthorized parties","C. APIs reduce application performance","D. APIs are only relevant to backend developers"],correct:1,explanation:"APIs are a primary attack vector in cloud. Vulnerabilities such as broken authentication, excessive data exposure, and lack of rate limiting can lead to unauthorized access to cloud resources."},
{id:17,domain:1,level:2,question:"What does the CSA Cloud Controls Matrix (CCM) provide?",options:["A. A regulatory mandate from NIST for cloud providers","B. A cybersecurity control framework with objectives specific to cloud environments","C. A pricing benchmark for cloud services","D. Technical standards for cloud APIs"],correct:1,explanation:"The CSA CCM provides 197 control objectives across 17 domains to help cloud customers and providers assess and improve cloud security posture. It maps to many compliance frameworks."},
{id:18,domain:1,level:2,question:"'Vendor lock-in' in cloud computing is BEST described as:",options:["A. A physical security measure locking vendors out of data centers","B. A mandatory single-vendor procurement policy","C. Difficulty moving applications and data away from a specific cloud provider","D. A license restriction preventing software redistribution"],correct:2,explanation:"Vendor lock-in arises from dependency on a provider's proprietary APIs, services, or formats, making migration costly and complex. It is mitigated through open standards and portability planning."},
{id:19,domain:1,level:2,question:"In cloud security architecture, a 'security domain' is BEST described as:",options:["A. A DNS zone for cloud services","B. A logical grouping of resources sharing the same security policies","C. A physical perimeter around data centers","D. An encryption algorithm family"],correct:1,explanation:"A security domain is a logical grouping of systems, users, and data that share the same security requirements and policies, simplifying consistent policy application across complex cloud environments."},
{id:20,domain:1,level:2,question:"Which principle states that users should only be granted the minimum access rights necessary to perform their job functions?",options:["A. Separation of duties","B. Least privilege","C. Defense in depth","D. Need to know"],correct:1,explanation:"Least privilege limits user access rights to only what is required for their role, reducing the attack surface and limiting damage if credentials are compromised."},
{id:21,domain:1,level:3,question:"An organization must comply with FIPS 140-2 for a cloud deployment. Which component is MOST critical to evaluate for compliance?",options:["A. Network topology design","B. Physical data center location","C. Cryptographic modules used by the cloud service","D. VM density on each host"],correct:2,explanation:"FIPS 140-2 validates cryptographic modules. When deploying under this requirement, all encryption libraries, key management systems, and HSMs must be FIPS 140-2 validated."},
{id:22,domain:1,level:3,question:"What is the KEY difference between RTO and RPO in cloud disaster recovery?",options:["A. RTO applies to databases; RPO applies to applications","B. RTO measures maximum acceptable downtime; RPO measures maximum acceptable data loss","C. RTO is a business metric; RPO is a technical metric","D. They are interchangeable terms"],correct:1,explanation:"Recovery Time Objective (RTO) is the maximum time to restore service after a failure. Recovery Point Objective (RPO) is the maximum acceptable amount of data loss measured in time."},
{id:23,domain:1,level:3,question:"Which approach BEST describes 'defense in depth' applied to cloud architecture?",options:["A. Deploying only the deepest level of encryption","B. Placing all controls at the network perimeter","C. Implementing multiple independent layers of security controls","D. Relying exclusively on the cloud provider's native security"],correct:2,explanation:"Defense in depth layers security controls across network, host, application, and data layers. A breach of one layer does not compromise the entire system because other controls remain."},
{id:24,domain:1,level:3,question:"For a heavily regulated organization, what is the MOST important architectural consideration for data residency?",options:["A. Storing data in geographically distributed regions for redundancy","B. Ensuring data remains within required legal jurisdictions","C. Placing data as close to users as possible for performance","D. Using the provider with the most global data centers"],correct:1,explanation:"Data residency requirements mandate that data be stored within specific geographic or legal jurisdictions. In regulated industries this may override performance or redundancy preferences."},
{id:25,domain:1,level:3,question:"In a zero-trust cloud architecture, what is the core principle regarding network location?",options:["A. Internal network traffic is always trusted","B. Trust is determined by the physical location of the device","C. No user or device is trusted by default regardless of network location","D. The cloud perimeter replaces the corporate firewall"],correct:2,explanation:"Zero trust assumes no implicit trust based on network location. Every access request is authenticated, authorized, and continuously validated regardless of whether it originates inside or outside the perimeter."},
{id:26,domain:1,level:3,question:"A company is migrating to cloud and wants to move VMs with minimal changes. Which migration strategy does this describe?",options:["A. Re-architect","B. Refactor","C. Lift and shift (Rehost)","D. Repurchase"],correct:2,explanation:"'Lift and shift' (rehosting) moves applications to cloud with minimal or no changes. It is the fastest migration approach but may not take full advantage of cloud-native features."},
{id:27,domain:1,level:3,question:"Which framework defines cloud computing roles such as Cloud Service Customer, Cloud Service Provider, and Cloud Service Partner?",options:["A. NIST SP 800-145","B. ISO/IEC 17789","C. CSA CCM","D. ENISA Cloud Risk Assessment"],correct:1,explanation:"ISO/IEC 17789 (Cloud Computing Reference Architecture) defines the cloud computing roles and activities including Cloud Service Customer, Cloud Service Provider, and Cloud Service Partner."},
{id:28,domain:1,level:3,question:"In serverless (FaaS) architecture, which layer does the customer NOT manage?",options:["A. Application code","B. Business logic","C. Runtime environment and below","D. Input validation"],correct:2,explanation:"In serverless/FaaS the provider manages the runtime, OS, and all infrastructure. The customer is responsible only for the function code, business logic, and data."},
{id:29,domain:1,level:3,question:"An organization uses multiple cloud providers for different workloads to avoid dependency on one vendor. This is called:",options:["A. Hybrid cloud","B. Cloud federation","C. Multi-cloud strategy","D. Cloud bursting"],correct:2,explanation:"Multi-cloud is the use of services from multiple cloud providers. It avoids vendor lock-in and can optimize cost and performance but introduces complexity in security management."},
{id:30,domain:1,level:3,question:"ENISA's cloud risk assessment identifies 'loss of governance' as a top risk. What does this mean for cloud customers?",options:["A. The provider's governance team lacks security expertise","B. Customers cede control to the provider and may not enforce their own security policies","C. Government regulators lose oversight of cloud providers","D. IT governance frameworks become obsolete in cloud"],correct:1,explanation:"Loss of governance occurs because cloud customers transfer control of systems to the provider. Customers may be unable to enforce their own security policies within the provider's infrastructure."},

// ─── DOMAIN 2: Cloud Data Security ──────────────────────────────────────────
{id:31,domain:2,level:1,question:"Which of the following correctly lists the phases of the Cloud Data Lifecycle defined by CSA?",options:["A. Create, Store, Use, Share, Archive, Destroy","B. Collect, Process, Store, Transmit, Delete","C. Input, Process, Output, Archive","D. Create, Classify, Encrypt, Share, Purge"],correct:0,explanation:"CSA defines six phases of the cloud data lifecycle: Create, Store, Use, Share, Archive, and Destroy. Understanding each phase helps apply appropriate security controls."},
{id:32,domain:2,level:1,question:"What is the PRIMARY purpose of data classification?",options:["A. To organize files alphabetically on storage systems","B. To assign a sensitivity level so appropriate controls can be applied","C. To identify duplicate data for deduplication","D. To comply with data retention schedules"],correct:1,explanation:"Data classification assigns sensitivity labels (e.g., Public, Internal, Confidential, Restricted) so that appropriate security controls, handling requirements, and access restrictions can be applied."},
{id:33,domain:2,level:1,question:"Which encryption approach protects data while it is being transmitted over a network?",options:["A. Encryption at rest","B. Encryption in transit","C. Encryption in use","D. Homomorphic encryption"],correct:1,explanation:"Encryption in transit (using TLS/SSL) protects data as it moves across networks, preventing interception. Encryption at rest protects stored data; encryption in use protects data while it is being processed."},
{id:34,domain:2,level:1,question:"What is Data Loss Prevention (DLP)?",options:["A. A backup technology ensuring data is never lost","B. A set of tools and processes that detect and prevent unauthorized data exfiltration","C. A redundancy strategy for databases","D. A protocol for secure file transfer"],correct:1,explanation:"DLP solutions monitor, detect, and block sensitive data from leaving the organization without authorization, whether via email, cloud uploads, USB, or other channels."},
{id:35,domain:2,level:1,question:"Which data state refers to data actively being processed in memory by an application?",options:["A. Data at rest","B. Data in transit","C. Data in use","D. Data in archive"],correct:2,explanation:"Data in use refers to data actively being accessed or processed in RAM or CPU. It is the hardest state to protect because it must be decrypted to be processed."},
{id:36,domain:2,level:1,question:"What is the purpose of a data retention policy?",options:["A. To ensure data is kept forever for legal purposes","B. To define how long data must be kept and when it must be destroyed","C. To specify backup frequency for critical data","D. To classify data by business value"],correct:1,explanation:"A data retention policy specifies how long different categories of data must be retained and the procedures for secure disposal when retention periods expire."},
{id:37,domain:2,level:1,question:"Which data sanitization technique destroys data on magnetic storage media by applying a strong magnetic field?",options:["A. Tokenization","B. Masking","C. Crypto-shredding","D. Degaussing"],correct:3,explanation:"Degaussing destroys data on magnetic media by applying a strong alternating magnetic field that disrupts and randomizes the magnetic domains, rendering data permanently unreadable. For SSDs and cloud storage where physical access is unavailable, crypto-shredding (destroying encryption keys) is the preferred method."},
{id:38,domain:2,level:1,question:"What is tokenization in the context of data security?",options:["A. Converting plaintext to ciphertext using an algorithm","B. Replacing sensitive data with a non-sensitive placeholder (token)","C. Splitting data into multiple fragments","D. Compressing data to reduce storage size"],correct:1,explanation:"Tokenization replaces sensitive data (e.g., credit card numbers) with a randomly generated token. The original value is stored in a secure token vault; the token is meaningless if stolen."},
{id:39,domain:2,level:1,question:"Which of the following BEST describes data masking?",options:["A. Encrypting data with a public key","B. Replacing real data with realistic but fictitious data for non-production use","C. Deleting data after a specified retention period","D. Compressing data to obscure its structure"],correct:1,explanation:"Data masking creates a structurally similar but inauthentic version of data for use in test/dev environments, protecting the actual sensitive data while preserving its format."},
{id:40,domain:2,level:1,question:"What is the primary role of a key management system (KMS) in cloud?",options:["A. Managing SSH keys for server access","B. Securely generating, storing, distributing, and retiring cryptographic keys","C. Managing API keys for developers","D. Controlling access to physical key cabinets"],correct:1,explanation:"A KMS manages the entire cryptographic key lifecycle including generation, storage, distribution, rotation, and destruction. Secure key management is critical because encrypted data is only as safe as its keys."},
{id:41,domain:2,level:1,question:"Which international standard provides a framework for information security management including data security?",options:["A. ISO/IEC 27001","B. SOC 2 Type II","C. PCI DSS","D. FIPS 140-2"],correct:0,explanation:"ISO/IEC 27001 is an international standard for Information Security Management Systems (ISMS). It provides a framework for managing sensitive data and includes requirements for data security controls."},
{id:42,domain:2,level:1,question:"What does 'data sovereignty' refer to?",options:["A. The owner's right to encrypt their own data","B. The concept that data is subject to the laws of the country in which it is stored","C. Cloud providers having ultimate control over customer data","D. The right of individuals to delete their own personal data"],correct:1,explanation:"Data sovereignty means that digital data is subject to the laws and governance structures of the nation where it is located. This affects where organizations can legally store data."},
{id:43,domain:2,level:2,question:"An organization stores encrypted data in a cloud provider's object storage. The organization holds the encryption keys. What happens to the data's confidentiality if the cloud provider is breached?",options:["A. Data is exposed because the provider has access to all stored content","B. Data remains confidential because the provider does not have the keys","C. Data is exposed because the provider can use the storage system to read it","D. Confidentiality depends on the type of encryption algorithm used"],correct:1,explanation:"If the customer controls the encryption keys and the provider only stores encrypted ciphertext, a provider breach exposes only unusable ciphertext. This is the BYOK (Bring Your Own Key) model."},
{id:44,domain:2,level:2,question:"What is 'Bring Your Own Key' (BYOK) in cloud encryption?",options:["A. Customers use USB keys to authenticate to the cloud","B. Customers generate and manage their own encryption keys used by the cloud provider","C. The cloud provider supplies pre-made encryption keys to customers","D. Customers bring physical hardware to the provider's data center"],correct:1,explanation:"BYOK allows customers to generate and manage encryption keys themselves (often in an on-premises HSM), then import those keys into the cloud provider's KMS, maintaining key control."},
{id:45,domain:2,level:2,question:"A company must ensure that deleted cloud data cannot be recovered. Which technique is MOST effective for cloud-stored data encrypted with AES-256?",options:["A. Overwriting storage blocks 7 times","B. Degaussing the physical drives","C. Destroying the encryption keys (crypto-shredding)","D. Deleting the object and waiting for provider garbage collection"],correct:2,explanation:"Crypto-shredding destroys the encryption keys, rendering the ciphertext permanently unreadable without needing physical access to storage media—ideal for cloud environments where you don't control the hardware."},
{id:46,domain:2,level:2,question:"What is a data eDiscovery challenge unique to cloud environments?",options:["A. Data is always encrypted and cannot be searched","B. Data may be spread across multiple jurisdictions and commingled with other tenants' data","C. Cloud providers always refuse legal holds","D. eDiscovery tools do not support cloud storage"],correct:1,explanation:"In cloud, data may be distributed across multiple geographic regions and storage systems, commingled with other tenants' data, making it difficult to identify, collect, and preserve relevant data for legal proceedings."},
{id:47,domain:2,level:2,question:"Which concept ensures that data integrity has not been compromised during storage or transmission?",options:["A. Confidentiality through encryption","B. Non-repudiation","C. Hashing to produce a message digest","D. Data masking"],correct:2,explanation:"Hashing produces a fixed-length digest of data. If any bit changes, the hash changes. Comparing hashes before and after transmission/storage verifies that data has not been tampered with."},
{id:48,domain:2,level:2,question:"A healthcare company uses a SaaS application. The vendor stores PHI in a shared database. Which control is MOST important for the customer to verify?",options:["A. The vendor's office physical security","B. Tenant data isolation and encryption in the shared database","C. The vendor's employee background checks","D. The vendor's marketing compliance"],correct:1,explanation:"In multi-tenant SaaS environments, tenant data isolation ensures that one customer's PHI cannot be accessed by another. Combined with encryption, this protects PHI even in shared infrastructure."},
{id:49,domain:2,level:2,question:"What is the difference between a data owner and a data custodian?",options:["A. They are the same role with different titles","B. The owner has business accountability for data; the custodian handles technical safeguarding","C. The owner handles backups; the custodian sets classification levels","D. The owner is a role for individuals; the custodian is a role for organizations"],correct:1,explanation:"The data owner (usually a business executive) is accountable for data classification and use decisions. The data custodian (usually IT) is responsible for implementing and maintaining technical security controls."},
{id:50,domain:2,level:2,question:"An organization wants to protect credit card data stored in a cloud database. Which standard mandates specific security controls for this data?",options:["A. HIPAA","B. SOX","C. PCI DSS","D. FERPA"],correct:2,explanation:"PCI DSS (Payment Card Industry Data Security Standard) mandates specific technical and operational security controls for organizations that store, process, or transmit payment card data."},
{id:51,domain:2,level:2,question:"What is Information Rights Management (IRM)?",options:["A. Managing user access rights in directory services","B. Technology that applies persistent access controls to documents regardless of location","C. A framework for managing intellectual property licensing","D. A process for classifying and labeling sensitive data"],correct:1,explanation:"IRM (also called Digital Rights Management/DRM) embeds access controls directly into documents so restrictions (view, edit, print, forward) persist even after the file leaves the organization."},
{id:52,domain:2,level:2,question:"Which data discovery technique scans cloud storage for sensitive data patterns like SSNs and credit card numbers?",options:["A. Vulnerability scanning","B. Data Loss Prevention content inspection","C. Log analysis","D. Penetration testing"],correct:1,explanation:"DLP tools use content inspection with pattern matching (regex), exact data matching, and machine learning to discover sensitive data in cloud storage, email, and endpoints."},
{id:53,domain:2,level:3,question:"An organization uses homomorphic encryption for cloud-stored data. What unique capability does this provide?",options:["A. Data can be encrypted with multiple keys simultaneously","B. Computations can be performed on encrypted data without decrypting it","C. Encryption and decryption happen at hardware speed","D. The encryption key is embedded within the data"],correct:1,explanation:"Homomorphic encryption allows computation on ciphertext, producing an encrypted result that, when decrypted, matches the result of operations performed on the plaintext. This enables cloud processing without exposing raw data."},
{id:54,domain:2,level:3,question:"A multi-national company stores data in multiple countries. Different countries have conflicting data localization laws. Which approach BEST addresses this conflict?",options:["A. Store all data in the country with the strictest laws","B. Implement data residency controls per-country with jurisdiction-aware routing","C. Use a single global data center and seek exemptions","D. Encrypt all data so localization laws do not apply"],correct:1,explanation:"Jurisdiction-aware data routing ensures each country's data is stored within that country's borders per local law. This requires careful architecture and policy enforcement across cloud regions."},
{id:55,domain:2,level:3,question:"What is the chain of custody and why is it critical in cloud forensics?",options:["A. The encryption chain protecting data in transit—critical for FIPS compliance","B. The documented history of evidence handling—critical to prove evidence integrity in legal proceedings","C. The sequence of cloud API calls—critical for debugging","D. The backup rotation schedule—critical for data recovery"],correct:1,explanation:"Chain of custody documents who collected, handled, transferred, and analyzed evidence. In cloud forensics, establishing and maintaining chain of custody is essential for evidence admissibility in court."},
{id:56,domain:2,level:3,question:"A cloud provider offers 'server-side encryption.' What is the primary risk of this model compared to client-side encryption?",options:["A. Server-side encryption uses weaker algorithms","B. The provider holds and manages the keys, meaning a provider compromise exposes keys and data","C. Server-side encryption has higher latency","D. Server-side encryption is not supported by major compliance frameworks"],correct:1,explanation:"In server-side encryption the provider manages the keys. If the provider's key management is compromised, or if the provider receives a legal order, the data can be decrypted. Client-side encryption keeps keys with the customer."},
{id:57,domain:2,level:3,question:"Which technique splits data into multiple shares such that a minimum number of shares is required to reconstruct the data (e.g., 3 of 5)?",options:["A. RAID striping","B. Data sharding","C. Secret sharing (Shamir's Secret Sharing)","D. Erasure coding"],correct:2,explanation:"Shamir's Secret Sharing splits a secret into N shares where a minimum threshold (K of N) is needed to reconstruct it. It is used for cryptographic key management to distribute trust."},
{id:58,domain:2,level:3,question:"An organization wants to comply with GDPR's 'right to erasure.' In a cloud environment with distributed caches and backups, what is the BEST approach?",options:["A. Submit a deletion request to the provider and trust it is done","B. Implement crypto-shredding so encrypted personal data becomes unreadable without the key","C. Delete records from the primary database only","D. Rely on the provider's data retention expiration"],correct:1,explanation:"Crypto-shredding is the recommended approach for GDPR erasure in cloud: destroy the encryption keys associated with a data subject's data, rendering it permanently unreadable across all copies without physically locating every instance."},
{id:59,domain:2,level:3,question:"What is a Hardware Security Module (HSM) and why is it preferred for key management?",options:["A. A cloud-based key management software service","B. A tamper-resistant hardware device that generates and protects cryptographic keys","C. An encryption accelerator card for faster SSL processing","D. A physical token used for multi-factor authentication"],correct:1,explanation:"An HSM is a tamper-resistant hardware device dedicated to cryptographic operations. Keys never leave the HSM in plaintext, and physical tamper-resistance protects against extraction attacks, making it the gold standard for key management."},
{id:60,domain:2,level:3,question:"A database stores both structured PII and unstructured documents. Which combination of controls BEST protects both data types?",options:["A. TDE for the database; file-level encryption for documents","B. Field-level encryption for PII fields; IRM for documents with DLP monitoring both","C. Full-disk encryption only—this covers all data types","D. VPN access restriction is sufficient for both"],correct:1,explanation:"Field-level encryption protects specific sensitive columns in the database while allowing queries on non-sensitive fields. IRM embeds persistent controls in documents. DLP provides monitoring and prevents unauthorized exfiltration across both."},

// ─── DOMAIN 2 – Batch 2 ──────────────────────────────────────────────────────
{id:299,domain:2,level:1,question:"What is the '3-2-1 backup rule'?",options:["A. Back up 3 times a day, 2 copies on-site, 1 copy encrypted","B. Keep 3 copies of data, on 2 different media types, with 1 copy off-site","C. Retain backups for 3 years, test 2 times a year, 1 administrator responsible","D. 3 full backups, 2 incremental, 1 differential per week"],correct:1,explanation:"The 3-2-1 rule: 3 total copies of data, stored on 2 different media types, with 1 copy stored off-site (or in a different cloud region). It protects against hardware failure, site disaster, and media corruption simultaneously."},
{id:300,domain:2,level:1,question:"What is the difference between a full backup and an incremental backup?",options:["A. Full backups encrypt data; incremental backups do not","B. A full backup copies all data; an incremental backup copies only data changed since the last backup","C. Full backups are stored on-site; incremental backups are stored off-site","D. They are the same — just different vendor terminology"],correct:1,explanation:"A full backup copies everything. An incremental backup copies only what changed since the last backup (full or incremental). Incremental backups are faster and smaller but require more complex restoration (apply full + all incrementals in sequence)."},
{id:301,domain:2,level:1,question:"What is a differential backup?",options:["A. A backup that captures the difference between two file versions","B. A backup that copies all data changed since the last FULL backup (regardless of subsequent incrementals)","C. A backup strategy that uses two different media types","D. An automated backup that runs on a different schedule than the primary backup"],correct:1,explanation:"A differential backup copies all changes since the last full backup. Restoration requires only the full backup plus the most recent differential — simpler than incremental restoration but differential files grow larger over time."},
{id:302,domain:2,level:1,question:"What is 'data deduplication' in cloud storage?",options:["A. Removing duplicate user accounts from a directory","B. A storage optimization technique that eliminates redundant copies of data, storing only unique chunks","C. A process for identifying and deleting old backups","D. Preventing users from saving the same file twice"],correct:1,explanation:"Deduplication identifies identical data chunks and stores only one copy, with references from all duplicate locations. It significantly reduces storage costs and backup windows for data sets with high redundancy (e.g., VM images, email attachments)."},
{id:303,domain:2,level:1,question:"What is 'data archiving' and how does it differ from backup?",options:["A. They are identical — archiving is just another word for backup","B. Archives preserve data for long-term retention and reference; backups protect against data loss for operational recovery","C. Archives are encrypted; backups are not","D. Backups are for cloud data; archives are for on-premises data"],correct:1,explanation:"Backup is operational — it protects against data loss and enables recovery. Archiving is for long-term retention of data that is no longer actively used but must be preserved for compliance, legal, or historical purposes. Archive data is typically stored on cheaper, slower media."},
{id:304,domain:2,level:1,question:"What is 'symmetric encryption'?",options:["A. Encryption that uses two mathematically related keys","B. Encryption that uses the same key for both encryption and decryption","C. Encryption applied equally to all data in a system","D. An encryption algorithm that is symmetric in its mathematical structure"],correct:1,explanation:"Symmetric encryption uses a single shared key for both encryption and decryption. It is fast and efficient for bulk data encryption (AES is the standard). The challenge is securely distributing the shared key to all parties who need it."},
{id:305,domain:2,level:1,question:"What is 'asymmetric encryption' and what is its primary use case?",options:["A. Encryption using different key lengths for different data types","B. Encryption using a key pair — public key encrypts, private key decrypts — primarily used for key exchange and digital signatures","C. Encryption that is asymmetric in performance between encryption and decryption","D. A type of encryption only used for asymmetric data structures"],correct:1,explanation:"Asymmetric encryption uses a mathematically linked key pair. Data encrypted with the public key can only be decrypted with the private key. It is used for secure key exchange, digital signatures, and TLS handshakes. It is slower than symmetric encryption."},
{id:306,domain:2,level:1,question:"What is a digital signature and what does it provide?",options:["A. An electronic version of a handwritten signature for document signing","B. A cryptographic mechanism using a private key that provides data integrity, authentication, and non-repudiation","C. An image file of a physical signature","D. A password used to authenticate document access"],correct:1,explanation:"A digital signature uses the signer's private key to create a unique hash of a message. Recipients use the public key to verify the signature, confirming: (1) the message came from the key holder, (2) the message was not altered, (3) the signer cannot deny signing."},
{id:307,domain:2,level:1,question:"What is Public Key Infrastructure (PKI)?",options:["A. A public network for key exchange","B. A framework of policies, procedures, hardware, software, and roles for managing digital certificates and public-key encryption","C. A government system for managing identity documents","D. An open-source encryption library"],correct:1,explanation:"PKI is the ecosystem that enables secure public-key encryption and digital signatures. It includes Certificate Authorities (CAs), registration authorities, certificate repositories, and policies for issuing, revoking, and validating digital certificates."},
{id:308,domain:2,level:1,question:"What is a Certificate Authority (CA)?",options:["A. A government agency that authorizes cloud providers","B. A trusted entity that issues digital certificates, binding public keys to identities","C. An automated tool for generating encryption keys","D. A hardware device that stores cryptographic keys"],correct:1,explanation:"A CA is a trusted third party that validates the identity of certificate requestors and issues digital certificates binding their public key to their verified identity. Web browsers include a list of trusted root CAs to validate server certificates."},
{id:309,domain:2,level:1,question:"What is TLS (Transport Layer Security) and what does it protect?",options:["A. A physical cable standard for secure network connections","B. A cryptographic protocol that provides confidentiality, integrity, and authentication for data in transit over networks","C. A tool for managing SSL certificates","D. A firewall protocol for filtering network traffic"],correct:1,explanation:"TLS (successor to SSL) encrypts data in transit between clients and servers, provides server authentication via certificates, and ensures data integrity. It is the foundation of HTTPS and secures email, VPNs, and API communications."},
{id:310,domain:2,level:1,question:"What is HMAC (Hash-based Message Authentication Code)?",options:["A. A type of asymmetric encryption algorithm","B. A mechanism combining a cryptographic hash function with a secret key to verify both data integrity and authenticity","C. A hardware module for accelerating MD5 hashing","D. A multi-factor authentication protocol"],correct:1,explanation:"HMAC uses a secret key combined with a hash function (e.g., HMAC-SHA256) to produce a MAC. It verifies that a message both has not been tampered with and came from the holder of the shared secret key, providing integrity and authentication."},
{id:311,domain:2,level:1,question:"Why should passwords never be stored in plaintext?",options:["A. Plaintext passwords are too long to store efficiently","B. If the database is breached, plaintext passwords expose all user credentials immediately","C. Regulations prohibit storing passwords at all","D. Plaintext passwords expire faster than hashed passwords"],correct:1,explanation:"Storing passwords in plaintext means a database breach instantly exposes all user credentials. Passwords should be stored as salted cryptographic hashes (e.g., bcrypt, Argon2) so that even with database access, an attacker must crack each hash individually."},
{id:312,domain:2,level:1,question:"What is a 'salt' in password hashing?",options:["A. An encryption key used to secure the password hash","B. A random value added to a password before hashing, ensuring identical passwords produce different hashes","C. A pepper applied after hashing to add a second layer","D. A timestamp appended to passwords to make them unique"],correct:1,explanation:"A salt is a unique random value prepended or appended to a password before hashing. It ensures two users with identical passwords have different hashes, and prevents precomputed rainbow table attacks since each password has a unique salt."},
{id:313,domain:2,level:2,question:"An organization migrates to cloud and wants to ensure encryption keys remain under their exclusive control. Which model achieves this?",options:["A. Provider-managed keys (SSE)","B. Customer-managed keys in the cloud KMS (BYOK)","C. Customer-managed keys in a customer-owned HSM with HYOK","D. No encryption — keys are unnecessary in a private cloud"],correct:2,explanation:"HYOK (Hold Your Own Key) keeps encryption keys entirely in the customer's own HSM, outside the cloud provider's reach. BYOK imports customer-generated keys into the cloud KMS but the provider still has logical access. HYOK provides the strongest isolation."},
{id:314,domain:2,level:2,question:"What is 'envelope encryption' as used by cloud KMS services?",options:["A. Encrypting data and sealing it in a virtual envelope for transit","B. Encrypting data with a data encryption key (DEK), then encrypting the DEK with a key encryption key (KEK) stored in KMS","C. A two-factor encryption scheme requiring two administrators","D. An email encryption standard for cloud communications"],correct:1,explanation:"Envelope encryption wraps a data encryption key (DEK) with a key encryption key (KEK) managed by KMS. Only the encrypted DEK is stored with the data; the KEK never leaves KMS. This enables efficient bulk encryption while protecting the DEK cryptographically."},
{id:315,domain:2,level:2,question:"What is 'key rotation' and why is it important?",options:["A. Physically rotating storage media that contains keys","B. Periodically replacing cryptographic keys with new ones to limit exposure if a key is compromised","C. Rotating responsibilities for key management among team members","D. Changing key algorithms from RSA to AES periodically"],correct:1,explanation:"Key rotation replaces old cryptographic keys with new ones on a regular schedule. If a key was silently compromised, rotation limits how much data an attacker can decrypt with the stolen key. Automated rotation reduces the burden and risk of manual processes."},
{id:316,domain:2,level:2,question:"What is 'perfect forward secrecy' (PFS) in TLS?",options:["A. A guarantee that TLS connections will never fail","B. A property where session keys are derived independently so compromise of the server's private key does not compromise past session keys","C. A feature preventing TLS certificates from expiring","D. An algorithm that makes TLS encryption mathematically perfect"],correct:1,explanation:"PFS ensures each TLS session uses ephemeral keys derived from Diffie-Hellman key exchange. If the server's long-term private key is later compromised, recorded past sessions cannot be decrypted because the session keys were never stored and the long-term key was not used to derive them."},
{id:317,domain:2,level:2,question:"What is 'format-preserving encryption' (FPE) and when is it useful?",options:["A. Encryption that preserves the file format of encrypted documents","B. Encryption that produces ciphertext in the same format as the plaintext (e.g., a 16-digit cipher for a 16-digit credit card number)","C. An encryption method that maintains backwards compatibility with older systems","D. Encryption that preserves data integrity through checksums"],correct:1,explanation:"FPE (e.g., FF3-1) produces ciphertext that matches the format, length, and character set of the plaintext. It is used when encrypted data must work in existing systems that validate format — for example, encrypting credit card numbers so they still pass Luhn check validation."},
{id:318,domain:2,level:2,question:"What is 'data lineage' and why is it important for cloud data security?",options:["A. The family history of data owners in an organization","B. The documented history of data's origin, movement, transformations, and usage — supporting audit, compliance, and breach investigation","C. A record of which cloud providers have held the data","D. The age of data records in a database"],correct:1,explanation:"Data lineage tracks data from origin through all transformations and movements. In cloud, it enables organizations to understand where sensitive data flows, demonstrate compliance (GDPR, CCPA), and trace data during breach investigations."},
{id:319,domain:2,level:2,question:"A cloud storage bucket is accidentally made public. What type of incident is this and what is the immediate response?",options:["A. A network intrusion — immediately isolate the network segment","B. A misconfiguration-caused data exposure — immediately restrict access, assess what data was exposed, and initiate breach notification procedures if applicable","C. A DDoS attack — activate traffic scrubbing","D. A malware infection — scan all files in the bucket"],correct:1,explanation:"An inadvertently public bucket is a misconfiguration data exposure. Immediate response: restrict access (make private), check access logs to assess who accessed the data, determine if sensitive data was exposed, and if so initiate breach notification under applicable regulations (GDPR 72-hour notification)."},
{id:320,domain:2,level:2,question:"What is 'data minimization' in practice within a cloud application?",options:["A. Compressing data to reduce storage costs","B. Collecting only fields necessary for the stated purpose, applying retention limits, and building deletion workflows into the application","C. Reducing the number of data copies across regions","D. Limiting data access to minimize the number of authorized users"],correct:1,explanation:"Data minimization means designing systems to only collect, process, and retain necessary personal data. Practically: avoid collecting optional fields, set TTLs on records, automate deletion when data is no longer needed, and pseudonymize where possible."},
{id:321,domain:2,level:2,question:"What is 'data classification' and what are common classification levels?",options:["A. Organizing files into folders by date","B. Labeling data by sensitivity so appropriate controls are applied — common levels: Public, Internal, Confidential, Restricted/Secret","C. Sorting data by file type for storage optimization","D. A process for categorizing data by its age for archiving"],correct:1,explanation:"Data classification assigns sensitivity labels that determine handling requirements, access controls, and encryption needs. Common schemes use four levels (Public → Internal → Confidential → Restricted) so controls scale with sensitivity — more sensitive data gets stronger protections."},
{id:322,domain:2,level:2,question:"What is 'rights management' in the context of cloud-stored documents?",options:["A. Managing intellectual property rights for software used in cloud","B. Technology that embeds persistent access controls within documents so restrictions follow the file wherever it goes","C. A process for managing user access rights to cloud storage","D. Legal rights of cloud providers to access customer documents"],correct:1,explanation:"Rights management (IRM/DRM) embeds access control metadata directly in documents. Restrictions (view-only, no-print, no-forward, expiry dates) persist even when files are downloaded, emailed, or moved to unauthorized cloud storage."},
{id:323,domain:2,level:3,question:"An auditor asks how deleted data is handled in a cloud environment. The provider uses SSDs shared across tenants. What is the BEST answer?",options:["A. Data is securely wiped using DoD 7-pass overwrite on deletion","B. The provider's crypto-shredding destroys the encryption keys, rendering deleted tenant data unreadable — physical destruction of SSDs occurs at end-of-life","C. Data is automatically deleted from all copies within 30 days","D. Physical drives are sent to customers for destruction after use"],correct:1,explanation:"In cloud environments using shared SSDs, physical overwrite of specific sectors is impractical. The standard approach is crypto-shredding (destroying encryption keys so data is unreadable) plus provider attestation of physical drive destruction at end-of-life, documented in the contract."},
{id:324,domain:2,level:3,question:"What is 're-identification risk' in anonymized datasets and how should it be managed?",options:["A. The risk that anonymized data can be restored by reversing the anonymization algorithm","B. The risk that combining anonymized datasets with publicly available data allows individual identification — managed through k-anonymity, differential privacy, and data minimization","C. The risk of accidentally re-naming records during data migration","D. A risk only applicable to biometric data"],correct:1,explanation:"Re-identification risk arises because 'anonymous' data can often be de-anonymized by correlating it with external datasets. Mitigation includes k-anonymity (each record is indistinguishable from k-1 others), l-diversity, differential privacy, and restricting access to quasi-identifiers."},
{id:325,domain:2,level:3,question:"What is 'differential privacy' and how does it protect individuals in cloud analytics?",options:["A. A privacy-preserving encryption scheme for differential equations","B. A mathematical framework adding calibrated noise to query results so individual records cannot be inferred from statistical outputs","C. A policy distinguishing between different privacy levels in a dataset","D. An encryption technique for databases with varying data sensitivity"],correct:1,explanation:"Differential privacy adds carefully calibrated statistical noise to query outputs, ensuring the presence or absence of any individual's data cannot be detected from the query result. It enables meaningful analytics on sensitive data while providing strong privacy guarantees."},
{id:326,domain:2,level:3,question:"A cloud data warehouse processes data from 50 source systems. How should a data governance program address data quality as a security concern?",options:["A. Data quality has no security implications — only accuracy matters","B. Poor data quality can lead to incorrect access decisions, flawed audit trails, and missed breach detection — governance must include data validation, lineage tracking, and quality monitoring","C. Restrict all data ingestion to a single trusted source","D. Use data quality tools only in development environments"],correct:1,explanation:"Data quality directly impacts security: inaccurate user records lead to wrong access provisioning, incomplete logs miss security events, and corrupted audit data undermines forensic investigations. A governance program must treat data quality as a security control."},
{id:327,domain:2,level:3,question:"What is 'data tokenization at the field level' and how does it differ from full-database encryption?",options:["A. They are equivalent — tokenization and encryption produce the same result","B. Field-level tokenization replaces specific sensitive values with tokens while leaving other fields in plaintext, enabling queries on non-sensitive fields without exposing sensitive data","C. Tokenization encrypts the entire database; field encryption targets specific tables","D. Tokenization is used for transit; field encryption is used for storage"],correct:1,explanation:"Field-level tokenization replaces specific sensitive values (e.g., SSN, card number) with format-preserving tokens. Non-sensitive fields remain queryable in plaintext. Unlike full-database encryption, tokenized databases can be queried efficiently without decrypting everything first."},
{id:328,domain:2,level:3,question:"An organization uses a multi-cloud strategy and must maintain consistent data security controls across all providers. What is the BEST tool for this?",options:["A. Apply each cloud provider's native security tools independently","B. Implement a cloud-agnostic CASB or data security platform that enforces consistent policies across all cloud environments","C. Choose only one cloud provider to simplify security","D. Write custom scripts for each provider's API"],correct:1,explanation:"A CASB or cloud-agnostic data security platform can enforce consistent DLP, access control, encryption, and monitoring policies across multiple cloud providers through a single policy engine, avoiding the risk of policy gaps between environments."},

// ─── DOMAIN 3: Cloud Platform & Infrastructure Security ──────────────────────
{id:61,domain:3,level:1,question:"What is a hypervisor?",options:["A. A high-performance network switch in cloud data centers","B. Software that creates and manages virtual machines on physical hardware","C. A security tool that monitors VM traffic","D. A load balancer for cloud applications"],correct:1,explanation:"A hypervisor (VMM) is software that abstracts physical hardware and allows multiple virtual machines to run on a single physical host, each isolated from the others."},
{id:62,domain:3,level:1,question:"Which type of hypervisor runs directly on physical hardware without an underlying OS?",options:["A. Type 1 (bare-metal) hypervisor","B. Type 2 (hosted) hypervisor","C. Paravirtualization hypervisor","D. Container runtime"],correct:0,explanation:"Type 1 (bare-metal) hypervisors run directly on hardware (e.g., VMware ESXi, Microsoft Hyper-V). Type 2 hypervisors run on top of a host OS (e.g., VirtualBox, VMware Workstation)."},
{id:63,domain:3,level:1,question:"What is a virtual machine (VM) escape attack?",options:["A. An attacker deleting all VMs on a cloud host","B. A guest VM breaking out of its isolation to access the hypervisor or other VMs","C. Shutting down VMs remotely without authorization","D. Cloning a VM without permission"],correct:1,explanation:"VM escape is a critical attack where malicious code in a guest VM exploits a hypervisor vulnerability to break out of isolation and access the hypervisor or other guest VMs on the same host."},
{id:64,domain:3,level:1,question:"What is the PRIMARY security function of network segmentation in cloud environments?",options:["A. Improving network performance","B. Reducing cloud costs by sharing resources","C. Limiting lateral movement by isolating network zones","D. Simplifying network management"],correct:2,explanation:"Network segmentation divides a network into isolated zones. If one zone is compromised, segmentation limits an attacker's ability to move laterally to other zones, containing the breach."},
{id:65,domain:3,level:1,question:"What does a Security Group in AWS (or similar construct in other clouds) function as?",options:["A. A group of IAM users with shared permissions","B. A virtual stateful firewall controlling traffic to/from cloud resources","C. A collection of security policies applied to a region","D. A team responsible for cloud security management"],correct:1,explanation:"Security Groups are virtual stateful firewalls attached to cloud resources (e.g., EC2 instances). They control inbound and outbound traffic based on rules and are stateful (return traffic is automatically allowed)."},
{id:66,domain:3,level:1,question:"What is the purpose of a bastion host (jump server) in cloud architecture?",options:["A. A server that stores and serves static content","B. A hardened entry point for administrative access to resources in a private network","C. A load balancer for distributing traffic","D. A database server for sensitive data"],correct:1,explanation:"A bastion host is a hardened server that acts as a single access point for administrative access (SSH/RDP) to private network resources. It reduces the attack surface by minimizing the number of systems exposed to the internet."},
{id:67,domain:3,level:1,question:"What is Infrastructure as Code (IaC) and its security benefit?",options:["A. Coding physical infrastructure in assembly language","B. Defining infrastructure through machine-readable files, enabling consistent and auditable deployments","C. A billing model where you pay per code execution","D. An API framework for managing cloud resources"],correct:1,explanation:"IaC (e.g., Terraform, CloudFormation) defines infrastructure in code, enabling version control, peer review, automated security scanning, and repeatable deployments—reducing configuration drift and human error."},
{id:68,domain:3,level:1,question:"What is a Software-Defined Network (SDN)?",options:["A. A network managed entirely by hardware-based switches","B. An approach where network control is decoupled from hardware and managed via software","C. A wireless network protocol for IoT devices","D. A standard for encrypting network traffic"],correct:1,explanation:"SDN separates the control plane (deciding where traffic goes) from the data plane (forwarding traffic). This enables centralized, programmatic network management and faster security policy updates."},
{id:69,domain:3,level:1,question:"Which of the following BEST describes container security compared to VM security?",options:["A. Containers are more secure because they have stronger hardware isolation","B. Containers share the host OS kernel, creating a smaller but potentially shared attack surface","C. Containers are always more secure because they are smaller","D. Container and VM security are identical concepts"],correct:1,explanation:"Unlike VMs, containers share the host OS kernel. If the kernel is compromised, all containers on that host are at risk. However, containers have lower overhead and faster deployment, requiring specific security controls like namespace isolation."},
{id:70,domain:3,level:1,question:"What is the purpose of vulnerability scanning in cloud infrastructure?",options:["A. To test application functionality","B. To identify known security weaknesses and misconfigurations in cloud resources","C. To measure network performance","D. To audit user access permissions"],correct:1,explanation:"Vulnerability scanning automatically identifies known CVEs, misconfigurations, and weaknesses in cloud infrastructure components (VMs, containers, network devices) so they can be remediated before exploitation."},
{id:71,domain:3,level:2,question:"An attacker gains access to the management plane of a cloud environment. What is the MOST severe potential impact?",options:["A. Degraded application performance","B. Access to a single VM's data","C. Complete control over all cloud resources and data in the account","D. Temporary service interruption"],correct:2,explanation:"The cloud management plane (control plane) manages all resources. Compromise of management plane credentials (e.g., root/admin cloud API keys) gives an attacker complete control: they can create, modify, or delete any resource."},
{id:72,domain:3,level:2,question:"Which security control BEST protects against unauthorized lateral movement in a cloud VPC?",options:["A. Encrypting all data at rest","B. Micro-segmentation with granular east-west traffic controls","C. Implementing MFA for all user accounts","D. Regular vulnerability scanning"],correct:1,explanation:"Micro-segmentation applies granular network policies between individual workloads (east-west traffic), preventing an attacker who has compromised one workload from easily accessing others even within the same network segment."},
{id:73,domain:3,level:2,question:"What is the PRIMARY risk of using a shared AMI (Amazon Machine Image) or cloud marketplace image from an unverified source?",options:["A. Higher cost than building custom images","B. The image may contain pre-installed malware, backdoors, or vulnerabilities","C. Shared images cannot be customized after deployment","D. Marketplace images are not supported by cloud providers"],correct:1,explanation:"Unverified marketplace images or shared AMIs could contain hidden malware, backdoors, crypto miners, or unpatched vulnerabilities inserted by a malicious publisher."},
{id:74,domain:3,level:2,question:"Which approach ensures that new cloud infrastructure configurations are scanned for security misconfigurations before deployment?",options:["A. Post-deployment penetration testing","B. Shifting security left by integrating IaC scanning into the CI/CD pipeline","C. Quarterly security audits","D. Relying on cloud provider default configurations"],correct:1,explanation:"Integrating IaC security scanning (e.g., Checkov, tfsec) into CI/CD pipelines catches misconfigurations before they reach production—shifting security left reduces remediation cost and risk."},
{id:75,domain:3,level:2,question:"What is a cloud-native WAF (Web Application Firewall) designed to protect against?",options:["A. DDoS attacks at the network layer only","B. OWASP Top 10 application-layer attacks such as SQL injection and XSS","C. Insider threats from cloud administrators","D. Data exfiltration through encrypted channels"],correct:1,explanation:"A WAF inspects HTTP/HTTPS traffic and filters requests based on rules to block OWASP Top 10 attacks including SQL injection, cross-site scripting (XSS), and remote file inclusion."},
{id:76,domain:3,level:2,question:"What is the purpose of cloud resource tagging from a security perspective?",options:["A. To improve cloud performance through resource categorization","B. To enable cost allocation, access control, and asset inventory for security governance","C. To label resources for marketing purposes","D. To mark resources as encrypted"],correct:1,explanation:"Resource tagging enables security teams to enforce tag-based access control policies, identify unmanaged resources, perform accurate asset inventory, and allocate costs to business units for governance."},
{id:77,domain:3,level:2,question:"Which mechanism provides temporary, short-lived credentials for cloud workloads instead of long-lived access keys?",options:["A. Multi-factor authentication","B. Instance profiles / IAM roles assigned to compute instances","C. VPN tunnels","D. Resource tagging"],correct:1,explanation:"IAM roles/instance profiles provide temporary, automatically rotated credentials to cloud workloads. This eliminates the risk of long-lived static access keys being exposed in code or configuration files."},
{id:78,domain:3,level:2,question:"What does 'immutable infrastructure' mean and what security benefit does it provide?",options:["A. Infrastructure that cannot be scaled","B. Servers that are replaced rather than updated, ensuring a known-good state after each deployment","C. Infrastructure protected by immutable cryptographic signatures","D. Physical hardware that cannot be physically moved"],correct:1,explanation:"Immutable infrastructure means servers are never modified after deployment; instead they are replaced with new instances. This eliminates configuration drift, ensures consistent state, and makes it harder for attackers to persist."},
{id:79,domain:3,level:2,question:"What is the purpose of a Cloud Security Posture Management (CSPM) tool?",options:["A. To encrypt all data stored in cloud environments","B. To continuously monitor cloud configurations and identify security risks and compliance violations","C. To manage user identities in cloud directories","D. To optimize cloud spending"],correct:1,explanation:"CSPM tools continuously assess cloud configurations against security best practices and compliance frameworks, automatically detecting misconfigurations like open S3 buckets or overly permissive security groups."},
{id:80,domain:3,level:2,question:"What is 'east-west traffic' in a cloud network context?",options:["A. Traffic between users in different geographic regions","B. Traffic flowing between workloads within the same cloud environment or data center","C. Traffic between cloud provider and on-premises data center","D. Internet-facing traffic from users to applications"],correct:1,explanation:"East-west traffic is lateral communication between workloads within the same environment (server-to-server). It is distinct from north-south traffic (external user to application). East-west traffic is often unsecured and requires micro-segmentation controls."},
{id:81,domain:3,level:3,question:"A security team discovers that a container image in production has a critical CVE. What is the MOST effective long-term mitigation?",options:["A. Patch the running container in place","B. Implement a container image scanning pipeline that blocks vulnerable images before deployment","C. Accept the risk and monitor for exploitation","D. Restrict network access to the container"],correct:1,explanation:"The most effective long-term solution is preventing vulnerable images from reaching production by integrating image scanning (e.g., Trivy, Clair) into the CI/CD pipeline with policy enforcement to block critical CVEs."},
{id:82,domain:3,level:3,question:"Which cloud storage security risk is unique to object storage (e.g., S3 buckets)?",options:["A. Data is always unencrypted at rest","B. Publicly accessible buckets can expose data to the entire internet if misconfigured","C. Object storage cannot be encrypted","D. Object storage has no access logging capability"],correct:1,explanation:"Object storage misconfiguration (public access enabled) is a leading cause of cloud data breaches. S3 buckets and similar services can be inadvertently made publicly readable, exposing sensitive data to anyone on the internet."},
{id:83,domain:3,level:3,question:"What is the purpose of a Hardware Security Module (HSM) in cloud key management?",options:["A. To accelerate TLS handshakes by offloading CPU-intensive operations","B. To provide tamper-resistant storage and processing for cryptographic keys in a cloud KMS","C. To authenticate hardware-based MFA tokens","D. To manage firmware updates for cloud hardware"],correct:1,explanation:"HSMs in cloud KMS provide FIPS 140-2/3 certified tamper-resistant hardware for key generation and storage. Keys never exist in plaintext outside the HSM, providing the highest assurance for key security."},
{id:84,domain:3,level:3,question:"An organization wants to detect if cloud compute instances have been compromised by comparing runtime behavior to a known baseline. What technology is BEST suited?",options:["A. Network intrusion detection system (NIDS)","B. Host-based intrusion detection system (HIDS) or EDR deployed on each instance","C. Web application firewall","D. Cloud Security Posture Management (CSPM)"],correct:1,explanation:"HIDS/EDR solutions monitor processes, file system changes, and system calls on individual instances, detecting anomalous behavior indicating compromise. CSPM detects configuration issues, not runtime behavior."},
{id:85,domain:3,level:3,question:"What is the PRIMARY security concern with 'shadow IT' cloud usage in an organization?",options:["A. Employees using personal devices to access approved cloud services","B. Unapproved cloud services used without IT knowledge, bypassing security controls","C. Cloud services that are too expensive for the security budget","D. Employees working in different time zones from the cloud provider"],correct:1,explanation:"Shadow IT refers to cloud services adopted without IT approval. These services bypass security controls (DLP, access management, vulnerability management), creating unmanaged risk and potential compliance violations."},
{id:86,domain:3,level:3,question:"What is a Trusted Platform Module (TPM) used for in cloud infrastructure?",options:["A. Managing user trust levels in identity systems","B. Providing hardware-based cryptographic functions and secure boot verification","C. A platform for trusted third-party cloud audits","D. A protocol for secure communication between cloud regions"],correct:1,explanation:"A TPM is a dedicated hardware chip providing cryptographic functions (key generation, random number generation) and enabling secure boot by verifying the integrity of firmware and OS before loading."},
{id:87,domain:3,level:3,question:"A company runs containers in a Kubernetes cluster. Which Kubernetes security control prevents a container from running as root?",options:["A. Network Policy","B. Pod Security Admission (PodSecurityPolicy)","C. Role-Based Access Control (RBAC)","D. Namespace isolation"],correct:1,explanation:"Pod Security Admission (and its predecessor PodSecurityPolicy) enforces security constraints on pods including running as non-root, read-only root filesystem, and dropped Linux capabilities."},
{id:88,domain:3,level:3,question:"What is 'Secure Boot' and why is it important for cloud infrastructure?",options:["A. A process for securely migrating VMs between hosts","B. A firmware security mechanism that ensures only cryptographically signed bootloaders and OS components are loaded","C. An encrypted boot disk for virtual machines","D. A secure remote access method for cloud management consoles"],correct:1,explanation:"Secure Boot uses cryptographic signatures to verify that each component of the boot process is trusted and unmodified. It protects against rootkits and boot-level malware that persist before the OS loads."},
{id:89,domain:3,level:3,question:"In cloud infrastructure, what is 'drift' and why is it a security concern?",options:["A. Network latency variations between cloud regions","B. Unauthorized changes to infrastructure that deviate from the approved baseline configuration","C. The gradual migration of workloads to a new cloud provider","D. Cost overruns caused by unmonitored resource usage"],correct:1,explanation:"Configuration drift occurs when infrastructure changes over time from its baseline (through manual changes, patches, etc.). Drift may introduce security vulnerabilities and compliance violations, which is why IaC and continuous compliance monitoring are important."},
{id:90,domain:3,level:3,question:"Which network security control operates at Layer 7 and can inspect application-layer protocols to enforce content-based policies?",options:["A. Network ACL","B. Security Group","C. Next-Generation Firewall (NGFW)","D. VPN gateway"],correct:2,explanation:"NGFWs operate at Layer 7 and can inspect application payloads, user identities, and URLs—not just IP/port—to enforce granular, context-aware security policies beyond what stateless ACLs or stateful security groups provide."},

// ─── DOMAIN 3 – Batch 2 ──────────────────────────────────────────────────────
{id:329,domain:3,level:1,question:"What is a 'security group' vs a 'network ACL' in cloud networking?",options:["A. They are identical controls with different names","B. Security groups are stateful and apply to instances; network ACLs are stateless and apply to subnets","C. Security groups apply to subnets; network ACLs apply to instances","D. Security groups block traffic; network ACLs allow traffic"],correct:1,explanation:"Security groups are stateful (return traffic automatically allowed) and operate at the instance/ENI level. Network ACLs are stateless (return traffic must be explicitly allowed) and operate at the subnet level. Both must permit traffic for it to flow."},
{id:330,domain:3,level:1,question:"What is 'instance metadata service' (IMDS) in cloud compute?",options:["A. A database storing VM performance metrics","B. An internal API available to cloud instances providing instance configuration, IAM credentials, and other metadata","C. A monitoring service for tracking instance uptime","D. A billing service recording instance usage"],correct:1,explanation:"IMDS (e.g., AWS at 169.254.169.254) provides running instances with configuration data and temporary IAM credentials. It is a critical attack target via SSRF — IMDSv2 adds session-oriented token requirements to mitigate SSRF-based credential theft."},
{id:331,domain:3,level:1,question:"What is 'egress filtering' in cloud network security?",options:["A. Filtering incoming traffic to the cloud environment","B. Monitoring and controlling outbound traffic from cloud resources to prevent data exfiltration and C2 communication","C. Filtering cloud provider access to customer resources","D. Removing old resources to reduce egress costs"],correct:1,explanation:"Egress filtering controls outbound traffic from cloud instances. It detects and blocks data exfiltration, communication to known-malicious IPs/domains (C2), and unauthorized data transfers — often overlooked in favor of ingress controls."},
{id:332,domain:3,level:1,question:"What is a 'private endpoint' in cloud networking?",options:["A. An endpoint that only internal employees can access","B. A network interface that connects to a cloud service over a private network without traversing the public internet","C. A restricted API endpoint for cloud administrators only","D. An endpoint with no public IP address"],correct:1,explanation:"Private endpoints (AWS PrivateLink, Azure Private Endpoint) allow access to cloud services (S3, Key Vault, etc.) over the VPC's private network without traffic leaving to the public internet, reducing exposure and enabling private IP-only access policies."},
{id:333,domain:3,level:1,question:"What is 'patch management' in cloud infrastructure and why is automation important?",options:["A. Manually updating cloud provider billing information","B. Identifying, testing, and applying OS and software patches — automation is important because cloud scale makes manual patching impractical and introduces consistency gaps","C. Updating application code in cloud deployments","D. Patching cloud provider network infrastructure"],correct:1,explanation:"Patch management keeps cloud instances protected against known vulnerabilities. At cloud scale (hundreds or thousands of instances), automated patch management (AWS SSM Patch Manager, Azure Update Management) ensures consistent, timely patching without manual intervention."},
{id:334,domain:3,level:1,question:"What is a 'hardened VM image' (golden image)?",options:["A. A VM image with maximum performance settings enabled","B. A pre-configured, security-hardened OS image used as the baseline for launching new instances, reducing attack surface from the start","C. An image of a VM that has been encrypted","D. A backup image of a production VM"],correct:1,explanation:"A golden/hardened image is a VM template configured to a security baseline: unnecessary services removed, default passwords changed, security tools installed, and CIS/STIG benchmarks applied. All new instances launched from it start in a known-good secure state."},
{id:335,domain:3,level:1,question:"What is 'least privilege' applied to cloud service accounts (IAM roles)?",options:["A. Service accounts should share permissions with human users for simplicity","B. Each service or application should have only the minimum IAM permissions needed for its specific function","C. Service accounts need broad permissions to avoid operational failures","D. Least privilege only applies to human users, not service accounts"],correct:1,explanation:"Over-privileged service accounts and IAM roles are one of the most common cloud security risks. A compromised service account with excessive permissions can give an attacker broad access. Each role should be scoped to exactly the permissions its application needs."},
{id:336,domain:3,level:1,question:"What is a 'VPN gateway' in cloud networking?",options:["A. A firewall that inspects VPN traffic","B. A cloud service that establishes encrypted IPSec tunnels between the cloud VPC and on-premises or other networks","C. A proxy that anonymizes cloud traffic","D. A load balancer for VPN connections"],correct:1,explanation:"A VPN gateway creates encrypted IPSec or TLS tunnels between cloud VPCs and on-premises networks or other clouds, enabling secure private connectivity over the public internet without exposing resources to the internet."},
{id:337,domain:3,level:2,question:"What is 'infrastructure hardening' and which benchmark is commonly used?",options:["A. Adding redundant hardware to cloud infrastructure","B. Configuring OS and services to minimize attack surface — the CIS Benchmarks provide authoritative hardening guidance","C. Encrypting all infrastructure components","D. Installing the latest patches immediately upon release"],correct:1,explanation:"Hardening reduces the attack surface by disabling unnecessary services, removing unused software, configuring secure defaults, and applying access restrictions. CIS (Center for Internet Security) Benchmarks and STIG (Security Technical Implementation Guides) provide specific hardening guidance."},
{id:338,domain:3,level:2,question:"What is 'east-west traffic inspection' and why is it challenging in cloud?",options:["A. Inspecting internet-facing traffic — challenging because of encryption","B. Inspecting lateral traffic between cloud workloads — challenging because traditional perimeter firewalls don't see internal traffic","C. Monitoring traffic between cloud regions — challenging because of distance","D. Inspecting cloud provider management traffic — challenging because providers don't allow it"],correct:1,explanation:"East-west (internal/lateral) traffic between workloads is a blind spot for traditional perimeter firewalls. In cloud, east-west inspection requires network policies, service mesh (with mTLS and authorization policies), or routing traffic through an inspection appliance."},
{id:339,domain:3,level:2,question:"What is 'cloud workload isolation' and what technologies enable it?",options:["A. Physically separating cloud servers in different data centers","B. Ensuring workloads cannot access each other's data or resources — enabled by VMs, containers, namespaces, network policies, and separate cloud accounts","C. Isolating cloud spending by department","D. Running workloads in different cloud providers for redundancy"],correct:1,explanation:"Workload isolation prevents one tenant or application from accessing another's resources. Technologies include: VM isolation (hypervisor), container namespaces, Kubernetes network policies, separate VPCs, and separate cloud accounts — each providing progressively stronger isolation."},
{id:340,domain:3,level:2,question:"What is 'cloud security benchmarking' and which organization publishes cloud-specific benchmarks?",options:["A. Comparing cloud costs across providers","B. Evaluating cloud security configuration against a standard — the CIS Cloud Benchmarks provide specific guidance for AWS, Azure, GCP, and Kubernetes","C. Measuring cloud performance against industry averages","D. Comparing security team staffing levels across organizations"],correct:1,explanation:"CIS Benchmarks for cloud (AWS Foundations, Azure Security Benchmark, GCP Foundations) provide specific configuration recommendations for cloud accounts and services. Automated tools can assess cloud environments against these benchmarks and report compliance percentage."},
{id:341,domain:3,level:2,question:"What is 'cloud-native network security' and how does it differ from traditional approaches?",options:["A. Network security implemented using only open-source tools","B. Security defined and enforced through APIs and software policies rather than physical appliances — dynamic, scalable, and programmable","C. Security that only protects cloud-native applications","D. Network security handled exclusively by the cloud provider"],correct:1,explanation:"Cloud-native network security uses API-driven security groups, network policies, and service meshes rather than physical firewalls. Policies are defined as code, automatically applied at scale, and can respond dynamically to workload changes — unlike static hardware appliances."},
{id:342,domain:3,level:2,question:"What is a 'WAF rule' and what types of attacks does a WAF protect against?",options:["A. A network access control rule in a firewall","B. A policy in a Web Application Firewall that matches request patterns to detect and block OWASP Top 10 attacks including SQLi, XSS, and command injection","C. A governance rule for web application development","D. A routing rule for web traffic distribution"],correct:1,explanation:"WAF rules inspect HTTP/HTTPS requests against patterns matching known attack signatures (SQLi, XSS, LFI, RFI, command injection) and block matching requests before they reach the application. Managed rule sets from providers like OWASP or AWS are regularly updated with new threat intelligence."},
{id:343,domain:3,level:2,question:"What is 'cloud DDoS protection' and how do cloud providers implement it?",options:["A. Blocking all traffic from foreign countries","B. Absorbing and scrubbing volumetric attack traffic using anycast routing, traffic scrubbing centers, and rate limiting before it reaches customer resources","C. Shutting down cloud services during a DDoS attack","D. Requiring all users to complete CAPTCHA challenges"],correct:1,explanation:"Cloud providers offer DDoS protection (AWS Shield, Azure DDoS Protection) that leverages their massive global network to absorb volumetric attacks, uses anycast routing to distribute attack traffic, and applies scrubbing to filter malicious traffic before it reaches customer resources."},
{id:344,domain:3,level:2,question:"What is a 'cloud access log' and what events should be captured?",options:["A. A log of cloud provider outages for SLA verification","B. Records of all API calls, console logins, resource modifications, and network access — essential for audit trails and incident investigation","C. A log of internet traffic passing through the cloud","D. A financial log of cloud service consumption"],correct:1,explanation:"Cloud access logs (CloudTrail, Azure Activity Log, GCP Audit Log) record API calls, who made them, from where, and what changed. They are essential for detecting unauthorized actions, investigating incidents, and demonstrating compliance with audit requirements."},
{id:345,domain:3,level:3,question:"A company discovers their Kubernetes cluster's etcd database is accessible without authentication. What is the severity and impact?",options:["A. Low severity — etcd only stores configuration data","B. Critical — etcd stores the entire cluster state including secrets; unauthenticated access gives full cluster control","C. Medium — etcd access allows only read operations","D. Low — etcd is protected by the Kubernetes API server"],correct:1,explanation:"etcd is the Kubernetes backing store containing all cluster state, including Secrets (which may hold TLS certificates, API keys, credentials). Unauthenticated access to etcd is equivalent to full cluster compromise — all secrets can be extracted directly."},
{id:346,domain:3,level:3,question:"What is 'Kubernetes RBAC' and why must it be carefully configured?",options:["A. Role-Based Access Control that restricts which kubectl commands users can run — misconfiguration lets attackers escalate privileges within the cluster","B. A Kubernetes network policy framework","C. A tool for managing Kubernetes cluster updates","D. A logging configuration for Kubernetes audit trails"],correct:1,explanation:"Kubernetes RBAC defines which subjects (users, service accounts) can perform which actions on which resources. Overly broad ClusterRoles (especially cluster-admin bindings to service accounts) allow compromised pods to take over the entire cluster."},
{id:347,domain:3,level:3,question:"What is a 'supply chain attack on container images' and how is it mitigated?",options:["A. Attackers physically tampering with hardware delivered to cloud data centers","B. Malicious code injected into base images or dependencies that becomes part of the production image — mitigated by image signing, trusted registries, and scanning","C. Attackers intercepting container images during transmission","D. Competitors stealing proprietary container images"],correct:1,explanation:"Supply chain attacks inject malicious code into open-source base images or dependencies (e.g., compromised npm package in a Node.js image). Mitigation: use trusted, minimal base images, sign images with Notary/Cosign, scan registries with CVE scanners, and use admission controllers to block unsigned images."},
{id:348,domain:3,level:3,question:"What is 'privileged access workstation' (PAW) and why is it critical for cloud administration?",options:["A. A workstation with administrator rights used for daily tasks","B. A dedicated, hardened device used exclusively for privileged cloud administration — isolated from email, web browsing, and other high-risk activities","C. A virtual workstation in the cloud for remote administration","D. A workstation requiring physical key access to operate"],correct:1,explanation:"PAWs are dedicated devices used only for administrative tasks, isolated from daily activities (email, web). A compromised daily-use device with admin cloud credentials is a critical risk; PAWs reduce this by ensuring admin actions only occur from hardened, monitored systems."},
{id:349,domain:3,level:3,question:"What is 'cloud infrastructure entitlement management' (CIEM) and what problem does it solve?",options:["A. A tool for managing cloud billing entitlements","B. A security tool that identifies, analyzes, and right-sizes excessive cloud IAM permissions across large, complex environments","C. A certification program for cloud IAM administrators","D. A cloud provider service for managing software licenses"],correct:1,explanation:"CIEM tools discover and analyze all IAM entitlements across cloud environments, identifying over-provisioned roles, unused permissions, and risky access combinations. They recommend least-privilege corrections, addressing the massive IAM complexity of large cloud estates."},
{id:350,domain:3,level:3,question:"A security team wants to prevent any new cloud resource from being created with a public IP address. Which control enforces this organization-wide?",options:["A. A policy document in a wiki page","B. Organization-level policy-as-code (SCPs, Azure Policy, GCP Org Policy) that automatically denies creation of resources with public IPs","C. Requesting developers to voluntarily comply","D. Quarterly audit reviews of resource configurations"],correct:1,explanation:"Organization-level preventive controls (AWS SCPs, Azure Policy Deny effects, GCP Organization Policies) can enforce constraints across all accounts/subscriptions in an organization, automatically blocking non-compliant resource creation before it happens — not after."},

// ─── DOMAIN 4: Cloud Application Security ────────────────────────────────────
{id:91,domain:4,level:1,question:"What does OWASP stand for and what is its primary purpose?",options:["A. Open Web Application Security Project—provides free resources for web application security","B. Online Web Assessment Security Platform—a paid scanning service","C. Official Web Application Standards Protocol—an internet standard","D. Open Worldwide Application Security Program—a government regulation"],correct:0,explanation:"OWASP (Open Web Application Security Project) is a nonprofit foundation that produces freely available articles, tools, and documentation to improve web application security, including the famous OWASP Top 10."},
{id:92,domain:4,level:1,question:"Which of the following is the MOST effective control against SQL injection attacks?",options:["A. Input validation and parameterized queries (prepared statements)","B. Encrypting the database at rest","C. Using a strong database password","D. Placing the database in a private subnet"],correct:0,explanation:"Parameterized queries/prepared statements separate SQL code from user input, making it impossible for user-supplied data to alter the query structure. Input validation adds an additional layer of defense."},
{id:93,domain:4,level:1,question:"What is Cross-Site Scripting (XSS)?",options:["A. Injecting malicious SQL into database queries","B. Injecting malicious scripts into web pages viewed by other users","C. Intercepting communications between two parties","D. Exhausting server resources with excessive requests"],correct:1,explanation:"XSS occurs when attackers inject malicious client-side scripts into web pages. When other users load the page, their browsers execute the script, potentially stealing session tokens or credentials."},
{id:94,domain:4,level:1,question:"What does 'secure SDLC' mean?",options:["A. Using secure coding languages only","B. Integrating security activities throughout all phases of the software development lifecycle","C. Performing a security test only before production release","D. Outsourcing security testing to a third party"],correct:1,explanation:"Secure SDLC integrates security at every phase: requirements (security requirements), design (threat modeling), development (secure coding standards), testing (SAST/DAST), and deployment (security review)."},
{id:95,domain:4,level:1,question:"What is OAuth 2.0 used for?",options:["A. Encrypting data in transit between services","B. Providing delegated authorization so third-party apps can access resources without sharing passwords","C. Authenticating users with username and password","D. Generating digital certificates for web servers"],correct:1,explanation:"OAuth 2.0 is an authorization framework that allows users to grant third-party applications limited access to their resources without exposing their credentials. It is used by major identity providers like Google and Microsoft."},
{id:96,domain:4,level:1,question:"What is the purpose of Multi-Factor Authentication (MFA)?",options:["A. To replace passwords with biometrics","B. To require multiple forms of verification, reducing the risk of credential compromise","C. To encrypt authentication data in transit","D. To allow users to log in from multiple devices simultaneously"],correct:1,explanation:"MFA requires at least two verification factors (something you know, have, or are), making account compromise significantly harder even if a password is stolen."},
{id:97,domain:4,level:1,question:"What is Role-Based Access Control (RBAC)?",options:["A. Granting access based on the user's physical location","B. Granting access based on a user's assigned role within the organization","C. Granting all users the same level of access","D. Granting access based on the time of day"],correct:1,explanation:"RBAC assigns permissions to roles rather than individuals. Users are then assigned roles. This simplifies access management, enforces least privilege, and makes access reviews more manageable."},
{id:98,domain:4,level:1,question:"What is a CSRF (Cross-Site Request Forgery) attack?",options:["A. Injecting malicious scripts into web pages","B. Tricking a user's browser into making unintended requests to a site where they are authenticated","C. Intercepting encrypted communications","D. Exhausting web server resources"],correct:1,explanation:"CSRF tricks an authenticated user's browser into sending unwanted requests to a trusted site. It exploits the trust the site has in the user's browser session. Mitigated by CSRF tokens and SameSite cookies."},
{id:99,domain:4,level:1,question:"What is the purpose of a penetration test?",options:["A. Automatically scanning for known CVEs","B. Simulating real-world attacks to identify exploitable vulnerabilities before attackers do","C. Auditing user access rights against policy","D. Testing application performance under load"],correct:1,explanation:"Penetration testing (pen testing) uses ethical hackers to attempt to exploit vulnerabilities in a controlled manner, providing a realistic assessment of an organization's defenses beyond what automated scanners detect."},
{id:100,domain:4,level:1,question:"What is Static Application Security Testing (SAST)?",options:["A. Testing application security by simulating live attacks","B. Analyzing application source code or binaries for vulnerabilities without executing the code","C. Monitoring application behavior in production","D. Testing application performance under static load"],correct:1,explanation:"SAST analyzes source code, bytecode, or binaries for security vulnerabilities (e.g., SQL injection patterns, buffer overflows) without running the application. It can be integrated into IDEs and CI/CD pipelines."},
{id:101,domain:4,level:2,question:"What is the key difference between SAST and DAST?",options:["A. SAST tests at runtime; DAST tests source code","B. SAST analyzes code without execution; DAST tests running applications from the outside","C. SAST is manual; DAST is automated","D. SAST applies to web apps; DAST applies to mobile apps"],correct:1,explanation:"SAST (Static) analyzes source code without running it—finding issues early. DAST (Dynamic) tests a running application by sending inputs and analyzing responses—simulating an outside attacker."},
{id:102,domain:4,level:2,question:"What is threat modeling and when should it occur in the SDLC?",options:["A. Identifying threats during production incidents; after deployment","B. Systematically identifying potential threats and mitigations; during the design phase","C. Listing known malware strains; during security training","D. Modeling attack scenarios for executive reports; quarterly"],correct:1,explanation:"Threat modeling (e.g., using STRIDE) systematically identifies threats, attack vectors, and mitigations for a system. It is most effective during the design phase when changes are cheapest to implement."},
{id:103,domain:4,level:2,question:"An API does not validate that the requesting user has rights to access the resource they specify. What OWASP API vulnerability is this?",options:["A. Broken Function Level Authorization","B. Broken Object Level Authorization (BOLA/IDOR)","C. Excessive Data Exposure","D. Security Misconfiguration"],correct:1,explanation:"BOLA (Broken Object Level Authorization), also known as IDOR (Insecure Direct Object Reference), occurs when APIs don't verify that the requester has rights to the specific object they are requesting by ID."},
{id:104,domain:4,level:2,question:"What is federated identity management?",options:["A. Managing identities across multiple databases within one organization","B. Allowing users to use their identity from one domain to access resources in another trusted domain","C. A centralized directory of all user identities","D. Managing multiple passwords for different applications"],correct:1,explanation:"Federated identity allows users authenticated by one identity provider to access resources in other organizations' domains without separate authentication, using standards like SAML, OAuth, or OIDC."},
{id:105,domain:4,level:2,question:"What does DevSecOps mean?",options:["A. A team structure where developers own security with no dedicated security team","B. Integrating security practices and automation throughout the DevOps pipeline","C. Outsourcing all security functions to a managed service provider","D. Running security tools only in the deployment phase"],correct:1,explanation:"DevSecOps integrates security into every phase of the DevOps pipeline—from code commit through deployment—making security a shared responsibility and automating security checks for speed and consistency."},
{id:106,domain:4,level:2,question:"What is the primary security risk of storing API keys and secrets in source code repositories?",options:["A. Keys stored in code run slower than keys in databases","B. Public or improperly controlled repositories expose secrets to unauthorized parties","C. Code repositories cannot encrypt secrets","D. API keys expire faster when stored in code"],correct:1,explanation:"Hardcoding secrets in source code frequently leads to exposure when repositories are made public, shared with third parties, or when version history reveals previously committed secrets."},
{id:107,domain:4,level:2,question:"Which HTTP header helps prevent XSS by controlling which sources can load content on a page?",options:["A. X-Frame-Options","B. Content-Security-Policy (CSP)","C. Strict-Transport-Security","D. X-Content-Type-Options"],correct:1,explanation:"Content-Security-Policy (CSP) specifies which domains can load scripts, styles, and other content. It prevents XSS by blocking execution of scripts from untrusted sources."},
{id:108,domain:4,level:2,question:"What is the principle behind 'shift-left' security?",options:["A. Moving security teams to the left side of the office","B. Introducing security earlier in the development process to catch issues when they are cheaper to fix","C. Prioritizing compliance over security testing","D. Shifting security responsibilities from developers to security teams"],correct:1,explanation:"Shift-left security moves security activities earlier in the SDLC (left in the timeline). Finding and fixing a vulnerability in design costs far less than fixing it in production."},
{id:109,domain:4,level:2,question:"What is the STRIDE threat model used for?",options:["A. Categorizing cloud providers by security capability","B. Identifying six categories of threats: Spoofing, Tampering, Repudiation, Information Disclosure, DoS, Elevation of Privilege","C. Scoring vulnerability severity","D. A regulatory compliance framework for applications"],correct:1,explanation:"STRIDE (developed by Microsoft) is a threat modeling methodology categorizing threats into: Spoofing, Tampering, Repudiation, Information Disclosure, Denial of Service, and Elevation of Privilege."},
{id:110,domain:4,level:2,question:"What does 'broken authentication' mean in the OWASP Top 10 context?",options:["A. The login page has a visual design flaw","B. Vulnerabilities in authentication mechanisms that allow attackers to compromise credentials or sessions","C. The app uses HTTP instead of HTTPS","D. The authentication system is temporarily unavailable"],correct:1,explanation:"Broken authentication includes weak password policies, session fixation, improper session timeout, missing MFA, and credential stuffing vulnerabilities that allow attackers to impersonate users."},
{id:111,domain:4,level:3,question:"An application uses JWTs for session management. An attacker changes the algorithm field in the JWT header to 'none.' What vulnerability does this exploit?",options:["A. SQL injection in JWT payload","B. Algorithm confusion attack where the server accepts unsigned tokens","C. Replay attack using captured tokens","D. Brute force of the JWT secret key"],correct:1,explanation:"The 'alg:none' attack exploits servers that accept JWTs without a signature when the algorithm is set to 'none.' Proper JWT validation must reject tokens with 'none' algorithm and verify the signature."},
{id:112,domain:4,level:3,question:"What is Server-Side Request Forgery (SSRF) and why is it particularly dangerous in cloud environments?",options:["A. Forging HTTP headers to bypass authentication","B. Inducing the server to make requests to internal resources, potentially accessing cloud metadata endpoints","C. Intercepting server-to-server communications","D. Forging server certificates for MITM attacks"],correct:1,explanation:"SSRF tricks the server into making requests to internal resources. In cloud environments this is critical because the instance metadata service (e.g., AWS 169.254.169.254) can be queried via SSRF to steal IAM credentials."},
{id:113,domain:4,level:3,question:"What is supply chain security in the context of cloud application development?",options:["A. Securing the physical delivery of hardware to cloud data centers","B. Verifying the integrity and security of third-party libraries, dependencies, and build tools","C. Managing vendor contracts and SLAs","D. Securing the CI/CD pipeline deployment credentials only"],correct:1,explanation:"Supply chain attacks target third-party dependencies (npm packages, Python libraries, container base images). Securing the supply chain includes dependency scanning, pinning versions, verifying signatures, and monitoring for compromised packages (e.g., SolarWinds, Log4Shell)."},
{id:114,domain:4,level:3,question:"Which of the following BEST describes Attribute-Based Access Control (ABAC)?",options:["A. Access based solely on a user's job title","B. Access decisions based on attributes of the user, resource, and environment combined","C. A simpler alternative to RBAC requiring fewer policies","D. Access based on IP address geolocation"],correct:1,explanation:"ABAC evaluates a combination of user attributes (department, clearance), resource attributes (sensitivity, owner), and environmental attributes (time, location) to make fine-grained access decisions—more flexible than RBAC."},
{id:115,domain:4,level:3,question:"What is Software Composition Analysis (SCA) and why is it important?",options:["A. Analyzing the organizational structure of development teams","B. Identifying open-source components in applications and checking them for known vulnerabilities and license issues","C. Decomposing a monolith into microservices","D. Auditing source code for coding standard compliance"],correct:1,explanation:"SCA tools inventory open-source dependencies and check them against vulnerability databases (NVD, OSV) and license databases. As open-source components make up the majority of modern applications, SCA is critical for supply chain security."},
{id:116,domain:4,level:3,question:"An API returns the full user object including internal fields not needed by the client. What OWASP API vulnerability is this?",options:["A. Broken Object Level Authorization","B. Excessive Data Exposure","C. Mass Assignment","D. Insufficient Logging"],correct:1,explanation:"Excessive Data Exposure occurs when APIs return more data than needed, relying on the client to filter. Attackers can intercept the full response to harvest sensitive fields. APIs should return only what is explicitly needed."},
{id:117,domain:4,level:3,question:"What is the primary security benefit of using OpenID Connect (OIDC) for application authentication?",options:["A. It replaces the need for TLS encryption","B. It provides a standardized identity layer on top of OAuth 2.0, enabling delegated authentication with identity assertions","C. It encrypts all application traffic","D. It eliminates the need for session management"],correct:1,explanation:"OIDC extends OAuth 2.0 with an identity layer (ID tokens), enabling applications to verify user identity and obtain profile information from an identity provider without managing credentials themselves."},
{id:118,domain:4,level:3,question:"Which activity in the secure SDLC is responsible for verifying that security requirements have been implemented correctly?",options:["A. Threat modeling","B. Security requirements gathering","C. Security acceptance testing / verification","D. Risk assessment"],correct:2,explanation:"Security acceptance testing verifies that security controls defined in requirements have been correctly implemented. This includes validation of authentication, authorization, encryption, and other controls before release."},
{id:119,domain:4,level:3,question:"What is Runtime Application Self-Protection (RASP)?",options:["A. A static code analysis tool integrated into the IDE","B. Security technology embedded in an application that monitors and blocks attacks at runtime","C. A WAF that sits in front of the application","D. An automated patching mechanism for running applications"],correct:1,explanation:"RASP is security technology built into an application. It monitors application behavior from within the runtime, detects and blocks attacks in real time without relying on external network devices."},
{id:120,domain:4,level:3,question:"What is 'security as code' in a DevSecOps pipeline?",options:["A. Writing application code with security requirements embedded as comments","B. Expressing security policies, tests, and compliance checks as code that runs in the CI/CD pipeline","C. Using code obfuscation to protect intellectual property","D. Encrypting all source code files"],correct:1,explanation:"Security as code treats security policies, compliance checks, and security tests as code artifacts—version-controlled, peer-reviewed, and automatically executed in the pipeline alongside application code."},

// ─── DOMAIN 4 – Batch 2 ──────────────────────────────────────────────────────
{id:351,domain:4,level:1,question:"What is 'input validation' and why is it a fundamental security control?",options:["A. Validating that users enter data in the correct format for usability","B. Verifying that all user-supplied input conforms to expected type, length, format, and range before processing — preventing injection attacks","C. Checking that database inputs match schema constraints","D. A testing technique for verifying application functionality"],correct:1,explanation:"Input validation ensures that only expected, well-formed data enters an application. It is the primary defense against injection attacks (SQLi, XSS, command injection) by rejecting malformed or malicious input before it can be processed."},
{id:352,domain:4,level:1,question:"What is 'output encoding' and how does it differ from input validation?",options:["A. They are the same — both prevent injection attacks","B. Output encoding converts data to a safe representation for the output context (HTML, JS, URL) — preventing XSS even if malicious input passes validation","C. Encoding compresses output for performance; validation checks security","D. Output encoding applies to API responses; input validation applies to web forms only"],correct:1,explanation:"Output encoding (contextual escaping) converts special characters to their safe equivalents for the output context (e.g., < becomes &lt; in HTML context). It prevents injected data from being interpreted as code, even if the data wasn't caught during input validation."},
{id:353,domain:4,level:1,question:"What is 'security testing' in the software development lifecycle?",options:["A. Testing the physical security of data centers","B. A set of activities (SAST, DAST, penetration testing, code review) that identify security vulnerabilities before software is deployed","C. Load testing to ensure the application doesn't fail under attack","D. Testing that the application logs security events correctly"],correct:1,explanation:"Security testing encompasses: SAST (static code analysis), DAST (dynamic testing of running app), IAST (interactive), SCA (dependency scanning), and manual penetration testing. Applied throughout the SDLC, it finds vulnerabilities when they are cheapest to fix."},
{id:354,domain:4,level:1,question:"What is 'session management' and what makes it secure?",options:["A. Managing database connection sessions","B. Generating cryptographically random session tokens, setting appropriate timeouts, using secure/HttpOnly cookies, and invalidating sessions on logout and privilege changes","C. Managing user login schedules","D. Controlling how many sessions a server can handle simultaneously"],correct:1,explanation:"Secure session management: generates unpredictable session IDs (128+ bits random), uses Secure + HttpOnly + SameSite cookie flags, expires sessions after inactivity, invalidates sessions on logout/password change, and regenerates session IDs after authentication."},
{id:355,domain:4,level:1,question:"What is 'authorization' and how does it differ from authentication?",options:["A. They are the same — both verify identity","B. Authentication verifies WHO you are; authorization determines WHAT you are permitted to do","C. Authentication is for users; authorization is for applications","D. Authorization happens before authentication in the security flow"],correct:1,explanation:"Authentication establishes identity (who are you?). Authorization determines permissions (what can you do?). Both must be implemented correctly — authentication without proper authorization still allows unauthorized actions after login."},
{id:356,domain:4,level:1,question:"What is a 'security code review'?",options:["A. A government review of source code for national security purposes","B. A manual or automated examination of source code to identify security vulnerabilities, logic flaws, and deviations from secure coding standards","C. A performance review of the security team's coding output","D. A review of access logs to identify unauthorized code changes"],correct:1,explanation:"Security code review examines source code for vulnerabilities that automated tools may miss — insecure cryptography, business logic flaws, improper error handling, hardcoded secrets. It can be manual (expert review) or assisted by SAST tools."},
{id:357,domain:4,level:1,question:"What is 'dependency scanning' in application security?",options:["A. Scanning applications for missing code dependencies","B. Analyzing third-party libraries and packages used by an application to identify known vulnerabilities (CVEs) in those dependencies","C. Checking that all application components load correctly","D. Scanning network dependencies between microservices"],correct:1,explanation:"Dependency (SCA) scanning checks open-source and third-party components against vulnerability databases (NVD, OSV, GitHub Advisory). Given that most application code is third-party libraries, dependency scanning is a critical supply chain security control."},
{id:358,domain:4,level:1,question:"What is an 'API gateway' and what security functions does it provide?",options:["A. A physical network device routing API traffic","B. A management layer for APIs providing authentication, rate limiting, input validation, logging, and traffic routing","C. A database gateway for API data storage","D. A cloud service for publishing APIs to developers"],correct:1,explanation:"An API gateway acts as a single entry point for API traffic, providing centralized authentication/authorization (OAuth, API keys), rate limiting, request validation, logging, TLS termination, and routing — reducing the security burden on individual backend services."},
{id:359,domain:4,level:2,question:"What is 'PKCE' (Proof Key for Code Exchange) and when is it used?",options:["A. A key exchange protocol for server-to-server API communication","B. An OAuth 2.0 extension that prevents authorization code interception attacks for public clients (mobile/SPA apps) that cannot keep a client secret","C. A password-based key derivation function","D. A SAML extension for mobile authentication"],correct:1,explanation:"PKCE extends OAuth 2.0 authorization code flow by having the client generate a code_verifier and code_challenge. Even if an attacker intercepts the authorization code, they cannot exchange it without the code_verifier, protecting mobile and SPA apps that cannot store secrets."},
{id:360,domain:4,level:2,question:"What is 'broken access control' (OWASP #1) and what is a common example?",options:["A. A login page that is broken and inaccessible","B. Failures to enforce restrictions on what authenticated users can do — example: accessing other users' records by changing an ID in the URL","C. An incorrectly configured access control list on a network device","D. A physical access control system that malfunctions"],correct:1,explanation:"Broken access control (OWASP Top 10 #1) occurs when authenticated users can perform actions or access data they shouldn't. Common example: changing /users/123 to /users/124 in the URL and accessing another user's profile because the server doesn't verify ownership."},
{id:361,domain:4,level:2,question:"What is 'cryptographic failure' (OWASP #2) and what does it include?",options:["A. Hardware encryption module failure","B. Failures related to cryptography — weak algorithms, improper key management, no encryption for sensitive data in transit or at rest","C. Expired SSL certificates causing application downtime","D. Failed decryption attempts by authorized users"],correct:1,explanation:"Cryptographic failures (OWASP #2, formerly 'Sensitive Data Exposure') include: using weak algorithms (MD5, SHA1, DES), improper key management, transmitting data in cleartext, using ECB mode, and hardcoding cryptographic keys. The result is sensitive data exposure."},
{id:362,domain:4,level:2,question:"What is 'security misconfiguration' (OWASP #5) in cloud applications?",options:["A. Incorrect security team organizational structure","B. Improperly configured security controls — default passwords, unnecessary features enabled, overly permissive access, missing security headers, verbose error messages","C. Using the wrong security framework for an application","D. Misconfigured load balancer causing performance issues"],correct:1,explanation:"Security misconfiguration is the most common cloud vulnerability. Examples: S3 buckets left public, default admin credentials, detailed error messages exposing stack traces, missing HTTP security headers, unnecessary cloud services enabled, and overly permissive IAM policies."},
{id:363,domain:4,level:2,question:"What is 'secure defaults' in application and infrastructure security?",options:["A. Default factory settings for hardware devices","B. Configuring systems so the out-of-box state is secure — requiring explicit action to reduce security rather than to enable it","C. A feature that automatically reverts configuration changes","D. Default passwords that are difficult to guess"],correct:1,explanation:"Secure defaults means systems are secure by default — deny all access, minimal services enabled, logging on, strong TLS enforced. Security is the default state; developers must explicitly open up access rather than explicitly lock things down."},
{id:364,domain:4,level:2,question:"What is a 'Content Security Policy' (CSP) header and what does it prevent?",options:["A. A header controlling which countries can access content","B. An HTTP header specifying allowed sources for scripts, styles, images — primarily preventing XSS by blocking inline scripts and unauthorized external resources","C. A policy governing content moderation on web platforms","D. A caching header controlling how long content is stored"],correct:1,explanation:"CSP is an HTTP response header that tells browsers which sources of content (scripts, styles, images, fonts) are permitted. A strict CSP prevents XSS by blocking execution of injected inline scripts and scripts loaded from unauthorized external domains."},
{id:365,domain:4,level:2,question:"What is 'HSTS' (HTTP Strict Transport Security) and what attack does it prevent?",options:["A. A protocol that forces HTTPS by having browsers cache the HTTPS-only directive — preventing SSL stripping/downgrade attacks","B. A tool for managing HTTPS certificates","C. A header preventing clickjacking attacks","D. An encryption protocol for HTTP/2 connections"],correct:1,explanation:"HSTS tells browsers to always connect to a domain over HTTPS, even if the user types http://. Once cached, browsers refuse to make HTTP connections to that domain, preventing SSL stripping attacks where an attacker downgrades HTTPS to HTTP."},
{id:366,domain:4,level:2,question:"What is a 'clickjacking' attack and how is it prevented?",options:["A. An attack where user clicks are tracked for analytics","B. Embedding a target site in a hidden iframe to trick users into clicking hidden buttons — prevented by X-Frame-Options or CSP frame-ancestors header","C. Hijacking a user's click stream on a network","D. An attack that hijacks JavaScript click event handlers"],correct:1,explanation:"Clickjacking overlays a malicious page over a legitimate one using an invisible iframe. Users think they're clicking the visible page but are actually clicking the hidden iframe (e.g., 'Like' button, 'Transfer funds'). X-Frame-Options: DENY or CSP frame-ancestors: 'none' prevents framing."},
{id:367,domain:4,level:3,question:"What is 'path traversal' (directory traversal) and how is it prevented?",options:["A. An SEO attack manipulating URL paths for search ranking","B. An attack using sequences like ../ to navigate outside the intended directory and access unauthorized files — prevented by canonicalizing paths and validating against an allowlist","C. A cloud storage attack accessing other tenants' directories","D. A network routing attack redirecting traffic through unauthorized paths"],correct:1,explanation:"Path traversal uses ../ sequences to escape the application's intended directory and access sensitive files (e.g., /etc/passwd, config files). Prevention: canonicalize all paths before validation, compare against a whitelist of allowed base directories, and avoid passing user input directly to filesystem APIs."},
{id:368,domain:4,level:3,question:"What is 'command injection' and how is it prevented?",options:["A. Injecting commands into a database query","B. Passing attacker-controlled input to OS shell commands — prevented by avoiding shell commands entirely, using parameterized APIs, and input allowlisting","C. Injecting malicious API commands into cloud management interfaces","D. Sending unauthorized commands to a network device"],correct:1,explanation:"Command injection occurs when user-supplied input is concatenated into OS commands (e.g., ping {user_input}). Attackers inject ; rm -rf / or similar. Prevention: avoid shell commands (use library functions instead), use parameterized APIs, and strictly validate/allowlist any input used in commands."},
{id:369,domain:4,level:3,question:"What is 'indirect prompt injection' in AI/LLM cloud applications and why is it a new application security concern?",options:["A. Injecting SQL through a natural language interface","B. Malicious instructions embedded in external content retrieved by an LLM that manipulate its behavior — causing unauthorized actions or data exfiltration","C. Prompt injection in physical printer interfaces","D. An attack against the model training pipeline"],correct:1,explanation:"Indirect prompt injection embeds attacker instructions in external data (web pages, documents, emails) that an LLM reads. When processed, these instructions can hijack the LLM's behavior — exfiltrating data, performing unauthorized actions, or bypassing safety filters — a novel attack class for AI-integrated applications."},
{id:370,domain:4,level:3,question:"What is 'API versioning' as a security practice?",options:["A. Numbering API versions for tracking in source control","B. Maintaining multiple API versions allows deprecating and removing insecure endpoints, and ensures customers migrate to secure versions with vulnerability fixes","C. A developer practice with no security implications","D. Versioning API keys for rotation purposes"],correct:1,explanation:"Proper API versioning allows security teams to retire old, vulnerable API versions while giving consumers time to migrate. Without versioning, fixing a security flaw in an API may break existing consumers, creating pressure to maintain insecure behavior."},
{id:371,domain:4,level:3,question:"What is 'security regression testing' and why is it important in CI/CD pipelines?",options:["A. Testing that the application regresses to a more secure previous version","B. Re-running security tests after code changes to ensure previously fixed vulnerabilities have not been reintroduced","C. A quarterly security review process","D. Testing that rollback procedures work correctly"],correct:1,explanation:"Security regression tests verify that known-fixed vulnerabilities stay fixed as code evolves. In CI/CD pipelines, automated regression tests catch if a refactor accidentally reintroduces a previously remediated SQLi or authentication bypass."},
{id:372,domain:4,level:3,question:"What is 'zero-day vulnerability' and how should cloud application teams prepare for them?",options:["A. A vulnerability that is zero days old — just discovered by the development team","B. A previously unknown vulnerability with no available patch — teams must use defense-in-depth, WAF virtual patching, network segmentation, and anomaly detection to reduce impact","C. A vulnerability that takes zero days to exploit","D. A vulnerability in day-zero cloud deployments"],correct:1,explanation:"A zero-day is a vulnerability unknown to the vendor with no available patch. Defense strategies: WAF virtual patching (blocking exploit patterns without code changes), micro-segmentation to limit blast radius, runtime protection (RASP), behavioral anomaly detection, and rapid patch deployment readiness."},

// ─── DOMAIN 5: Cloud Security Operations ─────────────────────────────────────
{id:121,domain:5,level:1,question:"What is a Security Information and Event Management (SIEM) system?",options:["A. A tool for managing cloud costs and billing","B. A platform that aggregates, correlates, and analyzes security logs and events from multiple sources","C. A vulnerability scanner for cloud infrastructure","D. An identity management system"],correct:1,explanation:"A SIEM collects and correlates log data from across the environment, providing real-time analysis for security monitoring, threat detection, incident investigation, and compliance reporting."},
{id:122,domain:5,level:1,question:"What is the first step in the incident response lifecycle per NIST SP 800-61?",options:["A. Containment","B. Detection and Analysis","C. Preparation","D. Eradication"],correct:2,explanation:"NIST SP 800-61 defines four phases: Preparation, Detection & Analysis, Containment/Eradication/Recovery, and Post-Incident Activity. Preparation is first and most important."},
{id:123,domain:5,level:1,question:"What does 'change management' prevent in cloud security operations?",options:["A. Unauthorized or poorly tested changes that could introduce vulnerabilities or outages","B. Employees changing their passwords too frequently","C. Cloud providers changing their service pricing","D. Changes to regulatory compliance requirements"],correct:0,explanation:"Change management processes ensure that all changes to production systems are reviewed, tested, approved, and documented, preventing unauthorized modifications that could introduce security vulnerabilities."},
{id:124,domain:5,level:1,question:"What is the purpose of log management in cloud security operations?",options:["A. To reduce storage costs by compressing log files","B. To capture, store, and analyze records of system and user activity for security monitoring and forensics","C. To log sales and customer transactions","D. To track developer code commits"],correct:1,explanation:"Log management captures activity across the cloud environment. Logs are critical for detecting security events, investigating incidents, supporting forensics, and demonstrating compliance."},
{id:125,domain:5,level:1,question:"What is patch management?",options:["A. Repairing physical cabling in data centers","B. The process of identifying, testing, and applying software updates to address vulnerabilities","C. Managing network configuration changes","D. Updating application user interfaces"],correct:1,explanation:"Patch management identifies known vulnerabilities, tests patches in non-production, and systematically applies them to production systems within risk-appropriate timeframes to reduce exposure."},
{id:126,domain:5,level:1,question:"What is a Security Operations Center (SOC)?",options:["A. A physical room where cloud servers are housed","B. A centralized team and facility that monitors, detects, analyzes, and responds to security threats","C. A compliance reporting tool","D. A cloud provider's network operations center"],correct:1,explanation:"A SOC is a centralized function (people, processes, tools) responsible for continuous security monitoring, threat detection, incident response, and security event management."},
{id:127,domain:5,level:1,question:"What is the purpose of a runbook in security operations?",options:["A. A directory of all running virtual machines","B. A documented set of step-by-step procedures for handling specific security events or operational tasks","C. A list of approved software for installation","D. A log of all network connections"],correct:1,explanation:"Runbooks provide step-by-step procedures for routine operations and incident response, ensuring consistent, efficient responses and reducing human error during high-pressure incidents."},
{id:128,domain:5,level:1,question:"What does Mean Time to Detect (MTTD) measure?",options:["A. The average time to fix a vulnerability after discovery","B. The average time between system failures","C. The average time to identify a security incident after it occurs","D. The average time to deploy a security patch"],correct:2,explanation:"MTTD measures the average time from when an incident occurs to when the security team detects it. Lower MTTD means earlier detection, limiting attacker dwell time and potential damage."},
{id:129,domain:5,level:1,question:"What is network flow (NetFlow) data used for in security monitoring?",options:["A. Managing the flow of network hardware procurement","B. Analyzing communication patterns between hosts to detect anomalies and suspicious connections","C. Measuring bandwidth utilization for billing","D. Routing network traffic between subnets"],correct:1,explanation:"NetFlow records metadata about network connections (source/destination IP, port, protocol, volume) without capturing payload content. It enables detection of unusual traffic patterns, lateral movement, and data exfiltration."},
{id:130,domain:5,level:1,question:"What is the purpose of an Intrusion Detection System (IDS)?",options:["A. To block all unauthorized network traffic","B. To monitor network or system activity and alert on suspicious or malicious behavior","C. To encrypt all network communications","D. To manage user authentication"],correct:1,explanation:"An IDS monitors traffic and system behavior, generating alerts when it detects signatures of known attacks or anomalous behavior. Unlike an IPS, it detects and alerts but does not automatically block traffic."},
{id:131,domain:5,level:2,question:"A cloud environment generates millions of log events daily. Which approach BEST enables effective security monitoring?",options:["A. Review all logs manually every morning","B. Ingest logs into a SIEM with correlation rules and automated alerting for high-priority events","C. Retain logs for 90 days and review after an incident","D. Rely only on cloud provider native monitoring"],correct:1,explanation:"A SIEM with automated correlation rules and alerting enables real-time detection of security events across millions of logs, prioritizing alerts so analysts focus on high-priority threats rather than manual log review."},
{id:132,domain:5,level:2,question:"During a cloud incident, an analyst wants to isolate a compromised VM without destroying evidence. What is the BEST approach?",options:["A. Immediately terminate the VM instance","B. Snapshot the VM, isolate it in a quarantine security group, and preserve volatile data","C. Reimage the VM from a clean image immediately","D. Shut down all VMs in the same network segment"],correct:1,explanation:"Taking a snapshot preserves disk evidence; isolating in a quarantine security group (blocking all traffic) contains the threat without destroying the instance. Volatile memory should also be captured if possible."},
{id:133,domain:5,level:2,question:"What is 'threat hunting' in cloud security operations?",options:["A. Automated scanning for known vulnerabilities","B. Proactive searching for threats that may have evaded existing security controls","C. Responding to alerts generated by a SIEM","D. Hunting for cloud resources with expired security certificates"],correct:1,explanation:"Threat hunting is a proactive practice where analysts manually search for indicators of compromise and advanced threats that automated tools may have missed, using hypothesis-driven investigation techniques."},
{id:134,domain:5,level:2,question:"What is the PRIMARY challenge of performing digital forensics in a cloud environment?",options:["A. Cloud environments generate too few logs for forensic analysis","B. The customer may have limited access to underlying infrastructure and evidence may be volatile or distributed","C. Cloud providers always refuse to cooperate with forensic investigations","D. Digital forensics tools don't work in cloud environments"],correct:1,explanation:"In cloud, customers typically cannot access physical hardware, hypervisor logs, or other tenants' data. Evidence can also be ephemeral (containers), distributed across regions, or overwritten—complicating forensic investigation."},
{id:135,domain:5,level:2,question:"What is a false positive in security monitoring?",options:["A. A real attack that successfully bypassed all defenses","B. An alert triggered by benign activity incorrectly identified as malicious","C. A vulnerability that cannot be exploited in practice","D. A security control that works correctly"],correct:1,explanation:"A false positive is an alert generated for normal, benign activity that the detection rule incorrectly flagged as malicious. High false positive rates cause alert fatigue, leading analysts to miss real incidents."},
{id:136,domain:5,level:2,question:"Which cloud-native service provides automated threat detection using machine learning to analyze logs and network traffic?",options:["A. AWS CloudTrail","B. AWS GuardDuty / Azure Defender / Google Security Command Center","C. AWS Config","D. AWS CloudWatch"],correct:1,explanation:"Services like AWS GuardDuty, Azure Defender for Cloud, and Google Security Command Center use ML to analyze logs (CloudTrail, VPC Flow Logs, DNS) and detect threats like cryptomining, credential compromise, and exfiltration."},
{id:137,domain:5,level:2,question:"What is the purpose of a Business Continuity Plan (BCP)?",options:["A. To ensure the business generates revenue during security incidents","B. To ensure critical business functions continue during and after a disruptive event","C. To document all business processes for compliance audits","D. To plan for business expansion into new markets"],correct:1,explanation:"A BCP defines how an organization will continue critical operations during and after a disruption (natural disaster, cyberattack, infrastructure failure). It encompasses people, processes, and technology."},
{id:138,domain:5,level:2,question:"What is the PRIMARY purpose of a cloud provider's audit log (e.g., AWS CloudTrail)?",options:["A. To monitor application performance metrics","B. To record all API calls and management console actions for security analysis and compliance","C. To log end-user application activity","D. To track cloud resource costs"],correct:1,explanation:"CloudTrail and equivalent services log all API calls to cloud services, capturing who did what, when, and from where. This is essential for security investigations, compliance audits, and detecting unauthorized activity."},
{id:139,domain:5,level:2,question:"What is 'least privilege' applied to cloud service accounts (non-human identities)?",options:["A. Service accounts should have admin rights to avoid permission errors","B. Service accounts should have only the minimum permissions needed for their specific function","C. Service accounts should share permissions with human users for simplicity","D. Service accounts do not require access controls"],correct:1,explanation:"Over-privileged service accounts are a critical cloud risk. If compromised, they can be used to access far more resources than needed. Each service account should have only the specific permissions required for its function."},
{id:140,domain:5,level:2,question:"What is Security Orchestration, Automation, and Response (SOAR)?",options:["A. A manual security operations framework","B. A platform that automates repetitive security tasks, orchestrates workflows, and accelerates incident response","C. A compliance reporting dashboard","D. A network traffic analysis tool"],correct:1,explanation:"SOAR platforms integrate security tools, automate repetitive tasks (e.g., IP blocking, ticket creation), and orchestrate complex response workflows, allowing analysts to handle more incidents faster."},
{id:141,domain:5,level:3,question:"An attacker has compromised cloud IAM credentials and used them to create new admin accounts. Which detection mechanism is MOST likely to catch this in real time?",options:["A. Scheduled weekly access reviews","B. SIEM correlation rule alerting on IAM privilege escalation API calls","C. Manual review of CloudTrail logs","D. Vulnerability scanner finding a misconfigured IAM policy"],correct:1,explanation:"Real-time SIEM correlation rules on IAM events (CreateUser, AttachUserPolicy, CreateAccessKey) can alert immediately on privilege escalation or new admin creation, enabling rapid containment."},
{id:142,domain:5,level:3,question:"What is the key principle of 'evidence preservation' in cloud incident response?",options:["A. Immediately deleting compromised resources to stop the attack","B. Capturing and protecting evidence (snapshots, logs, memory dumps) before taking containment actions","C. Reporting the incident to management before collecting any evidence","D. Notifying law enforcement before collecting evidence"],correct:1,explanation:"Evidence must be captured before containment actions that might destroy it. Snapshots of compromised instances, log exports, and memory captures should be taken and write-protected to maintain integrity."},
{id:143,domain:5,level:3,question:"A SIEM shows thousands of failed login attempts from a single IP followed by one successful login. What attack does this indicate and what is the immediate response?",options:["A. SQL injection—patch the database","B. Brute force attack leading to account compromise—reset credentials and block the source IP","C. DDoS attack—activate traffic scrubbing","D. Insider threat—interview the user"],correct:1,explanation:"This pattern indicates a successful brute force attack. Immediate response: reset the compromised account's credentials, revoke active sessions, block the source IP, and investigate what the attacker accessed after the successful login."},
{id:144,domain:5,level:3,question:"What is 'purple teaming' in cloud security operations?",options:["A. A team of external penetration testers attacking cloud systems","B. Collaboration between red team (attackers) and blue team (defenders) to improve detection and response","C. A third team responsible only for compliance monitoring","D. Cloud provider security teams assisting customers"],correct:1,explanation:"Purple teaming combines red team attack techniques with blue team defensive monitoring in a collaborative exercise, allowing defenders to see attacks in real time and tune detection rules and response procedures."},
{id:145,domain:5,level:3,question:"An organization's cloud backup was encrypted by ransomware. Which backup strategy would have BEST prevented this outcome?",options:["A. Increasing backup frequency to hourly","B. Implementing air-gapped or immutable backups that ransomware cannot modify or encrypt","C. Storing backups in the same cloud account with different folder structure","D. Encrypting backups before ransomware can encrypt them"],correct:1,explanation:"Immutable backups (using object lock or WORM storage) and air-gapped backups (disconnected from production) cannot be modified or deleted by ransomware, ensuring recovery capability survives an attack."},
{id:146,domain:5,level:3,question:"What is 'dwell time' and why is it a critical security metric?",options:["A. The time a cloud instance takes to restart after a failure","B. The time an attacker remains undetected in an environment after initial compromise","C. The average response time of cloud API calls","D. The time data is retained before deletion"],correct:1,explanation:"Dwell time (attacker dwell time) is the time between initial compromise and detection. Longer dwell time means more opportunity for data exfiltration and lateral movement. Reducing MTTD reduces dwell time."},
{id:147,domain:5,level:3,question:"Which approach BEST supports cloud forensics while maintaining operational continuity during an investigation?",options:["A. Shut down all affected systems to preserve evidence","B. Create forensic copies (snapshots) of affected instances while keeping production running on new clean instances","C. Let the attack continue to gather more evidence","D. Immediately terminate affected instances and rebuild from scratch"],correct:1,explanation:"Creating forensic snapshots allows investigation of compromised systems while migrating production workloads to clean instances, maintaining both forensic integrity and business continuity."},
{id:148,domain:5,level:3,question:"What is the purpose of a tabletop exercise in cloud incident response?",options:["A. Testing backup restoration procedures","B. A discussion-based simulation where stakeholders walk through a scenario to identify gaps in response plans","C. Automated testing of SIEM correlation rules","D. Physical testing of data center emergency procedures"],correct:1,explanation:"Tabletop exercises are structured discussions where stakeholders walk through simulated incident scenarios to identify gaps, clarify roles, and improve response plans—without requiring actual systems to fail."},
{id:149,domain:5,level:3,question:"What does 'mean time to respond' (MTTR) measure in security operations?",options:["A. The average time between security incidents","B. The average time from detection to full containment and remediation of an incident","C. The time required to conduct a threat hunt","D. The average time a patch takes to apply"],correct:1,explanation:"MTTR measures the average time from detecting an incident to fully resolving it (containment + eradication + recovery). Reducing MTTR minimizes impact and exposure duration."},
{id:150,domain:5,level:3,question:"A cloud workload is generating unusual outbound traffic to an unknown external IP. Which security tool should be used FIRST to analyze this activity?",options:["A. Static code analysis tool","B. VPC flow logs and DNS query logs to identify the destination and traffic volume","C. Antivirus scan of the workload","D. Compliance audit report"],correct:1,explanation:"VPC flow logs reveal connection metadata (destination IP, port, volume) and DNS logs can identify the domain being queried. Together, they quickly establish whether the traffic represents command-and-control or data exfiltration."},

// ─── DOMAIN 5 – Batch 2 ──────────────────────────────────────────────────────
{id:373,domain:5,level:1,question:"What is 'alert triage' in security operations?",options:["A. Organizing security alerts into alphabetical order","B. Evaluating incoming security alerts to determine validity, severity, and priority before investigation","C. Deleting low-priority alerts to reduce workload","D. Routing alerts to the appropriate vendor for resolution"],correct:1,explanation:"Alert triage is the initial assessment of security alerts — determining if an alert is a true positive or false positive, assessing severity, and prioritizing response actions. Effective triage prevents analyst fatigue and ensures the most critical incidents receive immediate attention."},
{id:374,domain:5,level:1,question:"What are 'indicators of compromise' (IOCs)?",options:["A. Key performance indicators for the security operations center","B. Artifacts such as malicious IP addresses, file hashes, domain names, and registry keys that indicate a system may have been compromised","C. Financial indicators suggesting a company has been breached","D. Legal indicators that compromise of personal data has occurred"],correct:1,explanation:"IOCs are evidence of malicious activity: known-bad IP addresses, malware file hashes, C2 domain names, unusual registry keys, suspicious process names. They are shared via threat intelligence feeds and used in SIEM rules to detect matching activity."},
{id:375,domain:5,level:1,question:"What is 'containment' in the incident response lifecycle?",options:["A. Preventing media from learning about a security incident","B. Actions taken to limit the spread and impact of an incident — short-term (isolation) and long-term (patching, credential rotation)","C. Containing the cost of incident response activities","D. Filing a containment order with law enforcement"],correct:1,explanation:"Containment stops an active incident from spreading further. Short-term containment may be immediate isolation (disconnect compromised instance from network). Long-term containment involves patching vulnerabilities, resetting credentials, and applying additional controls before returning to normal operations."},
{id:376,domain:5,level:1,question:"What is 'eradication' in the incident response lifecycle?",options:["A. Destroying all digital evidence after an incident","B. Removing the root cause of the incident — malware, unauthorized accounts, exploited vulnerabilities — from all affected systems","C. Deleting all logs generated during the incident","D. Terminating all cloud instances involved in the incident"],correct:1,explanation:"Eradication removes the threat completely: deleting malware, closing backdoors, removing unauthorized accounts, patching exploited vulnerabilities. It must be thorough before recovery begins — returning systems before complete eradication risks recompromise."},
{id:377,domain:5,level:1,question:"What is 'vulnerability management' as an operational process?",options:["A. Managing the vulnerability disclosure policy for the organization","B. A continuous process of identifying, classifying, remediating, and verifying vulnerabilities in cloud infrastructure and applications","C. A one-time annual security assessment","D. The process of managing bug bounty vulnerability reports"],correct:1,explanation:"Vulnerability management is an ongoing cycle: discover (scan), assess (prioritize by CVSS score, exploitability, and asset criticality), remediate (patch, mitigate, or accept), and verify (re-scan to confirm remediation). It is a core operational security function."},
{id:378,domain:5,level:1,question:"What is a 'security baseline' in cloud operations?",options:["A. The minimum acceptable security configuration for cloud resources, used as a reference for detecting deviations","B. The starting budget for a cloud security program","C. A line item in a security report showing average security scores","D. The first security control implemented in a new cloud account"],correct:1,explanation:"A security baseline defines the minimum required security configuration for cloud resources (e.g., CloudTrail enabled, MFA required, S3 block public access, encryption at rest). Automated tools continuously compare actual configurations to the baseline and alert on deviations."},
{id:379,domain:5,level:1,question:"What is 'Security as a Service' (SECaaS)?",options:["A. A business model where the security team operates as an internal startup","B. Cloud-delivered security services (SIEM, WAF, endpoint protection, identity) consumed on a subscription basis without owning the underlying infrastructure","C. The practice of treating security as a product rather than a cost center","D. Outsourcing the entire security function to a cloud provider"],correct:1,explanation:"SECaaS delivers security capabilities via the cloud on a subscription model — organizations consume WAF, CASB, SIEM, email security, and endpoint protection without managing the underlying infrastructure, benefiting from provider scale and continuous updates."},
{id:380,domain:5,level:2,question:"A cloud environment has no centralized logging. An incident occurred but there are no logs to investigate. What is the PRIMARY root cause?",options:["A. The attacker deleted the logs during the attack","B. Logging was not enabled or configured before the incident — logging must be proactively enabled and centralized before incidents occur","C. Cloud providers do not retain logs by default","D. Logs were automatically deleted after 24 hours"],correct:1,explanation:"Many cloud services do not enable all logging by default. Organizations must proactively configure and centralize logging (CloudTrail, VPC Flow Logs, application logs) before incidents occur. This is a key element of cloud forensic readiness."},
{id:381,domain:5,level:2,question:"What is 'Security Orchestration, Automation and Response' (SOAR) and how does it differ from SIEM?",options:["A. They are identical platforms","B. SIEM collects and correlates events to generate alerts; SOAR automates the response to those alerts through playbooks and integrations","C. SOAR replaces SIEM in modern security operations","D. SOAR is for cloud environments; SIEM is for on-premises"],correct:1,explanation:"SIEM detects and alerts on threats. SOAR automates the response: when SIEM fires an alert for a suspicious login, SOAR automatically runs a playbook — check geolocation, query HR system, disable account if confirmed, create ticket, notify analyst. SOAR reduces response time from hours to minutes."},
{id:382,domain:5,level:2,question:"What is 'cloud security posture management' (CSPM) and what does it address that IAM tools do not?",options:["A. CSPM manages security certificates; IAM manages access","B. CSPM continuously monitors cloud configurations for misconfigurations and compliance violations — complementing IAM tools which focus on identity and access","C. CSPM is for infrastructure; IAM is for applications","D. They address identical security concerns with different interfaces"],correct:1,explanation:"CSPM focuses on configuration security — detecting open S3 buckets, disabled encryption, missing MFA, exposed security groups, and compliance drift. IAM tools focus on identity and permissions. Together they address two different but complementary cloud security domains."},
{id:383,domain:5,level:2,question:"What is 'security event correlation' in a SIEM and why is it important?",options:["A. Organizing security events alphabetically for easier searching","B. Combining multiple low-severity events from different sources to identify patterns indicating a higher-level attack that no single event reveals","C. Correlating security spending with breach frequency","D. Matching security events to regulatory requirements"],correct:1,explanation:"Correlation identifies attack patterns across multiple events — for example: failed login (low severity) + VPN from new location + large data download = probable account compromise. Individual events are inconclusive; correlation reveals the attack chain."},
{id:384,domain:5,level:2,question:"What is 'Security Operations Center as a Service' (SOCaaS)?",options:["A. Turning the SOC into an internal startup charged for services","B. Outsourcing security monitoring and response to a managed security service provider that operates a SOC on behalf of the customer","C. Automating all SOC functions to eliminate the need for analysts","D. A cloud provider offering dedicated SOC facilities to enterprise customers"],correct:1,explanation:"SOCaaS (MSSP/MDR services) provides 24/7 security monitoring, threat detection, and incident response as a managed service. Organizations without the resources to staff a full internal SOC use SOCaaS to gain security expertise and continuous monitoring."},
{id:385,domain:5,level:2,question:"What is the purpose of 'threat modeling for operations' (as opposed to application threat modeling)?",options:["A. Modeling which cloud threats the security team should focus on for marketing purposes","B. Identifying threats to the security operations environment itself — SIEM, SOAR, admin consoles — to prevent attackers from blinding detection capabilities","C. A statistical model predicting future threats","D. A threat prioritization framework for vulnerability management"],correct:1,explanation:"Attackers targeting sophisticated organizations often attack the security monitoring infrastructure itself (delete logs, disable SIEM agents, compromise admin accounts). Threat modeling for operations identifies and mitigates threats to the security toolchain itself."},
{id:386,domain:5,level:3,question:"What is 'attacker dwell time' and what is the industry benchmark for detection?",options:["A. The time an attacker waits before launching an attack — typically measured in days","B. The time between initial compromise and detection — industry median is approximately 16-21 days depending on the report; the goal is to reduce this to hours","C. The time it takes to eradicate an attacker after detection","D. The duration of a penetration testing engagement"],correct:1,explanation:"Dwell time is the window between initial compromise and detection — during which attackers can move laterally, escalate privileges, and exfiltrate data. Median dwell times range from 16-24 days per industry reports. Reducing dwell time through better detection limits the blast radius of breaches."},
{id:387,domain:5,level:3,question:"A cloud SOC analyst receives an alert for an API call to sts:AssumeRole from an unusual IP. What is the investigation priority and first step?",options:["A. Low priority — AssumeRole is a normal cloud operation","B. High priority — check CloudTrail for all subsequent API calls made under the assumed role to determine the scope of activity","C. Medium priority — verify if the IP is in the threat intelligence feed only","D. Dismiss the alert — cross-account role assumption is always legitimate"],correct:1,explanation:"sts:AssumeRole from an unusual IP is a potential credential compromise indicator. Immediately examine all subsequent API calls under the assumed role identity in CloudTrail to understand what was accessed or modified, determine the blast radius, and identify any persistence mechanisms created."},
{id:388,domain:5,level:3,question:"What is 'living off trusted services' (LOTS) and why does it challenge cloud security monitoring?",options:["A. Using cloud services for legitimate business operations","B. Attackers abusing legitimate cloud services (S3, CloudFront, GitHub) for C2 and exfiltration — blending malicious traffic with normal cloud service traffic to evade detection","C. Attackers using their own trusted cloud accounts for attacks","D. Security teams relying on cloud provider security tools exclusively"],correct:1,explanation:"LOTS attacks use legitimate trusted cloud services (Slack, OneDrive, S3, Pastebin) for malware delivery, C2 communication, and exfiltration. This traffic cannot be blocked by domain reputation alone and blends with legitimate usage, requiring behavioral analysis rather than signature-based detection."},
{id:389,domain:5,level:3,question:"What is 'threat emulation' vs 'penetration testing' in cloud security?",options:["A. They are identical — just different vendor terms","B. Threat emulation simulates specific threat actor TTPs from frameworks like MITRE ATT&CK to test detection and response; pen testing finds vulnerabilities regardless of threat actor","C. Threat emulation tests the threat intelligence team; pen testing tests the infrastructure","D. Threat emulation is automated; pen testing is always manual"],correct:1,explanation:"Threat emulation (red team operations) simulates specific adversary techniques from MITRE ATT&CK (e.g., techniques used by APT29) to test whether the security team detects and responds correctly. Penetration testing broadly finds exploitable vulnerabilities without necessarily mapping to specific threat actors."},
{id:390,domain:5,level:3,question:"A cloud security team wants to measure the effectiveness of their detection capability. Which metric is MOST meaningful?",options:["A. Number of alerts generated per day","B. Mean Time to Detect (MTTD) measured against known-bad activity injected through purple team exercises","C. Number of security tools deployed","D. Size of the security operations team"],correct:1,explanation:"MTTD measured against deliberately injected attack activity (purple team exercises) objectively tests detection capability. Simply counting alerts measures volume, not effectiveness. Purple team exercises validate whether specific attack techniques are actually detected and how quickly."},

// ─── DOMAIN 6: Legal, Risk and Compliance ────────────────────────────────────
{id:151,domain:6,level:1,question:"Which regulation governs the protection of personal data for EU residents, regardless of where the processing organization is located?",options:["A. HIPAA","B. SOX","C. GDPR","D. GLBA"],correct:2,explanation:"GDPR (General Data Protection Regulation) applies to any organization processing personal data of EU/EEA residents, regardless of the organization's location. Non-compliance can result in fines up to 4% of global annual turnover."},
{id:152,domain:6,level:1,question:"What is a privacy impact assessment (PIA)?",options:["A. A financial audit of privacy-related expenditures","B. An evaluation process identifying and mitigating privacy risks in systems processing personal data","C. A user survey measuring satisfaction with privacy policies","D. A legal review of contracts for privacy clauses"],correct:1,explanation:"A PIA (also called DPIA under GDPR) systematically identifies and assesses privacy risks in systems processing personal data, ensuring controls are in place to mitigate identified risks before deployment."},
{id:153,domain:6,level:1,question:"What does SOC 2 Type II attestation verify?",options:["A. Financial statement accuracy for public companies","B. That security, availability, and other trust service criteria controls were operating effectively over a period of time","C. Payment card security compliance","D. Physical security of data centers"],correct:1,explanation:"SOC 2 Type II is an audit report that verifies security controls based on AICPA Trust Service Criteria were in place AND operating effectively over a defined period (typically 6-12 months)."},
{id:154,domain:6,level:1,question:"What is risk management in the context of cloud security?",options:["A. Eliminating all risks from cloud adoption","B. Identifying, assessing, and treating risks to an acceptable level through controls or risk transfer","C. Transferring all risk to the cloud provider through contracts","D. Documenting all risks without taking action"],correct:1,explanation:"Risk management is the process of identifying risks, assessing their likelihood and impact, and applying treatments: avoid, mitigate (apply controls), transfer (insurance, contracts), or accept."},
{id:155,domain:6,level:1,question:"What is a data processing agreement (DPA) and when is it required?",options:["A. A technical document describing how data is processed in a system","B. A contractual agreement between a data controller and processor defining data handling obligations—required under GDPR","C. An internal policy governing employee data handling","D. A cloud provider's terms of service"],correct:1,explanation:"A DPA (also called a data processing addendum) is a contract required by GDPR between data controllers and processors specifying how personal data will be processed, protected, and deleted."},
{id:156,domain:6,level:1,question:"What does HIPAA primarily protect?",options:["A. Financial records of patients","B. Protected Health Information (PHI) of patients in the United States","C. Health records of EU residents","D. Medical device software security"],correct:1,explanation:"HIPAA (Health Insurance Portability and Accountability Act) requires covered entities and their business associates to protect the privacy and security of Protected Health Information (PHI) of US patients."},
{id:157,domain:6,level:1,question:"What is the purpose of a right-to-audit clause in a cloud service contract?",options:["A. Giving the cloud provider the right to audit the customer's systems","B. Giving the customer the right to audit or have a third party audit the cloud provider's security controls","C. Allowing government regulators to audit the provider","D. Authorizing financial audits of the cloud contract"],correct:1,explanation:"Right-to-audit clauses give cloud customers the contractual right to audit (or commission audits of) cloud providers' security controls, ensuring providers meet their contractual and regulatory obligations."},
{id:158,domain:6,level:1,question:"What is PCI DSS and who must comply with it?",options:["A. A US government standard for federal cloud systems—government agencies only","B. A security standard for organizations that store, process, or transmit payment card data","C. A European privacy regulation for financial institutions","D. An ISO standard for information security management"],correct:1,explanation:"PCI DSS (Payment Card Industry Data Security Standard) is a security standard created by the card brands (Visa, Mastercard, etc.) mandating security controls for any organization that handles payment card data."},
{id:159,domain:6,level:1,question:"What does 'eDiscovery' refer to in legal proceedings?",options:["A. Discovering security vulnerabilities through ethical hacking","B. The process of identifying, collecting, and producing electronically stored information (ESI) for legal proceedings","C. A tool for discovering misconfigured cloud resources","D. The process of discovering new cloud services"],correct:1,explanation:"eDiscovery is the process of identifying, preserving, collecting, reviewing, and producing ESI (emails, documents, databases) in response to litigation or regulatory requirements."},
{id:160,domain:6,level:1,question:"What is 'jurisdiction' and why does it matter in cloud computing?",options:["A. A measure of a court's technical expertise in cloud matters","B. The geographic area within which a court or law has authority—determines which laws apply to cloud data","C. A provider's ability to operate across national borders","D. A certification for cloud providers operating in multiple countries"],correct:1,explanation:"Jurisdiction determines which country's laws apply to cloud data and operations. Data stored in a country is subject to that country's laws, which may include government access requirements (e.g., CLOUD Act, GDPR)."},
{id:161,domain:6,level:2,question:"Under GDPR, what is the maximum fine for the most serious violations?",options:["A. €10 million or 2% of global annual turnover, whichever is higher","B. €20 million or 4% of global annual turnover, whichever is higher","C. €5 million flat fee per violation","D. €100 million for repeated violations"],correct:1,explanation:"GDPR has two tiers of fines. For the most serious violations (e.g., breach of basic principles, no legal basis for processing), fines can be up to €20 million or 4% of global annual turnover, whichever is higher."},
{id:162,domain:6,level:2,question:"A US company processes EU citizens' personal data. GDPR applies. What is the required legal basis for processing personal data?",options:["A. Any contractual relationship with the data subject","B. One of six lawful bases: consent, contract, legal obligation, vital interests, public task, or legitimate interests","C. The data subject must always provide explicit consent","D. A court order from any EU member state"],correct:1,explanation:"GDPR Article 6 requires a lawful basis for processing: consent, contract performance, legal obligation, vital interests, public task, or legitimate interests. Organizations must identify and document the applicable basis."},
{id:163,domain:6,level:2,question:"What is FedRAMP and who does it apply to?",options:["A. A US cybersecurity framework for all businesses","B. A US government program standardizing cloud security authorization for federal agencies","C. A financial regulation for US federal banks","D. An international cloud security certification"],correct:1,explanation:"FedRAMP (Federal Risk and Authorization Management Program) provides a standardized approach to security assessment, authorization, and monitoring for cloud products used by US federal agencies."},
{id:164,domain:6,level:2,question:"An organization transfers EU personal data to a cloud provider in the US. Under GDPR, which mechanism can legitimately authorize this transfer?",options:["A. Privacy Shield (still active)","B. Standard Contractual Clauses (SCCs) or Binding Corporate Rules (BCRs)","C. An informal email agreement between legal teams","D. GDPR prohibits all transfers to the US"],correct:1,explanation:"Privacy Shield was invalidated (Schrems II). Valid transfer mechanisms include Standard Contractual Clauses (SCCs), Binding Corporate Rules (BCRs), adequacy decisions, or derogations. The EU-US Data Privacy Framework is the current adequacy mechanism."},
{id:165,domain:6,level:2,question:"What is the difference between a 'data controller' and a 'data processor' under GDPR?",options:["A. Controller processes data; processor owns the data","B. Controller determines purposes and means of processing; processor processes on behalf of the controller","C. They are equivalent roles with different titles","D. Controller is an individual; processor is an organization"],correct:1,explanation:"The data controller determines WHY and HOW personal data is processed (e.g., the business). The processor processes data on the controller's behalf (e.g., a cloud provider). Both have GDPR obligations but the controller has primary responsibility."},
{id:166,domain:6,level:2,question:"What is an Information Security Management System (ISMS)?",options:["A. A software platform for managing security incidents","B. A systematic approach (policies, procedures, controls) for managing organizational information security","C. An IT system that stores all security documentation","D. A government database of security breaches"],correct:1,explanation:"An ISMS (defined by ISO/IEC 27001) is a framework of policies, procedures, and controls for systematically managing organizational information security, addressing people, processes, and technology."},
{id:167,domain:6,level:2,question:"What does 'right to erasure' (right to be forgotten) under GDPR require?",options:["A. Organizations must delete all data after one year","B. Individuals can request their personal data be deleted under certain conditions","C. Organizations must delete data when requested regardless of legal obligations","D. Only European companies are required to delete data on request"],correct:1,explanation:"GDPR Article 17 grants individuals the right to request deletion of their personal data. Organizations must comply unless there is a legitimate reason to retain the data (e.g., legal obligation, public interest)."},
{id:168,domain:6,level:2,question:"What is a cloud provider's 'right to subcontract' provision and why does it matter?",options:["A. The provider's right to charge for additional services","B. The provider's right to use sub-processors for data processing, which must be disclosed and approved by the customer","C. The provider's right to sell the customer's contract to another provider","D. A billing arrangement for shared services"],correct:1,explanation:"Cloud providers often use sub-processors (e.g., AWS using third-party companies). Under GDPR, controllers must be notified of sub-processors and can object. Sub-processors must have equivalent data protection obligations."},
{id:169,domain:6,level:2,question:"What is ISO/IEC 27017 specifically designed for?",options:["A. General information security management","B. Security controls specifically for cloud services—extending ISO 27001 with cloud-specific guidance","C. Personal data protection in cloud","D. Business continuity management"],correct:1,explanation:"ISO/IEC 27017 provides guidelines for information security controls applicable to cloud services, building on ISO 27001 with additional cloud-specific controls for both cloud providers and cloud customers."},
{id:170,domain:6,level:2,question:"What does 'data subject access request' (DSAR) mean under GDPR?",options:["A. A request by law enforcement to access personal data","B. An individual's right to request a copy of their personal data held by an organization","C. A security auditor's right to access all data systems","D. A court order to access personal data"],correct:1,explanation:"GDPR Article 15 grants individuals the right to know what personal data an organization holds about them, how it's used, and who it's shared with. Organizations must respond within one month."},
{id:171,domain:6,level:3,question:"A US cloud provider receives a government request under the CLOUD Act for customer data stored in Ireland. Under what conditions can the provider be compelled to disclose?",options:["A. Only if the Irish government also approves the disclosure","B. The CLOUD Act allows US authorities to compel US providers to produce data stored abroad if it is within the provider's possession, custody, or control","C. US law never applies to data stored outside the US","D. GDPR automatically blocks all such requests"],correct:1,explanation:"The CLOUD Act (2018) allows US law enforcement to compel US-based providers to produce data stored anywhere globally, subject to some protections. This creates jurisdictional conflicts with GDPR, which is why cloud architecture for sensitive EU data must consider this."},
{id:172,domain:6,level:3,question:"An organization uses cloud services and is subject to both GDPR and HIPAA. Which principle governs how to handle conflicts between the two frameworks?",options:["A. GDPR always supersedes HIPAA for EU citizens","B. Apply the more stringent requirement of each applicable framework to achieve compliance with both","C. Choose one framework and document the exception for the other","D. HIPAA only applies in the US so GDPR takes precedence globally"],correct:1,explanation:"When multiple regulations apply, organizations must identify where requirements overlap or conflict and apply the more stringent standard to satisfy both. GDPR and HIPAA have complementary but sometimes different requirements (e.g., breach notification timelines)."},
{id:173,domain:6,level:3,question:"What is the 'right to data portability' under GDPR and how does it affect cloud providers?",options:["A. The right to move physical servers between locations","B. An individual's right to receive their data in a structured, machine-readable format and transfer it to another provider","C. The organization's right to migrate between cloud providers","D. A cloud provider's right to copy data between regions"],correct:1,explanation:"GDPR Article 20 grants individuals the right to receive their personal data in a machine-readable format (e.g., JSON, CSV) for transfer to another controller. Cloud providers must support data export in usable formats."},
{id:174,domain:6,level:3,question:"What is the significance of 'privacy by design' in cloud system development?",options:["A. Designing cloud UIs with privacy-friendly color schemes","B. Embedding privacy protections into system design from the start rather than adding them afterward","C. Creating separate privacy-focused cloud regions","D. A marketing approach to highlight privacy features"],correct:1,explanation:"Privacy by design (now a GDPR requirement under Article 25) requires that privacy controls be built into system architecture from the beginning—data minimization, pseudonymization, access controls—not added as an afterthought."},
{id:175,domain:6,level:3,question:"A breach notification under GDPR must be made to the supervisory authority within how many hours of the organization becoming aware of a breach?",options:["A. 24 hours","B. 48 hours","C. 72 hours","D. 7 days"],correct:2,explanation:"GDPR Article 33 requires notification to the relevant supervisory authority within 72 hours of becoming aware of a personal data breach that poses a risk to individuals' rights and freedoms."},
{id:176,domain:6,level:3,question:"What is the purpose of a 'data protection officer' (DPO) under GDPR?",options:["A. To encrypt all personal data processed by the organization","B. An independent expert role responsible for overseeing GDPR compliance and advising on data protection obligations","C. The person responsible for approving all data access requests","D. A government-appointed inspector for compliance monitoring"],correct:1,explanation:"GDPR requires a DPO for certain organizations (public bodies, large-scale processing of sensitive data). The DPO advises on GDPR compliance, monitors compliance, cooperates with supervisory authorities, and is the point of contact for data subjects—and must be independent."},
{id:177,domain:6,level:3,question:"What distinguishes a 'binding corporate rule' (BCR) from a standard contractual clause (SCC) for international data transfers?",options:["A. BCRs apply to transfers to any third country; SCCs only apply to EU-US transfers","B. BCRs are internal policies approved by regulators for intra-group transfers; SCCs are pre-approved contracts for any transfer","C. BCRs require individual consent; SCCs do not","D. They are legally equivalent mechanisms with different names"],correct:1,explanation:"BCRs are internal data protection policies approved by EU supervisory authorities, used by multinationals for intra-group transfers. SCCs are standardized contractual clauses approved by the European Commission for transfers to third parties in non-adequate countries."},
{id:178,domain:6,level:3,question:"What is 'regulatory arbitrage' in the context of cloud data storage?",options:["A. Negotiating better regulatory compliance rates with authorities","B. Choosing to store data in a jurisdiction with less stringent regulations to avoid stricter requirements elsewhere","C. A legal strategy to apply multiple regulations simultaneously","D. Auditing cloud providers across multiple jurisdictions"],correct:1,explanation:"Regulatory arbitrage is choosing to locate data or operations in jurisdictions with less stringent regulations to avoid stricter requirements. Regulators are increasingly closing this loophole by extending jurisdiction based on where data subjects reside rather than where data is stored."},
{id:179,domain:6,level:3,question:"What is 'legal hold' and how does it interact with a cloud data deletion policy?",options:["A. A contract clause preventing the customer from terminating cloud services","B. A preservation requirement that suspends normal deletion of data potentially relevant to litigation or investigation","C. A regulatory requirement to delete data after a fixed period","D. A cloud provider's right to hold data as security for unpaid bills"],correct:1,explanation:"A legal hold (litigation hold) preserves data that may be relevant to legal proceedings, overriding normal retention/deletion schedules. Cloud environments must support legal hold capabilities that prevent data destruction while the hold is active."},
{id:180,domain:6,level:3,question:"Under the shared responsibility model, who is ultimately accountable to regulators for compliance with data protection regulations when using a cloud provider?",options:["A. The cloud provider, because they control the infrastructure","B. The data controller (customer), because regulators hold them responsible for protecting data subjects","C. Both are equally and jointly liable in all cases","D. The DPO of the cloud provider"],correct:1,explanation:"Data controllers (customers) are the primary accountable party to regulators. The customer remains responsible for compliance even when processing is delegated to a cloud provider. The customer must ensure the provider meets required standards through due diligence and contracts."},
,
// ─── MIXED BATCH C (IDs 541–770) ─────────────────────────────────────────────
// Domain 1
{id:541,domain:1,level:1,question:"What is 'Software as a Service' (SaaS) and what security responsibilities does the customer retain?",options:["A. Customer has no security responsibility in SaaS","B. In SaaS, the provider manages everything through the application; customers remain responsible for data, user access management, and configuration of security settings within the application","C. SaaS customers must manage the OS and middleware security","D. SaaS providers are responsible only for physical security"],correct:1,explanation:"In SaaS, providers manage the entire stack (physical, network, OS, middleware, application). Customers retain responsibility for: data classification and protection, IAM for their users, configuration of application security features, and compliance with their own regulatory obligations. 'The provider is secure' does not mean 'the customer is compliant.'"},
{id:542,domain:1,level:1,question:"What is 'cloud orchestration' vs 'cloud automation'?",options:["A. They are identical — orchestration is just automated automation","B. Automation handles individual tasks; orchestration coordinates multiple automated tasks in sequence/parallel to achieve a complex workflow outcome","C. Automation is for cloud; orchestration is for on-premises","D. Orchestration is manual; automation is programmatic"],correct:1,explanation:"Automation: a single task runs without human intervention (start a server, run a script). Orchestration: coordinates multiple automated tasks across systems in the right order — for example, provision a VPC, then subnets, then security groups, then instances, then deploy application — ensuring each step depends correctly on prior ones."},
{id:543,domain:1,level:2,question:"What is 'cloud security architecture review'?",options:["A. A vendor assessment of cloud provider security","B. A structured evaluation of a proposed or existing cloud architecture against security principles, threat models, and compliance requirements — identifying gaps before deployment","C. A quarterly security audit of cloud configurations","D. A review of security team organizational structure"],correct:1,explanation:"Security architecture review evaluates: threat model completeness, defense-in-depth adequacy, identity architecture, network segmentation, data flow security, encryption approach, logging coverage, and compliance alignment. Performed during design, it is far cheaper than remediating post-deployment architectural flaws."},
{id:544,domain:1,level:2,question:"What is 'Infrastructure as Code' (IaC) security scanning?",options:["A. Scanning application code for infrastructure-related bugs","B. Analyzing Terraform, CloudFormation, ARM templates for security misconfigurations before deployment — tools like Checkov, tfsec, KICS detect open security groups, missing encryption, public access settings","C. Scanning cloud instances for installed software","D. A compliance scan run on the IaC development team's workstations"],correct:1,explanation:"IaC security scanners analyze infrastructure templates before they create real resources, detecting: unrestricted security group ingress (0.0.0.0/0), S3 buckets without encryption, IAM policies with *, unencrypted databases, missing logging. Integrated into CI/CD, they prevent misconfigurations from ever deploying to production."},
{id:545,domain:1,level:3,question:"What is 'immutable infrastructure' and how does it support security?",options:["A. Infrastructure that cannot be scaled","B. Infrastructure components are never modified after deployment — updates create new components replacing old ones; this eliminates configuration drift, ensures known-good state, and simplifies forensics","C. Infrastructure protected by immutable storage","D. Infrastructure with immutable encryption keys"],correct:1,explanation:"Immutable infrastructure: deploy a new server image instead of patching the old one; destroy and recreate rather than modifying in-place. Security benefits: no configuration drift (server always matches its template), easy rollback (redeploy previous version), simpler forensics (any deviation from template indicates compromise), and attacker persistence is eliminated by replacement."},
{id:546,domain:1,level:3,question:"What is 'secure cloud architecture patterns' and give an example?",options:["A. Decorative patterns on cloud provider marketing materials","B. Reusable security design solutions for recurring cloud problems — example: hub-and-spoke network with centralized inspection VPC routing all traffic through security controls before reaching spoke VPCs","C. Security design patterns from the Gang of Four applied to cloud","D. Cloud provider recommended configurations for specific services"],correct:1,explanation:"Examples of secure cloud architecture patterns: Hub-and-spoke (centralized security inspection), DMZ pattern (tiered network with inspection between tiers), landing zone (secure account baseline), secrets rotation pattern (automated credential rotation), zero-trust network access pattern (identity-based access bypassing VPN)."},
// Domain 2
{id:547,domain:2,level:1,question:"What is 'cloud storage access logging'?",options:["A. Logging cloud storage billing events","B. Recording all requests to cloud storage (who accessed what object, when, from where) — essential for detecting unauthorized access, exfiltration attempts, and compliance auditing","C. A performance monitoring log for cloud storage operations","D. Logging cloud storage capacity changes over time"],correct:1,explanation:"Object storage access logs (S3 Server Access Logging, Azure Storage Analytics) record every API request: requester, bucket/object, operation, response code, and timestamp. They are essential for forensic investigation of data access, detecting unauthorized access, and demonstrating compliance with data access policies."},
{id:548,domain:2,level:2,question:"What is 'data classification automation' and why is it needed in cloud?",options:["A. Automatically classifying cloud providers by their security ratings","B. Using ML-based tools to automatically identify and label sensitive data (PII, PHI, financial) in cloud storage at scale — manual classification is impractical for petabytes of data","C. A tool that automatically encrypts all data regardless of classification","D. Automatically applying retention policies based on file age"],correct:1,explanation:"At cloud scale (petabytes, millions of objects), manual data classification is impossible. Services like AWS Macie, Azure Purview, and Google Cloud DLP use ML to automatically scan storage, identify sensitive data patterns, classify it, and alert on policy violations — enabling consistent protection without manual effort."},
{id:549,domain:2,level:2,question:"What is 'database encryption at rest' and what are the implementation options?",options:["A. Encrypting all database backups only","B. Encrypting data stored in databases — options: transparent data encryption (TDE) at database level, column-level encryption for specific fields, tablespace encryption, or storage-level encryption","C. Requiring encrypted connections to the database","D. Hashing all database records for integrity checking"],correct:1,explanation:"Database encryption at rest options: TDE (database engine transparently encrypts/decrypts, easiest to implement), column-level encryption (selective protection of sensitive columns, can still query non-sensitive columns), field-level encryption in application (strongest isolation, application holds keys), and storage-level encryption (cheapest, least granular protection)."},
{id:550,domain:2,level:3,question:"What is 'zero-knowledge proof' (ZKP) and its application in cloud security?",options:["A. Proving identity without any prior knowledge of the prover","B. A cryptographic method where one party proves knowledge of a secret without revealing the secret itself — applications include anonymous authentication and verifiable computation","C. An encryption scheme requiring zero knowledge of cryptography from the user","D. A cloud security audit with no prior knowledge of the environment"],correct:1,explanation:"ZKPs allow proving a statement is true without revealing the underlying information — e.g., proving you are over 18 without revealing your birthdate, or proving you know a password without transmitting it. Applications: privacy-preserving authentication, blockchain privacy, verifiable computation on encrypted data."},
{id:551,domain:2,level:3,question:"What is 'data masking in production' vs 'data masking in non-production'?",options:["A. They are identical processes applied in different environments","B. Non-production masking replaces real data with fictitious data for testing; production masking (dynamic) applies masking at query time so different users see different views of the same data based on their authorization","C. Production masking is illegal under most privacy regulations","D. Production masking means running masking tools in a production-grade environment"],correct:1,explanation:"Dynamic data masking (production) shows different users different views of the same underlying data based on their role — a call center agent sees ***-**-1234 while a DBA sees the full SSN. Static masking creates a sanitized copy for non-production use. Both address different use cases with different implementation approaches."},
// Domain 3
{id:552,domain:3,level:1,question:"What is 'cloud physical security' and what is the customer's role?",options:["A. Customers are responsible for physical security of cloud data centers","B. Cloud providers are entirely responsible for physical data center security; customers cannot access or influence it — this is a key advantage of cloud (provider economies of scale) but also requires trusting the provider","C. Physical security is shared equally between provider and customer","D. Customers must hire third-party auditors to verify provider physical security annually"],correct:1,explanation:"Physical security (data center access controls, environmental controls, hardware security) is entirely the cloud provider's responsibility. Customers cannot verify it directly but can review SOC 2 Type II reports, ISO 27001 certifications, and provider transparency reports that cover physical security controls and audits."},
{id:553,domain:3,level:1,question:"What is 'security patch SLA' in cloud managed services?",options:["A. An SLA guaranteeing cloud providers patch within 72 hours","B. The provider's commitment to patch managed service components (RDS, ElastiCache, managed Kubernetes) within a defined timeframe — customers remain responsible for patching self-managed components","C. A customer's internal SLA for applying cloud security patches","D. A regulatory requirement for cloud patch timing"],correct:1,explanation:"For managed services (RDS, managed Kubernetes, Lambda runtime), the provider patches the managed infrastructure per their SLA. Customers remain responsible for patching EC2 instances, containers, Lambda function dependencies, and application code. Understanding this split is critical for vulnerability management planning."},
{id:554,domain:3,level:2,question:"What is 'cloud security benchmark compliance' measurement?",options:["A. Comparing cloud security spending to industry benchmarks","B. Quantifying the percentage of resources meeting defined security standards (CIS Benchmarks, NIST, provider security frameworks) using automated assessment tools","C. A competitive benchmark of different cloud providers' security","D. Measuring how many security incidents occurred compared to the industry average"],correct:1,explanation:"Compliance measurement tools (AWS Security Hub, Azure Security Center, Google SCC) continuously assess resources against benchmarks and generate compliance scores — percentage of resources meeting each control. This enables tracking security posture over time, identifying regressions, and reporting compliance to management."},
{id:555,domain:3,level:2,question:"What is 'cloud interconnect security' when connecting multiple clouds?",options:["A. Using the public internet with TLS for multi-cloud connectivity","B. Securing direct network connections between cloud providers using encryption, authentication, and traffic inspection — using provider interconnect services rather than public internet","C. A security standard for cloud provider peering agreements","D. Firewall rules governing traffic between different cloud accounts"],correct:1,explanation:"Multi-cloud connectivity options: public internet (encrypted with VPN/TLS), cloud provider interconnect (AWS Direct Connect Gateway, Azure Virtual WAN), and dedicated fiber between providers. Security considerations: encrypt all cross-cloud traffic (assume the interconnect is untrusted), inspect east-west traffic between clouds, and minimize the data that crosses cloud boundaries."},
{id:556,domain:3,level:3,question:"What is 'cloud workload identity' and why does it replace service account passwords?",options:["A. Identifying cloud workloads for billing purposes","B. Cryptographic identity for workloads (Kubernetes service accounts, AWS instance profiles) enabling workloads to authenticate to cloud services without managing passwords or long-lived credentials","C. A directory service for registering cloud workload information","D. A network identity protocol for cloud service discovery"],correct:1,explanation:"Workload identity (SPIFFE/SPIRE, AWS instance profiles, GCP workload identity) provides short-lived, automatically rotated cryptographic credentials to workloads. This eliminates service account passwords embedded in code or config files — a leading cause of credential exposure. Workloads authenticate using their cryptographic identity rather than static secrets."},
{id:557,domain:3,level:3,question:"What is 'zero-trust network access' (ZTNA) and how does it differ from VPN for cloud access?",options:["A. ZTNA is a more expensive version of VPN with better performance","B. ZTNA grants access to specific applications based on continuous identity/device verification with no network access; VPN grants broad network access after a single authentication","C. ZTNA only works for cloud applications; VPN is for on-premises","D. They are equivalent security models with different underlying protocols"],correct:1,explanation:"VPN authenticates once and grants broad network access. ZTNA (Zscaler, Cloudflare Access, BeyondCorp) verifies identity AND device posture for EVERY application access, grants access only to specific apps (not the network), continuously re-evaluates trust signals, and hides application infrastructure from the internet. Dramatically smaller attack surface than VPN."},
// Domain 4
{id:558,domain:4,level:1,question:"What is 'security requirements' in the SDLC and when should they be defined?",options:["A. Security requirements are defined after design is complete","B. Security requirements (authentication strength, encryption requirements, audit logging, data retention, access control model) must be defined during the requirements phase before design begins","C. Security requirements are optional for agile development teams","D. Security requirements are defined by the security team after delivery"],correct:1,explanation:"Security requirements defined during the requirements phase drive secure design from the start. They include: authentication mechanisms required, data classification of information handled, regulatory compliance requirements (HIPAA, PCI DSS), audit logging needs, access control model, and acceptable vulnerability standards — all informing architecture decisions."},
{id:559,domain:4,level:1,question:"What is 'fuzz testing' (fuzzing) and what vulnerabilities does it find?",options:["A. Testing application behavior under fuzzy (approximate) user inputs","B. Automatically feeding random, malformed, or unexpected inputs to find crashes, memory corruption, buffer overflows, and unhandled exceptions that manual testing misses","C. Testing applications with blurred visual inputs","D. A type of penetration testing using social engineering"],correct:1,explanation:"Fuzzing sends malformed inputs (random bytes, oversized inputs, invalid formats, boundary values) to APIs, parsers, and interfaces. It discovers: buffer overflows, integer overflows, format string bugs, crashes, and unhandled exceptions — vulnerabilities that are difficult to find with manual code review or structured testing."},
{id:560,domain:4,level:2,question:"What is 'software composition analysis' (SCA) and what risk does it address?",options:["A. Analyzing the organizational composition of software development teams","B. Identifying open-source components and third-party libraries in applications, checking them against CVE databases and license databases to manage vulnerability and legal risk","C. Decomposing software architecture for security review","D. Analyzing software for performance bottlenecks"],correct:1,explanation:"SCA addresses supply chain risk: 80-90% of modern application code is open-source libraries. SCA tools (Snyk, Black Duck, OWASP Dependency-Check) inventory all dependencies, check against CVE databases, alert on newly disclosed vulnerabilities, and identify license compliance issues (GPL code in proprietary applications)."},
{id:561,domain:4,level:2,question:"What is 'HTTP parameter pollution' and what attack does it enable?",options:["A. Sending multiple requests with different parameters","B. Sending duplicate parameters in an HTTP request, potentially confusing server-side logic or WAFs — can be used to bypass input validation or WAF rules","C. Polluting server memory with excessive HTTP parameters","D. Injecting parameters into HTTP header fields"],correct:1,explanation:"HTTP parameter pollution sends the same parameter multiple times (e.g., ?id=1&id=2). Different web frameworks handle duplicates differently (use first, use last, use both). Attackers exploit this inconsistency to bypass WAF rules that check only one value while the application processes another, enabling SQLi or other injection attacks."},
{id:562,domain:4,level:3,question:"What is 'security by obscurity' and why is it insufficient as a primary control?",options:["A. Encrypting security documentation to keep it confidential","B. Relying on secrecy of design or implementation as a security mechanism — insufficient because it fails when the secret is discovered (reverse engineering, insider disclosure, accidental exposure)","C. Using obfuscated code to protect intellectual property","D. A valid security approach when combined with other controls"],correct:1,explanation:"Security by obscurity (hiding algorithm details, using non-standard ports, obfuscating code) should never be a primary control. Kerckhoffs's principle: security must not depend on secrecy of the mechanism but only on secrecy of the key. Obfuscation will eventually be reversed; proper cryptography and access controls don't rely on remaining secret."},
{id:563,domain:4,level:3,question:"What is 'API gateway security' for microservices and what attacks does it prevent?",options:["A. A physical gateway protecting API servers from physical attacks","B. Centralizing authentication, rate limiting, input validation, TLS termination, and logging at the gateway prevents: DDoS, credential stuffing, injection attacks, and unauthorized access before requests reach backend services","C. A firewall deployed in front of API servers","D. An API authentication protocol"],correct:1,explanation:"API gateways implement centralized security for all microservices: OAuth/OIDC authentication, API key management, rate limiting (DDoS/credential stuffing prevention), request validation (schema enforcement), SSL/TLS termination, request logging, and IP allowlisting. Backend services only need to implement business logic authorization, not common security controls."},
// Domain 5
{id:564,domain:5,level:1,question:"What is 'security monitoring' vs 'compliance monitoring'?",options:["A. They are identical — security monitoring is just compliance monitoring for security requirements","B. Security monitoring detects active threats and anomalies; compliance monitoring verifies configurations and processes meet regulatory/policy requirements — both are needed, both can generate alerts","C. Security monitoring is real-time; compliance monitoring is annual","D. Compliance monitoring is for regulated industries; security monitoring is for all organizations"],correct:1,explanation:"Security monitoring (SIEM, IDS, UEBA) detects threats in real time: active attacks, credential compromise, lateral movement. Compliance monitoring (CSPM, AWS Config) verifies configurations meet requirements: encryption enabled, MFA enforced, logging configured. Both are needed — security monitoring finds active threats; compliance monitoring finds configuration drift that creates future risk."},
{id:565,domain:5,level:1,question:"What is 'cloud provider security notifications' and why should organizations subscribe?",options:["A. Marketing emails from cloud providers about security product upgrades","B. Provider notifications about security vulnerabilities in their services, incidents affecting customer environments, and abuse reports — critical for timely response and risk awareness","C. Billing alerts that security costs are increasing","D. Notifications sent by cloud providers to government regulators"],correct:1,explanation:"Cloud providers publish security advisories (AWS Security Bulletins, Azure Security Advisories) for: vulnerabilities in managed services, incidents affecting customer data, and changes to security features. Organizations must subscribe and have processes to evaluate and respond to relevant notifications quickly."},
{id:566,domain:5,level:2,question:"What is 'detection rule lifecycle management'?",options:["A. Managing the software lifecycle of the SIEM platform","B. Creating, testing, tuning, and retiring detection rules over time — rules must be updated as attacker TTPs evolve, tuned to reduce false positives, and retired when they no longer provide value","C. Managing renewal of security tool licenses","D. Documenting the lifecycle of past security incidents"],correct:1,explanation:"Detection rules degrade over time: attackers change TTPs, environment changes cause new false positives, and rule coverage gaps emerge. Lifecycle management: develop rules from threat intelligence/TTPs, test against known-bad data, measure false positive rates, tune regularly, retire rules that no longer fire or generate only false positives."},
{id:567,domain:5,level:2,question:"What is 'cloud security monitoring blind spots' and how to address them?",options:["A. Time periods when the security team is not working","B. Areas with limited or no security telemetry — e.g., provider-managed service internals, encrypted traffic, ephemeral resources that terminate before logs are collected","C. Literal blind spots in cloud data center cameras","D. Areas of the cloud environment not covered by compliance requirements"],correct:1,explanation:"Cloud monitoring blind spots: provider-managed service internals (you see API calls but not service internals), container logs before log agents start, very short-lived Lambda executions, encrypted east-west traffic without inspection, and resources in accounts not forwarding logs centrally. Address by: enabling all available log sources, using provider-native threat detection, and designing for ephemeral log capture."},
{id:568,domain:5,level:3,question:"What is 'proactive threat hunting' methodology and how does it differ from reactive alert response?",options:["A. Purchasing threat intelligence before needing it","B. Hypothesis-driven investigation seeking signs of undetected compromise — analyst formulates hypothesis (attacker living off land in our environment), queries telemetry specifically for TTPs, rather than waiting for SIEM alerts","C. Blocking known threats before they reach the environment","D. Pre-approving response actions to speed up incident response"],correct:1,explanation:"Threat hunting starts with a hypothesis ('based on threat intelligence, APT X uses technique Y — do we see evidence of Y in our environment?') then hunts for TTPs in telemetry — even when no alert fired. It finds sophisticated attackers who have successfully evaded automated detection by specifically looking for their techniques rather than waiting for alerts."},
// Domain 6
{id:569,domain:6,level:1,question:"What is 'privacy notice' (privacy policy) under GDPR?",options:["A. An internal document describing security controls for personal data","B. A transparency document informing data subjects about what data is collected, why, how long it is retained, who it is shared with, and what rights they have","C. A contract between the organization and cloud provider","D. A technical specification for data encryption methods"],correct:1,explanation:"GDPR Articles 13-14 require privacy notices to be: concise, transparent, intelligible, accessible, free of charge, and provided at the time of collection. Required content: controller identity, purposes and legal basis, retention periods, recipient categories, international transfer information, and data subject rights."},
{id:570,domain:6,level:2,question:"What is 'ISO 27017' vs 'ISO 27018'?",options:["A. They are the same standard with different version numbers","B. ISO 27017 addresses cloud service security controls (for both providers and customers); ISO 27018 specifically addresses protection of PII in public cloud — both extend ISO 27001/27002","C. ISO 27017 is for private cloud; ISO 27018 is for public cloud","D. ISO 27017 covers cloud networking; ISO 27018 covers cloud storage"],correct:1,explanation:"ISO 27017 provides cloud-specific implementation guidance for both cloud customers and providers, extending ISO 27002 controls with cloud context. ISO 27018 focuses specifically on personal data protection in public cloud, providing PII-specific controls. Organizations processing PII in cloud should target both."},
{id:571,domain:6,level:2,question:"What is 'penetration testing permission' requirement for cloud environments?",options:["A. Cloud providers prohibit all penetration testing of their infrastructure","B. Most providers require advance notification or approval for penetration testing — testing provider infrastructure (shared hypervisors, network) without authorization may violate terms and trigger security responses","C. Customers may penetration test any cloud resource without restriction","D. Government authorization is required for all cloud penetration tests"],correct:1,explanation:"AWS, Azure, and GCP generally permit customers to test their own cloud resources but prohibit testing other customers' resources or shared infrastructure. Requirements vary: AWS no longer requires prior approval for most testing; Azure requires notification; GCP has specific permitted/prohibited activities. Always review current provider policies before testing."},
{id:572,domain:6,level:3,question:"What is 'cross-border eDiscovery' challenge in multi-national cloud environments?",options:["A. Difficulty accessing eDiscovery tools from different countries","B. Collecting evidence across multiple jurisdictions may conflict with local privacy laws (GDPR blocking transfer to US courts), require letters rogatory, or face data localization restrictions","C. Time zone differences making coordinated eDiscovery difficult","D. Different file formats used in different countries complicating ESI collection"],correct:1,explanation:"Cross-border eDiscovery conflicts: GDPR may prohibit transferring EU data to US courts without appropriate mechanisms; some countries (China, Russia) have data localization laws prohibiting export; blocking statutes in some jurisdictions prohibit disclosure to foreign courts. Organizations need international legal counsel and cloud architectures that anticipate these requirements."},
// More Domain 1
{id:573,domain:1,level:1,question:"What is 'cloud elasticity' security implication?",options:["A. Elastic resources are more vulnerable to attack than fixed resources","B. New instances launched during auto-scaling must automatically inherit security configurations — security policies must be embedded in launch templates, not manually applied","C. Elasticity makes cloud environments harder to monitor","D. Elastic scaling reduces security costs by using fewer resources"],correct:1,explanation:"Cloud elasticity means new instances can appear within seconds. If security configuration requires manual steps (installing agents, applying policies, running hardening scripts), elastic instances may be insecure for minutes or hours. Security must be embedded in instance launch templates, AMIs, or enforced via provider policies at launch."},
{id:574,domain:1,level:2,question:"What is 'cloud security maturity model' and how is it used?",options:["A. A maturity model for cloud provider security capabilities","B. A framework (like CSA CCM Maturity, NIST CSF maturity tiers) assessing an organization's cloud security capability level from initial/ad-hoc through optimized/continuous improvement","C. A model measuring cloud security product quality","D. An age-based model for evaluating cloud provider experience"],correct:1,explanation:"Security maturity models assess cloud security capability across dimensions: governance, IAM, infrastructure, data protection, incident response, monitoring. They benchmark current state, identify gaps, and provide a roadmap from reactive (Tier 1) to proactive and continuously improving (Tier 4-5) cloud security posture."},
{id:575,domain:1,level:3,question:"What is 'policy-as-code' in cloud governance and what are its advantages?",options:["A. Writing cloud policies in plain language code comments","B. Expressing security and compliance policies as executable code (OPA, Sentinel, AWS Config Rules) that is version-controlled, tested, and automatically enforced — replacing manual policy review","C. A coding standard for security policy documentation","D. Using code to document existing manual security policies"],correct:1,explanation:"Policy-as-code advantages: policies are version-controlled (changes tracked), automatically tested (unit tests for policies), consistently enforced (no human inconsistency), executable at scale (evaluate thousands of resources instantly), and auditable (code represents the exact policy). Examples: OPA Rego policies, HashiCorp Sentinel, AWS Config Rules, Kubernetes admission policies."},
// Domain 2
{id:576,domain:2,level:1,question:"What is 'data owner' vs 'data steward' role?",options:["A. They are identical roles with different titles in different organizations","B. Data owner: business executive accountable for data classification and use decisions; data steward: business-side role responsible for data quality, governance, and day-to-day compliance","C. Data owner holds the encryption keys; data steward manages backups","D. Data owner is a legal role; data steward is a technical role"],correct:1,explanation:"Data owner (often a VP or Director) has ultimate accountability for a data asset — classification, approved uses, risk acceptance. Data steward (data analyst or business manager) manages data quality, enforces governance policies, and coordinates between business and IT. Both are distinct from data custodian (IT role implementing technical controls)."},
{id:577,domain:2,level:2,question:"What is 'data loss prevention (DLP) false positive' management?",options:["A. Managing cases where DLP fails to detect actual data loss","B. Tuning DLP policies to reduce alerts on legitimate business activities while maintaining effective protection — excessive false positives cause alert fatigue and policy bypass","C. Preventing data loss in DLP tool deployments","D. Managing DLP vendor licensing and false billing charges"],correct:1,explanation:"DLP false positives block legitimate business activities (legitimate document sharing, analyst sharing financial reports) and cause alert fatigue — analysts stop reviewing alerts. Tuning: refine patterns, add business context, use contextual analysis (destination, user role), and create exclusions for verified legitimate use cases while monitoring those exclusions."},
{id:578,domain:2,level:3,question:"What is 'privacy-enhancing technology' (PET) and give three examples?",options:["A. Technologies that make privacy policies more readable","B. Technical tools that enable data use while minimizing privacy risk: differential privacy (adds noise to statistical outputs), homomorphic encryption (compute on encrypted data), federated learning (train ML models without centralizing data)","C. Encryption tools specifically designed for privacy compliance","D. Browser privacy features like incognito mode"],correct:1,explanation:"PETs enable privacy-preserving data processing: (1) Differential privacy: adds noise to outputs so individuals cannot be singled out, (2) Homomorphic encryption: compute on ciphertext, (3) Federated learning: train ML at data location without centralizing data, (4) Secure multi-party computation: joint computation without data sharing, (5) Synthetic data: generate realistic artificial datasets."},
// Domain 3
{id:579,domain:3,level:1,question:"What is 'cloud firewall' vs 'on-premises firewall' key difference?",options:["A. Cloud firewalls are always more secure because providers manage them","B. Cloud firewalls are software-defined and API-managed, scaling automatically with workloads; on-premises firewalls are hardware appliances with fixed capacity requiring manual configuration","C. On-premises firewalls encrypt traffic; cloud firewalls only filter it","D. Cloud firewalls only protect internet-facing services; on-premises protect all internal traffic"],correct:1,explanation:"Cloud firewalls (security groups, NACLs, network firewall services) are API-driven, apply instantly across many instances, scale automatically, and are managed as code. On-premises firewalls are hardware with fixed throughput, manual ACL updates, and physical maintenance requirements. Cloud firewalls shift from device-centric to policy-centric network security."},
{id:580,domain:3,level:2,question:"What is 'shared storage security' in cloud environments?",options:["A. Security considerations when multiple employees share access to the same storage account","B. Ensuring storage volumes shared between multiple instances have appropriate access controls and are not shared across trust boundaries — NFS/SMB shares with broad access are a lateral movement risk","C. A protocol for encrypting shared cloud storage","D. Security controls for cloud storage shared between business partners"],correct:1,explanation:"Shared storage (EFS, Azure Files, NFS volumes) accessible to multiple instances can become a lateral movement vector — a compromised instance with access to a shared volume can read/write data from all other mounted instances. Controls: restrict mount access to minimum required instances, encrypt the volume, monitor access patterns."},
{id:581,domain:3,level:3,question:"What is 'network flow analysis' for detecting cloud data exfiltration?",options:["A. Analyzing cloud provider network infrastructure design","B. Examining VPC Flow Logs for unusual outbound traffic patterns: unexpected destinations, unusual ports, large transfer volumes, or traffic to known-malicious IPs indicating potential data exfiltration","C. Analyzing the flow of network change requests through approval processes","D. Performance analysis of network throughput between cloud services"],correct:1,explanation:"VPC Flow Logs record source/destination IP, port, protocol, and bytes for each connection. Exfiltration indicators: unexpected destinations (new external IPs), unusual protocols (DNS tunneling, ICMP exfiltration), large outbound volumes to non-corporate destinations, transfers during off-hours. ML-based anomaly detection identifies deviations from normal baseline traffic patterns."},
// Domain 4
{id:582,domain:4,level:1,question:"What is 'access token' security in cloud APIs?",options:["A. Physical tokens used to access cloud data centers","B. Short-lived credentials issued by identity providers after authentication, scoped to specific permissions — must be kept secret, transmitted over HTTPS only, and validated on every request","C. API keys that never expire, used for long-term access","D. Tokens used to track the number of cloud API calls"],correct:1,explanation:"Access tokens (JWT, OAuth bearer tokens) grant API access. Security requirements: use HTTPS only (never expose in URLs), minimize token lifetime, validate signature and claims on every request, scope to minimum necessary permissions, implement token revocation for compromised tokens, and never log full token values."},
{id:583,domain:4,level:2,question:"What is 'security testing in agile development' and how is it integrated?",options:["A. Running a complete security test cycle at the end of each sprint","B. Integrating security testing throughout the sprint: security stories in backlog, SAST in developer IDEs, automated security tests in CI/CD, and security acceptance criteria in definition of done","C. Replacing traditional sprints with security-focused iterations","D. Hiring a security tester as a dedicated scrum team member"],correct:1,explanation:"Agile security integration: security requirements as user stories (with acceptance criteria), SAST/linting in developers' IDEs (immediate feedback), automated SAST/DAST/SCA in CI/CD pipeline (gate on critical findings), security reviews for high-risk features, and security acceptance criteria in the Definition of Done — ensuring security is continuous, not a phase."},
{id:584,domain:4,level:3,question:"What is 'server-side template injection' (SSTI) and why is it critical?",options:["A. Injecting code into HTML templates on the client side","B. Exploiting template engines (Jinja2, Twig, Velocity) to execute arbitrary code on the server when user input is directly embedded in templates — often leads to Remote Code Execution","C. Injecting JavaScript into server-rendered templates","D. An XSS attack targeting server-rendered web pages"],correct:1,explanation:"SSTI occurs when user input is embedded directly in server-side templates. Template engines can execute code within special delimiters. If input like {{7*7}} is rendered as 49, the engine is executing expressions from user input. Attackers use template syntax to invoke OS commands, achieving RCE. Prevention: never render user input in templates directly; use sandboxed templates."},
// Domain 5
{id:585,domain:5,level:1,question:"What is 'security event correlation' rule example in cloud?",options:["A. Organizing security events by alphabetical category","B. A rule combining: multiple failed logins + successful login from new country + API calls to new S3 buckets = high-confidence credential compromise alert","C. Correlating cloud costs with security incidents for ROI analysis","D. Matching security events to calendar events for scheduling"],correct:1,explanation:"Correlation rules combine low-severity events that individually seem innocuous but together indicate an attack: (1) 5+ failed login attempts, (2) followed by successful login, (3) from a new geographic location, (4) with data download activity = probable account compromise. Single events alone would each be low-severity."},
{id:586,domain:5,level:2,question:"What is 'cloud security incident communication plan'?",options:["A. A plan for marketing cloud security capabilities to customers","B. Documented procedures defining who to notify, when, how, and with what information during a cloud security incident — covering internal stakeholders, legal, regulators, customers, and media","C. A communication protocol for security tool integrations","D. A plan for communicating cloud security requirements to development teams"],correct:1,explanation:"Incident communication plan covers: internal escalation (CISO, Legal, PR), regulatory notification timelines (GDPR 72-hour), customer notification procedures, media response protocol, and coordination with cloud providers. Pre-drafted notification templates (fill in specifics) enable fast, accurate communication under pressure."},
{id:587,domain:5,level:3,question:"What is 'MITRE ATT&CK for Cloud' and how is it used in security operations?",options:["A. A list of cloud provider attack capabilities","B. A knowledge base of adversary tactics, techniques, and procedures (TTPs) specific to cloud environments — used to structure threat hunting, build detection rules, assess coverage gaps, and conduct adversary emulation","C. A cloud security certification from MITRE Corporation","D. A vulnerability scoring system for cloud services"],correct:1,explanation:"MITRE ATT&CK for Cloud (IaaS, SaaS, O365, Azure AD, Google Workspace) documents real adversary techniques: initial access (phishing, valid accounts), persistence (create cloud accounts, backdoor functions), privilege escalation (IAM role abuse), defense evasion (disable logging), exfiltration (S3 data transfer). Teams map their detection coverage to this framework to identify and fill gaps."},
// Domain 6
{id:588,domain:6,level:1,question:"What is 'notification of breach' obligation in cloud contracts?",options:["A. Cloud providers must notify the media when breaches occur","B. Contracts must specify timelines and procedures for the provider to notify the customer of security incidents — supporting the customer's regulatory notification obligations (GDPR 72-hour)","C. A requirement for customers to notify cloud providers of vulnerabilities they discover","D. A requirement to notify competing cloud providers of security incidents"],correct:1,explanation:"Cloud contracts must include breach notification provisions: provider notifies customer of confirmed incidents within a defined timeframe (e.g., 24-48 hours), provides sufficient detail for customer risk assessment, cooperates with investigation, and preserves evidence. This enables the customer to meet their own regulatory obligations (GDPR Article 33's 72-hour supervisory authority notification)."},
{id:589,domain:6,level:2,question:"What is 'third-party risk assessment' for cloud vendors?",options:["A. Assessing risks to the cloud vendor's business from market competition","B. Evaluating a cloud vendor's security practices through questionnaires (SIG, CAIQ), reviewing certifications (SOC 2, ISO 27001), and assessing contractual terms before engagement — and periodically thereafter","C. An assessment performed by a third party on behalf of the organization","D. Reviewing cloud vendor financial stability before signing contracts"],correct:1,explanation:"Third-party risk assessment for cloud vendors: (1) Pre-engagement due diligence (questionnaire, certification review, contract review), (2) Contractual security requirements (data handling, breach notification, audit rights), (3) Ongoing monitoring (re-assess annually, monitor their breach history, review new certifications). CSA CAIQ provides cloud-specific assessment questions."},
{id:590,domain:6,level:3,question:"What is 'GDPR Article 28' and what must it include for cloud providers?",options:["A. The data subject rights article requiring customer notification","B. The processor agreement article — requires a written contract between controller (customer) and processor (cloud provider) specifying: processing purpose, subject matter, duration, nature, data categories, and processor obligations (technical/organizational measures, subprocessors, audit cooperation)","C. The data breach notification article with 72-hour requirement","D. The cross-border transfer article governing data flows outside the EU"],correct:1,explanation:"GDPR Article 28 mandates a data processing agreement (DPA) when a controller engages a processor. Required DPA contents: processing only on documented instructions, confidentiality obligations, security measures (Article 32), subprocessor conditions, data subject rights assistance, return/deletion of data, audit rights, and evidence of compliance. No DPA = GDPR violation."},
// Continuing across domains
{id:591,domain:1,level:2,question:"What is 'cloud tagging strategy' for security governance?",options:["A. A strategy for labeling cloud provider documentation","B. A consistent taxonomy of tags (Environment, Owner, DataClassification, CostCenter, Compliance) applied to all cloud resources enabling policy enforcement, automated security controls, and resource inventory","C. Organizing cloud resources into tag-based security groups","D. A customer support tagging system for cloud security tickets"],correct:1,explanation:"A tagging strategy defines: mandatory tags (Environment=prod/dev, DataClassification=restricted/public, Owner=team@company), conventions (consistent naming, allowed values), enforcement (deny resource creation without required tags via SCPs/policies), and use cases (tag-based IAM policies, compliance reporting, cost allocation, automated security controls by classification)."},
{id:592,domain:2,level:1,question:"What is 'cloud storage cold tier' security consideration?",options:["A. Cloud storage in cold geographic regions","B. Infrequently accessed data moved to cheaper cold storage — security consideration: encryption and access controls must remain in place even when data appears 'inactive,' as it may still be sensitive","C. Temporarily cooled storage media for improved data integrity","D. Storage that is cooled below normal operating temperature for energy efficiency"],correct:1,explanation:"Cold tier (AWS Glacier, Azure Archive) stores infrequently accessed data at very low cost but with retrieval delays. Security considerations: encryption must remain active, access policies must be reviewed (not assumed unchanged), and retention policies must apply. 'Cold' refers to access frequency, not security importance — data can remain highly sensitive regardless of access tier."},
{id:593,domain:3,level:2,question:"What is 'cloud-native application protection platform' (CNAPP)?",options:["A. A cloud provider's native security monitoring platform","B. An integrated security platform combining CSPM, CWPP, KSPM, and CIEM to provide comprehensive protection of cloud-native applications across development and runtime","C. A compliance management tool for cloud applications","D. A cloud access security broker focused on application traffic"],correct:1,explanation:"CNAPP integrates: CSPM (cloud posture management), CWPP (workload protection at runtime), KSPM (Kubernetes security posture), and CIEM (entitlement management) into a unified platform. It provides end-to-end visibility from code (shift-left scanning) through runtime (behavioral detection) in a single tool with unified risk context."},
{id:594,domain:4,level:2,question:"What is 'container escape' vulnerability and how is it mitigated?",options:["A. A vulnerability allowing containers to escape from a Kubernetes cluster","B. A vulnerability in the container runtime or kernel allowing a process in a container to break out of isolation and access the host system or other containers","C. A performance issue where containers escape memory limits","D. An application vulnerability allowing users to escape the container's application sandbox"],correct:1,explanation:"Container escape vulnerabilities (e.g., runc CVE-2019-5736, dirty COW) allow a process in a container to break namespace isolation and access the host OS. Mitigations: keep container runtimes patched, use seccomp/AppArmor to limit syscalls, run containers as non-root, use rootless containers, and consider gVisor/Kata Containers for stronger isolation using separate kernels."},
{id:595,domain:5,level:2,question:"What is 'cloud threat modeling for operations' and what threats should be modeled?",options:["A. Modeling business threats to cloud adoption decisions","B. Identifying threats to cloud operational systems themselves: SIEM poisoning (false events), log deletion, security agent compromise, admin credential theft, monitoring tool misconfiguration creating blind spots","C. A threat model for cloud providers to apply to their infrastructure","D. Modeling competitive threats from rival cloud providers"],correct:1,explanation:"Operations-focused threat modeling asks: what if the SIEM receives false events masking real attacks? What if log forwarding is disrupted? What if security agent credentials are stolen? What if admin consoles are compromised? Modeling these threats drives: immutable logging, log integrity verification, multi-signal detection, and separate security accounts for monitoring infrastructure."},
{id:596,domain:6,level:2,question:"What is 'certification vs accreditation' in government cloud security?",options:["A. They are identical processes called differently in different agencies","B. Certification: technical evaluation verifying security controls meet requirements; Accreditation (Authorization): official decision by an authorizing official accepting risk and granting permission to operate","C. Certification applies to providers; accreditation applies to customers","D. Certification is for commercial cloud; accreditation is for government cloud"],correct:1,explanation:"In US government (FISMA/FedRAMP): Security Assessment (formerly Certification) evaluates technical controls. Authorization to Operate (ATO, formerly Accreditation) is the authorizing official's risk acceptance decision based on that evaluation. FedRAMP centralized this for cloud: one security assessment reused by multiple agencies via the FedRAMP Marketplace."},
{id:597,domain:1,level:3,question:"What is 'cloud security posture' and how is it measured?",options:["A. The physical posture of cloud data center employees","B. The overall state of cloud security — measured through: misconfiguration count and severity, compliance score against benchmarks, vulnerability age, IAM risk score, and detection coverage — tracked over time to show improvement","C. A cloud provider's security marketing position relative to competitors","D. The security budget allocation as a percentage of cloud spend"],correct:1,explanation:"Cloud security posture is the aggregate security state across the cloud environment. Measured by: CSPM compliance scores (% resources meeting benchmarks), critical open vulnerabilities and mean time to remediate, IAM risk (% of roles with excessive permissions), detection coverage (% of MITRE ATT&CK techniques with detection rules), and trend direction (improving/declining)."},
{id:598,domain:2,level:2,question:"What is 'data classification label propagation'?",options:["A. Marketing data classified information to data stewards","B. Automatically applying the classification of a source dataset to all derived datasets — if a report is generated from Restricted data, the report inherits the Restricted classification","C. Propagating classification decisions across different organizational units","D. Applying classification labels to network traffic packets"],correct:1,explanation:"Label propagation ensures that when sensitive data is used to generate derivative artifacts (reports, exports, copies, analysis outputs), those artifacts inherit the appropriate classification. Without propagation, an export of Restricted data could be mislabeled as Public and handled without appropriate controls."},
{id:599,domain:3,level:1,question:"What is 'cloud account hijacking' and how is it prevented?",options:["A. A cloud provider taking over a customer's account for non-payment","B. Attackers gaining control of cloud management accounts through credential theft, phishing, or IAM misconfiguration — prevented by MFA, strong credential policies, monitoring for unusual API activity","C. A competitor copying a cloud organization's architecture","D. A government agency seizing a cloud account for legal reasons"],correct:1,explanation:"Account hijacking gives attackers full control over all cloud resources. Prevention: mandatory MFA for all accounts (especially root/admin), complex passwords, never sharing account credentials, phishing-resistant authentication (hardware keys), CloudTrail monitoring for unusual API patterns, and regular access reviews to detect unauthorized accounts."},
{id:600,domain:4,level:1,question:"What is 'input allowlisting' vs 'input denylisting'?",options:["A. Allowlisting is stricter — only explicitly permitted inputs are accepted; denylisting is more permissive — only explicitly forbidden inputs are rejected (allowlisting is the recommended approach)","B. Denylisting is stricter; allowlisting is more permissive","C. They are equivalent approaches with the same security outcome","D. Allowlisting applies to network traffic; denylisting applies to application input"],correct:1,explanation:"Allowlisting (whitelist) only permits known-good inputs and rejects everything else — much stronger because attackers only need to find one encoding/bypass to evade denylisting. Denylisting (blacklist) rejects known-bad patterns but attackers find bypasses through encoding, obfuscation, and novel attack vectors. Always prefer allowlisting for validation."},
{id:601,domain:5,level:1,question:"What is 'cloud security operations escalation path'?",options:["A. The process of escalating cloud costs to management","B. Documented procedures defining when and how to escalate security incidents to higher authority — Tier 1 analyst → Tier 2 analyst → Incident commander → CISO → Legal — with criteria and contact information","C. A technical escalation path for cloud provider support requests","D. The career path for cloud security operations professionals"],correct:1,explanation:"Escalation paths define: who makes decisions as incident severity increases, what criteria trigger escalation (data breach confirmed, media involved, regulatory implications), contact information for all escalation levels including after-hours, and communication templates for each level. Pre-defined escalation prevents confusion during high-pressure incidents."},
{id:602,domain:6,level:1,question:"What is 'legal hold' technical implementation in cloud?",options:["A. Physically holding cloud servers during legal investigations","B. Technical controls preventing deletion or modification of potentially relevant data: object lock/WORM storage, suspended retention policies, preserved accounts, and maintained log streams — triggered by legal or compliance notification","C. A legal contract preventing cloud providers from deleting customer data","D. Court-ordered freeze of cloud provider operations"],correct:1,explanation:"Legal hold in cloud: (1) Identify custodians and relevant data sources, (2) Apply object lock/WORM to prevent deletion of cloud storage objects, (3) Suspend automated retention/deletion policies for in-scope data, (4) Preserve cloud accounts of relevant users, (5) Maintain continuous log forwarding, (6) Document all holds and review periodically for scope changes."},
{id:603,domain:1,level:2,question:"What is 'cloud security dashboard' for executive reporting?",options:["A. The cloud provider's security management console","B. A board/executive-level view showing: overall risk score, trending security posture, critical open issues, compliance status, and investment effectiveness — translating technical metrics into business risk language","C. A technical dashboard for SOC analysts monitoring real-time alerts","D. A financial dashboard tracking security tool spending"],correct:1,explanation:"Executive security dashboards translate technical security metrics into business risk: trend lines (posture improving/degrading), compliance percentages (regulatory risk), critical vulnerability counts by age (liability), breach risk indicators, and ROI metrics (incidents prevented, mean response time improvement). Data must be accurate, timely, and actionable at the executive level."},
{id:604,domain:2,level:3,question:"What is 'verifiable deletion' in cloud and why is it challenging?",options:["A. Deleting data in a way that is verifiable by the cloud provider","B. Providing cryptographic or audit proof that data has been irrecoverably destroyed — challenging because cloud storage is distributed, data may exist in caches/replicas, and providers cannot always provide per-record deletion evidence","C. A deletion process that requires customer verification before executing","D. Deleting data with a verification code sent to the data owner"],correct:1,explanation:"Verifiable deletion is difficult in cloud because: data may be in multiple replicas, caches, and backup tiers; storage media is not customer-dedicated; and providers cannot always provide evidence of physical media sanitization for specific customer data. Best approaches: crypto-shredding (provider certifies key destruction) + provider attestation of general media sanitization per standards like NIST 800-88."},
{id:605,domain:3,level:2,question:"What is 'cloud security review board' function?",options:["A. A government board reviewing cloud provider security practices","B. An internal governance body reviewing and approving significant cloud architecture decisions, security exceptions, and risk acceptances — ensuring decisions are made with appropriate expertise and accountability","C. A vendor selection board for cloud security tools","D. A legal review board for cloud security contracts"],correct:1,explanation:"A Cloud Security Review Board (or Architecture Review Board) evaluates proposed cloud architectures before implementation: reviews threat models, validates security controls, approves exceptions to security policies, ensures compliance requirements are met, and provides expert oversight for high-risk decisions — preventing security issues from being discovered only after deployment."},

// ─── MIXED BATCH A (IDs 409–558) ─────────────────────────────────────────────
// Domain 1
{id:409,domain:1,level:1,question:"Which of the following BEST describes 'cloud bursting'?",options:["A. A denial-of-service attack against a cloud provider","B. Automatically extending workloads from a private cloud to a public cloud when demand exceeds private capacity","C. A pricing model where costs spike unpredictably","D. A migration technique for moving all on-premises workloads to cloud at once"],correct:1,explanation:"Cloud bursting allows a private cloud to overflow to a public cloud during peak demand, giving organizations the cost control of private cloud for baseline loads and the elasticity of public cloud for peaks."},
{id:410,domain:1,level:1,question:"What is 'serverless computing'?",options:["A. Computing without any servers in the cloud data center","B. A model where the provider manages all server infrastructure; customers deploy code that runs in response to events and pay only for execution time","C. Computing performed entirely on client devices","D. A development model that does not require writing server-side code"],correct:1,explanation:"Serverless (FaaS) abstracts server management entirely. Customers upload functions that are executed on demand (event-triggered). Billing is per-invocation and execution duration. AWS Lambda, Azure Functions, and Google Cloud Functions are examples."},
{id:411,domain:1,level:1,question:"What is 'auto-scaling' in cloud computing?",options:["A. Automatically updating software without user intervention","B. Dynamically adding or removing compute capacity based on demand metrics","C. Automatically scaling security permissions with workload growth","D. A tool that scales pricing automatically based on usage"],correct:1,explanation:"Auto-scaling automatically adjusts the number of running instances based on metrics (CPU, request rate, queue depth). It maintains performance during peaks and reduces cost during low-demand periods without manual intervention."},
{id:412,domain:1,level:1,question:"What does 'multi-tenancy' mean in cloud computing?",options:["A. Having multiple cloud providers for one organization","B. Multiple customers sharing the same physical infrastructure, with logical isolation between them","C. Running multiple operating systems on one server","D. Having multiple administrators for one cloud account"],correct:1,explanation:"Multi-tenancy means multiple customers (tenants) share the same underlying physical resources (servers, storage, network) while being logically isolated from each other. It enables economies of scale for providers but introduces isolation requirements."},
{id:413,domain:1,level:2,question:"What is a 'cloud reference architecture' and why is it useful?",options:["A. A blueprint provided by cloud providers to sell more services","B. A pre-defined, tested architecture pattern for common cloud scenarios that incorporates best practices for security, reliability, and performance","C. A government-mandated architecture standard for federal cloud","D. A reference document listing all available cloud services"],correct:1,explanation:"Cloud reference architectures (AWS Well-Architected examples, Azure Architecture Center patterns) provide pre-validated designs for common scenarios (web app, data lake, microservices). They accelerate design while embedding proven security and reliability patterns."},
{id:414,domain:1,level:2,question:"What is the 'principle of separation of duties' in cloud IAM?",options:["A. Separating cloud duties between multiple providers","B. Ensuring no single individual or role has the combination of permissions needed to perform a sensitive action end-to-end without a second party","C. Dividing security duties between the security team and developers","D. Separating production and development cloud environments"],correct:1,explanation:"Separation of duties requires that sensitive actions need multiple parties — for example, no single person can both approve and execute a production change, or both create and approve a privileged account. In cloud IAM, this is enforced through role design and approval workflows."},
{id:415,domain:1,level:2,question:"What is 'cloud cost optimization' from a security perspective?",options:["A. Reducing security spending to lower cloud costs","B. Identifying and eliminating unused or forgotten resources — which also reduces the attack surface of unmanaged assets","C. Using cheaper cloud regions regardless of data residency requirements","D. Automating security tasks to reduce headcount costs"],correct:1,explanation:"Cloud cost optimization and security are aligned: unused instances, forgotten storage buckets, and orphaned IAM roles are both wasteful and security risks. Eliminating them reduces both cost and attack surface — a rare security/business win-win."},
{id:416,domain:1,level:3,question:"An organization wants to implement a 'zero-trust' network architecture for its cloud environment. Which of the following BEST describes the implementation approach?",options:["A. Remove all firewalls and rely on cloud-native encryption","B. Verify every request explicitly using identity, device posture, and context; apply least-privilege access; assume breach by segmenting and monitoring all traffic","C. Place all workloads in a single trusted VPC with strong perimeter controls","D. Require VPN for all access to cloud resources"],correct:1,explanation:"Zero trust implements: strong identity verification (MFA, device health), explicit authorization per request (not session-based), micro-segmentation (no implicit trust between workloads), continuous monitoring, and assume-breach design (limit blast radius). VPN provides a network perimeter but not zero trust."},
{id:417,domain:1,level:3,question:"What is 'security chaos engineering' and how does it differ from traditional penetration testing?",options:["A. Randomly attacking production systems without planning","B. Deliberately injecting security failures (remove firewall rules, expire certs, kill security agents) to test whether detection and response actually work","C. Using AI to generate random attack vectors","D. Pen testing performed by an external team unfamiliar with the organization"],correct:1,explanation:"Security chaos engineering tests whether security controls actually work under failure conditions — what happens when a security agent crashes, a WAF is misconfigured, or credentials expire? Unlike pen testing (finding vulnerabilities), it validates that detection and response mechanisms are resilient."},
// Domain 2
{id:418,domain:2,level:1,question:"What is 'data sovereignty' from a practical cloud configuration standpoint?",options:["A. Ensuring data is owned by the organization that creates it","B. Configuring cloud services to store and process data only in specified geographic regions using data residency controls","C. A legal right of countries to access data stored within their borders","D. The technical capability to migrate data between cloud providers"],correct:1,explanation:"Practically, data sovereignty means configuring cloud region restrictions, AWS SCPs denying use of non-approved regions, Azure Policies enforcing location, and verifying that every service used (including backups and replicas) keeps data within the required jurisdiction."},
{id:419,domain:2,level:1,question:"What is 'structured data' and how does it differ from 'unstructured data'?",options:["A. Structured data is organized; unstructured data is corrupted","B. Structured data follows a defined schema (databases, spreadsheets); unstructured data has no predefined format (emails, documents, images)","C. Structured data is encrypted; unstructured data is not","D. Structured data is stored on-premises; unstructured data is stored in cloud"],correct:1,explanation:"Structured data (SQL databases, CSV files) follows a fixed schema with defined fields. Unstructured data (emails, PDFs, videos, social media) has no predefined format. Semi-structured data (JSON, XML) has some structure but is flexible. Different data types require different security and DLP approaches."},
{id:420,domain:2,level:1,question:"What is 'data at rest encryption' and what does it protect against?",options:["A. Encrypting data during transmission to protect against interception","B. Encrypting stored data so that physical theft of storage media or unauthorized access to raw storage does not expose plaintext data","C. Encrypting data while it is being processed in memory","D. Encrypting backups to reduce their file size"],correct:1,explanation:"Data at rest encryption protects stored data if storage media is stolen, improperly decommissioned, or accessed by unauthorized parties (including cloud provider staff). It does not protect data from authorized application-layer access — access controls are needed for that."},
{id:421,domain:2,level:2,question:"A regulated organization must prove that customer data has been completely destroyed after contract termination. What is the BEST approach?",options:["A. Ask the cloud provider to confirm deletion verbally","B. Use crypto-shredding with customer-held keys, then obtain provider attestation of storage media sanitization per NIST 800-88 or equivalent standard","C. Delete the objects via the cloud console and take a screenshot","D. Wait 90 days for the provider's garbage collection to run"],correct:1,explanation:"Crypto-shredding destroys encryption keys, rendering data unreadable without physical media access. Provider attestation of media sanitization per NIST 800-88 (Clear, Purge, Destroy) provides verifiable evidence for auditors. Together they satisfy regulatory destruction requirements."},
{id:422,domain:2,level:2,question:"What is 'data masking' and in which environment is it most commonly applied?",options:["A. Hiding data access logs from unauthorized users","B. Replacing sensitive data with realistic but fake values — most commonly applied in non-production (dev/test) environments that need realistic data without real PII","C. Physically masking storage drives during decommissioning","D. Hiding sensitive columns in database reports"],correct:1,explanation:"Data masking creates structurally accurate but fictitious data for non-production use. Developers and testers need realistic data formats (valid SSN format, real-looking names) without exposing actual customer data. Masking prevents real PII from entering test environments."},
{id:423,domain:2,level:2,question:"What is 'data governance' in cloud environments?",options:["A. A government regulation governing how cloud data must be handled","B. A framework of policies, processes, roles, and standards ensuring data is accurate, secure, compliant, and available across its lifecycle","C. Technical controls preventing unauthorized data modification","D. The process of governing access to cloud storage buckets"],correct:1,explanation:"Data governance defines accountability for data quality, security, privacy, and compliance. It encompasses: data ownership roles, classification policies, retention schedules, access controls, lineage tracking, and compliance monitoring — ensuring data assets are managed consistently across cloud environments."},
{id:424,domain:2,level:3,question:"An organization stores genomic data in cloud. Why is this data considered permanently sensitive even when anonymized?",options:["A. Genomic data is too large to anonymize effectively","B. Genomic data is unique to individuals and can re-identify people across datasets — including future family members not yet born — making true anonymization practically impossible","C. Genomic data is classified as state secrets in most countries","D. Cloud providers prohibit storing genomic data"],correct:1,explanation:"Genomic data uniquely identifies individuals and is inherited, meaning it also identifies family members. As genomic databases grow, re-identification risk increases. Unlike other data, it cannot be changed if compromised, making it permanently sensitive. Special category under GDPR, requiring explicit consent and highest protection."},
{id:425,domain:2,level:3,question:"What is 'tokenization vault security' and why is it a critical control?",options:["A. Securing the physical vault where encryption hardware is stored","B. The tokenization vault stores the mappings between tokens and real values — compromise of the vault defeats tokenization entirely, requiring HSM-protected storage and strict access controls","C. A security control for cloud-based password managers","D. Protecting backup tapes in a physical vault"],correct:1,explanation:"The tokenization vault holds the token-to-real-value mapping. If the vault is compromised, all tokenized data is exposed — the tokens can be reversed. The vault must be protected with: HSM-backed encryption, strict access logging, network isolation, and multi-party authorization for access."},
// Domain 3
{id:426,domain:3,level:1,question:"What is 'network segmentation' in a cloud VPC?",options:["A. Dividing a cloud account budget into segments","B. Dividing the VPC into subnets with different security controls and access policies to limit lateral movement","C. Segmenting network traffic logs for easier analysis","D. Dividing cloud regions into smaller availability segments"],correct:1,explanation:"Network segmentation divides a VPC into subnets with different security controls — public subnets for internet-facing resources, private subnets for application tiers, and isolated subnets for databases. Security groups and NACLs control traffic between segments, limiting lateral movement."},
{id:427,domain:3,level:1,question:"What is a 'jump server' (bastion host) and what security requirement does it satisfy?",options:["A. A server that jumps between cloud providers for redundancy","B. A hardened, single-entry-point server through which administrators access private cloud resources — minimizing the attack surface by limiting direct exposure of private resources","C. A server that automatically jumps between availability zones during failures","D. A load balancer that routes traffic to the appropriate backend server"],correct:1,explanation:"A bastion host is a hardened server exposed to the internet only for administrative access (SSH/RDP). All other servers in private subnets are only accessible through the bastion. This minimizes internet-exposed attack surface and centralizes access logging for all administrative activity."},
{id:428,domain:3,level:1,question:"What is 'disk encryption' on a cloud virtual machine and what does it protect?",options:["A. Encrypting data before uploading to cloud storage","B. Encrypting the VM's root volume and data volumes so that raw disk snapshots or physical media access does not expose data","C. Encrypting all network traffic from the VM","D. A technique for speeding up disk access using encryption hardware"],correct:1,explanation:"VM disk encryption (AWS EBS encryption, Azure Disk Encryption) encrypts volumes at rest. If an attacker obtains raw disk snapshots or the physical drive is repurposed, the data remains encrypted. It does not protect against access through legitimate OS interfaces."},
{id:429,domain:3,level:2,question:"What is 'lateral movement' in a cloud breach and what controls prevent it?",options:["A. Cloud workloads moving between availability zones","B. An attacker pivoting from a compromised resource to other resources in the same environment — prevented by micro-segmentation, least-privilege IAM, and network policies","C. Horizontal scaling of application instances","D. Moving cloud resources between cloud provider accounts"],correct:1,explanation:"After compromising one resource, attackers use it to access others (lateral movement). Prevention: micro-segment networks (no default allow between workloads), apply least-privilege IAM to service accounts, monitor east-west traffic, and isolate workloads in separate accounts."},
{id:430,domain:3,level:2,question:"What is a 'cloud security assessment' and what does it evaluate?",options:["A. An assessment of a cloud provider's data center physical security","B. A systematic review of cloud environment configurations, IAM, network controls, logging, and compliance posture against security benchmarks","C. A financial assessment of cloud security spending","D. An evaluation of cloud security training materials"],correct:1,explanation:"A cloud security assessment reviews: IAM configuration, network architecture (open ports, unrestricted security groups), storage security (public buckets), encryption status, logging completeness, compliance with benchmarks (CIS, AWS Foundations), and incident response readiness."},
{id:431,domain:3,level:2,question:"What is 'privileged access management' (PAM) in cloud environments?",options:["A. Managing permissions for the most expensive cloud services","B. Controlling, monitoring, and auditing access by privileged accounts (cloud administrators, root accounts) using just-in-time access and session recording","C. A tool for managing administrator password complexity","D. Granting all developers temporary privileged access during deployments"],correct:1,explanation:"PAM for cloud administrators: uses just-in-time (JIT) privilege elevation (no standing admin rights), requires approval workflows for sensitive access, records privileged sessions, enforces MFA, and limits root account use to break-glass scenarios only."},
{id:432,domain:3,level:3,question:"What is 'supply chain integrity verification' for cloud infrastructure components?",options:["A. Auditing vendor contracts for cloud hardware procurement","B. Using cryptographic attestation to verify that firmware, software, and hardware components have not been tampered with before deployment in the cloud trusted computing base","C. Checking that cloud provider supply chains comply with environmental standards","D. Verifying that hardware delivery schedules are met"],correct:1,explanation:"Supply chain integrity uses Secure Boot (firmware signature verification), TPM attestation (hardware state verification), and software signing to ensure components are authentic and unmodified. This protects against hardware implants, firmware backdoors, and compromised installation packages."},
// Domain 4
{id:433,domain:4,level:1,question:"What is 'secure coding' and which practices does it include?",options:["A. Writing code that compiles without errors","B. Developing software following practices that prevent common vulnerabilities: input validation, parameterized queries, output encoding, least privilege, error handling, and avoiding hardcoded secrets","C. Using a code signing certificate for all software releases","D. Writing code that passes all security scans without modification"],correct:1,explanation:"Secure coding practices prevent vulnerabilities during development: validate/sanitize all inputs, use parameterized queries (prevent SQLi), encode outputs (prevent XSS), handle errors without leaking info, use cryptographic libraries correctly, and never hardcode credentials."},
{id:434,domain:4,level:1,question:"What is 'error handling' as a security concern in cloud applications?",options:["A. Routing application errors to the correct team for remediation","B. Ensuring errors are handled gracefully without revealing sensitive system information (stack traces, database queries, file paths) to users","C. A performance concern ensuring errors don't slow down applications","D. Documenting errors for developer debugging purposes"],correct:1,explanation:"Insecure error handling exposes system internals: stack traces reveal technology stack, database errors reveal query structure, file path errors reveal server configuration. Attackers use this information for reconnaissance. Errors should be generic to users but detailed in secure internal logs."},
{id:435,domain:4,level:1,question:"What is 'open redirect' vulnerability?",options:["A. An open-source redirect library with security vulnerabilities","B. A vulnerability where an application accepts an attacker-controlled URL parameter and redirects users to it — used in phishing to abuse trusted domain reputation","C. A misconfigured HTTP redirect causing performance issues","D. A vulnerability in DNS redirect configuration"],correct:1,explanation:"Open redirect allows attackers to craft URLs on a trusted domain (e.g., bank.com/redirect?to=evil.com) that redirect users to malicious sites. Users trust the URL domain and click it, then land on a phishing site. Prevention: validate redirect destinations against an allowlist of trusted URLs."},
{id:436,domain:4,level:2,question:"What is 'DAST' (Dynamic Application Security Testing) and when should it run?",options:["A. Testing application performance under dynamic load conditions","B. Black-box testing of a running application by sending inputs and analyzing responses — run in staging/pre-production environments and as part of CI/CD pipelines","C. Static analysis of compiled application binaries","D. A database security testing methodology"],correct:1,explanation:"DAST tests applications from the outside like an attacker would, sending malformed inputs and analyzing responses for vulnerabilities (SQLi, XSS, SSRF). It doesn't require source code access but needs a running application. Run in staging to avoid disrupting production."},
{id:437,domain:4,level:2,question:"What is 'IAST' (Interactive Application Security Testing)?",options:["A. Interviewing developers about security practices","B. Security testing that instruments running application code to monitor behavior from within during normal testing, combining SAST and DAST benefits","C. Interactive security awareness training for developers","D. A testing methodology requiring human tester interaction at each step"],correct:1,explanation:"IAST instruments application code (via agents) and monitors security-relevant operations during normal functional testing. It identifies vulnerabilities with precise code-location details (like SAST) while testing the running app (like DAST), with fewer false positives than either alone."},
{id:438,domain:4,level:2,question:"What is a 'bug bounty program' and what is its security benefit?",options:["A. A program rewarding developers for finding bugs in their own code","B. A program inviting external security researchers to find and report vulnerabilities, typically with monetary rewards — expanding vulnerability discovery beyond internal teams","C. An insurance program covering software defects","D. A competitive programming contest focused on security"],correct:1,explanation:"Bug bounty programs (HackerOne, Bugcrowd) crowdsource vulnerability discovery from a global pool of security researchers. They find real-world vulnerabilities that internal teams and automated tools miss, typically far more cost-effectively than equivalent internal testing."},
{id:439,domain:4,level:3,question:"What is 'deserialization of untrusted data' (OWASP) and what makes it dangerous?",options:["A. Parsing untrusted JSON input — dangerous because JSON is complex","B. Deserializing attacker-controlled objects that can manipulate application logic, achieve RCE, or bypass authentication — dangerous because deserialization often executes code during the process","C. Reading untrusted certificate data causing TLS failures","D. Parsing untrusted XML with external entity references"],correct:1,explanation:"Many deserialization libraries execute code during object reconstruction (magic methods, constructors). Attackers craft malicious serialized objects containing gadget chains that execute arbitrary code when deserialized. Prevention: avoid deserializing untrusted data; use safe formats (JSON); validate integrity with HMAC before deserializing."},
{id:440,domain:4,level:3,question:"What is 'SSRF to cloud metadata' and why is it a critical finding?",options:["A. A misconfiguration exposing metadata endpoint to the internet","B. Exploiting SSRF to reach the cloud instance metadata service, extracting temporary IAM credentials that grant attacker access to cloud resources","C. A network misconfiguration causing routing loops","D. An accidental exposure of server metadata in HTTP response headers"],correct:1,explanation:"SSRF to the metadata endpoint (169.254.169.254 in AWS, similar in Azure/GCP) extracts temporary IAM credentials attached to the instance. These credentials have real cloud access — the attacker can access S3, call APIs, and pivot to other cloud resources. IMDSv2 (requiring a session token) is the primary mitigation."},
// Domain 5
{id:441,domain:5,level:1,question:"What is 'log retention' and why does it matter for security?",options:["A. Retaining log files to save storage costs","B. Keeping security logs for a defined period so they are available for incident investigations and compliance audits — many regulations specify minimum retention periods","C. Compressing logs to retain more data in less space","D. Retaining only error logs and discarding informational logs"],correct:1,explanation:"Log retention ensures historical records are available for forensic investigation (breaches discovered months later) and compliance (regulators may require 1-7 years of logs). Logs must be retained in tamper-evident storage — a forensic investigation with missing logs is severely hampered."},
{id:442,domain:5,level:1,question:"What is 'configuration management' in cloud security operations?",options:["A. Managing application configuration files in source control","B. Tracking, controlling, and auditing changes to cloud resource configurations to ensure they remain in a known, secure state","C. Managing cloud provider account configurations and billing settings","D. A tool for managing software licenses and versions"],correct:1,explanation:"Configuration management (AWS Config, Azure Policy, Chef/Puppet) maintains a record of resource configurations over time, detects deviations from approved baselines, enforces compliance, and provides a configuration history essential for incident investigation."},
{id:443,domain:5,level:1,question:"What is 'identity lifecycle management' in cloud operations?",options:["A. Managing the lifecycle of SSL certificates","B. Processes for creating, modifying, and revoking user and service accounts throughout their lifecycle — ensuring prompt deprovisioning prevents orphaned accounts","C. Managing the lifecycle of cloud provider subscriptions","D. A framework for managing identity verification documents"],correct:1,explanation:"Identity lifecycle management ensures accounts are provisioned with correct permissions when needed and deprovisioned promptly when access is no longer required (employee departure, role change). Orphaned accounts with valid credentials are prime targets for attackers."},
{id:444,domain:5,level:2,question:"What is a 'security operations dashboard' and what key metrics should it display?",options:["A. A decorative display showing cloud infrastructure topology","B. A real-time view of security posture showing: open critical vulnerabilities, MTTD/MTTR trends, active incidents, compliance status, and anomaly detection alerts","C. A management dashboard showing security team headcount and budget","D. A customer-facing dashboard showing cloud uptime and performance"],correct:1,explanation:"A security operations dashboard provides situational awareness: open critical vulnerabilities by age, active incidents and status, detection/response time trends, top alert sources, compliance posture, and threat intelligence indicators — enabling data-driven prioritization of security resources."},
{id:445,domain:5,level:2,question:"What is 'just-in-time (JIT) access' and how does it improve cloud security?",options:["A. Granting access immediately when a developer requests it, without approval","B. Providing elevated access only when needed, for the minimum duration required, with automatic expiration — eliminating standing privileged access","C. A scheduling system for cloud maintenance windows","D. An access control system that approves requests just before they time out"],correct:1,explanation:"JIT access eliminates persistent privileged accounts. When a developer needs admin access, they request it, it is approved (or automatically granted based on policy), granted for a limited time (e.g., 4 hours), then automatically revoked. No standing access means stolen credentials have no persistent privilege."},
{id:446,domain:5,level:2,question:"What is 'security awareness training' and why is it considered a technical control?",options:["A. It is not a technical control — purely administrative","B. Training that changes human behavior (the most exploited attack vector) is a direct control reducing phishing susceptibility, social engineering success, and insider mistakes","C. A tool for training developers to write secure code only","D. A compliance requirement with no measurable security impact"],correct:1,explanation:"Security awareness training reduces the human attack surface: phishing simulation programs reduce click rates by 60-80%. Trained employees recognize social engineering, report incidents faster, and avoid common mistakes (weak passwords, misdelivered emails). While not technical in implementation, its impact is measurable and security-significant."},
{id:447,domain:5,level:3,question:"What is 'detection engineering' and how does it differ from writing SIEM rules?",options:["A. Engineering new security detection hardware","B. A disciplined practice of developing, testing, validating, and maintaining detection logic as code — including false positive measurement, coverage mapping to MITRE ATT&CK, and lifecycle management","C. Writing ad-hoc SIEM queries when incidents occur","D. Configuring cloud provider native alerting with default thresholds"],correct:1,explanation:"Detection engineering treats detections as code: develop in version control, test against known-good and known-bad datasets, validate against MITRE ATT&CK coverage, measure false positive rates, and maintain over time as attacker TTPs evolve. It's systematic rather than reactive rule-writing."},
{id:448,domain:5,level:3,question:"What is 'cloud-native threat detection' and what are its advantages over agent-based approaches?",options:["A. Threat detection built into cloud provider hardware","B. Analyzing cloud-native telemetry (API logs, flow logs, DNS) without installing agents — advantages: no agent maintenance, coverage of serverless/managed services, provider-level visibility","C. Using cloud VMs to host threat detection tools","D. Threat detection that only works with cloud-native applications"],correct:1,explanation:"Cloud-native detection (AWS GuardDuty, Azure Sentinel, GCP SCC) analyzes CloudTrail, VPC Flow Logs, DNS logs, and service-specific logs without agents. This covers serverless functions and managed services where agents cannot be installed, and provides provider-level API visibility impossible with host agents."},
// Domain 6
{id:449,domain:6,level:1,question:"What is 'informed consent' in data privacy law?",options:["A. Consent given by an IT administrator on behalf of users","B. A data subject's freely given, specific, informed, and unambiguous agreement to processing of their personal data","C. Agreement to cloud provider terms of service during account signup","D. Consent required only for sensitive medical data processing"],correct:1,explanation:"Valid consent under GDPR must be: freely given (not coerced), specific (each purpose separately), informed (clear explanation of processing), and unambiguous (clear affirmative action). Pre-ticked boxes and bundled consent for unrelated purposes are invalid under GDPR."},
{id:450,domain:6,level:1,question:"What is 'data portability' right under GDPR and how does it affect cloud applications?",options:["A. The right of organizations to move data between cloud providers","B. An individual's right to receive their personal data in a machine-readable format (JSON, CSV) and transfer it to another service — cloud applications must support data export","C. A right that only applies to financial data","D. The technical ability to migrate data without format conversion"],correct:1,explanation:"GDPR Article 20 grants individuals the right to receive their data in a portable, machine-readable format for transfer to another controller when processing is based on consent or contract. Cloud applications must build export functionality to support this right."},
{id:451,domain:6,level:2,question:"What is 'privacy by default' under GDPR Article 25?",options:["A. Privacy controls are optional by default in cloud applications","B. By default, only data necessary for the specific purpose is processed — the most privacy-protective setting must be the default, requiring explicit user action to share more data","C. Default privacy settings are set by cloud providers, not developers","D. Privacy preferences default to those of the last logged-in user"],correct:1,explanation:"Privacy by default (Article 25(2)) means applications must default to the most privacy-protective configuration. Social networks default to public profiles = violation. Applications should default to minimal data sharing, with users explicitly opting into broader sharing rather than opting out."},
{id:452,domain:6,level:2,question:"What is a 'supervisory authority' under GDPR and what powers does it have?",options:["A. A company's internal data protection compliance team","B. An independent national authority enforcing GDPR — powers include investigations, audits, warnings, reprimands, and fines up to €20M or 4% of global turnover","C. A cloud provider's compliance monitoring department","D. An EU committee that reviews GDPR adequacy decisions"],correct:1,explanation:"Each EU member state has a Supervisory Authority (e.g., ICO in UK, CNIL in France, BfDI in Germany) that enforces GDPR within its jurisdiction. Powers include: investigations, mandatory compliance orders, temporary data processing bans, and significant financial penalties."},
{id:453,domain:6,level:3,question:"What is 'cross-border data transfer' risk under GDPR when using a US cloud provider?",options:["A. Physical risk of data loss during transmission","B. Transfer to the US is a transfer to a third country — requires an adequacy mechanism (EU-US DPF, SCCs) and risk assessment considering US surveillance laws (FISA Section 702)","C. US cloud providers are automatically GDPR compliant","D. Cross-border transfers are permitted without restriction when data is encrypted"],correct:1,explanation:"Transferring EU personal data to US cloud providers requires a valid transfer mechanism. The EU-US Data Privacy Framework (2023) restored adequacy for certified US companies. However, Schrems II (2020) established that transfer mechanisms must include a risk assessment considering actual access by US intelligence agencies under FISA 702/EO 12333."},
{id:454,domain:6,level:3,question:"What is 'regulatory stacking' and how should organizations address it?",options:["A. Organizing compliance requirements in a stack for easier management","B. When multiple regulations apply simultaneously — address by mapping all applicable regulations, identifying overlaps and conflicts, then building a unified control framework satisfying all","C. A method of prioritizing regulations by their penalty severity","D. The practice of using one compliance framework to satisfy all regulations"],correct:1,explanation:"Regulatory stacking occurs when organizations face multiple overlapping regulations (GDPR + HIPAA + PCI DSS + CCPA + NIS2). Solution: compliance mapping (unified control matrix showing which control satisfies which requirement across all frameworks) to avoid duplicating effort and identify gaps."},
{id:455,domain:6,level:1,question:"What is 'intellectual property' (IP) protection concern in cloud environments?",options:["A. Protecting cloud providers' intellectual property from customer misuse","B. Ensuring proprietary algorithms, source code, and trade secrets are protected from unauthorized access, especially when stored in shared cloud infrastructure","C. Copyright registration for cloud applications","D. Preventing competitors from reverse-engineering cloud-hosted applications"],correct:1,explanation:"Cloud storage of source code, algorithms, and business logic creates IP risk: multi-tenant environments, provider employee access, and insecure configurations could expose proprietary assets. Controls include encryption, access logging, code repository access controls, and careful review of provider terms."},
{id:456,domain:6,level:2,question:"What is 'continuous compliance monitoring' and how does cloud technology enable it?",options:["A. Hiring additional compliance staff to monitor continuously","B. Using automated tools (AWS Config Rules, Azure Policy, CSPM) to continuously evaluate cloud configurations against compliance requirements and alert on violations in real time","C. Running compliance scans weekly instead of annually","D. Engaging auditors to continuously audit cloud environments"],correct:1,explanation:"Cloud APIs enable continuous compliance monitoring: AWS Config evaluates resource configurations against rules continuously, triggering alerts or auto-remediation when violations occur. This replaces point-in-time annual audits with ongoing assurance — catching misconfigurations within minutes rather than months."},
{id:457,domain:6,level:3,question:"What is 'cloud forensics' legal admissibility challenge?",options:["A. Cloud logs are always inadmissible in legal proceedings","B. Evidence from cloud must maintain chain of custody, demonstrate integrity (hash verification), and overcome challenges around log authenticity, multi-jurisdiction issues, and provider cooperation","C. Cloud providers are legally protected from forensic investigations","D. Digital evidence is never admissible in court without physical media"],correct:1,explanation:"Cloud forensic evidence admissibility requires: documented chain of custody, cryptographic integrity verification (hash values), authentication testimony (proving logs are unaltered), overcoming hearsay objections (business records exception), and potentially letters rogatory for cross-border evidence collection."},
// Domain 1 continued
{id:458,domain:1,level:1,question:"What is 'Infrastructure as a Service' (IaaS) and who manages what?",options:["A. The provider manages everything; customer provides only data","B. Provider manages physical infrastructure, hypervisor, and networking; customer manages OS, middleware, applications, and data","C. Customer manages everything including physical servers","D. Provider and customer share management of all layers equally"],correct:1,explanation:"IaaS provides virtualized computing resources. Provider manages: physical servers, data center, networking, hypervisor. Customer manages: OS, patching, middleware, runtime, applications, and data. This gives the most customer control of the three main service models."},
{id:459,domain:1,level:1,question:"What does 'high availability' mean in cloud architecture?",options:["A. Having the fastest possible cloud instances","B. Designing systems to minimize downtime by eliminating single points of failure through redundancy, failover, and geographic distribution","C. Maximizing the number of cloud instances running","D. Ensuring cloud services are available in the most countries"],correct:1,explanation:"High availability (HA) means designing for maximum uptime through redundancy: multiple AZs, load balancing, auto-scaling, health checks, and automatic failover. HA removes single points of failure so individual component failures don't cause service outages."},
{id:460,domain:1,level:2,question:"What is 'service mesh' security and why is mTLS important in microservices?",options:["A. A physical mesh network providing wireless connectivity to cloud services","B. Service mesh (Istio, Linkerd) provides mutual TLS between all microservices — mTLS ensures both parties authenticate each other, preventing impersonation attacks between services","C. A tool for monitoring network traffic between cloud regions","D. An application framework for building secure microservices"],correct:1,explanation:"In microservices, many services communicate internally. mTLS (mutual TLS) means both the client service and server service present certificates, authenticating each other — preventing a compromised service from impersonating legitimate ones. Service meshes implement this transparently without code changes."},
{id:461,domain:1,level:3,question:"What is 'blast radius reduction' in cloud account architecture?",options:["A. Physically shielding cloud data centers from explosions","B. Organizing workloads into separate cloud accounts by environment/risk level so a compromise of one account cannot cascade to others","C. Reducing the number of cloud regions to limit geographic risk","D. Limiting the number of cloud services to reduce complexity"],correct:1,explanation:"Cloud account separation (production account, development account, security account, logging account) limits blast radius: credentials or policies compromised in one account have no effect in others. AWS Organizations + SCPs enforce guardrails across all accounts while maintaining isolation."},
// Domain 2 continued
{id:462,domain:2,level:1,question:"What is 'AES-256' and why is it the standard for cloud data encryption?",options:["A. A 256-bit hash algorithm used for data integrity verification","B. Advanced Encryption Standard with 256-bit key — NIST-approved symmetric cipher considered secure against brute force for the foreseeable future, including quantum computing concerns","C. An asymmetric encryption algorithm with 256-bit security","D. A cloud provider's proprietary encryption standard"],correct:1,explanation:"AES-256 is the NIST-standardized symmetric block cipher using 256-bit keys. It is computationally infeasible to brute-force (2^256 possible keys), hardware-accelerated on modern CPUs (AES-NI instructions), FIPS 140-2 approved, and widely supported by cloud KMS services."},
{id:463,domain:2,level:2,question:"What is 'key escrow' and when is it required?",options:["A. Storing backup copies of encryption keys with a third party for recovery purposes or regulatory access requirements","B. A process for generating new encryption keys when old ones expire","C. An escrow account holding funds for cloud service payments","D. Temporarily holding encryption keys during key rotation"],correct:1,explanation:"Key escrow provides recovery access to encrypted data by depositing key copies with a trusted third party. Required in some jurisdictions for law enforcement access; used in enterprise settings for business continuity (recovering data if key holder is unavailable). It is controversial because it creates additional key exposure."},
{id:464,domain:2,level:3,question:"What is 'cryptographic agility' and why is it important for long-lived cloud systems?",options:["A. Using many different encryption algorithms simultaneously","B. Designing systems to easily swap cryptographic algorithms when current ones become weak — essential as quantum computing threatens current asymmetric algorithms","C. Rapidly generating new cryptographic keys","D. An agile development methodology applied to cryptographic systems"],correct:1,explanation:"Cryptographic agility allows systems to replace algorithms without redesign — critical as: quantum computers will break RSA/ECC (requiring migration to post-quantum algorithms), new weaknesses are discovered in algorithms (SHA-1, MD5 were deprecated), or compliance requirements change minimum key lengths."},
// Domain 3 continued
{id:465,domain:3,level:1,question:"What is 'object storage security' in cloud environments?",options:["A. Physical security of storage hardware in cloud data centers","B. Access controls, encryption, versioning, and public access blocking for cloud object storage services like S3, Azure Blob, or GCS","C. Security controls for database objects (tables, views)","D. Security for storing physical objects in smart warehouses"],correct:1,explanation:"Object storage security includes: blocking all public access (default), bucket policies restricting access to authorized principals, encryption at rest (SSE), versioning and MFA delete for ransomware protection, access logging, and cross-account access controls."},
{id:466,domain:3,level:2,question:"What is 'image vulnerability scanning' in a container workflow?",options:["A. Scanning container images for visual defects","B. Automated analysis of container images for known CVEs in OS packages, application libraries, and configuration issues — integrated into CI/CD to block vulnerable images","C. Network scanning of running containers","D. Compliance scanning of container orchestration platforms"],correct:1,explanation:"Container image scanning (Trivy, Clair, Anchore) checks base images and all installed packages/libraries against CVE databases. Integrated into CI/CD pipelines, it can block images with critical vulnerabilities before they reach registries or production clusters."},
{id:467,domain:3,level:3,question:"What is 'eBPF-based security' in cloud-native environments?",options:["A. A type of firewall built on Ethernet Bridge Protocol","B. Using extended Berkeley Packet Filter to run security logic in the Linux kernel — enabling efficient, high-performance network filtering, syscall monitoring, and runtime threat detection without kernel modifications","C. A cloud provider's proprietary security technology","D. An encryption protocol for cloud storage"],correct:1,explanation:"eBPF runs sandboxed programs in the kernel for security monitoring (tracing syscalls, network packets, file access) with minimal overhead. Tools like Falco, Cilium, and Tetragon use eBPF for container runtime security, network policy enforcement, and threat detection at kernel level."},
// Domain 4 continued
{id:468,domain:4,level:1,question:"What is 'principle of least privilege' in application design?",options:["A. Applications should use the fewest features possible","B. Applications and users are granted only the minimum permissions needed to perform required functions — limiting damage if credentials are compromised","C. Applications should use minimal code to reduce complexity","D. Least privilege only applies to database access, not application design"],correct:1,explanation:"Least privilege in applications: database accounts with SELECT-only for read operations; API keys scoped to specific endpoints; service accounts restricted to required cloud resources; functions with minimal IAM permissions. Minimizing access reduces the blast radius of any compromise."},
{id:469,domain:4,level:2,question:"What is 'API security testing' and what OWASP resource addresses it?",options:["A. Testing API response times under load","B. Identifying security vulnerabilities in APIs including authentication flaws, BOLA, excessive data exposure, and injection — the OWASP API Security Top 10 is the primary reference","C. Testing that APIs conform to their OpenAPI specification","D. Verifying API availability and uptime"],correct:1,explanation:"API security testing specifically targets API vulnerabilities per the OWASP API Security Top 10: BOLA/IDOR, broken authentication, excessive data exposure, lack of resources/rate limiting, BFLA, mass assignment, security misconfiguration, injection, improper asset management, and insufficient logging."},
{id:470,domain:4,level:3,question:"What is 'threat modeling' using the PASTA methodology?",options:["A. A pasta-themed security framework for Italian cloud providers","B. Process for Attack Simulation and Threat Analysis — a 7-stage risk-centric methodology aligning threat analysis with business objectives and producing actionable mitigation requirements","C. A simplified threat modeling approach for small teams","D. A threat modeling tool that analyzes attack patterns automatically"],correct:1,explanation:"PASTA (Process for Attack Simulation and Threat Analysis) stages: define objectives → define technical scope → application decomposition → threat analysis → vulnerability detection → attack enumeration → risk/impact analysis. Unlike STRIDE (attacker-centric), PASTA aligns threats with business risk."},
// Domain 5 continued
{id:471,domain:5,level:1,question:"What is 'forensic imaging' in cloud incident response?",options:["A. Taking screenshots of the cloud management console during an incident","B. Creating a bit-for-bit copy (snapshot) of a compromised system's storage for forensic analysis without altering the original","C. Photographing physical cloud infrastructure during an investigation","D. Creating backup images of all cloud resources for recovery purposes"],correct:1,explanation:"Forensic imaging captures an exact replica of storage media (VM snapshots) preserving all data including deleted files and slack space for analysis. The original instance is preserved unchanged while the copy is mounted in an isolated forensic environment for investigation."},
{id:472,domain:5,level:2,question:"What is 'false negative' in security monitoring and why is it more dangerous than a false positive?",options:["A. They are equally dangerous","B. A false negative is a real attack that the detection system misses — more dangerous because the attacker succeeds undetected; a false positive is a harmless alert that wastes analyst time","C. A false negative is a detected attack that turns out to be harmless","D. False negatives only occur in vulnerability scanning, not threat detection"],correct:1,explanation:"False negatives (missed attacks) are more dangerous than false positives (unnecessary alerts). A missed attack allows a real breach to proceed undetected. False positives cause alert fatigue but don't directly result in compromise. Both must be minimized, but false negatives represent actual security failures."},
{id:473,domain:5,level:3,question:"What is 'adversarial simulation' (red team) in cloud environments and what makes cloud red teams different?",options:["A. A simulation where the red team pretends to be cloud administrators","B. Realistic attack simulation using cloud-specific TTPs — lateral movement via IAM role chaining, S3 exfiltration, Lambda privilege escalation, and cloud API abuse rather than traditional network exploitation","C. A vendor assessment of cloud provider security","D. A simulation using only publicly known exploit code"],correct:1,explanation:"Cloud red teams must master cloud-specific attack techniques: abusing overly permissive IAM roles, lateral movement through AssumeRole chaining, data exfiltration via S3 sync, serverless abuse, resource-based policy exploitation, and evading cloud-native detection. Traditional penetration testing techniques must be supplemented with cloud-specific TTPs."},
// Domain 6 continued
{id:474,domain:6,level:1,question:"What is 'whistleblower protection' relevance to cloud security programs?",options:["A. Cloud providers must protect data of corporate whistleblowers","B. Cloud security programs should include secure reporting channels for employees to report security concerns without fear of retaliation — legally protected in many jurisdictions","C. A legal requirement for cloud providers to report customer wrongdoing","D. Protection for security researchers who report vulnerabilities"],correct:1,explanation:"Many jurisdictions (EU Whistleblower Directive, US SOX, Dodd-Frank) legally protect employees who report security or compliance violations. Cloud security programs should implement anonymous, secure reporting channels (secure drop boxes) and clearly communicate non-retaliation policies."},
{id:475,domain:6,level:2,question:"What is 'forensic evidence preservation' obligation in cloud environments under legal proceedings?",options:["A. An obligation to destroy all digital evidence before legal proceedings","B. A legal hold obligation requiring organizations to suspend normal deletion/retention policies and preserve all relevant data immediately upon notice of potential litigation","C. An obligation to share all cloud logs with opposing counsel","D. A requirement to maintain forensic copies of all cloud data at all times"],correct:1,explanation:"Upon notice of potential litigation (litigation hold trigger), organizations must immediately suspend normal deletion schedules and preserve all potentially relevant ESI — including cloud logs, emails, databases, and snapshots. Failure to preserve (spoliation) can result in severe sanctions including adverse inference instructions."},
{id:476,domain:6,level:3,question:"What is 'AI governance' in cloud security and compliance contexts?",options:["A. Government oversight of cloud AI research","B. Frameworks for responsible AI use covering transparency, accountability, bias monitoring, data quality, model security, and compliance — increasingly required by regulations like the EU AI Act","C. Cloud provider policies for AI service availability","D. Security controls preventing unauthorized access to AI models"],correct:1,explanation:"AI governance addresses: data quality and bias in training, model explainability (decisions must be understood/challenged), adversarial robustness (model security), privacy compliance in training data, regulatory compliance (EU AI Act risk categories), audit trails for AI decisions, and human oversight requirements."},

// ─── DOMAIN 6 – Batch 2 ──────────────────────────────────────────────────────
{id:391,domain:6,level:1,question:"What is a 'risk appetite' statement?",options:["A. A statement of how hungry the organization is for new technology","B. A formal expression of the amount and type of risk an organization is willing to accept in pursuit of its objectives","C. A security budget allocation document","D. A list of risks the organization has decided to eliminate"],correct:1,explanation:"Risk appetite defines how much risk an organization is willing to tolerate. It guides risk treatment decisions — risks within appetite may be accepted; risks exceeding appetite must be mitigated, transferred, or avoided. It is set by the board and informs security investment decisions."},
{id:392,domain:6,level:1,question:"What is the difference between a 'risk' and a 'threat'?",options:["A. They are interchangeable terms in information security","B. A threat is a potential event that can cause harm; risk is the likelihood and impact of that threat exploiting a vulnerability","C. A threat is technical; a risk is financial","D. A risk is external; a threat is internal"],correct:1,explanation:"A threat is anything that can cause harm (hacker, natural disaster, insider). A vulnerability is a weakness. Risk is the probability that a threat will exploit a vulnerability and the resulting impact. Risk = Threat × Vulnerability × Impact."},
{id:393,domain:6,level:1,question:"What is 'risk transfer' as a risk treatment option?",options:["A. Moving risk from one department to another internally","B. Shifting the financial consequences of risk to a third party through insurance or contractual liability clauses","C. Transferring data to a less risky cloud environment","D. Moving risky applications from cloud to on-premises"],correct:1,explanation:"Risk transfer shifts the financial impact of a risk to another party — cyber insurance transfers financial loss; SLA penalty clauses transfer remediation costs to the provider. Risk transfer does not eliminate the underlying risk but reduces the organization's financial exposure."},
{id:394,domain:6,level:1,question:"What is a 'compliance framework' in the context of cloud security?",options:["A. A software framework for automating compliance checks","B. A structured set of standards, guidelines, and controls organizations use to demonstrate adherence to regulatory or industry requirements","C. A legal framework governing cloud provider compliance","D. A project management framework for compliance projects"],correct:1,explanation:"Compliance frameworks (ISO 27001, SOC 2, PCI DSS, HIPAA, FedRAMP) define the security controls organizations must implement and evidence they must provide to demonstrate compliance to regulators, auditors, and customers."},
{id:395,domain:6,level:1,question:"What is the purpose of a security audit?",options:["A. To find and punish employees who violate security policies","B. An independent examination of security controls and practices to verify they are implemented correctly and operating effectively","C. A financial audit focused on security budget expenditure","D. A technical scan for system vulnerabilities"],correct:1,explanation:"A security audit independently examines and verifies security controls — examining configurations, reviewing policies, interviewing staff, and testing controls — to provide objective assurance that stated security requirements are actually met."},
{id:396,domain:6,level:1,question:"What is 'non-repudiation' and how is it achieved in cloud systems?",options:["A. A legal term for denying responsibility for a breach","B. A security property ensuring that a party cannot deny taking an action — achieved through digital signatures, audit logs, and timestamping","C. A data integrity control preventing data modification","D. A contract clause preventing providers from repudiating SLA obligations"],correct:1,explanation:"Non-repudiation prevents denial of an action. Digital signatures prove the signer sent a message; immutable audit logs (CloudTrail with log file validation) prove actions were taken. In legal proceedings, non-repudiation evidence makes it impossible to credibly deny an action."},
{id:397,domain:6,level:1,question:"What is the 'right to erasure' under GDPR and what limitations apply?",options:["A. An absolute right to have all personal data deleted at any time for any reason","B. The right to request deletion of personal data under specific conditions — subject to limitations such as legal obligations, public interest, and freedom of expression","C. A right that only applies to EU citizens living within the EU","D. A right to physically destroy the storage media containing personal data"],correct:1,explanation:"GDPR Article 17 grants the right to erasure ('right to be forgotten') when: data is no longer necessary, consent is withdrawn, or erasure is required by law. It does not apply when the organization has legal obligations to retain data, legitimate interests that override privacy, or public health/research justifications."},
{id:398,domain:6,level:1,question:"What is a 'data processing impact assessment' (DPIA) under GDPR?",options:["A. A financial impact assessment of data breach costs","B. A systematic analysis of processing activities likely to result in high risk to individuals' rights and freedoms — required before high-risk processing begins","C. An environmental impact assessment for cloud data centers","D. An assessment of data quality before migration"],correct:1,explanation:"DPIA (GDPR Article 35) is required when processing is likely to result in high risk — systematic profiling, processing special category data at scale, systematic monitoring of public areas. It identifies and minimizes privacy risks before processing begins."},
{id:399,domain:6,level:2,question:"What is 'SOC 2 Type I' vs 'SOC 2 Type II' and which provides stronger assurance?",options:["A. Type I covers availability; Type II covers security — they are equal","B. Type I verifies controls are suitably designed at a point in time; Type II verifies they operated effectively over a period (6-12 months) — Type II provides stronger assurance","C. Type I is for cloud providers; Type II is for SaaS applications","D. They are equivalent reports with different audience focuses"],correct:1,explanation:"SOC 2 Type I is a point-in-time assessment verifying control design. SOC 2 Type II tests whether those controls actually operated effectively over a sustained period (typically 6-12 months). Type II provides much stronger assurance of operational security maturity."},
{id:400,domain:6,level:2,question:"What is 'vendor due diligence' in cloud security and what should it assess?",options:["A. Checking a vendor's financial stability before signing a contract","B. Systematic assessment of a cloud provider's security controls, compliance certifications, incident history, and contractual terms before engagement","C. A legal review of vendor contracts by the legal team","D. Verifying the vendor's marketing claims about security features"],correct:1,explanation:"Vendor due diligence for cloud security assesses: certifications (SOC 2, ISO 27001, FedRAMP), penetration test results, data handling practices, breach history, subprocessor list, data residency, exit procedures, and SLA/liability terms — before trusting them with organizational data."},
{id:401,domain:6,level:2,question:"What is the 'shared responsibility model' from a legal/contractual perspective?",options:["A. A government regulation requiring cloud providers and customers to share liability equally","B. A contractual and operational framework defining which security obligations belong to the provider vs. the customer — regulators hold customers accountable regardless","C. A legal standard where providers bear full liability for all cloud breaches","D. An agreement between two cloud providers sharing security responsibilities"],correct:1,explanation:"The shared responsibility model is primarily operational, not legal. Regulators (GDPR, HIPAA enforcement) hold customers (data controllers) accountable for compliance. Customers cannot contractually transfer their regulatory obligations to providers — they retain accountability."},
{id:402,domain:6,level:2,question:"What is 'ISO 27001 certification' and what does it demonstrate?",options:["A. Certification that an organization has passed a government security audit","B. Third-party verified implementation of an Information Security Management System meeting ISO 27001 requirements — demonstrating systematic, ongoing security management","C. Certification of individual cloud security professionals","D. Compliance with a specific set of technical security controls"],correct:1,explanation:"ISO 27001 certification means an accredited third-party auditor has verified that an organization has implemented a compliant ISMS. Unlike compliance standards listing specific controls, ISO 27001 certifies the management system — processes for identifying, treating, and monitoring risks."},
{id:403,domain:6,level:2,question:"What is 'data sovereignty' vs 'data residency'?",options:["A. They are identical terms used in different countries","B. Data residency is where data is physically stored; data sovereignty is which country's laws govern the data — they can differ when a US company stores EU data in Germany","C. Data sovereignty applies to governments; data residency applies to private companies","D. Data residency is a legal concept; data sovereignty is a technical concept"],correct:1,explanation:"Data residency is the physical location of stored data. Data sovereignty is the legal framework governing the data. An EU company storing data in a US-owned cloud in Germany has German residency but US sovereignty concerns (CLOUD Act applies to US companies). Both must be understood."},
{id:404,domain:6,level:2,question:"What is a 'cloud exit clause' and what should it specify?",options:["A. A clause allowing providers to terminate service without notice","B. Contractual terms specifying data portability rights, migration assistance, transition periods, and data deletion procedures when leaving a cloud provider","C. A penalty clause for customers who exit their contract early","D. A clause specifying emergency exit procedures from cloud data centers"],correct:1,explanation:"Cloud exit clauses protect customers when changing providers. They should specify: data export formats, export assistance obligations, export duration and cost, continued service during transition, and certified data deletion with proof after migration — ensuring no vendor lock-in consequences."},
{id:405,domain:6,level:3,question:"An organization is subject to NIS2 Directive in the EU. What new obligations does this create compared to GDPR?",options:["A. NIS2 supersedes GDPR making GDPR irrelevant","B. NIS2 focuses on cybersecurity of essential and important entities (energy, transport, healthcare, cloud providers), requiring risk management measures, incident reporting, and supply chain security — complementary to GDPR, not replacing it","C. NIS2 only applies to cloud providers, not cloud customers","D. NIS2 requires organizations to obtain a government cybersecurity certification"],correct:1,explanation:"NIS2 (Network and Information Security Directive 2) expands cybersecurity requirements for essential and important sectors including cloud computing services. It requires: risk management, incident reporting (24-hour initial notification), supply chain security, and enforcement with fines up to €10M or 2% global turnover."},
{id:406,domain:6,level:3,question:"What is the EU AI Act's impact on cloud AI services used for high-risk applications?",options:["A. It bans all AI in the EU","B. High-risk AI systems (HR decisions, credit scoring, biometric identification) require conformity assessments, transparency, human oversight, and registration before deployment in the EU","C. It only applies to AI developed in the EU","D. Cloud providers bear full liability for AI decisions made with their services"],correct:1,explanation:"The EU AI Act classifies AI applications by risk. High-risk uses (employment, credit, critical infrastructure, law enforcement) require: risk management systems, data governance, technical documentation, transparency to users, human oversight mechanisms, and registration in an EU database."},
{id:407,domain:6,level:3,question:"What is 'contractual security requirements' and why must they be established before cloud adoption?",options:["A. Requirements for security guards at cloud data centers","B. Explicit security obligations in cloud contracts — audit rights, incident notification, encryption standards, data deletion, SLA penalties — that protect customer interests and cannot be negotiated after signing","C. Technical specifications for cloud security tools","D. Government requirements imposed on cloud contracts"],correct:1,explanation:"Security requirements must be negotiated before signing because cloud providers offer standard terms favoring themselves. Post-signing negotiation rarely yields favorable terms. Requirements to establish: data residency, encryption standards, breach notification timelines, audit rights, SLA penalties, data deletion certification, and subprocessor controls."},
{id:408,domain:6,level:3,question:"What is 'ITAR' (International Traffic in Arms Regulations) and how does it affect cloud deployments?",options:["A. A US tax regulation for cloud services exports","B. US export control regulations for defense-related articles and services — cloud systems handling ITAR-controlled data must ensure only authorized US persons can access it, regardless of physical location","C. International standards for cloud data transfer protocols","D. EU regulations for cross-border cloud service delivery"],correct:1,explanation:"ITAR controls export and transfer of defense-related items and technical data. Cloud environments handling ITAR data must: restrict access to US persons only, maintain physical or logical separation, prohibit foreign nationals from accessing controlled data — even within US-domiciled cloud providers. Violations carry severe criminal penalties."},

// ─── DOMAIN 1 – Additional Questions ─────────────────────────────────────────
{id:181,domain:1,level:1,question:"Which NIST cloud deployment model is BEST suited for an organization that wants complete ownership and control, with infrastructure operated solely for itself?",options:["A. Public cloud","B. Private cloud","C. Community cloud","D. Hybrid cloud"],correct:1,explanation:"A private cloud is provisioned for exclusive use by a single organization and may be owned, managed, and operated by that organization, a third party, or a combination. It provides the highest level of control and customization."},
{id:182,domain:1,level:1,question:"Which term describes the ability of cloud resources to appear unlimited and to be purchased in any quantity at any time?",options:["A. Scalability","B. Elasticity","C. Availability","D. Durability"],correct:1,explanation:"Elasticity, per NIST, means capabilities can be elastically provisioned and released—sometimes automatically—so that from the consumer's perspective the capabilities available for provisioning often appear to be unlimited."},
{id:183,domain:1,level:1,question:"What does 'broad network access' mean as a NIST cloud characteristic?",options:["A. Cloud services must have unlimited bandwidth","B. Capabilities are available over the network and accessed through standard mechanisms supporting diverse client platforms","C. The cloud provider must have data centers on every continent","D. All cloud traffic must be encrypted during transit"],correct:1,explanation:"Broad network access means cloud capabilities are available over the network (internet or intranet) and can be accessed by standard mechanisms (web browsers, APIs) from heterogeneous client platforms such as phones, tablets, and laptops."},
{id:184,domain:1,level:2,question:"A cloud architect is designing a microservices application. Each service communicates with others over APIs. What is the PRIMARY security concern with this architecture?",options:["A. Microservices consume more CPU than monoliths","B. The large number of internal API calls increases the attack surface for lateral movement","C. Microservices cannot be encrypted","D. Container registries are always public"],correct:1,explanation:"In microservices architectures, each service-to-service API call is a potential attack vector. Lateral movement within the mesh is a key risk, mitigated by mutual TLS (mTLS), service mesh policies, and API authorization between services."},
{id:185,domain:1,level:2,question:"What is a service mesh in cloud-native architecture and its security benefit?",options:["A. A physical network dedicated to inter-data-center communication","B. An infrastructure layer handling service-to-service communication with built-in mTLS, observability, and policy enforcement","C. A CDN for distributing application content","D. A mesh of cloud providers used for redundancy"],correct:1,explanation:"A service mesh (e.g., Istio, Linkerd) abstracts inter-service communication, providing mutual TLS authentication, traffic encryption, fine-grained authorization policies, and observability between microservices without modifying application code."},
{id:186,domain:1,level:2,question:"What is 'edge computing' and what security challenge does it introduce compared to centralized cloud?",options:["A. Putting servers at the edge of the internet—no security difference from cloud","B. Processing data closer to its source, introducing challenges around physical security and remote patch management","C. Using edge routers to encrypt cloud traffic","D. A cloud pricing model that charges at the edge of each billing cycle"],correct:1,explanation:"Edge computing moves compute to locations near data sources (factories, vehicles, retail stores). Physical devices at the edge may be in unsecured locations, are harder to patch remotely, and have limited security monitoring capability compared to centralized cloud."},
{id:187,domain:1,level:2,question:"An availability calculation shows 99.9% uptime. Approximately how much downtime per year does this allow?",options:["A. About 8.7 hours","B. About 52 minutes","C. About 26 hours","D. About 3.65 days"],correct:0,explanation:"99.9% uptime = 0.1% downtime. 0.001 × 8,760 hours/year ≈ 8.76 hours per year of allowable downtime. This is the 'three nines' SLA level."},
{id:188,domain:1,level:3,question:"A company is migrating to cloud using the 6 Rs framework. Their legacy application requires a complete rebuild using cloud-native services. Which R applies?",options:["A. Rehost (Lift & Shift)","B. Replatform","C. Refactor / Re-architect","D. Retire"],correct:2,explanation:"Re-architect (Refactor) means rebuilding the application from scratch using cloud-native features to improve agility and performance. This is the most expensive and time-consuming migration path but yields the greatest cloud benefits."},
{id:189,domain:1,level:3,question:"In a shared cloud environment, what is 'noisy neighbor' and what is its security implication?",options:["A. A cloud tenant whose applications are excessively loud—no security implication","B. A co-tenant consuming disproportionate shared resources, causing performance degradation to others—can be exploited as a DoS","C. A network monitoring tool that detects anomalous traffic","D. A hypervisor that generates excessive log events"],correct:1,explanation:"Noisy neighbor is a multi-tenancy problem where one tenant's resource consumption degrades others' performance. Malicious actors can deliberately create noisy neighbor conditions as a denial-of-service attack against co-tenants."},
{id:190,domain:1,level:3,question:"What is the Cloud Security Alliance (CSA) STAR program?",options:["A. A government certification for cloud providers serving federal agencies","B. A cloud provider security assurance program combining self-assessment, third-party audits, and continuous monitoring based on the CCM","C. A cloud penetration testing certification","D. A standard for cloud pricing transparency"],correct:1,explanation:"CSA STAR (Security, Trust, Assurance, and Risk) is a publicly accessible registry of cloud provider security controls. It has three levels: self-assessment, third-party certification, and continuous monitoring—all mapped to the CSA Cloud Controls Matrix."},
{id:191,domain:1,level:3,question:"What does the ENISA cloud risk 'Resource exhaustion' refer to?",options:["A. Running out of budget for cloud services","B. A situation where cloud resources are fully consumed preventing legitimate customers from provisioning services","C. An attacker consuming all available encryption keys","D. Log storage being filled by excessive security events"],correct:1,explanation:"Resource exhaustion is an availability risk where shared cloud resources (compute, storage, network bandwidth) are fully consumed—either by legitimate demand spikes or deliberate attack—preventing legitimate tenants from accessing services."},

// ─── MIXED BATCH B (IDs 477–656) ─────────────────────────────────────────────
// Domain 1
{id:477,domain:1,level:1,question:"What is 'cloud computing' as defined by NIST SP 800-145?",options:["A. Renting physical servers in a remote data center","B. A model for enabling ubiquitous, convenient, on-demand network access to a shared pool of configurable computing resources that can be rapidly provisioned with minimal management effort","C. Any computing service delivered over the internet","D. A virtualization technology that runs multiple OSes on one server"],correct:1,explanation:"NIST SP 800-145 defines cloud computing as a model enabling ubiquitous, convenient, on-demand network access to a shared pool of configurable computing resources (networks, servers, storage, applications, services) that can be rapidly provisioned and released with minimal management effort or service provider interaction."},
{id:478,domain:1,level:1,question:"What is 'virtual networking' in cloud environments?",options:["A. Network connectivity between virtual reality applications","B. Software-defined network constructs (VPCs, subnets, route tables, security groups) that provide network services without physical hardware configuration","C. A wireless network protocol for cloud data centers","D. A VPN tunnel between two cloud regions"],correct:1,explanation:"Virtual networking uses software to define network topology, routing, and security policies in cloud — replacing physical routers, switches, and cables. VPCs, subnets, route tables, NACLs, and security groups are all virtual network constructs managed through APIs."},
{id:479,domain:1,level:1,question:"What is a 'cloud management platform' (CMP)?",options:["A. A cloud provider's data center management system","B. Software providing a unified interface for managing resources, costs, performance, and governance across single or multiple cloud environments","C. A government platform for managing public cloud procurement","D. A platform specifically for managing cloud security tools"],correct:1,explanation:"A CMP provides a single pane of glass for multi-cloud governance: resource provisioning, cost management, performance monitoring, compliance reporting, and policy enforcement across heterogeneous cloud environments — essential for large organizations with complex cloud estates."},
{id:480,domain:1,level:2,question:"What is 'inter-region data replication' and its security implications?",options:["A. Replicating security tools between cloud regions","B. Automatically copying data to another geographic region for DR — introduces data residency/sovereignty risks if destination region is in a different legal jurisdiction","C. A network protocol for connecting cloud regions","D. Synchronizing security policies across cloud regions"],correct:1,explanation:"Cross-region replication ensures data availability and disaster recovery but may violate data residency requirements if data flows to a different country. Organizations must verify all destination regions are within permitted jurisdictions and subject to equivalent legal protection."},
{id:481,domain:1,level:2,question:"What is 'cloud cost management' as a security enabler?",options:["A. Reducing security spending to optimize cloud costs","B. Visibility into cloud spending helps identify unauthorized resource provisioning (cryptomining VMs, data exfiltration storage) as anomalous cost spikes","C. A compliance requirement for cloud financial management","D. Managing security vendor contracts and licensing costs"],correct:1,explanation:"Cloud cost anomalies can indicate security incidents: sudden EC2 spend spikes may indicate cryptomining, large data transfer costs may indicate exfiltration, unexpected new services may indicate resource abuse. Cost monitoring supplements security monitoring as an independent detection channel."},
{id:482,domain:1,level:3,question:"What is 'cloud-native security' and how does it differ from 'cloud security'?",options:["A. They are identical concepts","B. Cloud-native security uses platform-native controls (policies-as-code, immutable infra, service mesh) built into the deployment pipeline; cloud security may use traditional tools adapted for cloud","C. Cloud-native security is only for containerized workloads","D. Cloud-native security is provided by cloud providers; cloud security is customer-managed"],correct:1,explanation:"Cloud-native security is designed for cloud from the ground up: security as code in CI/CD, immutable infrastructure, service mesh policies, cloud-native CSPM/CWPP tools, and API-driven controls. Adapting traditional tools (agents, perimeter firewalls) to cloud environments is 'cloud security' but not 'cloud-native security.'"},
// Domain 2
{id:483,domain:2,level:1,question:"What is 'sensitive data discovery'?",options:["A. Finding sensitive data breached by attackers","B. Automated scanning of data stores to identify sensitive information (PII, PHI, credentials, financial data) that requires protection","C. A manual process of reviewing all files for sensitive content","D. Discovering which cloud providers store sensitive data"],correct:1,explanation:"Sensitive data discovery tools (DLP scanners, Macie, Purview) automatically scan cloud storage, databases, and data lakes for sensitive data patterns (SSNs, credit cards, medical records, API keys) to ensure appropriate controls are applied and to understand the data security risk landscape."},
{id:484,domain:2,level:1,question:"What is 'data loss' vs 'data breach'?",options:["A. They are identical events with different regulatory implications","B. Data loss means data becomes unavailable or destroyed; data breach means unauthorized parties gain access to data — both have different impacts and response requirements","C. Data loss is accidental; data breach is always malicious","D. Data loss affects backup systems; data breach affects production systems"],correct:1,explanation:"Data loss: data is destroyed, corrupted, or made unavailable (ransomware, accidental deletion, hardware failure) — business continuity impact. Data breach: unauthorized access to data (exfiltration, unauthorized disclosure) — privacy/compliance impact requiring notification. They can overlap (ransomware may exfiltrate before encrypting)."},
{id:485,domain:2,level:2,question:"What is 'data flow mapping' and why is it essential for compliance?",options:["A. Creating network diagrams showing data center connectivity","B. Documenting how personal data flows through systems — who collects it, where it's stored, who it's shared with, and how it's processed — required for GDPR compliance and privacy governance","C. Mapping the performance of data flows for optimization","D. A technical exercise mapping database schema relationships"],correct:1,explanation:"Data flow mapping (GDPR Article 30 records of processing) documents: data categories, collection sources, processing purposes, storage locations, retention periods, third-party recipients, and transfer mechanisms. It is mandatory for GDPR compliance and essential for identifying where controls must be applied."},
{id:486,domain:2,level:2,question:"What is 'secure multi-party computation' (MPC) in cloud contexts?",options:["A. A cloud architecture using multiple compute instances for security","B. A cryptographic technique allowing multiple parties to jointly compute a function over their inputs without revealing those inputs to each other","C. Multi-factor authentication for cloud computing resources","D. A secure communication protocol between cloud services"],correct:1,explanation:"MPC allows, for example, three hospitals to compute average patient statistics without sharing individual patient data with each other. Each party's input remains confidential; only the agreed output is revealed. It enables privacy-preserving collaboration without a trusted intermediary."},
{id:487,domain:2,level:3,question:"What is 'k-anonymity' and what are its limitations?",options:["A. A key management protocol requiring k-of-n keys for decryption","B. A privacy model ensuring each record is indistinguishable from at least k-1 others on quasi-identifier attributes — limited because homogeneous groups can still reveal sensitive attributes (l-diversity needed)","C. A cryptographic algorithm with k-bit security","D. An access control model limiting data access to k authorized users"],correct:1,explanation:"k-anonymity generalizes quasi-identifiers (ZIP, age, gender) so each combination matches at least k records, preventing singling out individuals. Limitation: if all k records share the same sensitive attribute (all have diabetes), the individual's sensitivity is revealed despite anonymity. l-diversity extends k-anonymity to require diversity in sensitive attributes."},
{id:488,domain:2,level:3,question:"What is 'post-quantum cryptography' (PQC) and why should cloud architects start planning now?",options:["A. Cryptography designed for use after the current quantum computing era","B. Algorithms resistant to attacks by quantum computers — planning needed now because encrypted data captured today can be decrypted in the future when quantum computers mature ('harvest now, decrypt later')","C. A new cryptographic standard replacing AES-256","D. Encryption strong enough to protect quantum computing research data"],correct:1,explanation:"'Harvest now, decrypt later' attacks store today's encrypted data to decrypt when quantum computers can break RSA/ECC (estimated 5-15 years). Long-lived sensitive data (health records, state secrets) needs PQC protection now. NIST standardized first PQC algorithms (ML-KEM, ML-DSA, SLH-DSA) in 2024."},
// Domain 3
{id:489,domain:3,level:1,question:"What is 'network access control list' (NACL) in cloud networking?",options:["A. A list of authorized cloud network administrators","B. A stateless firewall applied at the subnet level controlling inbound and outbound traffic based on IP, port, and protocol rules","C. A list of approved network devices in the cloud environment","D. An access control system for cloud management APIs"],correct:1,explanation:"NACLs are stateless subnet-level firewalls. They evaluate each packet independently — return traffic must be explicitly allowed. NACLs are ordered rule lists (first match wins) applied to all resources in a subnet, providing a subnet-level security layer complementing instance-level security groups."},
{id:490,domain:3,level:1,question:"What is 'cloud storage versioning'?",options:["A. Tracking software version numbers for cloud storage services","B. Maintaining multiple versions of objects so any previous version can be restored — protects against accidental deletion and ransomware by enabling rollback","C. A billing feature tracking storage usage over time","D. Organizing storage objects by version number for compliance"],correct:1,explanation:"Object versioning (S3 Versioning, GCS Object Versioning) preserves every version of an object when overwritten or deleted. Ransomware encrypting and overwriting files can be recovered by rolling back. MFA Delete adds an additional layer requiring MFA to permanently delete versions."},
{id:491,domain:3,level:2,question:"What is 'cross-account access' in cloud IAM and its security risk?",options:["A. Users accessing cloud services from different countries","B. Allowing IAM principals in one cloud account to access resources in another — risk: overly permissive cross-account trust policies expand the blast radius of a compromise","C. Billing access shared between multiple departments","D. A cloud provider accessing customer accounts for support purposes"],correct:1,explanation:"Cross-account access (via IAM role trust policies, resource policies) enables multi-account architectures but requires careful control. Overly broad trust policies (*) can allow any account to assume roles. Cross-account access should be scoped to specific accounts (aws:PrincipalOrgID) and specific roles with least-privilege permissions."},
{id:492,domain:3,level:2,question:"What is 'cloud workload protection' for serverless functions?",options:["A. Protecting physical servers hosting serverless platforms","B. Security controls specific to serverless: function code scanning, runtime protection, least-privilege execution roles, input validation, and dependency management — agents cannot be installed","C. A traditional antivirus solution adapted for serverless","D. Network firewalls protecting serverless function endpoints"],correct:1,explanation:"Serverless functions cannot host traditional agents. Protection includes: SAST/SCA of function code before deployment, runtime application security (RASP) where supported, least-privilege execution roles, input validation at the API gateway level, and dependency scanning for vulnerable libraries."},
{id:493,domain:3,level:3,question:"What is 'runtime security' in container environments and which tool is commonly used?",options:["A. Security configuration applied when containers start","B. Real-time monitoring of container behavior at runtime — Falco uses eBPF/kernel module to detect unexpected syscalls, file access, network connections, and privilege escalation within running containers","C. A container orchestration security feature","D. Scanning containers for vulnerabilities while they are running"],correct:1,explanation:"Runtime security monitors containers as they execute, detecting behavior anomalies that indicate compromise: unexpected network connections, sensitive file reads, privilege escalation, shell spawning in web servers. Falco, Sysdig Secure, and Aqua Security provide cloud-native runtime security using eBPF probes."},
// Domain 4
{id:494,domain:4,level:1,question:"What is 'OWASP Top 10' and what is its purpose?",options:["A. A list of the top 10 cloud security tools","B. A regularly updated list of the 10 most critical web application security risks, used as a minimum security awareness baseline for developers and security teams","C. The 10 most common cloud configuration mistakes","D. A certification exam covering 10 security domains"],correct:1,explanation:"OWASP Top 10 (latest: 2021) lists the most critical application security risks: Broken Access Control, Cryptographic Failures, Injection, Insecure Design, Security Misconfiguration, Vulnerable Components, Auth Failures, Software/Data Integrity Failures, Logging Failures, SSRF. It guides prioritization of application security investments."},
{id:495,domain:4,level:1,question:"What is 'SQL injection' and what is its impact?",options:["A. Injecting malicious SQL scripts into a web page for display","B. Inserting malicious SQL code into application queries, allowing attackers to read, modify, or delete database data, bypass authentication, or execute OS commands","C. A performance optimization technique using SQL query injection","D. An attack on the SQL server's network connectivity"],correct:1,explanation:"SQL injection manipulates database queries by inserting malicious SQL through user input. Impact ranges from data exposure (SELECT all records), data manipulation (UPDATE/DELETE), authentication bypass (always-true conditions), to complete server compromise (xp_cmdshell). Parameterized queries/prepared statements are the primary prevention."},
{id:496,domain:4,level:2,question:"What is 'RBAC vs ABAC' in cloud application authorization?",options:["A. RBAC is newer and replaces ABAC","B. RBAC grants access based on user roles; ABAC grants access based on attribute combinations (user, resource, environment) — ABAC is more flexible but more complex","C. RBAC applies to users; ABAC applies to services","D. They implement identical access control but with different terminology"],correct:1,explanation:"RBAC: user is assigned a role (editor, viewer), role has permissions. Simple, scalable, well-understood. ABAC: access decision evaluates multiple attributes (user.clearance ≥ resource.classification AND time.hour < 18 AND device.compliant = true). More flexible and fine-grained but complex to manage."},
{id:497,domain:4,level:2,question:"What is 'web application firewall bypass' and how do attackers achieve it?",options:["A. Physically bypassing the server hosting the WAF","B. Encoding payloads (URL encoding, Unicode, case variation, comments) to evade WAF signature matching while preserving attack functionality","C. Finding a path to the application that doesn't route through the WAF","D. A vendor vulnerability in WAF software allowing complete bypass"],correct:1,explanation:"Attackers bypass WAFs by: encoding payloads (double URL encoding, Unicode normalization), inserting SQL comments to break pattern matching, case variation (SeLeCt), using equivalent syntax, HTTP parameter pollution, or finding direct paths to the origin server (bypassing the WAF entirely). WAFs are one layer — not sufficient alone."},
{id:498,domain:4,level:3,question:"What is 'Insecure Direct Object Reference' (IDOR) and provide a cloud-specific example?",options:["A. Referencing insecure cloud object storage buckets","B. Accessing objects (records, files) by directly referencing their identifier without authorization check — cloud example: accessing s3.amazonaws.com/backups/customer_123.zip by guessing customer_124.zip","C. A vulnerability in cloud object storage APIs","D. A NoSQL injection attack targeting document databases"],correct:1,explanation:"IDOR (now BOLA in API context) allows accessing other users' resources by manipulating identifiers. Cloud examples: S3 presigned URL with predictable object name, API endpoint /api/invoices/1234 accessible without ownership check (change to 1235), or cloud console URL parameter manipulation exposing other tenants' dashboards."},
// Domain 5
{id:499,domain:5,level:1,question:"What is 'business continuity' vs 'disaster recovery'?",options:["A. They are identical — DR is just a subset of BC terminology","B. Business continuity ensures critical functions continue during a disruption; disaster recovery focuses on restoring IT systems after a disaster — BC is broader, DR is a component","C. Business continuity applies to people; disaster recovery applies to technology","D. BC is for natural disasters; DR is for cyberattacks"],correct:1,explanation:"Business Continuity (BC) is the broader capability — ensuring an organization continues operating during any disruptive event (pandemic, power outage, cyberattack, natural disaster). Disaster Recovery (DR) is the IT-focused subset specifically about restoring systems and data after a disaster. BC includes people, processes, and communications beyond IT."},
{id:500,domain:5,level:1,question:"What is a 'disaster recovery site' and what are the types?",options:["A. A physical location for employees to gather during a disaster","B. An alternate processing facility — hot site (fully operational, minutes RTO), warm site (partially equipped, hours RTO), cold site (facility only, days RTO)","C. A cloud backup account for disaster recovery data","D. The primary data center's emergency response facility"],correct:1,explanation:"DR site types by readiness: Hot site (fully mirrored, real-time replication, RTO in minutes — most expensive), Warm site (equipment ready, needs data restoration, RTO in hours — moderate cost), Cold site (empty facility, need to procure/configure equipment, RTO in days — cheapest but slowest recovery)."},
{id:501,domain:5,level:2,question:"What is 'security event management' vs 'security incident management'?",options:["A. Event management is automated; incident management is manual","B. Security events are logged system activities requiring review; security incidents are events confirmed to have negative security impact requiring a formal response process","C. Event management applies to network events; incident management applies to user events","D. They are identical — an event is always an incident"],correct:1,explanation:"A security event is any observable system occurrence (login, file access, connection) — most are benign. A security incident is an event (or series of events) confirmed to violate security policy or cause harm. Not all events are incidents; all incidents begin as events. The triage process separates them."},
{id:502,domain:5,level:2,question:"What is a 'threat feed' and how does it integrate with cloud security monitoring?",options:["A. News feeds about cybersecurity threats for awareness training","B. Structured data of IOCs (malicious IPs, domains, hashes) from threat intelligence sources — integrated with SIEM/WAF/firewall to automatically block or alert on matching activity","C. A social media feed monitoring for mention of the organization","D. A financial feed tracking the cost of cyber threats"],correct:1,explanation:"Threat intelligence feeds (MISP, commercial TI platforms, ISAC feeds) provide IOCs: malicious IP addresses, C2 domain names, malware hashes, phishing URLs. Integrated with SIEM rules, security groups, WAF rules, and DNS filtering, they enable automatic blocking and detection of known-malicious activity."},
{id:503,domain:5,level:3,question:"What is 'cloud incident response' capability gap compared to on-premises?",options:["A. There are no gaps — cloud response is identical to on-premises","B. Limited access to physical media, ephemeral resources that may auto-terminate, multi-jurisdiction issues, limited hypervisor-level visibility, and provider cooperation requirements for evidence","C. Cloud incidents are smaller in scale than on-premises incidents","D. Cloud providers handle all incident response on behalf of customers"],correct:1,explanation:"Cloud IR gaps: no physical media access (no drive imaging), ephemeral instances may auto-terminate destroying evidence, data in provider-managed services may not be accessible, multi-jurisdiction evidence collection requires legal process, and provider API logs may have limited retention. These require cloud-specific IR planning and tooling."},
// Domain 6
{id:504,domain:6,level:1,question:"What is 'GDPR' and which organizations must comply?",options:["A. A US federal privacy law for healthcare organizations","B. General Data Protection Regulation — EU law requiring any organization worldwide that processes personal data of EU/EEA residents to comply with data protection requirements","C. A global cloud security standard replacing ISO 27001","D. A privacy law applicable only to companies headquartered in the EU"],correct:1,explanation:"GDPR applies based on where data subjects are located, not where the organization is based. Any organization worldwide processing personal data of EU/EEA residents for services or behavior monitoring must comply — with extraterritorial enforcement and fines up to €20M or 4% of global annual turnover."},
{id:505,domain:6,level:1,question:"What are 'special categories of data' under GDPR?",options:["A. Data classified at 'Top Secret' level by governments","B. Sensitive personal data requiring stronger protection: health, biometric, genetic, racial/ethnic origin, political opinions, religious beliefs, trade union membership, sexual orientation, criminal records","C. Financial and banking data requiring encryption","D. Data of children under 16 years old"],correct:1,explanation:"GDPR Article 9 identifies special categories requiring explicit consent or specific legal basis (not just legitimate interest): health data, biometric data for identification, genetic data, racial/ethnic origin, political opinions, religious beliefs, trade union membership, sexual life/orientation. Processing prohibited without explicit consent or specific exemption."},
{id:506,domain:6,level:2,question:"What is 'purpose limitation' under GDPR?",options:["A. A limit on how many purposes an organization can have","B. Personal data must be collected for specified, explicit, and legitimate purposes and not further processed in a way incompatible with those purposes","C. Organizations are limited to processing data for one purpose per dataset","D. A limitation on how long personal data can be used for each purpose"],correct:1,explanation:"GDPR Article 5(1)(b) requires purposes to be defined before collection, communicated to data subjects, and data not reused for incompatible new purposes. If data collected for service delivery is later used for targeted advertising without compatible legal basis, this violates purpose limitation."},
{id:507,domain:6,level:2,question:"What is the 'legitimate interest' legal basis under GDPR and its key limitation?",options:["A. Any business interest qualifies as legitimate interest","B. Processing is permitted when necessary for the controller's legitimate interest and not overridden by data subjects' interests/rights — requires a balancing test; cannot be used for special category data","C. Legitimate interest applies only to business-to-business data processing","D. Legitimate interest requires explicit consent from data subjects"],correct:1,explanation:"Legitimate interest (Article 6(1)(f)) requires a three-part test: identify the legitimate interest, show processing is necessary for it, and balance against data subjects' interests (if subject interests override, legitimate interest fails). It cannot replace consent for direct marketing to individuals or processing special category data."},
{id:508,domain:6,level:3,question:"What is 'accountability' as a GDPR principle and how is it demonstrated?",options:["A. The data protection officer is personally accountable for all GDPR compliance","B. Organizations must not only comply but be able to demonstrate compliance — through documented policies, DPIAs, processing records, training records, and audit trails","C. Cloud providers are accountable for GDPR compliance on behalf of their customers","D. Accountability means organizations must publicly disclose all data processing activities"],correct:1,explanation:"GDPR Article 5(2) accountability requires demonstrating compliance — not just achieving it. Evidence: Article 30 Records of Processing Activities, DPIAs for high-risk processing, staff training records, privacy policies, data transfer mechanisms, incident response logs, and vendor due diligence records. Regulators may request this documentation during investigations."},
{id:509,domain:6,level:3,question:"What is 'adequacy decision' expiry risk for cloud international data transfers?",options:["A. Adequacy decisions are permanent and cannot be revoked","B. Adequacy decisions can be invalidated (Schrems I invalidated Safe Harbor, Schrems II invalidated Privacy Shield) — organizations must monitor for invalidation and have backup transfer mechanisms (SCCs) ready","C. Expired adequacy decisions require re-negotiation every year","D. Only the European Commission can challenge adequacy decisions"],correct:1,explanation:"Schrems I (2015) and Schrems II (2020) demonstrated that privacy advocates can challenge adequacy decisions in court and have them invalidated. Organizations relying solely on an adequacy decision have no fallback. Best practice: maintain SCCs as a parallel mechanism so data transfers can continue if the adequacy decision is struck down."},
// Domain 1
{id:510,domain:1,level:1,question:"What is a 'cloud API' and why is it central to cloud security?",options:["A. A cloud provider's advertising platform interface","B. Programmatic interfaces that provision and manage cloud resources — all cloud management happens through APIs, making API security the foundation of cloud security","C. An application installed on cloud instances","D. A network protocol specific to cloud environments"],correct:1,explanation:"In cloud, everything is API-driven — creating VMs, configuring security groups, accessing storage, managing IAM. API security (authentication, authorization, rate limiting, logging) is the foundation of cloud security because all control-plane operations occur through APIs."},
{id:511,domain:1,level:2,question:"What is 'least functionality' principle in cloud service design?",options:["A. Using the least capable cloud services to save costs","B. Enabling only services, protocols, and ports necessary for business functions — disabling all others to minimize attack surface","C. Reducing application features to improve security","D. Using minimal compute resources to reduce the attack surface"],correct:1,explanation:"Least functionality means enabling only what is required. In cloud: disable unused cloud services, close all unnecessary ports/protocols, remove unnecessary software from instances, disable root access, and use service control policies to prevent enabling prohibited services — minimizing attack surface through feature reduction."},
{id:512,domain:1,level:3,question:"What is 'defense in depth' applied specifically to cloud IAM?",options:["A. Having multiple IAM administrators for redundancy","B. Layering IAM controls: MFA for human users, short-lived credentials for services, SCPs as guardrails, resource policies as secondary authorization, CloudTrail for audit, UEBA for anomaly detection","C. Using different IAM systems for different cloud providers","D. Requiring multiple approvals for all IAM changes"],correct:1,explanation:"Cloud IAM defense in depth: MFA (prevents credential theft), password policies (prevents brute force), SCPs (organizational guardrails preventing misuse even with valid credentials), resource policies (secondary authorization checks), session policies (limiting temporary credential scope), CloudTrail (audit), and UEBA (behavioral anomaly detection). No single control is sufficient."},
// Domain 2
{id:513,domain:2,level:1,question:"What is 'information lifecycle management' (ILM)?",options:["A. Managing the careers of information security professionals","B. Managing data from creation through active use, archival, and final disposition — applying appropriate storage, access controls, and retention policies at each stage","C. A tool for managing database schema changes over time","D. The process of managing cloud storage capacity lifecycle"],correct:1,explanation:"ILM ensures data is stored on appropriate media (hot SSD for active, cold storage for archive), protected with appropriate controls, retained for required periods, and securely disposed of when retention expires. It aligns data management with business, regulatory, and security requirements throughout the data lifecycle."},
{id:514,domain:2,level:2,question:"What is 'data inventory' and why is it a security prerequisite?",options:["A. Counting the number of records in each database for billing","B. A comprehensive catalog of all data assets — what data exists, where it lives, who owns it, its classification, and applicable compliance requirements — required before applying security controls","C. An audit of data backup completeness","D. A process for verifying data accuracy and quality"],correct:1,explanation:"You cannot protect what you don't know you have. A data inventory (data catalog) identifies all data assets, their sensitivity, location, and owner. It is a prerequisite for: DLP configuration (what to protect), encryption decisions (what must be encrypted), retention policy application, and compliance scoping."},
// Domain 3
{id:515,domain:3,level:1,question:"What is 'Multi-Factor Authentication' (MFA) for cloud management console access?",options:["A. Requiring multiple administrators to approve each console action","B. Requiring a second authentication factor (TOTP, hardware token, biometric) in addition to username/password for cloud management console login","C. A cloud monitoring feature tracking multiple failed login attempts","D. Enforcing different password requirements for different account types"],correct:1,explanation:"MFA for cloud console access is critical because cloud management credentials give control over all resources. NIST and all cloud provider security benchmarks mandate MFA for all human users with management console access — especially for privileged accounts and root/admin accounts."},
{id:516,domain:3,level:2,question:"What is 'cloud resource tagging' from a security governance perspective?",options:["A. Adding metadata tags to cloud resources for billing allocation only","B. Using consistent tags (environment, owner, data-classification, compliance) to enforce policies, identify unmanaged resources, apply security controls, and automate compliance reporting","C. Marking cloud resources as public or private","D. Tagging resources with vulnerability scan results"],correct:1,explanation:"Security-relevant tags enable: enforcing encryption policies on resources tagged 'data-classification:sensitive', identifying untagged/unmanaged resources for cleanup, applying IAM policies based on resource attributes, automated compliance reporting per environment/team, and cost allocation to security-relevant business functions."},
{id:517,domain:3,level:3,question:"What is 'Kubernetes admission control' and how does it enforce security policies?",options:["A. The process of admitting new nodes to a Kubernetes cluster","B. Webhook-based plugins that intercept API requests before resource creation — admission controllers (OPA Gatekeeper, Kyverno) can validate and mutate requests to enforce security policies","C. Network policies controlling traffic admission to pods","D. RBAC policies governing cluster administrator admission"],correct:1,explanation:"Kubernetes admission controllers intercept API server requests before objects are created/modified. They validate (reject non-compliant) or mutate (modify to comply) requests. OPA Gatekeeper and Kyverno enforce policies: block privileged containers, require resource limits, mandate security contexts, enforce image registry restrictions, and more."},
// Domain 4
{id:518,domain:4,level:1,question:"What is 'secure design' principle 'fail securely'?",options:["A. Systems should never fail","B. When a system fails, it should default to a secure state (deny access, lock down) rather than opening up or exposing data","C. Security controls should have redundant backups that activate on failure","D. Failure messages should be hidden from users for security"],correct:1,explanation:"Fail securely means that on failure, the system defaults to the most secure state. A firewall that fails should deny all traffic (fail-closed), not permit all traffic (fail-open). An authentication system failure should lock users out, not grant access. Security must be maintained even when components fail."},
{id:519,domain:4,level:2,question:"What is 'OAuth 2.0 authorization code flow' and why is it preferred over implicit flow?",options:["A. Authorization code is older and less secure than implicit flow","B. Authorization code flow exchanges a short-lived code for tokens server-side — the token is never exposed in the browser URL; implicit flow returned tokens in URL fragments where they could be logged or leaked","C. Authorization code flow is only for mobile apps; implicit is for web apps","D. They are equivalent security-wise but have different latency characteristics"],correct:1,explanation:"Authorization code flow: browser receives a code (not a token) in the redirect; server exchanges code + client secret for tokens out-of-band. Tokens never appear in browser history or server logs. Implicit flow returned tokens in URL fragments — logged by proxies, accessible via Referer headers. Authorization code + PKCE is now the standard for all clients."},
{id:520,domain:4,level:3,question:"What is 'prototype pollution' in JavaScript applications?",options:["A. Polluting the codebase with excessive prototyping","B. An attack where malicious properties are added to JavaScript Object.prototype, affecting all objects inheriting from it — potentially leading to RCE or security bypass in Node.js applications","C. An XSS variant targeting JavaScript prototype functions","D. A performance issue caused by excessive JavaScript object creation"],correct:1,explanation:"JavaScript objects inherit from Object.prototype. If attacker input like {'__proto__':{'isAdmin':true}} is merged into an object without sanitization, isAdmin becomes true for all objects. In Node.js server-side contexts, prototype pollution can lead to RCE through gadget chains in commonly used libraries."},
// Domain 5
{id:521,domain:5,level:1,question:"What is 'mean time to contain' (MTTC) in incident response?",options:["A. The average time between security incidents","B. The average time from incident detection to successful isolation of the threat — measuring how quickly responders limit attacker spread after detection","C. The time to fully eradicate and recover from an incident","D. The average time for containment tools to be deployed"],correct:1,explanation:"MTTC measures how quickly, after detection, the security team contains the threat (isolates systems, revokes credentials, blocks C2 communication). It is a key metric separate from MTTD (time to detect) and MTTR (time to fully resolve) — each measures a different phase of the response cycle."},
{id:522,domain:5,level:2,question:"What is 'insider threat detection' in cloud environments?",options:["A. Detecting threats from cloud providers accessing customer data","B. Using UEBA, DLP, and access analytics to detect malicious or negligent actions by authorized users — unusual data access volumes, off-hours activity, bulk downloads, privilege escalation","C. Monitoring external contractors who have cloud access","D. A physical security control monitoring cloud data center employees"],correct:1,explanation:"Insider threat detection uses: UEBA (baseline normal behavior, alert on deviations), DLP (detect unusual data movements), privileged access monitoring (unexpected admin actions), and access analytics (resource access outside normal patterns). Cloud telemetry (CloudTrail, CASB logs) provides the data for these analytics."},
{id:523,domain:5,level:3,question:"What is 'operational resilience' in cloud security operations?",options:["A. Having a resilient security team with cross-trained staff","B. The ability of the security operations function itself to continue operating under adverse conditions — including the security toolchain (SIEM, SOAR) having its own DR, redundancy, and backup processes","C. A cloud provider's operational uptime guarantee","D. The resilience of cloud applications to security attacks"],correct:1,explanation:"Operational resilience for SecOps means: SIEM is itself highly available (not dependent on the environment it monitors), SOC can function when primary tools fail (backup communication channels, offline runbooks), key management is redundant, and incident response can proceed even during a major cloud outage or when the SOC's own systems are compromised."},
// Domain 6
{id:524,domain:6,level:1,question:"What is 'records management' in cloud environments?",options:["A. Managing cloud provider account records and invoices","B. Applying retention, disposition, and protection requirements to records (legally or regulatorily defined data) — ensuring records are kept for required periods and securely destroyed afterward","C. Managing cloud monitoring dashboard records","D. Database management practices for cloud data"],correct:1,explanation:"Records management applies to data that meets the legal definition of a 'record' — business communications, contracts, financial transactions, medical records. Cloud environments must implement: retention schedules (by record type), legal hold capability, immutable storage for records, and certified destruction processes."},
{id:525,domain:6,level:2,question:"What is 'HIPAA Security Rule' and what does it require for cloud environments?",options:["A. Physical security requirements for healthcare facilities","B. Technical safeguards for ePHI including access controls, audit logging, encryption in transit, and integrity controls — cloud providers must sign Business Associate Agreements","C. A marketing rule governing health insurance advertising","D. A US regulation applying only to hospitals and health insurance companies"],correct:1,explanation:"HIPAA Security Rule (45 CFR Part 164) requires covered entities and business associates to protect ePHI through: access controls (unique user IDs, emergency access, auto logoff), audit controls (activity logging), integrity controls (tampering detection), and transmission security (encryption in transit). Cloud providers handling ePHI must sign BAAs."},
{id:526,domain:6,level:3,question:"What is 'extraterritorial jurisdiction' in cloud computing and why does it create legal uncertainty?",options:["A. A cloud provider's legal right to operate in any country","B. The ability of a country's laws to apply to data or companies outside its borders — creates conflict when multiple countries' laws apply to the same data with incompatible requirements","C. A legal concept preventing courts from ruling on cloud disputes","D. The jurisdictional area of cloud regulatory bodies"],correct:1,explanation:"Extraterritorial jurisdiction means multiple countries may claim authority over the same data: the US CLOUD Act applies to US companies' data worldwide; GDPR applies to EU residents' data processed anywhere. When requirements conflict (one law requires disclosure; another prohibits it), organizations face genuine legal dilemmas requiring legal counsel in all relevant jurisdictions."},
// More Domain 1
{id:527,domain:1,level:1,question:"What is 'cloud vendor lock-in' mitigation strategy?",options:["A. Signing longer contracts to lock in favorable pricing","B. Using open standards, portable formats, abstraction layers, and multi-cloud strategies to ensure workloads can be migrated between providers","C. Avoiding cloud adoption entirely","D. Only using cloud providers headquartered in your country"],correct:1,explanation:"Vendor lock-in mitigation: use open standards (Kubernetes, Terraform, S3-compatible APIs), avoid proprietary services where alternatives exist, design for portability, regularly test migration capability, negotiate contractual data portability rights, and maintain documentation of all provider-specific dependencies."},
{id:528,domain:1,level:2,question:"What is a 'cloud center of excellence' (CCoE) and how does it improve security?",options:["A. The physical location of the cloud provider's best data centers","B. A cross-functional team (security, architecture, operations, finance) that establishes cloud best practices, standards, and governance — ensuring consistent security across the organization's cloud adoption","C. A cloud provider certification program for partner organizations","D. A cloud-specific security operations center"],correct:1,explanation:"A CCoE provides organizational cloud governance: defining approved services and architectures, establishing security baselines, creating reusable secure templates (landing zones), training teams, and enforcing governance through policy-as-code — ensuring all cloud adoption follows consistent security standards rather than each team inventing their own approach."},
{id:529,domain:1,level:3,question:"What is 'chaos monkey' and what does it test in cloud environments?",options:["A. A malware category that randomly deletes cloud resources","B. Netflix's tool that randomly terminates production instances to verify that services are designed to survive unexpected failures without requiring manual intervention","C. A penetration testing tool for cloud environments","D. A load testing tool that generates random traffic patterns"],correct:1,explanation:"Chaos Monkey (part of Netflix's Simian Army) randomly terminates EC2 instances in production. By engineering systems to survive random instance termination, Netflix ensures true resilience — if the system can handle random terminations, it handles real failures. This philosophy drives fault-tolerant cloud architecture design."},
// Domain 2
{id:530,domain:2,level:1,question:"What is 'object versioning' security benefit for cloud storage?",options:["A. Tracking the version number of cloud storage service updates","B. Preserving previous versions of objects enables recovery from ransomware, accidental overwrites, and malicious deletions — attackers cannot permanently destroy data","C. Managing multiple software versions stored in cloud buckets","D. A performance optimization for cloud object access"],correct:1,explanation:"S3 Versioning/GCS Object Versioning preserves all object versions. Ransomware that overwrites objects creates a new version — the original is preserved and recoverable. MFA Delete (requiring a second authentication factor to permanently delete versions) adds additional protection against malicious deletion."},
{id:531,domain:2,level:2,question:"What is 'data classification policy' and what should it specify?",options:["A. A policy classifying cloud providers by their security capability","B. A policy defining classification levels, criteria for assigning them, required controls per level, and handling procedures — ensuring consistent data protection across the organization","C. A technical configuration for automated data scanning","D. A regulatory requirement specifying government data classification levels"],correct:1,explanation:"A data classification policy specifies: classification levels (Public/Internal/Confidential/Restricted), criteria for each level (what makes data 'Confidential'), required controls per level (Restricted = encryption + MFA + DLP), handling procedures (printing, sharing, transmission), and roles responsible for classification decisions."},
// Domain 3
{id:532,domain:3,level:2,question:"What is 'cloud native WAF' vs 'third-party WAF' and trade-offs?",options:["A. Cloud native WAFs are always superior to third-party options","B. Cloud native WAFs (AWS WAF, Azure WAF) have deep provider integration but less sophistication; third-party WAFs (Cloudflare, F5) offer advanced ML-based detection but add complexity and cost","C. Third-party WAFs are more secure because providers cannot access customer WAF rules","D. Cloud native WAFs only protect cloud-native applications"],correct:1,explanation:"Cloud native WAFs integrate seamlessly with provider load balancers and CDNs, are simpler to deploy, and have no egress cost. Third-party WAFs offer more sophisticated detection, consistent protection across multi-cloud, and often better managed rule sets. Choice depends on sophistication needs, multi-cloud requirements, and operational capacity."},
{id:533,domain:3,level:3,question:"What is 'cloud-native firewall' (NFW) and how does it differ from security groups?",options:["A. A physical firewall installed in cloud data centers","B. A stateful, layer-7 managed firewall (AWS Network Firewall, Azure Firewall) providing centralized inspection with IDS/IPS, domain filtering, and protocol inspection — complementing stateful but simpler security groups","C. A security group with more than 100 rules","D. A firewall appliance deployed on a cloud VM"],correct:1,explanation:"Cloud-native firewalls (AWS Network Firewall, Azure Firewall Premium) provide centralized, stateful layer-7 inspection: IDS/IPS signatures, TLS inspection, domain-based filtering, and protocol-level inspection. Security groups are simpler instance-level stateful firewalls with no deep packet inspection capability."},
// Domain 4
{id:534,domain:4,level:2,question:"What is 'HTTP security header' best practice and which headers are most important?",options:["A. Custom HTTP headers used for authentication","B. Response headers instructing browsers on security behavior — critical headers: Content-Security-Policy (XSS), Strict-Transport-Security (HTTPS), X-Frame-Options (clickjacking), X-Content-Type-Options (MIME sniffing)","C. Headers used to bypass WAF rules for legitimate traffic","D. Authentication headers required for API security"],correct:1,explanation:"Critical HTTP security headers: HSTS (force HTTPS), CSP (control script sources, prevent XSS), X-Frame-Options/CSP frame-ancestors (prevent clickjacking), X-Content-Type-Options: nosniff (prevent MIME type confusion), Referrer-Policy (control referer header leakage), Permissions-Policy (restrict browser feature access)."},
{id:535,domain:4,level:3,question:"What is 'cache poisoning' attack and how does it affect cloud CDN deployments?",options:["A. Poisoning a system's DNS cache to redirect traffic","B. Manipulating CDN or web cache to serve malicious responses to legitimate users — exploiting cache key variations to store attacker-controlled content that is served to others","C. An attack corrupting in-memory application caches","D. Poisoning the browser cache to deliver malware"],correct:1,explanation:"Cache poisoning manipulates what gets stored in CDN/web caches. Attackers find requests where responses are cached but the attacker can influence the cached content (via headers, parameters not included in cache keys). The poisoned cache entry is then served to all subsequent users of that cached resource — multiplying impact."},
// Domain 5
{id:536,domain:5,level:2,question:"What is 'network traffic analysis' (NTA) in cloud security?",options:["A. Analyzing cloud provider pricing for network services","B. Analyzing network flow data to detect anomalies — C2 beaconing, lateral movement, data exfiltration, port scanning — without requiring full packet capture","C. Testing network performance before cloud migration","D. Analyzing cloud network architecture for optimization"],correct:1,explanation:"NTA analyzes flow metadata (VPC Flow Logs, NetFlow) for security-relevant patterns: periodic beaconing (malware C2), unusual port access (lateral movement), large outbound transfers (exfiltration), internal port scanning (attacker reconnaissance). Machine learning detects deviations from normal traffic baselines."},
{id:537,domain:5,level:3,question:"What is 'cloud forensics first response' when a cloud instance is suspected of being compromised?",options:["A. Immediately terminate the instance to stop the attacker","B. Capture volatile data first (memory, running processes, network connections), then snapshot disk, isolate instance in quarantine security group, preserve all logs before taking any remediation actions","C. Contact the cloud provider immediately and let them handle the response","D. Reimage the instance from a clean image to restore security"],correct:1,explanation:"Cloud IR first response order of operations: (1) Document current state, (2) Capture volatile data (memory dump if possible), (3) Snapshot disk volumes, (4) Isolate instance (quarantine security group blocking all traffic), (5) Preserve all relevant logs (export from CloudTrail, VPC Flow Logs), (6) Then begin investigation and remediation. Never reimage before evidence capture."},
// Domain 6
{id:538,domain:6,level:1,question:"What is 'COPPA' and its cloud relevance?",options:["A. A US cybersecurity standard for public cloud providers","B. Children's Online Privacy Protection Act — US law requiring parental consent before collecting personal information from children under 13; cloud applications targeting children must comply","C. A European regulation for children's data protection","D. A compliance framework for educational cloud applications"],correct:1,explanation:"COPPA requires verifiable parental consent before collecting PII from children under 13. Cloud applications (games, educational tools, social platforms) that knowingly collect data from under-13s must: obtain consent, provide parental review/deletion rights, minimize data collection, and maintain data securely."},
{id:539,domain:6,level:2,question:"What is 'cloud service agreement' (CSA) vs 'service level agreement' (SLA) difference?",options:["A. They are identical documents with different names","B. A cloud service agreement defines the overall terms of service (acceptable use, liability, IP, termination); an SLA is a subset defining specific performance and availability guarantees","C. The CSA is negotiable; the SLA is non-negotiable","D. The SLA covers security; the CSA covers billing"],correct:1,explanation:"The cloud service agreement (master agreement) covers the entire relationship: acceptable use, intellectual property, data ownership, liability limits, termination, dispute resolution. The SLA is a schedule/exhibit within it defining specific measurable commitments: uptime percentage, support response times, and service credits for violations."},
{id:540,domain:6,level:3,question:"What is 'privacy engineering' and how does it differ from compliance-driven privacy?",options:["A. Privacy engineering is more expensive and compliance is more effective","B. Privacy engineering builds privacy into systems as a technical discipline (minimization by design, differential privacy, encryption architecture) rather than bolting on compliance controls after design is complete","C. Privacy engineering only applies to large technology companies","D. Compliance-driven privacy is proactive; privacy engineering is reactive"],correct:1,explanation:"Privacy engineering applies engineering discipline to privacy: designing systems with minimization at the data model level, using privacy-enhancing technologies (PETs) like differential privacy and MPC, building deletion pipelines from day one, and validating privacy properties formally. Compliance-driven privacy often adds controls on top of systems not designed with privacy in mind."},

// ─── DOMAIN 6 – Batch 2 ──────────────────────────────────────────────────────
{id:265,domain:1,level:1,question:"What is a Cloud Service Broker (CSB)?",options:["A. An ISP that provides internet connectivity to cloud data centers","B. An entity that manages the use, performance, and delivery of cloud services and negotiates relationships between providers and consumers","C. A software tool for monitoring cloud costs","D. A load balancer that distributes traffic between cloud providers"],correct:1,explanation:"A CSB is an intermediary that adds value to cloud services by aggregating, integrating, or customizing offerings from one or more cloud providers. CSBs handle negotiation, security, and service management on behalf of customers."},
{id:266,domain:1,level:1,question:"What does CapEx (Capital Expenditure) mean in the context of cloud adoption?",options:["A. The ongoing monthly subscription cost of cloud services","B. Large upfront investments in physical hardware and infrastructure","C. The cost of cloud training and certification","D. Variable costs that scale with cloud usage"],correct:1,explanation:"CapEx refers to large upfront investments in physical assets like servers, data centers, and networking equipment. Cloud computing shifts spending to OpEx (Operational Expenditure)—pay-as-you-go costs that avoid large upfront capital outlays."},
{id:267,domain:1,level:1,question:"What is OpEx (Operational Expenditure) in cloud computing?",options:["A. The cost of purchasing and owning physical infrastructure","B. Ongoing operational costs paid for services consumed, such as monthly cloud bills","C. One-time setup fees for cloud accounts","D. The cost of hiring cloud security staff"],correct:1,explanation:"OpEx is ongoing spending on services consumed. Cloud computing converts infrastructure spending from CapEx (buy servers) to OpEx (pay monthly per use), improving financial flexibility and eliminating large upfront capital requirements."},
{id:268,domain:1,level:1,question:"What is a Content Delivery Network (CDN)?",options:["A. A network used exclusively for content creators","B. A geographically distributed network of servers that caches content closer to users to reduce latency","C. A type of private cloud for media companies","D. An encrypted channel for delivering sensitive content"],correct:1,explanation:"A CDN caches static content (images, videos, scripts) at edge nodes geographically close to users. This reduces latency, decreases load on origin servers, and improves availability. CDNs also help absorb DDoS traffic."},
{id:269,domain:1,level:1,question:"What is an Availability Zone (AZ) in cloud computing?",options:["A. A geographic region where the cloud provider operates","B. An isolated data center or group of data centers within a region with independent power, cooling, and networking","C. A zone where cloud services are always available at 100% uptime","D. A time zone configuration for cloud resource scheduling"],correct:1,explanation:"An AZ is one or more physically separate data centers within a region, each with redundant power, networking, and cooling. Deploying across multiple AZs provides high availability and fault tolerance within a region."},
{id:270,domain:1,level:1,question:"What is the difference between a cloud region and an availability zone?",options:["A. Regions are logical; AZs are physical","B. A region is a geographic area containing multiple AZs; an AZ is an isolated data center within that region","C. Regions are for compute; AZs are for storage","D. They are the same concept with different names across cloud providers"],correct:1,explanation:"A region is a geographic cluster (e.g., US East) containing multiple isolated AZs. AZs within a region are connected by low-latency links but are sufficiently separated to be isolated from failures affecting other AZs."},
{id:271,domain:1,level:1,question:"What is a Virtual Machine (VM) snapshot?",options:["A. A screenshot of the VM console","B. A point-in-time copy of a VM's disk state that can be used to restore the VM","C. A performance benchmark of VM resources","D. A security scan of a running VM"],correct:1,explanation:"A VM snapshot captures the entire state of a VM (disk contents, memory, settings) at a specific point in time. Snapshots are used for backup, testing, and rapid recovery, but are not a substitute for full backups."},
{id:272,domain:1,level:1,question:"What is cloud orchestration?",options:["A. The process of tuning cloud musical instruments","B. Automated coordination and management of cloud services, workflows, and resources to achieve a defined goal","C. A manual process for provisioning cloud resources","D. A tool for visualizing cloud network topology"],correct:1,explanation:"Cloud orchestration automates the arrangement, coordination, and management of complex cloud tasks and workflows—for example, automatically provisioning a multi-tier application stack in the correct sequence using tools like Terraform or CloudFormation."},
{id:273,domain:1,level:1,question:"What is 'single sign-on' (SSO)?",options:["A. Using the same password on multiple systems","B. Authentication mechanism allowing users to log in once and access multiple applications without re-authenticating","C. A security control requiring one-time passwords for sensitive systems","D. Logging into a single cloud provider account"],correct:1,explanation:"SSO allows users to authenticate once with an identity provider (IdP) and then access multiple applications seamlessly. It reduces password fatigue, improves user experience, and centralizes authentication management."},
{id:274,domain:1,level:1,question:"What does SAML stand for and what is it used for?",options:["A. Security Assertion Markup Language — used for exchanging authentication and authorization data between an IdP and service provider","B. Secure Access Management Layer — a network protocol for VPN connections","C. Standard Authentication and Markup Language — used for web form design","D. Service Account Management Login — used for cloud service accounts"],correct:0,explanation:"SAML (Security Assertion Markup Language) is an XML-based standard for exchanging authentication and authorization data. It enables SSO by allowing an Identity Provider (IdP) to assert a user's identity to a Service Provider (SP)."},
{id:275,domain:1,level:1,question:"What is a DMZ (Demilitarized Zone) in network security?",options:["A. A geographic area where cloud data centers are prohibited","B. A network segment that sits between the public internet and internal networks, hosting publicly accessible services","C. A zone where all traffic is automatically blocked","D. A cloud region with no regulatory requirements"],correct:1,explanation:"A DMZ is a perimeter network segment hosting externally accessible services (web servers, mail servers). It sits between the internet (untrusted) and the internal network (trusted), limiting exposure if a public-facing system is compromised."},
{id:276,domain:1,level:1,question:"What is a load balancer and why is it used?",options:["A. A device that limits how many users can access a system","B. A service that distributes incoming traffic across multiple servers to improve availability and performance","C. A tool for balancing cloud costs across departments","D. A network device that encrypts outbound traffic"],correct:1,explanation:"A load balancer distributes incoming requests across a pool of backend servers, improving application performance, preventing any single server from being overwhelmed, and providing high availability by routing around failed instances."},
{id:277,domain:1,level:1,question:"What is the purpose of a DNS (Domain Name System) in cloud environments?",options:["A. To encrypt all cloud network traffic","B. To translate human-readable domain names to IP addresses, enabling service discovery and traffic routing","C. To manage user identities in cloud directories","D. To monitor network performance metrics"],correct:1,explanation:"DNS translates domain names (e.g., app.example.com) to IP addresses. In cloud, DNS also enables advanced traffic routing (latency-based, failover, weighted) and service discovery for microservices."},
{id:278,domain:1,level:1,question:"What is 'resource pooling' in cloud computing?",options:["A. Combining financial resources from multiple companies to purchase cloud services","B. The provider's computing resources serve multiple consumers using a multi-tenant model, with resources dynamically assigned","C. A pool of dedicated servers reserved for a single customer","D. Combining CPU and memory resources within a single server"],correct:1,explanation:"Resource pooling means cloud providers serve multiple consumers using shared physical and virtual resources that are dynamically assigned and reassigned according to demand. Consumers generally have no control or knowledge of the exact location of resources."},
{id:279,domain:1,level:2,question:"A company wants to use a cloud provider but must keep sensitive data within its own data center. Which pattern achieves this?",options:["A. Multi-cloud — use two public providers","B. Hybrid cloud with data classification — run sensitive workloads on-premises and non-sensitive in public cloud","C. Community cloud with trusted partners","D. Public cloud with encryption only"],correct:1,explanation:"A hybrid cloud with data classification keeps regulated/sensitive data on-premises while using public cloud for non-sensitive workloads. This satisfies data residency requirements while still benefiting from cloud elasticity."},
{id:280,domain:1,level:2,question:"What is the 'shared fate' model and how does it differ from shared responsibility?",options:["A. They are identical concepts","B. Shared fate means the provider has skin in the game — they experience real consequences when customers fail, incentivizing better tooling and support beyond contractual minimums","C. Shared fate means all tenants experience outages simultaneously","D. Shared fate is a regulatory framework for cloud providers"],correct:1,explanation:"Shared fate (promoted by Google) goes beyond shared responsibility by having the provider invest in customer success — providing better defaults, guardrails, and tooling — because provider reputation and business success are tied to customer outcomes."},
{id:281,domain:1,level:2,question:"An organization needs 99.99% availability ('four nines'). Approximately how much downtime per year is permitted?",options:["A. About 8.7 hours","B. About 52 minutes","C. About 52 seconds","D. About 5 minutes"],correct:1,explanation:"99.99% uptime = 0.01% downtime. 0.0001 × 525,600 minutes/year ≈ 52.6 minutes of allowed downtime per year. Each additional '9' reduces allowed downtime by roughly 10x."},
{id:282,domain:1,level:2,question:"What is 'cloud sprawl' and its security implication?",options:["A. Rapid expansion of cloud data centers into new geographic regions","B. Uncontrolled proliferation of cloud resources, accounts, and services — creating unmanaged assets with security gaps","C. A cloud provider expanding into too many service categories","D. The spread of cloud adoption across different industries"],correct:1,explanation:"Cloud sprawl occurs when teams provision resources without governance, leading to forgotten instances, unpatched VMs, open storage buckets, and orphaned accounts. Unmanaged resources are prime targets for attackers and create compliance gaps."},
{id:283,domain:1,level:2,question:"What is a cloud 'control plane' vs 'data plane'?",options:["A. Control plane handles user data; data plane handles management commands","B. Control plane manages configuration and routing decisions; data plane forwards actual traffic/data based on those decisions","C. Control plane is the provider's responsibility; data plane is the customer's responsibility","D. They are interchangeable terms for the cloud management interface"],correct:1,explanation:"The control plane is responsible for management functions (routing tables, configuration, orchestration). The data plane handles actual data forwarding/processing. In cloud, compromising the control plane (management API) gives attackers full control over all resources."},
{id:284,domain:1,level:2,question:"What is the purpose of a cloud 'governance framework'?",options:["A. To govern relationships between multiple cloud providers","B. To establish policies, processes, and accountability structures ensuring cloud resources are used securely, efficiently, and in compliance with requirements","C. A government-mandated set of rules for cloud providers","D. A technical standard for cloud API design"],correct:1,explanation:"A cloud governance framework establishes guardrails for cloud use: who can provision what, how resources must be configured, what data can go where, cost controls, and compliance requirements — preventing ungoverned sprawl and security gaps."},
{id:285,domain:1,level:2,question:"What is a 'well-architected' cloud framework?",options:["A. A certification program for cloud architects","B. A set of design principles and best practices across pillars (security, reliability, performance, cost, sustainability) for building optimal cloud workloads","C. A physical data center design standard","D. A cloud provider's marketing framework"],correct:1,explanation:"Well-Architected Frameworks (AWS, Azure, GCP equivalents) provide guidance across pillars including security, operational excellence, reliability, performance efficiency, and cost optimization. They help architects make principled design decisions."},
{id:286,domain:1,level:2,question:"What is 'cloud federation'?",options:["A. A political alliance of cloud providers","B. The ability to extend identity and access across multiple cloud environments so users authenticate once and access resources in multiple clouds","C. A data sharing agreement between cloud providers","D. A regulatory body overseeing cloud providers"],correct:1,explanation:"Cloud federation enables identity federation across cloud boundaries — users authenticated by one organization's IdP can access resources in another organization's cloud, using standards like SAML, OAuth, or OIDC. Common in partner, supplier, and multi-cloud scenarios."},
{id:287,domain:1,level:2,question:"A company runs workloads on three different cloud providers. What is the PRIMARY security challenge of this multi-cloud strategy?",options:["A. Higher total cloud cost","B. Inconsistent security controls, monitoring, and governance across different cloud environments","C. Slower application performance","D. Difficulty hiring cloud engineers"],correct:1,explanation:"Multi-cloud security challenges include managing inconsistent IAM models, differing native security tools, separate audit logs, and the need to build a unified security monitoring posture across providers with different interfaces and capabilities."},
{id:288,domain:1,level:2,question:"What is 'infrastructure drift' in a cloud environment?",options:["A. Data migrating between cloud regions","B. Configuration changes that cause deployed infrastructure to diverge from the approved baseline over time","C. Cloud provider changing their service APIs","D. Network latency fluctuations between cloud regions"],correct:1,explanation:"Infrastructure drift occurs when manual changes, patches, or failed IaC runs cause actual infrastructure to differ from its defined baseline. Drift introduces unknown security configurations and compliance gaps, detected and corrected by tools like AWS Config or Terraform plan."},
{id:289,domain:1,level:2,question:"What is a 'cloud service catalog'?",options:["A. A public directory of all cloud providers","B. A curated set of approved cloud services and configurations that teams within an organization are permitted to use","C. A pricing list for cloud services","D. A technical catalog of cloud API documentation"],correct:1,explanation:"A cloud service catalog defines which services, configurations, and providers are approved for use within an organization. It enables self-service provisioning of pre-approved resources while enforcing security and compliance standards through governance."},
{id:290,domain:1,level:2,question:"What is 'cloud-native' application design?",options:["A. Applications developed by cloud provider employees","B. Applications designed to take full advantage of cloud capabilities: microservices, containers, serverless, CI/CD, and dynamic scaling","C. Applications that only run in private cloud environments","D. Applications that are native to a specific operating system"],correct:1,explanation:"Cloud-native applications are designed specifically for cloud environments, leveraging containers, microservices, declarative APIs, and cloud services. They are resilient, manageable, and observable, following principles from the Cloud Native Computing Foundation (CNCF)."},
{id:291,domain:1,level:3,question:"An organization must guarantee that their cloud environment meets specific security standards before any workload is deployed. Which approach implements this most rigorously?",options:["A. Rely on post-deployment audits","B. Implement policy-as-code with automated compliance gates in the CI/CD pipeline that block non-compliant deployments","C. Conduct quarterly manual reviews","D. Require developers to complete security training"],correct:1,explanation:"Policy-as-code (e.g., Open Policy Agent, AWS Service Control Policies) expresses compliance requirements as code that is automatically evaluated before or during deployment, preventing non-compliant infrastructure from ever being created."},
{id:292,domain:1,level:3,question:"What is 'confidential computing' and what security problem does it solve?",options:["A. Encrypting data before uploading to cloud — solves data at rest exposure","B. Processing data within hardware-protected enclaves (TEEs) that keep data encrypted even while in use — protecting data from the cloud provider itself","C. A marketing term for security-focused cloud services","D. Encrypting inter-service communications within cloud environments"],correct:1,explanation:"Confidential computing uses Trusted Execution Environments (TEEs) like Intel SGX or AMD SEV to keep data encrypted even while being processed. This protects against a malicious cloud provider or compromised hypervisor accessing plaintext data in memory."},
{id:293,domain:1,level:3,question:"What is the 'blast radius' concept in cloud security architecture?",options:["A. The physical damage radius of an explosion in a cloud data center","B. The maximum scope of damage an attacker or failure can cause — minimized through least privilege, segmentation, and isolation","C. The performance impact of a DDoS attack on cloud infrastructure","D. The number of users affected by a cloud service outage"],correct:1,explanation:"Blast radius refers to the potential impact of a security incident or failure. Architectural principles that minimize blast radius include least-privilege IAM, network micro-segmentation, separate accounts per environment, and circuit breakers — so a compromise in one area cannot cascade."},
{id:294,domain:1,level:3,question:"A global organization needs to architect a cloud solution that complies with data sovereignty laws in 15 different countries simultaneously. What is the MOST important architectural consideration?",options:["A. Choose the cloud provider with the most global regions","B. Implement data classification with jurisdiction-aware routing that ensures each country's data is processed and stored only within that country's boundaries","C. Encrypt all data so jurisdiction laws don't apply","D. Hire legal counsel in each country"],correct:1,explanation:"Multi-jurisdiction data sovereignty requires data classification (knowing what data belongs to which jurisdiction), jurisdiction-aware routing policies, and architectural enforcement that data never leaves its required geographic boundary — enforced through cloud region restrictions and SCPs."},
{id:295,domain:1,level:3,question:"What is 'chaos engineering' and how does it improve cloud security posture?",options:["A. Introducing random security vulnerabilities to test detection capability","B. Deliberately introducing failures into production to discover resilience weaknesses before they become real outages","C. A development methodology that prioritizes speed over security","D. Random penetration testing without prior planning"],correct:1,explanation:"Chaos engineering (e.g., Netflix Chaos Monkey) proactively injects failures (instance termination, network partitions, latency) to discover weaknesses in resilience, failover mechanisms, and recovery procedures before real failures expose them."},
{id:296,domain:1,level:3,question:"An enterprise is designing a cloud security program. Which framework BEST maps cloud security controls to multiple compliance requirements simultaneously?",options:["A. ISO 27001 alone","B. CSA Cloud Controls Matrix (CCM), which maps to ISO 27001, PCI DSS, HIPAA, GDPR, and other frameworks","C. NIST SP 800-53 alone","D. SOC 2 Type II criteria alone"],correct:1,explanation:"The CSA CCM is specifically designed for cloud environments and maps its 197 controls to more than 40 compliance frameworks including ISO 27001, NIST CSF, PCI DSS, HIPAA, GDPR, and FedRAMP — enabling organizations to demonstrate compliance with multiple requirements simultaneously."},
{id:297,domain:1,level:3,question:"What is 'supply chain security' at the cloud infrastructure level?",options:["A. Securing the physical delivery of hardware to cloud data centers","B. Verifying integrity of cloud provider firmware, software, and hardware to ensure the trusted computing base has not been compromised","C. Auditing cloud provider employee supply chains","D. Managing procurement contracts for cloud services"],correct:1,explanation:"Infrastructure supply chain security ensures that hardware (servers, network gear), firmware, and cloud provider software have not been tampered with. This includes Secure Boot, hardware attestation, and trusted computing base verification — critical for highly sensitive workloads."},
{id:298,domain:1,level:3,question:"What distinguishes 'sovereign cloud' from a standard private cloud?",options:["A. Sovereign cloud is owned and operated by a government","B. Sovereign cloud ensures data, operations, and personnel are all within a specific legal jurisdiction, often with national-security-level isolation","C. Sovereign cloud uses different encryption standards","D. Sovereign cloud is a marketing term with no technical distinction"],correct:1,explanation:"Sovereign cloud goes beyond private cloud by ensuring data residency, operational sovereignty (cloud personnel are in-country and subject to local law), and portability — often required by governments and regulated industries where foreign law must not reach the environment."},

// ─── DOMAIN 2 – Additional Questions ─────────────────────────────────────────
{id:192,domain:2,level:1,question:"Which of the following BEST describes 'data at rest'?",options:["A. Data being transmitted between two systems","B. Data stored on persistent media such as disks, databases, or backup tapes","C. Data actively being processed by an application in memory","D. Data that has been archived and will never be accessed again"],correct:1,explanation:"Data at rest refers to data stored on any persistent medium—hard drives, SSDs, databases, cloud object storage, backup media. Protecting it typically involves encryption of the storage medium or the data files themselves."},
{id:193,domain:2,level:1,question:"What is the purpose of a data loss prevention (DLP) policy?",options:["A. To back up data in case of hardware failure","B. To define rules for detecting and blocking unauthorized transmission of sensitive data","C. To classify data based on its business value","D. To set data retention periods for compliance"],correct:1,explanation:"A DLP policy defines what constitutes sensitive data (e.g., credit card numbers, SSNs, PHI) and specifies what actions to take when such data is detected in transit, in use, or at rest—typically alert, block, or quarantine."},
{id:194,domain:2,level:1,question:"What is 'data remanence'?",options:["A. Data that remains after a retention period expires","B. Residual data that persists on storage media after deletion attempts","C. Duplicate data stored in multiple cloud regions","D. Data that remains encrypted even when decryption is attempted"],correct:1,explanation:"Data remanence is the residual representation of data that remains on storage media even after attempts to erase it. It is a concern when decommissioning cloud storage because simply deleting a file may not remove all traces."},
{id:195,domain:2,level:1,question:"Which of the following cloud storage types is BEST suited for unstructured data such as images, videos, and backups?",options:["A. Block storage","B. File storage (NFS/SMB)","C. Object storage","D. In-memory storage"],correct:2,explanation:"Object storage (e.g., AWS S3, Azure Blob) is ideal for unstructured data. Each item is stored as an object with metadata and a unique ID, and is accessed via HTTP APIs—highly scalable and cost-effective for large volumes."},
{id:196,domain:2,level:2,question:"What is Database Activity Monitoring (DAM) and why is it important for cloud data security?",options:["A. A tool that monitors database query performance","B. A security control that monitors and logs all database access to detect unauthorized queries and policy violations","C. A database replication technology for high availability","D. A tool that enforces database schema standards"],correct:1,explanation:"DAM monitors all database activity in real time, logging queries, users, and access times. It detects anomalous access patterns (unusual queries, after-hours access, bulk data retrieval) independent of the database's own logging."},
{id:197,domain:2,level:2,question:"An organization stores data in a cloud data lake. What is the GREATEST security risk unique to data lakes?",options:["A. Data lakes are always unencrypted","B. Data from many sources with different sensitivity levels is commingled, increasing the risk of unauthorized access to sensitive data","C. Data lakes do not support backups","D. Cloud providers cannot monitor data lake access"],correct:1,explanation:"Data lakes aggregate data from many sources. Without proper access controls, data classification, and governance, sensitive data (PII, financial records) can be accessed by users who should only see aggregated or anonymized data."},
{id:198,domain:2,level:2,question:"What is 'pseudonymization' and how does it differ from anonymization?",options:["A. They are identical—both render data permanently unidentifiable","B. Pseudonymization replaces identifying data with pseudonyms; re-identification is possible with the key. Anonymization is irreversible.","C. Pseudonymization uses encryption; anonymization uses masking","D. Anonymization is weaker than pseudonymization"],correct:1,explanation:"Pseudonymization replaces direct identifiers with pseudonyms but keeps a mapping that allows re-identification. Anonymization irreversibly removes all identifying information. GDPR treats pseudonymized data as still personal data since re-identification is possible."},
{id:199,domain:2,level:2,question:"A security team wants to prevent a compromised insider from exfiltrating the entire customer database. Which control is MOST effective?",options:["A. Full-disk encryption on the database server","B. Column-level encryption and row-level security, ensuring access only to needed data","C. Requiring VPN to access the database","D. Running the database on a private subnet"],correct:1,explanation:"Column-level encryption protects specific sensitive columns so a query returning all rows still returns encrypted values for unauthorized users. Row-level security limits which rows a user can query. Together they reduce the blast radius of an insider threat."},
{id:200,domain:2,level:2,question:"What is 'data aggregation' and why is it a privacy concern?",options:["A. Combining cloud regions' storage for performance—no privacy concern","B. Combining individually non-sensitive data elements that together reveal sensitive information about an individual","C. Backing up data across multiple cloud providers","D. Merging duplicate customer records into a single record"],correct:1,explanation:"Data aggregation combines data that is benign individually (name, employer, neighborhood) but in combination reveals sensitive information (health condition, income level, daily routine). It is a key privacy risk in analytics and AI contexts."},
{id:201,domain:2,level:3,question:"A cloud provider stores customer encryption keys in the same environment as customer data. What security principle does this violate?",options:["A. Defense in depth","B. Separation of duties","C. Separation of key management from data storage","D. Least privilege"],correct:2,explanation:"Keys and the data they protect should be stored separately. If both are compromised together (e.g., a provider breach), the encryption provides no protection. BYOK and HYOK (Hold Your Own Key) address this by keeping keys outside the provider."},
{id:202,domain:2,level:3,question:"What is 'Hold Your Own Key' (HYOK) encryption?",options:["A. The customer generates keys but lets the provider store them","B. The customer retains full control of encryption keys on their own infrastructure, never sharing them with the cloud provider","C. A shared key model where both customer and provider hold half the key","D. A backup key held in escrow by a third party"],correct:1,explanation:"HYOK means encryption and decryption occur in the customer's environment; the cloud provider only ever processes ciphertext. The provider cannot access plaintext data even under legal compulsion. It offers the strongest protection but limits cloud-native functionality."},
{id:203,domain:2,level:3,question:"What is the PRIMARY challenge of applying traditional data classification schemes to cloud big data environments?",options:["A. Cloud data is always unstructured and cannot be classified","B. The volume, velocity, and variety of data make manual classification impractical—requiring automated discovery and classification tools","C. Cloud providers prohibit customers from classifying data","D. Classification labels cannot survive cloud storage migrations"],correct:1,explanation:"Traditional manual classification cannot scale to petabytes of data generated at high velocity. Automated data discovery tools using ML-based pattern recognition are required to identify and classify sensitive data at cloud scale."},
{id:204,domain:2,level:3,question:"Which technique allows a cloud analytics engine to query sensitive data without the provider ever seeing the plaintext data?",options:["A. TLS encryption of API calls","B. Secure multi-party computation or homomorphic encryption","C. VPN between the customer and provider","D. Tokenization of all fields before storage"],correct:1,explanation:"Secure multi-party computation (MPC) and homomorphic encryption both allow computation on encrypted data without exposing plaintext. These technologies are emerging solutions for privacy-preserving cloud analytics."},
{id:205,domain:2,level:3,question:"An organization needs to verify that cloud-stored data has not been altered without retrieving the entire dataset. What is the MOST efficient mechanism?",options:["A. Download all data and compare with a local copy","B. Use cryptographic hash trees (Merkle trees) to verify integrity of specific segments","C. Ask the provider to certify the data is unmodified","D. Re-encrypt the data and compare ciphertext"],correct:1,explanation:"Merkle trees create hierarchical hash structures where any change in data changes the root hash. They allow efficient integrity verification of specific data segments without downloading the entire dataset, widely used in blockchain and distributed storage."},

// ─── DOMAIN 3 – Additional Questions ─────────────────────────────────────────
{id:206,domain:3,level:1,question:"What is a Virtual Private Cloud (VPC)?",options:["A. A private cloud hosted on-premises","B. A logically isolated section of a public cloud where a customer can launch resources in a defined virtual network","C. A VPN connection between the customer and the cloud provider","D. A dedicated physical server in a cloud data center"],correct:1,explanation:"A VPC is a logically isolated virtual network within a public cloud (e.g., AWS VPC, Azure VNet). The customer controls IP address ranges, subnets, route tables, and network gateways—similar to managing an on-premises network."},
{id:207,domain:3,level:1,question:"What is the difference between a public subnet and a private subnet in a cloud VPC?",options:["A. Public subnets are faster; private subnets are more secure","B. Resources in a public subnet have routes to the internet via an internet gateway; private subnet resources do not","C. Public subnets allow all traffic; private subnets block all traffic","D. They are identical but named differently by different cloud providers"],correct:1,explanation:"A public subnet has a route to an internet gateway, allowing resources to be directly addressable from the internet. Private subnets have no direct internet route; outbound internet access (if needed) goes through a NAT gateway."},
{id:208,domain:3,level:1,question:"What is the purpose of a NAT Gateway in a cloud VPC?",options:["A. To translate private IP addresses for internal routing only","B. To allow private subnet resources to initiate outbound internet connections without being directly reachable from the internet","C. To provide DNS resolution for cloud resources","D. To load balance traffic between availability zones"],correct:1,explanation:"A NAT Gateway allows instances in private subnets to initiate outbound traffic to the internet (for software updates, external APIs) while preventing inbound connections from the internet, maintaining the security of private resources."},
{id:209,domain:3,level:1,question:"What is 'auto-scaling' and what is its security implication?",options:["A. Automatically upgrading software without testing—security risk from untested patches","B. Dynamically adding or removing compute instances based on load—new instances must be automatically provisioned securely and decommissioned safely","C. Automatically changing security group rules based on traffic","D. Scaling encryption key length based on data sensitivity"],correct:1,explanation:"Auto-scaling automatically adjusts capacity. The security implication is that new instances must launch in a secure state (using hardened AMIs, instance profiles, security groups) and be decommissioned properly so ephemeral data is securely wiped."},
{id:210,domain:3,level:2,question:"What is a Cloud Workload Protection Platform (CWPP)?",options:["A. A platform that automatically scales cloud workloads","B. A security solution providing runtime protection for servers, VMs, containers, and serverless functions in cloud","C. A DLP tool specifically for cloud storage","D. A compliance automation platform for cloud environments"],correct:1,explanation:"CWPP provides runtime protection for diverse cloud workloads including physical servers, VMs, containers, and serverless. It combines capabilities like host-based IDS, vulnerability management, application control, and behavioral monitoring."},
{id:211,domain:3,level:2,question:"What is a Service Control Policy (SCP) in AWS Organizations?",options:["A. An IAM policy applied to a single user","B. An organization-level policy that sets maximum available permissions for accounts—overriding account-level IAM policies","C. A network policy controlling traffic between cloud services","D. A pricing policy for cloud services in an organization"],correct:1,explanation:"SCPs in AWS Organizations define guardrails at the organization, OU, or account level. Even if an account's IAM policies allow an action, the SCP can deny it. They enable centralized governance and prevent account-level policy bypasses."},
{id:212,domain:3,level:2,question:"An organization uses AWS Direct Connect instead of VPN for cloud connectivity. What is the PRIMARY security advantage?",options:["A. Direct Connect is faster so it is more secure","B. Direct Connect provides a dedicated private network connection bypassing the public internet, reducing exposure to internet-based threats","C. Direct Connect automatically encrypts all traffic","D. Direct Connect is cheaper and cost savings improve security budgets"],correct:1,explanation:"Direct Connect (and Azure ExpressRoute/Google Cloud Interconnect) creates a dedicated private connection between on-premises and cloud, bypassing the public internet. This reduces the attack surface and avoids internet-based man-in-the-middle risks, though encryption should still be applied."},
{id:213,domain:3,level:2,question:"What is 'container image hardening'?",options:["A. Using a physically stronger storage medium for container images","B. Removing unnecessary packages, running as non-root, minimizing attack surface, and scanning images before deployment","C. Encrypting the container image file at rest","D. Compressing container images to reduce size"],correct:1,explanation:"Container image hardening reduces the attack surface by using minimal base images, removing unnecessary tools, running as a non-root user, dropping Linux capabilities, and scanning for vulnerabilities before publishing to a registry."},
{id:214,domain:3,level:2,question:"What is the purpose of a cloud 'landing zone'?",options:["A. A physical space in the cloud data center for customer equipment","B. A pre-configured, secure baseline environment with governance controls into which cloud workloads are deployed","C. The geographic region where data first lands when uploaded","D. A staging environment for testing before production"],correct:1,explanation:"A landing zone is a well-architected, multi-account cloud environment that is the starting point for secure cloud adoption. It includes account structure, network topology, security controls, logging, and identity federation—establishing secure foundations at scale."},
{id:215,domain:3,level:3,question:"What is a Kubernetes Network Policy and what security gap does it address?",options:["A. A policy controlling which kubectl commands users can run","B. A specification that controls which pods can communicate with each other, enforcing micro-segmentation within a cluster","C. A firewall rule applied at the cloud VPC level","D. A policy governing container image sources"],correct:1,explanation:"By default, all pods in a Kubernetes cluster can communicate with all other pods. Network Policies define allow-rules for pod-to-pod and pod-to-external communication, implementing micro-segmentation to limit lateral movement within the cluster."},
{id:216,domain:3,level:3,question:"What is 'secrets management' in cloud environments and why should secrets not be stored in environment variables?",options:["A. Managing administrator passwords in a spreadsheet—environment variables are safer","B. Securely storing API keys and passwords in a dedicated vault; environment variables are visible in process listings, logs, and container inspection","C. A cloud provider service for managing TLS certificates only","D. Encrypting all configuration files—environment variables are fine for non-sensitive values"],correct:1,explanation:"Secrets management systems (HashiCorp Vault, AWS Secrets Manager) securely store, rotate, and audit access to credentials. Environment variables are risky because they appear in crash dumps, logs, process listings, and can be read by any process in the container."},
{id:217,domain:3,level:3,question:"What is the purpose of cloud provider 'guardrails' in a multi-account organization?",options:["A. Physical barriers around cloud data centers","B. Preventive and detective controls applied centrally to enforce baseline security across all accounts regardless of individual account settings","C. Rate limits on API calls to prevent abuse","D. Network ACLs applied at the internet gateway"],correct:1,explanation:"Guardrails (implemented via SCPs, Azure Policies, GCP Organization Policies) prevent non-compliant configurations at the organizational level—for example, preventing any account from disabling CloudTrail or creating public S3 buckets regardless of individual IAM permissions."},
{id:218,domain:3,level:3,question:"A cloud security team discovers that a developer left an SSH port (22) open to 0.0.0.0/0 on a production security group. What is the IMMEDIATE risk?",options:["A. Minimal risk as SSH requires a valid key pair","B. The instance is exposed to automated scanning and brute-force attacks from the entire internet","C. Only a risk if the instance is in a public subnet","D. The cloud provider will automatically close the port"],correct:1,explanation:"Port 22 open to the internet invites automated SSH scanners and brute-force attacks. Even with key-based auth, unpatched SSH vulnerabilities or weak key management can be exploited. Immediate remediation: restrict to known IPs or remove the rule."},
{id:219,domain:3,level:3,question:"What is 'serverless security' and what is the customer's primary security responsibility in a FaaS model?",options:["A. Securing physical servers—customers have no security responsibility","B. Securing function code, IAM permissions, input validation, and dependencies; the provider secures everything below the function runtime","C. The provider is fully responsible for all security in serverless","D. Serverless has fewer security concerns than VMs because there are no servers to patch"],correct:1,explanation:"In FaaS, the provider manages infrastructure, OS, and runtime security. Customers are responsible for: function code security, least-privilege IAM roles, input validation, dependency management, and securing the event sources that trigger functions."},

// ─── DOMAIN 4 – Additional Questions ─────────────────────────────────────────
{id:220,domain:4,level:1,question:"What are the three types of XSS attacks?",options:["A. SQL, NoSQL, and XML injection","B. Reflected, Stored (Persistent), and DOM-based","C. Active, Passive, and Hybrid","D. Client-side, Server-side, and Network-based"],correct:1,explanation:"Reflected XSS: malicious script is reflected off the server in the response. Stored XSS: script is saved in the database and served to all users. DOM-based XSS: the payload is executed through client-side JavaScript manipulating the DOM."},
{id:221,domain:4,level:1,question:"What is an XML External Entity (XXE) attack?",options:["A. An attack that floods an XML parser with oversized inputs","B. An attack exploiting insecure XML parsing to read local files, perform SSRF, or execute code via external entity references","C. Injecting malicious XML into a database","D. A cross-site scripting attack targeting XML-based web services"],correct:1,explanation:"XXE attacks exploit XML parsers that process external entity references. Attackers can use this to read sensitive files (/etc/passwd), perform SSRF, or cause denial of service. Mitigation: disable external entity processing in XML parsers."},
{id:222,domain:4,level:1,question:"What is insecure deserialization?",options:["A. Storing serialized objects without encryption","B. A vulnerability where attackers manipulate serialized objects to achieve remote code execution, privilege escalation, or replay attacks","C. Failing to validate JSON input format","D. Using deprecated serialization libraries"],correct:1,explanation:"Insecure deserialization occurs when an application deserializes attacker-controlled data without validation. Attackers can craft malicious serialized objects to manipulate application logic, achieve RCE, or bypass authentication."},
{id:223,domain:4,level:1,question:"What is the purpose of the 'HttpOnly' flag on a cookie?",options:["A. To restrict the cookie to HTTP connections only (not HTTPS)","B. To prevent client-side scripts from accessing the cookie, mitigating XSS-based session theft","C. To make the cookie available only on the home page","D. To encrypt the cookie contents"],correct:1,explanation:"HttpOnly prevents JavaScript from accessing the cookie via document.cookie. This means even if an attacker injects malicious scripts (XSS), they cannot steal session cookies marked HttpOnly."},
{id:224,domain:4,level:1,question:"What does the 'Secure' flag on an HTTP cookie do?",options:["A. Encrypts the cookie value","B. Ensures the cookie is only transmitted over HTTPS connections","C. Prevents the cookie from being modified by the user","D. Makes the cookie available across all subdomains"],correct:1,explanation:"The Secure flag instructs the browser to only send the cookie over encrypted HTTPS connections, preventing it from being transmitted in plaintext over HTTP and intercepted by network attackers."},
{id:225,domain:4,level:2,question:"What is the OWASP Application Security Verification Standard (ASVS)?",options:["A. A cloud security certification program","B. A framework providing security requirements and verification criteria for application security testing and design","C. A vulnerability scoring system for web applications","D. An automated scanning tool for OWASP Top 10"],correct:1,explanation:"OWASP ASVS provides a basis for testing web application security controls and requirements. It defines three levels of verification depth and maps to secure development practices, making it useful for security requirements and test planning."},
{id:226,domain:4,level:2,question:"What is 'business logic vulnerability' in web applications?",options:["A. A flaw in the server's business intelligence software","B. A flaw in the application's workflow that allows attackers to abuse intended functionality in ways developers did not anticipate","C. A vulnerability in the ERP system integrated with the web app","D. An SQL injection in the order processing module"],correct:1,explanation:"Business logic flaws exploit the application's intended behavior rather than technical vulnerabilities. Examples: purchasing items at negative prices, skipping payment steps, applying discount codes multiple times. They are invisible to automated scanners."},
{id:227,domain:4,level:2,question:"What is API rate limiting and why is it a security control?",options:["A. Limiting the number of APIs a developer can create","B. Restricting the number of requests a client can make in a time period, preventing brute force, credential stuffing, and DoS attacks","C. Limiting the size of API responses to improve performance","D. Restricting API access to specific IP ranges"],correct:1,explanation:"Rate limiting caps the number of API requests from a client within a time window. This prevents brute-force login attacks, credential stuffing, scraping, and API-layer denial-of-service attacks."},
{id:228,domain:4,level:2,question:"What is 'mass assignment vulnerability' in web APIs?",options:["A. Bulk assignment of user roles without proper approval","B. When an API automatically binds client-provided fields to data model properties, allowing attackers to set fields they shouldn't control","C. Assigning too many permissions to a single API endpoint","D. A vulnerability caused by excessive logging of API parameters"],correct:1,explanation:"Mass assignment (also called auto-binding) occurs when an API maps request parameters directly to object properties. An attacker can include extra fields (e.g., isAdmin=true) to set properties they shouldn't control. Mitigation: explicitly whitelist allowed fields."},
{id:229,domain:4,level:2,question:"What is the purpose of a 'security champion' program in a development organization?",options:["A. A competition where developers win prizes for finding the most bugs","B. Embedding security-aware developers within development teams to promote secure coding practices and act as liaisons to the security team","C. A senior security officer who approves all code deployments","D. A bug bounty program for external researchers"],correct:1,explanation:"Security champions are developers with security training who embed within dev teams, promoting secure coding, conducting peer reviews for security, and bridging the gap between development speed and security rigor—enabling scalable DevSecOps."},
{id:230,domain:4,level:3,question:"What is the 'Confused Deputy' problem in cloud IAM?",options:["A. An IAM administrator who accidentally grants excessive permissions","B. A vulnerability where a privileged service is tricked by a less-privileged caller into performing actions using its higher privileges","C. A multi-account IAM misconfiguration causing privilege escalation","D. An attacker who impersonates a cloud administrator"],correct:1,explanation:"The Confused Deputy problem occurs when service A (trusted with high privileges) is tricked by service B (less trusted) into performing privileged actions on B's behalf. In AWS, this is mitigated by including aws:SourceArn and aws:SourceAccount conditions in trust policies."},
{id:231,domain:4,level:3,question:"What is 'OAuth 2.0 token leakage via referrer header' and how is it prevented?",options:["A. Tokens sent in Authorization headers being logged—prevented by disabling logging","B. Access tokens included in redirect URIs appearing in browser history and Referer headers—prevented by using authorization codes instead of implicit flow","C. TLS interception exposing OAuth tokens—prevented by certificate pinning","D. Tokens being stored in localStorage—prevented by using sessionStorage"],correct:1,explanation:"The implicit OAuth flow returned tokens in URL fragments that could leak via Referer headers or browser history. The authorization code flow with PKCE (Proof Key for Code Exchange) is now recommended, keeping tokens server-side and using short-lived codes in URLs."},
{id:232,domain:4,level:3,question:"A web application dynamically generates PDF reports using user-supplied data. An attacker injects HTML/CSS with file:// URIs into the input. What attack is this?",options:["A. XSS","B. Server-Side Template Injection","C. HTML Injection leading to Server-Side Request Forgery via PDF renderer","D. Path Traversal"],correct:2,explanation:"When a PDF generator renders user-supplied HTML, attackers can inject elements that cause the server-side renderer to fetch local files (file:/// paths) or internal network resources, achieving SSRF or local file disclosure. Mitigation: sanitize input and disable external resource loading in the PDF renderer."},
{id:233,domain:4,level:3,question:"What is 'Software Bill of Materials' (SBOM) and why is it critical for cloud application security?",options:["A. A financial document listing software licensing costs","B. A formal inventory of all components, dependencies, and their versions in an application—enables rapid identification of affected components when new CVEs emerge","C. A document describing the software architecture of cloud applications","D. A list of approved cloud services in an organization"],correct:1,explanation:"An SBOM is a machine-readable inventory of software components and dependencies. When a critical CVE is published (e.g., Log4Shell), organizations with SBOMs can immediately identify which applications are affected, dramatically reducing response time."},
{id:234,domain:4,level:3,question:"What is 'GraphQL-specific security risk' compared to REST APIs?",options:["A. GraphQL always uses HTTP GET, making it less secure than POST-based REST","B. GraphQL's flexible query language allows deep nested queries enabling DoS via query complexity and introspection revealing schema details","C. GraphQL cannot be protected by a WAF","D. GraphQL doesn't support authentication mechanisms"],correct:1,explanation:"GraphQL's flexible query language allows clients to request nested relationships, which can lead to deeply recursive queries causing exponential database load (DoS). Introspection exposes the full schema. Mitigations: query depth/complexity limits, disable introspection in production, input validation."},

// ─── DOMAIN 5 – Additional Questions ─────────────────────────────────────────
{id:235,domain:5,level:1,question:"What is User and Entity Behavior Analytics (UEBA)?",options:["A. A tool that tracks employee internet usage for HR purposes","B. A security technology that uses ML to establish behavioral baselines and detect anomalous activity indicating insider threats or account compromise","C. A user interface for the SIEM console","D. An analytics platform for security awareness training effectiveness"],correct:1,explanation:"UEBA applies machine learning to establish normal behavioral baselines for users and entities (devices, applications). Deviations from baseline—unusual login times, abnormal data access volumes, atypical geographic locations—trigger alerts for potential threats."},
{id:236,domain:5,level:1,question:"What is a honeypot and how does it support cloud security operations?",options:["A. A sweetener added to security reports to make them more appealing to management","B. A decoy system designed to attract and detect attackers, providing early warning and intelligence about attack techniques","C. A cache system for accelerating cloud application performance","D. A tool for filtering spam email"],correct:1,explanation:"A honeypot is a decoy resource that mimics real systems. Any interaction with it is suspicious by definition. In cloud, honey tokens (fake credentials), honey buckets (fake S3 buckets), and honey instances detect attackers probing the environment."},
{id:237,domain:5,level:1,question:"What does 'Mean Time Between Failures' (MTBF) measure?",options:["A. The average time to recover from a security incident","B. The average time a system operates between failures—indicating reliability","C. The average time between security patches","D. The time between scheduled maintenance windows"],correct:1,explanation:"MTBF measures the average time a system operates without failure. Higher MTBF indicates greater reliability. It is used alongside RTO and RPO to design disaster recovery solutions and evaluate cloud provider SLAs."},
{id:238,domain:5,level:1,question:"What is the purpose of a post-incident review (also called a post-mortem)?",options:["A. To assign blame for the security incident","B. To identify root causes, lessons learned, and process improvements to prevent recurrence","C. To document the incident for regulatory reporting only","D. To calculate the financial cost of the incident"],correct:1,explanation:"A post-incident review (blameless post-mortem) analyzes what happened, why, what the response was, and what can be improved. The goal is organizational learning and prevention of recurrence, not finding someone to blame."},
{id:239,domain:5,level:1,question:"What is the difference between an IDS and an IPS?",options:["A. IDS works on networks; IPS works on hosts","B. IDS detects and alerts on threats; IPS detects and actively blocks threats","C. IDS uses signatures; IPS uses anomaly detection","D. They are the same technology with different names"],correct:1,explanation:"An IDS (Intrusion Detection System) monitors and alerts. An IPS (Intrusion Prevention System) additionally takes action to block or mitigate detected threats inline. IPS introduces the risk of false-positive blocks disrupting legitimate traffic."},
{id:240,domain:5,level:2,question:"A cloud environment generates logs across 20 services in 5 regions. What is the BEST architecture for centralized security monitoring?",options:["A. Review each service's native console separately","B. Aggregate all logs to a centralized security account/log archive and ingest into a SIEM with cross-account log shipping","C. Only monitor the highest-risk services to reduce alert volume","D. Rely entirely on the cloud provider's native threat detection"],correct:1,explanation:"Best practice is aggregating logs (CloudTrail, VPC Flow, WAF, DNS, application logs) from all accounts and regions into a dedicated, locked-down security/log-archive account, then ingesting into a SIEM for centralized correlation and detection."},
{id:241,domain:5,level:2,question:"What is 'threat intelligence' and how does it improve cloud security operations?",options:["A. Intelligence gathered from security awareness training scores","B. Information about threat actors, TTPs, and indicators of compromise used to proactively detect and respond to known threats","C. A measure of the security team's knowledge level","D. Automated vulnerability scanning results"],correct:1,explanation:"Threat intelligence (tactical: IOCs; operational: TTPs; strategic: actor profiles) enriches SIEM alerts with context, enables proactive blocking of known-malicious IPs/domains, and helps prioritize response based on active threat actor campaigns."},
{id:242,domain:5,level:2,question:"What is a 'playbook' in security incident response?",options:["A. A document containing all company policies","B. A predefined, step-by-step response procedure for a specific type of security incident","C. A script used to automate vulnerability scanning","D. A training manual for security awareness"],correct:1,explanation:"An incident response playbook defines the specific steps, tools, communication paths, and decisions for responding to a particular type of incident (e.g., ransomware, credential compromise, data breach). It enables consistent, fast response under pressure."},
{id:243,domain:5,level:2,question:"What is the purpose of 'log integrity' controls in cloud environments?",options:["A. To ensure logs are compressed efficiently","B. To prevent attackers who compromise an environment from deleting or modifying audit logs to conceal their activity","C. To ensure all log entries are in the same format","D. To rotate logs on a regular schedule to save storage costs"],correct:1,explanation:"Log integrity controls (immutable S3 Object Lock, CloudTrail log file validation, write-once log storage) ensure that even a compromised environment administrator cannot delete or tamper with audit logs, preserving the forensic record."},
{id:244,domain:5,level:2,question:"What is 'patch Tuesday' and what is the cloud security implication?",options:["A. The day cloud providers perform scheduled maintenance","B. Microsoft's monthly security patch release cycle—cloud Windows VMs must be patched on a regular cadence to remain secure","C. A weekly vulnerability scan schedule recommended by NIST","D. The day security teams submit compliance reports"],correct:1,explanation:"Microsoft releases security patches on the second Tuesday of each month. Cloud environments running Windows workloads must apply these patches promptly. Cloud-native patch management tools (AWS SSM Patch Manager, Azure Update Management) automate this at scale."},
{id:245,domain:5,level:3,question:"An analyst observes a cloud IAM role performing API calls to regions where the organization has no workloads. What is the MOST likely explanation and response?",options:["A. A developer testing new regions—no action needed","B. Credential compromise with an attacker operating in unfamiliar regions—rotate credentials, revoke active sessions, and investigate the role's activity","C. A misconfigured auto-scaling group—review scaling policies","D. Cloud provider infrastructure testing—wait 24 hours before acting"],correct:1,explanation:"API calls to unexpected regions are a strong indicator of credential compromise. An attacker operating in unfamiliar regions avoids detection in monitored regions. Immediate response: rotate/revoke the credential, investigate CloudTrail for the full blast radius, and check for persistence mechanisms."},
{id:246,domain:5,level:3,question:"What is 'living off the land' (LotL) in the context of cloud attacks?",options:["A. An attacker setting up a long-term presence by growing their own infrastructure","B. Using legitimate cloud services and built-in tools for attack activities to evade detection by blending in with normal traffic","C. An attack that targets agricultural or utility cloud systems","D. A cloud cost optimization technique"],correct:1,explanation:"LotL attacks use cloud-native tools (AWS CLI, cloud SDKs, built-in services) and legitimate cloud resources (S3 for exfiltration, Lambda for execution) to blend malicious activity with normal usage, making detection by signature-based tools difficult."},
{id:247,domain:5,level:3,question:"What is 'cloud forensic readiness' and what actions should be taken BEFORE an incident?",options:["A. Having forensics tools installed on the incident responders' laptops","B. Pre-configuring logging, retention policies, snapshot capabilities, and documented procedures so evidence can be rapidly collected when an incident occurs","C. Conducting a penetration test before deploying new cloud workloads","D. Ensuring the cloud provider has a forensics team available 24/7"],correct:1,explanation:"Forensic readiness means proactively enabling all relevant log sources, setting appropriate retention periods, configuring snapshot automation, establishing chain-of-custody procedures, and training responders—before an incident—so evidence collection is immediate and reliable."},
{id:248,domain:5,level:3,question:"A security engineer wants to detect data exfiltration from a cloud environment. Which combination of controls is MOST effective?",options:["A. Antivirus scanning and firewall logs only","B. VPC flow logs with anomaly detection, DNS query monitoring, UEBA for unusual data access patterns, and egress DLP","C. Weekly vulnerability scans and quarterly penetration testing","D. CloudTrail logging and monthly log review"],correct:1,explanation:"Detecting exfiltration requires multiple layers: VPC flow logs detect unusual egress volumes and destinations; DNS monitoring detects DNS tunneling; UEBA detects abnormal data access patterns; DLP intercepts sensitive data leaving defined boundaries."},

// ─── DOMAIN 6 – Additional Questions ─────────────────────────────────────────
{id:249,domain:6,level:1,question:"What is ISO/IEC 27018 specifically designed to address?",options:["A. General cloud security controls for all cloud services","B. Protection of Personally Identifiable Information (PII) in public cloud environments","C. Business continuity requirements for cloud providers","D. Cloud provider financial reporting standards"],correct:1,explanation:"ISO/IEC 27018 is the international standard for protection of PII in public cloud computing. It extends ISO 27001/27002 with specific controls for cloud processors handling personal data."},
{id:250,domain:6,level:1,question:"What is the California Consumer Privacy Act (CCPA) primarily focused on?",options:["A. Protecting health information of California residents","B. Granting California residents rights over their personal information held by businesses","C. Regulating financial data of California-based companies","D. A state-level version of HIPAA"],correct:1,explanation:"CCPA grants California residents rights to know what personal data is collected, the right to delete it, the right to opt out of its sale, and protection from discrimination for exercising these rights. It applies to businesses meeting certain revenue or data volume thresholds."},
{id:251,domain:6,level:1,question:"What is 'cyber liability insurance' and what does it typically cover?",options:["A. Insurance protecting cloud providers against physical damage to data centers","B. Insurance covering costs from data breaches, ransomware, business interruption, and regulatory fines resulting from cyber incidents","C. Insurance for personal devices used for cloud access","D. A type of professional liability insurance for cloud architects"],correct:1,explanation:"Cyber liability insurance covers first-party costs (incident response, breach notification, ransomware payments) and third-party costs (lawsuits from affected customers, regulatory penalties). It is increasingly required by cloud contracts and regulations."},
{id:252,domain:6,level:1,question:"What is a 'Business Associate Agreement' (BAA) under HIPAA?",options:["A. A partnership agreement between healthcare providers","B. A contract required when a covered entity shares PHI with a third-party vendor (business associate) defining the vendor's data protection obligations","C. An employee confidentiality agreement for healthcare staff","D. A technical specification for healthcare data formats"],correct:1,explanation:"A BAA is a legally required contract between a HIPAA covered entity and any business associate (including cloud providers) that handles PHI, specifying how the associate will protect the data and respond to breaches."},
{id:253,domain:6,level:1,question:"What is a cloud 'exit strategy' or 'cloud exit plan'?",options:["A. The procedure for shutting down a cloud provider's data center","B. A documented plan for how an organization will migrate data and workloads away from a cloud provider","C. A procedure for terminating cloud users who leave the organization","D. The process for logging out of cloud management consoles"],correct:1,explanation:"A cloud exit plan documents how the organization will retrieve data, migrate workloads, and cease using a cloud provider's services—whether due to provider failure, contract end, or strategic change. It mitigates vendor lock-in risk."},
{id:254,domain:6,level:2,question:"Under GDPR, what must an organization do within 72 hours of becoming aware of a personal data breach?",options:["A. Notify all affected data subjects","B. Notify the relevant supervisory authority if the breach poses a risk to individuals' rights and freedoms","C. Notify the European Data Protection Board","D. Submit a breach notification to the cloud provider"],correct:1,explanation:"GDPR Article 33 requires notification to the competent supervisory authority within 72 hours when a breach is likely to result in a risk to individuals. Notification to affected data subjects (Article 34) is required for high-risk breaches, but has no fixed timeframe."},
{id:255,domain:6,level:2,question:"What is 'third-party risk management' in the context of cloud security?",options:["A. Managing risk from three different cloud providers simultaneously","B. Assessing and monitoring the security practices of vendors and cloud providers that have access to or process organizational data","C. Transferring all security risk to cloud providers through contracts","D. A risk management framework for managing three tiers of organizational risk"],correct:1,explanation:"Third-party risk management (TPRM) involves assessing vendor security posture during procurement (due diligence), contractually requiring security controls, and continuously monitoring compliance—because an organization's security is only as strong as its weakest third party."},
{id:256,domain:6,level:2,question:"A contract between a company and its cloud provider includes a 'limitation of liability' clause. What does this mean?",options:["A. The provider has no liability for any breaches","B. The provider's maximum financial liability is capped—often at fees paid in a recent period—regardless of damage caused","C. The company's liability to its customers is limited by the contract","D. Neither party can be sued for security incidents"],correct:1,explanation:"Limitation of liability clauses cap the provider's maximum financial exposure, often to fees paid in the last 12 months. This can be significantly less than the actual damages from a major breach, leaving the customer exposed. Negotiating higher caps is an important cloud contract consideration."},
{id:257,domain:6,level:2,question:"What is the purpose of an 'indemnification clause' in a cloud services agreement?",options:["A. To ensure the provider is paid on time","B. To allocate financial responsibility for losses, requiring one party to compensate the other for specified types of harm","C. To guarantee cloud service availability","D. To define the process for contract disputes"],correct:1,explanation:"Indemnification clauses specify that one party (typically the provider) will compensate the other (customer) for certain losses or liabilities—for example, losses resulting from the provider's breach of data protection obligations or intellectual property infringement."},
{id:258,domain:6,level:2,question:"FERPA protects the educational records of students. Which cloud use case would require FERPA compliance?",options:["A. A cloud-hosted financial system used by a university's finance department","B. A cloud-based student information system storing grades, transcripts, and enrollment data","C. A cloud email system used by university professors for internal communication","D. A cloud storage system for university marketing materials"],correct:1,explanation:"FERPA (Family Educational Rights and Privacy Act) protects the privacy of student education records. Any cloud system storing or processing student records (SIS, LMS, grade systems) must comply with FERPA, requiring appropriate vendor agreements."},
{id:259,domain:6,level:3,question:"A cloud customer discovers its provider has received a foreign government data request for customer data. The contract has a 'notification of legal orders' clause. What should the provider do first?",options:["A. Immediately provide all requested data to avoid legal penalties","B. Evaluate whether it is legally permitted to notify the customer, challenge overbroad requests, and produce only what is legally compelled","C. Delete the data before the government can access it","D. Terminate the customer's contract to avoid legal entanglement"],correct:1,explanation:"Responsible cloud providers evaluate legal requests, seek to notify customers when legally permitted, challenge overbroad orders, and provide the minimum data required. The ability to challenge requests and notify customers are important factors in cloud provider selection for sensitive workloads."},
{id:260,domain:6,level:3,question:"What is 'adequacy decision' in the context of GDPR international data transfers?",options:["A. A decision by an organization that its security controls are adequate","B. A European Commission ruling that a third country provides an adequate level of data protection, allowing data transfers without additional safeguards","C. A regulator's determination that an organization's response to a breach was adequate","D. A legal assessment that a DPA is adequate for GDPR compliance"],correct:1,explanation:"An adequacy decision (Article 45 GDPR) is the European Commission's formal determination that a non-EU country, territory, or sector offers protection essentially equivalent to GDPR, permitting data transfers without requiring SCCs or BCRs (e.g., the EU-US Data Privacy Framework)."},
{id:261,domain:6,level:3,question:"What is the legal concept of 'data minimization' and how should it be applied in cloud architecture?",options:["A. Minimizing cloud storage costs by compressing all data","B. Collecting and retaining only the minimum personal data necessary for the specified purpose, and deleting it when no longer needed","C. Reducing the number of data classification levels to simplify governance","D. Limiting the number of cloud services that can access the same data"],correct:1,explanation:"Data minimization (GDPR Article 5) requires that personal data be adequate, relevant, and limited to what is necessary. Architecturally this means designing systems to collect only required fields, applying retention limits, and building deletion workflows into the system from the start."},
{id:262,domain:6,level:3,question:"A cloud provider suffers a breach exposing customer data. The customer's data processing agreement includes a sub-processor clause listing the breached sub-processor. Under GDPR, who bears primary accountability to regulators?",options:["A. The sub-processor who was breached","B. The cloud provider (processor) who engaged the sub-processor","C. The customer (data controller) who chose the cloud provider","D. All three parties equally"],correct:2,explanation:"Under GDPR, the data controller (customer) bears primary accountability to regulators for the protection of personal data—even when processing is delegated to a processor who further sub-processes. The controller must ensure all processors and sub-processors provide sufficient guarantees."},
{id:263,domain:6,level:3,question:"What is 'regulatory arbitrage' risk in a multi-cloud deployment spanning multiple countries?",options:["A. Different cloud providers charging different prices for the same service","B. Unintentionally routing personal data through jurisdictions creating unexpected compliance obligations that conflict with the organization's requirements","C. Arbitration clauses in cloud contracts preventing regulatory investigation","D. Using multiple cloud providers to spread regulatory risk"],correct:1,explanation:"In multi-cloud or multi-region deployments, data may unexpectedly traverse or be stored in jurisdictions with stringent privacy laws (creating obligations) or weak ones (creating risk). Organizations must map data flows to understand all applicable regulatory obligations."},
// ─── MIXED BATCH E (IDs 706–805) ────────────────────────────────────────────
{id:706,domain:1,level:1,question:"Which term describes moving an application to cloud with minor code optimizations to take better advantage of cloud capabilities?",options:["A. Rehost (lift and shift)","B. Replatform (lift and reshape)","C. Refactor (re-architect)","D. Retire"],correct:1,explanation:"Replatforming makes targeted optimizations — such as migrating to a managed database service — without changing core application architecture. It is a middle ground between lift-and-shift and full re-architecture."},
{id:707,domain:1,level:2,question:"What is 'cloud federation'?",options:["A. A group of cloud providers forming a regulatory body","B. The ability for multiple cloud environments to share identity, resources, or services across organizational or provider boundaries","C. A backup strategy using multiple cloud regions","D. A billing arrangement for multi-cloud contracts"],correct:1,explanation:"Cloud federation enables different cloud environments (or organizations) to establish trust relationships and share services, identities, or resources. Common examples include federated identity (SSO across providers) and resource federation."},
{id:708,domain:1,level:3,question:"A company deploying in a regulated sector must demonstrate continuous compliance. Which cloud approach BEST supports this?",options:["A. Annual third-party audits of the cloud provider","B. Continuous compliance monitoring using policy-as-code and automated evidence collection","C. Maintaining manual compliance checklists updated quarterly","D. Relying on the provider's SOC 2 report as sufficient evidence"],correct:1,explanation:"Continuous compliance uses policy-as-code tools (AWS Config, Azure Policy, OPA) to automatically check configurations against compliance controls in real time and collect machine-readable evidence, reducing audit preparation effort."},
{id:709,domain:2,level:1,question:"What is 'data in transit'?",options:["A. Data being moved between storage tiers","B. Data actively moving across a network between systems","C. Data queued for processing","D. Data in a database transaction buffer"],correct:1,explanation:"Data in transit is data actively moving across a network (e.g., from client to server, between cloud services). It should be protected with strong transport encryption such as TLS 1.2+ to prevent interception."},
{id:710,domain:2,level:2,question:"What is the difference between data masking and data encryption?",options:["A. They are identical techniques used interchangeably","B. Encryption transforms data reversibly with a key; masking replaces data with realistic but fictional substitutes, typically irreversibly for non-production use","C. Masking is stronger than encryption for production data","D. Encryption is only used for data in transit; masking only for data at rest"],correct:1,explanation:"Encryption is reversible with a key and protects real data in production. Data masking replaces sensitive fields with realistic fictional data (e.g., fake names, credit card numbers) for non-production environments, providing no pathway back to the original."},
{id:711,domain:2,level:3,question:"An organization must retain financial records for 7 years but also comply with GDPR's data minimization principle. How should these requirements be reconciled?",options:["A. Data minimization always overrides retention laws; delete after minimum retention","B. Comply with the longer retention requirement and document the legal basis; delete promptly once the retention period ends","C. Store only in jurisdictions where retention laws do not apply","D. Anonymize the records immediately after creation to satisfy both requirements"],correct:1,explanation:"When legal retention requirements conflict with data minimization, the legal obligation takes precedence as a lawful basis for continued storage. The organization should document this basis and have automated deletion workflows that erase data immediately upon expiry."},
{id:712,domain:3,level:1,question:"What is a 'jump server' (jump host)?",options:["A. A server that automatically restarts failed applications","B. A hardened intermediary server used to access and manage devices in a separate security zone","C. A server that handles load balancing between regions","D. A failover server activated when the primary fails"],correct:1,explanation:"A jump server (also called bastion host) is a hardened, monitored server that sits between an untrusted network and a trusted internal network. Administrators connect to the jump server first, then from there to internal resources."},
{id:713,domain:3,level:2,question:"What is 'patch management' and why is it important in cloud environments?",options:["A. Managing software license patches to reduce costs","B. The process of identifying, testing, and applying software updates to address vulnerabilities and bugs","C. Patching network routing tables for performance","D. Updating cloud provider billing systems"],correct:1,explanation:"Patch management ensures systems are updated to fix known vulnerabilities. In cloud, the shared responsibility model means customers must patch guest OS and application layers. Unpatched systems are a leading cause of breaches."},
{id:714,domain:3,level:3,question:"What is eBPF (extended Berkeley Packet Filter) used for in cloud security?",options:["A. Filtering packets at the hardware NIC level","B. Running sandboxed programs in the Linux kernel for deep observability, networking, and security enforcement without kernel modules","C. Encrypting network packets at the Berkeley standard","D. A Kubernetes network policy engine"],correct:1,explanation:"eBPF allows programs to run in the Linux kernel sandbox, enabling deep observability (tracing syscalls, network flows) and security enforcement (blocking malicious behavior) with minimal overhead. It underpins tools like Falco, Cilium, and Tetragon."},
{id:715,domain:4,level:1,question:"What is 'broken authentication' in web application security?",options:["A. A login form that fails to load properly","B. Weaknesses in authentication mechanisms allowing attackers to compromise passwords, keys, or session tokens","C. Multi-factor authentication being unavailable","D. Slow authentication causing application timeouts"],correct:1,explanation:"Broken authentication encompasses flaws in session management, credential storage, or login flows — such as weak passwords, missing account lockout, session fixation, or insecure 'remember me' tokens — that allow attackers to assume other users' identities."},
{id:716,domain:4,level:2,question:"What is the purpose of 'output encoding' in web application security?",options:["A. Compressing API responses for faster transmission","B. Converting user-supplied data to a safe representation before rendering in a browser to prevent XSS","C. Encoding database outputs with encryption","D. Formatting API responses in JSON or XML"],correct:1,explanation:"Output encoding ensures that user-controlled data rendered in HTML, JavaScript, CSS, or URL contexts is treated as data rather than executable code, preventing XSS attacks by neutralizing characters with special meaning in each context."},
{id:717,domain:4,level:3,question:"What is 'broken access control' and why is it the top OWASP risk?",options:["A. Physical access controls that have been bypassed","B. Failures in enforcing restrictions on what authenticated users are allowed to do, enabling privilege escalation or unauthorized data access","C. Access control systems that crash under load","D. Missing MFA on administrative accounts"],correct:1,explanation:"Broken access control (OWASP #1) occurs when restrictions on what authenticated users can do are not properly enforced. Examples include accessing other users' data by manipulating IDs, accessing admin functions, or bypassing access checks in APIs."},
{id:718,domain:5,level:1,question:"What is 'change management' in IT security?",options:["A. Managing organizational culture change during cloud migration","B. A formal process to review, approve, and document changes to IT systems to prevent unintended security impacts","C. Version control for application source code","D. Managing security budget changes"],correct:1,explanation:"Change management ensures that modifications to IT systems (configuration, software, infrastructure) are assessed for security impact, approved, tested, and documented. Unauthorized or untested changes are a common source of security incidents."},
{id:719,domain:5,level:2,question:"What is 'purple team' in cybersecurity?",options:["A. A third-party security audit team","B. A collaborative approach combining red team (offensive) and blue team (defensive) to improve security posture","C. A specialized team focused on threat intelligence","D. A regulatory compliance team"],correct:1,explanation:"Purple teaming combines the offensive techniques of the red team with the defensive capabilities of the blue team in a collaborative exercise. Rather than adversarial, the focus is on knowledge transfer to help defenders detect and respond to real attack techniques."},
{id:720,domain:5,level:3,question:"What is 'detection engineering' in modern SOC operations?",options:["A. Engineering surveillance systems in data centers","B. The practice of designing, building, testing, and maintaining detection logic (rules, models) as code to find threats in security telemetry","C. Configuring SIEM parsing rules for log ingestion","D. Building hardware sensors for physical security"],correct:1,explanation:"Detection engineering treats detection content (SIEM rules, ML models, behavioral analytics) as software: written in code, version-controlled, tested against known-good and known-bad data, and continuously improved as the threat landscape evolves."},
{id:721,domain:6,level:1,question:"What is a 'privacy policy'?",options:["A. An internal security policy governing data encryption","B. A public-facing document explaining how an organization collects, uses, shares, and protects personal data","C. A contractual agreement between a company and its cloud provider","D. A technical specification for data anonymization"],correct:1,explanation:"A privacy policy is a legally required public statement informing individuals (data subjects) about what personal data is collected, why, how it is used and shared, how it is protected, and how individuals can exercise their rights."},
{id:722,domain:6,level:2,question:"What is the difference between a data processor and a data controller under GDPR?",options:["A. Controllers store data; processors analyze it","B. The controller determines purposes and means of processing; the processor processes data on behalf of and under instruction from the controller","C. Processors have more accountability than controllers","D. Controllers are always individuals; processors are always companies"],correct:1,explanation:"Under GDPR: the data controller determines why and how personal data is processed (the decision-maker). The data processor processes data only on documented instructions from the controller. Cloud providers are typically processors; their customers are controllers."},
{id:723,domain:6,level:3,question:"What is the 'accountability principle' under GDPR and how does it apply to cloud?",options:["A. Organizations must publish all security incidents publicly","B. Organizations must be able to demonstrate compliance with GDPR principles — not just comply but prove it","C. Cloud providers are solely accountable for data breaches","D. Accountability means accepting financial penalties for all breaches"],correct:1,explanation:"GDPR's accountability principle (Article 5(2)) requires organizations to not only comply with data protection principles but demonstrate that compliance through documentation, records of processing activities, DPIAs, policies, training, and audit trails."},
{id:724,domain:1,level:2,question:"What is the purpose of a 'cloud architecture review board'?",options:["A. Review cloud provider contracts for legal compliance","B. Evaluate proposed cloud architectures for security, compliance, cost, and operational fit before deployment","C. Approve cloud spending requests","D. Audit cloud provider data centers"],correct:1,explanation:"An architecture review board (ARB) evaluates proposed cloud designs for alignment with security standards, compliance requirements, cost efficiency, and operational best practices before resources are provisioned, preventing problems from being baked in."},
{id:725,domain:2,level:2,question:"What is 'data lifecycle management' in cloud?",options:["A. Managing the life expectancy of cloud hardware","B. The policies and processes governing data from creation through active use, archiving, and secure deletion","C. Automating data backups throughout the day","D. Managing database version upgrades"],correct:1,explanation:"Data lifecycle management encompasses creation/collection, storage, use, sharing, archiving, and destruction of data. Each phase has specific security requirements (classification, access control, encryption, retention, secure deletion)."},
{id:726,domain:3,level:2,question:"What is the security purpose of 'VPC flow logs'?",options:["A. Monitor application performance","B. Record network traffic metadata (source/dest IP, port, protocol, bytes) flowing through VPC interfaces for security analysis and troubleshooting","C. Encrypt network traffic in the VPC","D. Control routing between VPC subnets"],correct:1,explanation:"VPC flow logs capture metadata about IP traffic to/from network interfaces. They are essential for security investigations (detecting lateral movement, data exfiltration, port scanning) and compliance auditing of network activity."},
{id:727,domain:4,level:2,question:"What is 'security misconfiguration' in application and cloud security?",options:["A. Incorrectly installing a security appliance","B. Improperly configured security settings in applications, frameworks, cloud services, or infrastructure leaving systems exposed","C. A configuration error that reduces application performance","D. Misconfigured SIEM alert thresholds"],correct:1,explanation:"Security misconfiguration (OWASP Top 10 #5) includes default credentials, overly permissive cloud storage, enabled unnecessary features, missing security headers, and verbose error messages. It is the most prevalent vulnerability category and is largely preventable."},
{id:728,domain:5,level:2,question:"What is 'log correlation' in security monitoring?",options:["A. Ensuring all systems write logs in the same format","B. Linking related log events across different sources to identify patterns or incidents not visible in individual logs","C. Correlating log volume with network bandwidth usage","D. Matching log timestamps across time zones"],correct:1,explanation:"Log correlation connects related events across disparate sources (firewall, IDS, authentication, application) to detect complex attacks. For example, correlating a failed SSH scan with a successful login followed by data movement reveals an intrusion invisible from any single log."},
{id:729,domain:6,level:2,question:"What is 'consent management' under GDPR?",options:["A. Managing employee consent for monitoring policies","B. Processes and systems to collect, record, and manage data subject consent as a legal basis for processing personal data","C. Consent from cloud providers to process data","D. Managing regulatory consent for cross-border data transfers"],correct:1,explanation:"Consent management ensures that consent obtained for processing personal data is freely given, specific, informed, and unambiguous; documented; and revocable. Organizations must have processes to honor withdrawal of consent and cease processing."},
{id:730,domain:1,level:3,question:"Which cloud security principle is violated when administrative access keys are stored in application source code?",options:["A. Defense in depth","B. Least privilege","C. Separation of duties","D. Secrets management / secure by default"],correct:3,explanation:"Hardcoded credentials in source code violate secrets management principles. If the code is checked into a repository, credentials are exposed to anyone with code access, version history, or a repository breach. Credentials must be externalized to a secrets manager."},
{id:731,domain:2,level:3,question:"What is 'certificate transparency' and how does it improve TLS security?",options:["A. Making TLS certificates human-readable","B. A framework requiring all publicly trusted TLS certificates to be logged in public, auditable logs, enabling detection of misissued certificates","C. Transparent pricing for SSL certificate purchases","D. Open-source TLS certificate generation"],correct:1,explanation:"Certificate Transparency (RFC 6962) requires CAs to log all issued certificates in append-only public logs. Browsers and domain owners can monitor these logs to detect unauthorized or misissued certificates (e.g., from a compromised CA) quickly."},
{id:732,domain:3,level:3,question:"What is 'infrastructure drift' in cloud security?",options:["A. Physical movement of cloud infrastructure between data centers","B. Divergence between the intended (IaC-defined) state and the actual runtime state of infrastructure, often due to manual changes","C. Cloud costs drifting over budget over time","D. Network latency increasing as infrastructure ages"],correct:1,explanation:"Infrastructure drift occurs when manual changes made outside IaC processes cause the actual state to diverge from the defined state. This creates unknown configurations, inconsistent security controls, and makes the environment unpredictable. Immutable infrastructure and IaC drift detection tools address this."},
{id:733,domain:4,level:3,question:"What is 'insecure deserialization' and why is it dangerous?",options:["A. Storing serialized objects without encryption","B. Processing attacker-controlled serialized data in a way that allows object manipulation, leading to remote code execution, privilege escalation, or replay attacks","C. Deserializing JSON without schema validation","D. Slow deserialization causing denial of service"],correct:1,explanation:"Insecure deserialization occurs when an application deserializes data from untrusted sources without validation. Attackers can craft malicious serialized objects that, when deserialized, execute arbitrary code or manipulate application logic."},
{id:734,domain:5,level:3,question:"What is 'memory forensics' and when is it used in cloud incident response?",options:["A. Analyzing cloud billing memory allocation after an incident","B. Capturing and analyzing the contents of RAM to find malware, encryption keys, or attacker tools present only in running processes","C. Recovering deleted files from cloud storage","D. Analyzing application memory leaks after a crash"],correct:1,explanation:"Memory forensics captures volatile RAM contents (process list, network connections, loaded DLLs, encryption keys, malware artifacts) that are not present on disk. In cloud, it is used for deep malware analysis and to find fileless threats that exist only in memory."},
{id:735,domain:6,level:3,question:"What is the 'NIS2 Directive' and how does it extend EU cybersecurity requirements?",options:["A. A national cybersecurity standard for individual EU member states","B. The EU's updated Network and Information Security directive expanding scope, adding incident reporting requirements, and increasing penalties for critical infrastructure sectors","C. A GDPR amendment adding cybersecurity requirements for data processors","D. An EU standard for cloud provider security certifications"],correct:1,explanation:"NIS2 (effective October 2024) expands NIS1 to cover more sectors (including cloud providers, managed services, public administration), mandates risk management measures, requires 24-hour incident notification, and introduces senior management accountability."},
{id:736,domain:1,level:1,question:"What is 'elasticity' in cloud computing?",options:["A. The ability to compress data to reduce storage costs","B. The ability to scale resources up and down dynamically to match workload demand","C. Flexible contract terms with cloud providers","D. The network's ability to reroute traffic"],correct:1,explanation:"Elasticity is the cloud's ability to rapidly provision and release resources in proportion to demand. This enables organizations to handle peak load without over-provisioning, paying only for what they use."},
{id:737,domain:2,level:1,question:"What is 'multi-factor authentication' (MFA)?",options:["A. Authentication requiring multiple administrators to approve access","B. An authentication method requiring two or more verification factors from different categories (something you know, have, or are)","C. Using multiple passwords for different systems","D. Authentication through multiple network hops"],correct:1,explanation:"MFA requires users to present at least two independent authentication factors: typically something you know (password), something you have (OTP token, phone), or something you are (biometric). This dramatically reduces risk from compromised credentials."},
{id:738,domain:3,level:1,question:"What is 'encryption in transit'?",options:["A. Encrypting data before moving it to a different storage tier","B. Protecting data from interception by encrypting it while it travels across networks using protocols like TLS","C. Encrypting data in transit vehicles used for hardware shipping","D. Encrypting network routing tables"],correct:1,explanation:"Encryption in transit (typically TLS/HTTPS) protects data from eavesdropping and tampering as it moves across networks between clients, services, and cloud systems."},
{id:739,domain:4,level:1,question:"What is 'parameterized query' (prepared statement) and what attack does it prevent?",options:["A. A query with configurable performance parameters","B. A query where SQL structure is pre-compiled separately from user-supplied data, preventing SQL injection","C. A query that is cached for performance","D. A query that runs in parallel across partitions"],correct:1,explanation:"Parameterized queries (prepared statements) separate the SQL command structure from data inputs. User-supplied values are treated as literal data, never as SQL syntax, making SQL injection impossible regardless of the input."},
{id:740,domain:5,level:1,question:"What does 'chain of custody' mean in digital forensics?",options:["A. A management hierarchy for security incidents","B. The documented, unbroken record of who collected, handled, and transferred evidence, ensuring its integrity and admissibility","C. A sequence of events during an attack","D. The chain of approvals for forensic tool purchases"],correct:1,explanation:"Chain of custody documents every person who had access to evidence from collection through analysis. An unbroken chain is required for evidence to be admissible in legal proceedings, proving it has not been tampered with."},
{id:741,domain:6,level:1,question:"What is 'HIPAA' and what data does it protect?",options:["A. A financial regulation protecting payment card data","B. A US law protecting the privacy and security of individually identifiable health information held by covered entities and their business associates","C. An EU regulation governing health data","D. A self-regulatory framework for healthcare cloud providers"],correct:1,explanation:"HIPAA (Health Insurance Portability and Accountability Act) mandates privacy and security protections for Protected Health Information (PHI). It applies to covered entities (healthcare providers, insurers, clearinghouses) and their business associates."},
{id:742,domain:1,level:2,question:"What is a 'service mesh' in cloud-native architecture?",options:["A. A network of cloud service providers sharing resources","B. An infrastructure layer handling service-to-service communication with features like mTLS, traffic management, and observability","C. A mesh topology connecting cloud regions","D. A management portal for multiple cloud services"],correct:1,explanation:"A service mesh (e.g., Istio, Linkerd) provides service-to-service communication capabilities — mutual TLS, load balancing, circuit breaking, retries, and distributed tracing — as infrastructure, offloading these concerns from application code."},
{id:743,domain:2,level:2,question:"What is 'database activity monitoring' (DAM)?",options:["A. Monitoring database server CPU and memory utilization","B. Real-time monitoring and analysis of database queries and transactions to detect unauthorized access, data exfiltration, or policy violations","C. Automated database performance tuning","D. Monitoring database replication lag"],correct:1,explanation:"DAM solutions monitor and log all database activity (queries, logins, schema changes) in real time, independent of the database audit log. They detect SQL injection, privilege abuse, and unauthorized data access and support compliance reporting."},
{id:744,domain:3,level:2,question:"What is the purpose of 'cloud workload protection platforms' (CWPP)?",options:["A. Protect cloud provider infrastructure from customer misuse","B. Provide security for cloud workloads (VMs, containers, serverless) including vulnerability assessment, runtime protection, and threat detection","C. Protect cloud workloads from cost overruns","D. Backup and disaster recovery for cloud workloads"],correct:1,explanation:"CWPPs secure individual workloads (VMs, containers, serverless functions) across any cloud. They provide vulnerability scanning, anti-malware, runtime protection, network segmentation, and behavioral monitoring at the workload level."},
{id:745,domain:4,level:2,question:"What is 'threat modeling' in application security?",options:["A. Modeling attacker behavior for law enforcement","B. A structured analysis of a system to identify potential threats, attack vectors, and security requirements before or during design","C. Building machine learning models to predict threats","D. Documenting historical security incidents"],correct:1,explanation:"Threat modeling (e.g., STRIDE, PASTA, LINDDUN) systematically identifies what could go wrong with a system: what assets need protection, who the adversaries are, what attacks are possible, and what mitigations should be implemented. Done early, it is the most cost-effective security activity."},
{id:746,domain:5,level:2,question:"What is 'endpoint detection and response' (EDR)?",options:["A. Detecting threats at network endpoints like routers","B. Security technology providing continuous monitoring and response capability on endpoints (servers, workstations) with behavioral detection and investigation tools","C. A cloud service for managing endpoint certificates","D. Response procedures for endpoint hardware failures"],correct:1,explanation:"EDR solutions continuously monitor endpoint activity, record process execution, network connections, and file operations, apply behavioral analytics to detect threats, and provide investigation and remote response capabilities."},
{id:747,domain:6,level:2,question:"What is 'vendor risk management' (VRM) in cloud security?",options:["A. Managing financial risk from cloud vendor price changes","B. The process of assessing and managing security and compliance risks introduced by third-party vendors and cloud service providers","C. Risk management for cloud vendor selection","D. Managing SLA risk from cloud provider downtime"],correct:1,explanation:"VRM assesses the security posture, compliance status, and contractual protections of third-party vendors (including cloud providers). It includes due diligence before engagement, contractual requirements, ongoing monitoring, and incident notification processes."},
{id:748,domain:1,level:3,question:"What is the 'Jericho Forum Commandments' concept relevant to cloud security?",options:["A. Ten security rules published by Jericho Forum for cloud compliance","B. A de-perimeterization philosophy that security should be data-centric and identity-based, not dependent on network perimeters","C. A compliance framework for international cloud deployments","D. Security requirements for cloud providers serving financial institutions"],correct:1,explanation:"The Jericho Forum's de-perimeterization concept (predating zero trust) argued that networks cannot be secured purely at the perimeter — security must be embedded in applications, data, and identities. This thinking influenced zero-trust architectures."},
{id:749,domain:2,level:3,question:"What is 'format-preserving encryption' (FPE) and when is it used?",options:["A. Encryption that preserves file formats when encrypting documents","B. Encryption that produces ciphertext with the same format and length as the plaintext (e.g., encrypting a 16-digit card number into a 16-digit ciphertext)","C. A standard for encrypting database backup files","D. Encrypting data while preserving metadata for search"],correct:1,explanation:"FPE (e.g., FF3-1, FF1) produces ciphertext matching the format of plaintext — a 16-digit number encrypts to a 16-digit number. This allows encryption of legacy systems that cannot store arbitrary ciphertext, such as payment processing systems expecting specific field formats."},
{id:750,domain:3,level:3,question:"What is 'cloud infrastructure entitlement management' (CIEM)?",options:["A. Managing cloud service contracts and entitlements","B. Specialized tools for discovering, analyzing, and right-sizing cloud IAM permissions to enforce least privilege across cloud environments","C. Entitlement management for SaaS application licenses","D. Managing cloud provider credits and entitlements"],correct:1,explanation:"CIEM addresses the challenge of excessive and unused permissions in cloud IAM (often called permission sprawl). CIEM tools discover all identities and their permissions, identify over-privileged or unused entitlements, and recommend or enforce least-privilege policies."},
{id:751,domain:4,level:3,question:"What is 'runtime application self-protection' (RASP)?",options:["A. Applications that self-heal after security incidents","B. Security technology embedded in an application that monitors and blocks attacks at runtime from within the application itself","C. A cloud-native WAF deployed at the application layer","D. Automated patching of application vulnerabilities at runtime"],correct:1,explanation:"RASP integrates into the application runtime (agent in the app), monitoring application behavior and intercepting malicious calls (e.g., SQL injection, command injection) from within. Unlike a WAF, it has context about the application's internal state."},
{id:752,domain:5,level:3,question:"What is 'MITRE ATT&CK' and how is it used in cloud security?",options:["A. A military cybersecurity classification system","B. A knowledge base of adversary tactics, techniques, and procedures used to improve threat detection, hunting, and red team coverage","C. A vulnerability scoring system replacing CVSS","D. An automated threat response framework"],correct:1,explanation:"MITRE ATT&CK is a globally accessible knowledge base of real-world adversary TTPs organized by tactic (initial access, execution, persistence, etc.). Cloud security teams use it to map detection coverage, design threat hunts, and assess red team scenarios."},
{id:753,domain:6,level:3,question:"What is 'data residency' vs 'data sovereignty'?",options:["A. They are the same concept","B. Data residency specifies where data is physically stored; data sovereignty specifies which jurisdiction's laws govern it (the two may differ)","C. Data sovereignty applies to government data; residency to private data","D. Data residency is a technical control; sovereignty is a contractual one"],correct:1,explanation:"Data residency is the physical location of data storage (e.g., data must be stored in Germany). Data sovereignty is the legal framework governing data (e.g., German law applies). Data can be resident in one country but legally governed by another, creating complex compliance scenarios."},
{id:754,domain:1,level:1,question:"What is the primary advantage of the pay-as-you-go cloud billing model?",options:["A. Lower total cost compared to any alternative","B. Converting capital expenditure to operational expenditure and paying only for resources consumed","C. Guaranteed cost savings over on-premises infrastructure","D. Eliminating the need for IT budget planning"],correct:1,explanation:"Pay-as-you-go (OpEx) eliminates large upfront capital investments (CapEx) in hardware. Organizations pay only for resources consumed, enabling cost scaling with business needs and reducing waste from over-provisioned infrastructure."},
{id:755,domain:2,level:1,question:"What is an 'access control list' (ACL) in data security?",options:["A. A list of all users with access to the company network","B. A table specifying which subjects (users, processes) have which permissions on which objects (files, resources)","C. A cloud billing report showing resource access patterns","D. A list of IP addresses blocked by a firewall"],correct:1,explanation:"An ACL is an ordered list of entries specifying permitted or denied operations for each subject on a particular object. In file systems and cloud storage, ACLs define read/write/execute permissions per user or group."},
{id:756,domain:3,level:1,question:"What is a 'subnet' in cloud networking?",options:["A. A virtual machine running sub-tasks","B. A logical subdivision of a VPC's IP address range, enabling network segmentation within a cloud environment","C. A sub-network connecting cloud to on-premises","D. A secondary network interface on a cloud instance"],correct:1,explanation:"A subnet is a range of IP addresses within a VPC. Cloud resources deployed in a subnet inherit its routing rules and network ACLs. Subnets can be public (internet-routable) or private (internal only), enabling security zonation."},
{id:757,domain:4,level:1,question:"What is 'session management' in web application security?",options:["A. Managing cloud compute session costs","B. Securely creating, maintaining, and terminating user sessions, including generating and protecting session tokens","C. Managing database connection sessions","D. Tracking user sessions for analytics"],correct:1,explanation:"Session management handles the stateful relationship between a user and web application after authentication. Vulnerabilities include predictable tokens, session fixation, missing expiration, and insecure transmission — any of which can allow session hijacking."},
{id:758,domain:5,level:1,question:"What is 'asset management' in cloud security?",options:["A. Managing financial assets of the organization","B. Maintaining a complete inventory of cloud resources, their configurations, owners, and security status","C. Managing IT hardware procurement","D. Tracking cloud cost allocation by business unit"],correct:1,explanation:"Asset management in cloud security maintains an up-to-date inventory of all cloud resources (instances, storage, databases, functions). Without knowing what exists, it is impossible to apply consistent security controls or detect unauthorized resources."},
{id:759,domain:6,level:1,question:"What is a 'data breach'?",options:["A. Unauthorized deletion of data","B. A security incident resulting in unauthorized access to, disclosure of, or loss of personal or sensitive data","C. A backup failure causing data loss","D. A compliance audit finding related to data handling"],correct:1,explanation:"A data breach is a confirmed security incident where data is accessed, disclosed, altered, or destroyed without authorization. Most privacy laws (GDPR, HIPAA, state breach laws) require notification to affected individuals and regulators within defined timeframes."},
{id:760,domain:1,level:2,question:"What is 'continuous integration/continuous deployment' (CI/CD) and how does it relate to cloud security?",options:["A. Continuous monitoring and deployment of security patches","B. Automated pipelines that build, test, and deploy code; they must incorporate security testing to prevent vulnerable code from reaching production","C. Continuously integrating new cloud services into the architecture","D. Deploying applications continuously across multiple cloud regions"],correct:1,explanation:"CI/CD pipelines automate code integration, testing, and deployment. Security must be embedded (DevSecOps): SAST, SCA, container image scanning, IaC security scanning, and secrets detection in the pipeline prevent security regressions from shipping to production."},
{id:761,domain:2,level:2,question:"What is 'key rotation' and why is it a security best practice?",options:["A. Physically rotating HSM hardware for maintenance","B. Periodically replacing cryptographic keys with new ones to limit the data exposed if a key is compromised","C. Rotating data between encryption algorithms","D. Distributing encryption keys to additional administrators"],correct:1,explanation:"Key rotation limits the blast radius of key compromise: even if a key is exposed, only data encrypted under that key is at risk, and only for its rotation period. Automated rotation removes human error and ensures compliance with key management policies."},
{id:762,domain:3,level:2,question:"What is a 'software-defined perimeter' (SDP)?",options:["A. A perimeter defined by software inventory","B. A security architecture that creates one-to-one network connections between verified users and specific resources, replacing network-level access with identity-verified tunnels","C. The logical boundary of a cloud VPC","D. A next-generation firewall with software-based rules"],correct:1,explanation:"SDP (used in ZTNA implementations) dynamically creates encrypted, authenticated one-to-one connections between users and the specific resources they need. Resources are invisible to the network until authentication and authorization succeed, eliminating the attack surface."},
{id:763,domain:4,level:2,question:"What is 'cross-site request forgery' (CSRF)?",options:["A. Forging HTTP requests using a cross-site scripting payload","B. Tricking an authenticated user's browser into sending an unwanted request to a web app where they are authenticated","C. Cross-domain API requests without CORS headers","D. Forging SSL certificates for cross-site impersonation"],correct:1,explanation:"CSRF exploits the trust a web app has in a user's browser. An attacker tricks the user's browser into making authenticated requests (e.g., fund transfer, password change) to an app where the user is already logged in, without the user's knowledge."},
{id:764,domain:5,level:2,question:"What is the purpose of a 'honeypot' in cloud security?",options:["A. A system for storing passwords securely","B. A decoy system designed to attract and detect attackers, gathering intelligence about their techniques","C. A cache server for frequently accessed data","D. A backup server for high-availability failover"],correct:1,explanation:"A honeypot is an intentionally vulnerable decoy system designed to attract attackers. Any interaction with it is anomalous and indicates malicious activity. Honeypots gather attacker intelligence (tools, techniques) and provide early warning."},
{id:765,domain:6,level:2,question:"What is 'e-discovery' (electronic discovery) and what are the cloud implications?",options:["A. Discovering misconfigured cloud resources automatically","B. The process of identifying, preserving, collecting, and reviewing electronically stored information for legal proceedings, complicated in cloud by multi-tenancy and jurisdiction","C. Automatically discovering new cloud services","D. Electronic submission of compliance documentation to regulators"],correct:1,explanation:"E-discovery requires preserving and producing ESI for litigation or regulatory investigations. Cloud complicates this: data may span jurisdictions (legal conflicts), be co-mingled with other tenants (privacy), or be in formats difficult to export. Legal hold and data mapping are essential."},
{id:766,domain:1,level:3,question:"What is 'cloud-native security' and how does it differ from 'cloud-hosted security'?",options:["A. They are the same concept under different names","B. Cloud-native security uses cloud-platform features and APIs for security; cloud-hosted security simply runs traditional security tools on cloud VMs","C. Cloud-native security is less effective than traditional security","D. Cloud-native security only applies to containerized applications"],correct:1,explanation:"Cloud-native security leverages cloud-platform primitives — IAM policies, security groups, KMS, CloudTrail, GuardDuty — built into the infrastructure. Cloud-hosted security deploys traditional tools (virtual firewalls, AV) on cloud VMs, missing cloud-specific capabilities and increasing complexity."},
{id:767,domain:2,level:3,question:"What is 'split-key encryption' and when is it used?",options:["A. Dividing an encryption key across multiple storage locations for performance","B. Requiring multiple key shares (held by different parties) to reconstruct the full key, providing no single point of control","C. Using different keys for encrypting different portions of a file","D. Splitting an encryption key between a customer and cloud provider"],correct:1,explanation:"Split-key (or M-of-N) encryption uses secret sharing schemes (e.g., Shamir's Secret Sharing) so that any M of N key shares are needed to reconstruct the key. No single party can decrypt data alone, useful for highly sensitive scenarios requiring multi-party authorization."},
{id:768,domain:3,level:3,question:"What is a 'sidecar proxy' pattern in microservices security?",options:["A. A secondary load balancer running alongside the primary","B. A proxy container deployed alongside each service pod, transparently handling mTLS, telemetry, and policy enforcement without application code changes","C. A disaster recovery instance mirroring the primary service","D. A monitoring agent deployed on each host"],correct:1,explanation:"The sidecar proxy pattern (used in service meshes like Istio) injects a proxy (e.g., Envoy) into each pod. The proxy intercepts all inbound/outbound traffic, providing mTLS encryption, access policy enforcement, and distributed tracing transparently."},
{id:769,domain:4,level:3,question:"What is 'dependency confusion' attack in software supply chain?",options:["A. Confusion between software dependencies causing application crashes","B. An attack where malicious public packages with the same name as internal private packages are published, causing build tools to download the malicious version","C. A conflict between library versions causing compilation errors","D. An attacker confusing developers with similar-sounding package names (typosquatting)"],correct:1,explanation:"Dependency confusion exploits how package managers (npm, pip, Maven) resolve packages: if an attacker publishes a package with the same name as an internal one but a higher version, build tools may download the malicious public package instead of the internal one."},
{id:770,domain:5,level:3,question:"What is 'cloud forensic readiness'?",options:["A. Having cloud resources ready for incident response deployment","B. Proactively implementing logging, monitoring, and access controls to ensure cloud environments can support forensic investigations when needed","C. Training forensic analysts on cloud tools before incidents","D. Pre-approving forensic investigation procedures with the cloud provider"],correct:1,explanation:"Forensic readiness means configuring environments in advance — enabling comprehensive logging (CloudTrail, VPC flow logs, DNS logs), immutable log storage, time synchronization, and provider cooperation agreements — so that evidence can be reliably collected when an incident occurs."},
{id:771,domain:6,level:3,question:"What does 'binding corporate rules' (BCR) provide for international data transfers under GDPR?",options:["A. Rules binding cloud providers to specific SLAs","B. Approved internal data protection policies allowing multinational corporations to transfer personal data within the corporate group across borders","C. Corporate rules binding all EU member state regulations","D. Contractual rules binding data processors to controller instructions"],correct:1,explanation:"BCRs are legally binding data protection policies approved by an EU data protection authority, allowing multinationals to transfer personal data to group entities in non-adequate countries. They are complex to obtain but provide flexible intra-group transfer mechanisms."},
// ─── MIXED BATCH F (IDs 772–900) ────────────────────────────────────────────
{id:772,domain:1,level:1,question:"Which cloud service model is MOST appropriate for hosting a custom machine learning model with GPU compute requirements?",options:["A. SaaS","B. IaaS","C. FaaS","D. DaaS"],correct:1,explanation:"IaaS provides the raw compute resources (GPU-enabled instances) needed for custom ML workloads. PaaS or managed ML services (a subset of PaaS) could also apply, but IaaS gives the most control over GPU type, driver versions, and environment configuration."},
{id:773,domain:1,level:2,question:"What is the MAIN security concern with using third-party cloud marketplaces to deploy VM images?",options:["A. Marketplace images are always more expensive","B. Pre-built images may contain malware, backdoors, or unpatched vulnerabilities inserted by the publisher","C. Marketplace images cannot be customized","D. Cloud providers do not support marketplace images in production"],correct:1,explanation:"Third-party marketplace images may not be vetted for security. Malicious publishers can embed backdoors or cryptocurrency miners. Organizations should validate images, prefer known vendors or official images, and scan before use."},
{id:774,domain:1,level:3,question:"What do the CSA Top Threats to Cloud Computing reports (Egregious Eleven / Pandemic Eleven) consistently highlight as the greatest overall risk?",options:["A. DDoS attacks on cloud provider infrastructure","B. Data breaches and data loss, often stemming from misconfiguration, insecure APIs, and insufficient IAM","C. Advanced persistent threats targeting cloud control planes","D. Supply chain attacks on cloud provider software"],correct:1,explanation:"Across all CSA Top Threats editions (Treacherous 12 → Egregious 11 → Pandemic 11), data breaches and data loss consistently rank as top concerns. Contributing factors include misconfiguration, weak credentials, insecure APIs, and shared-technology vulnerabilities — all amplified in multi-tenant cloud."},
{id:775,domain:2,level:1,question:"What is 'data deduplication' and what security consideration does it introduce?",options:["A. Removing duplicate user accounts from a directory","B. A storage optimization removing redundant data copies; it can leak information about data content across tenants in shared environments","C. Deduplicating log entries for SIEM efficiency","D. Removing duplicate entries from a database"],correct:1,explanation:"Data deduplication reduces storage by storing one copy of identical data blocks. In multi-tenant cloud, cross-tenant deduplication can theoretically be used as a side channel: if deduplication savings change when you upload data, it may indicate another tenant has the same data."},
{id:776,domain:2,level:2,question:"What is 'field-level encryption' in cloud database security?",options:["A. Encrypting an entire database at the storage layer","B. Encrypting individual data fields (columns) within a database so specific sensitive values are protected even from privileged database users","C. Encrypting database connection strings in application configuration","D. Applying encryption at the database schema level"],correct:1,explanation:"Field-level encryption encrypts individual columns or fields (e.g., SSN, credit card) using application-layer encryption. Even DBAs with full database access see only ciphertext. Keys are managed externally, providing stronger protection than storage-level encryption alone."},
{id:777,domain:2,level:3,question:"An organization uses envelope encryption for all cloud data. How does this protect against a compromised KMS?",options:["A. It does not — KMS compromise exposes all data","B. Only data encrypted under the specific compromised key is exposed; other KEKs protect other data sets","C. Envelope encryption prevents KMS compromise entirely","D. The HSM backing the KMS provides absolute protection"],correct:1,explanation:"Envelope encryption uses unique data encryption keys (DEKs) per data set, wrapped by key encryption keys (KEKs) in KMS. If one KEK is compromised, only data encrypted under that KEK's DEKs is exposed. Data under other KEKs remains protected, limiting the blast radius."},
{id:778,domain:3,level:1,question:"What is an 'internet gateway' in cloud networking?",options:["A. A dedicated hardware device connecting the cloud to the internet","B. A VPC component that enables communication between VPC resources and the internet","C. A security device filtering inbound internet traffic","D. A VPN gateway for secure internet connections"],correct:1,explanation:"An internet gateway is a horizontally scaled, redundant VPC component that allows resources with public IP addresses to communicate with the internet. Without an internet gateway, VPC resources cannot be reached from or reach the internet."},
{id:779,domain:3,level:2,question:"What is 'network address translation' (NAT) gateway used for in cloud security?",options:["A. Translating between IPv4 and IPv6 addresses","B. Allowing private subnet resources to initiate outbound internet connections without being directly reachable from the internet","C. Providing load balancing across availability zones","D. Encrypting outbound network traffic"],correct:1,explanation:"A NAT gateway allows resources in private subnets to reach the internet (for patches, updates) while preventing inbound connections. It preserves the security of private resources while enabling necessary outbound connectivity."},
{id:780,domain:3,level:3,question:"What is 'zero-trust network access' (ZTNA) and how does it replace traditional VPN?",options:["A. A VPN that uses zero-knowledge proofs","B. An architecture granting application-level access based on identity and context verification, replacing broad network access granted by VPN","C. Network access requiring zero configuration","D. A trust model where all traffic is blocked by default at the firewall"],correct:1,explanation:"ZTNA grants access to specific applications (not networks) after verifying user identity, device health, and context. Unlike VPN, which puts users on the network (enabling lateral movement), ZTNA never exposes the broader network, aligning with zero-trust principles."},
{id:781,domain:4,level:1,question:"What is 'threat intelligence integration' in application security?",options:["A. Embedding threat models into application documentation","B. Using current threat data (known bad IPs, malicious domains, CVEs) to inform application security controls and block known threats","C. Sharing application vulnerability data with threat intelligence vendors","D. Integrating threat intelligence into end-user security training"],correct:1,explanation:"Integrating threat intelligence (e.g., IP reputation feeds, malicious domain lists, known-bad file hashes) into WAFs, API gateways, and security controls allows applications to proactively block known threats without waiting for behavior-based detection."},
{id:782,domain:4,level:2,question:"What is 'secure coding standard' and why does it matter for cloud applications?",options:["A. A standard specifying secure coding font and style","B. A set of guidelines prescribing secure development practices to prevent common vulnerabilities throughout the software development lifecycle","C. Encrypting source code to prevent reverse engineering","D. A cloud provider requirement for applications deployed on their platform"],correct:1,explanation:"Secure coding standards (e.g., OWASP, SEI CERT) specify how to avoid common vulnerabilities: input validation, output encoding, error handling, cryptographic usage, and session management. Consistent application throughout the SDLC reduces vulnerability density."},
{id:783,domain:4,level:3,question:"What is 'business logic vulnerability' in application security?",options:["A. A vulnerability in the application's business intelligence module","B. A flaw in the application's intended workflow that an attacker can exploit to achieve unintended outcomes (e.g., bypassing payment, manipulating prices)","C. Logic errors causing application crashes under business hours load","D. A vulnerability in ERP system business logic"],correct:1,explanation:"Business logic vulnerabilities occur in application-specific workflows: buying items at negative prices, skipping payment steps, transferring funds beyond authorized limits. They are often missed by automated scanners because they require understanding of intended business rules."},
{id:784,domain:5,level:1,question:"What is 'log retention' and why is it a compliance requirement?",options:["A. Compressing logs to retain more data per GB","B. Keeping log data for a specified period so it is available for security investigations and compliance audits","C. Retaining only error-level log entries","D. Retaining logs on the originating system rather than centralizing them"],correct:1,explanation:"Log retention policies specify how long logs must be stored. Regulatory requirements (PCI DSS: 1 year, HIPAA: 6 years) mandate retention to support forensic investigations and compliance audits. Logs must be tamper-evident and accessible for the required period."},
{id:785,domain:5,level:2,question:"What is 'indicators of compromise' (IOCs) vs 'indicators of attack' (IOAs)?",options:["A. They are the same concept used by different vendors","B. IOCs are evidence a breach occurred (file hashes, IPs); IOAs are behavioral signals indicating an attack in progress (unusual process activity, lateral movement)","C. IOCs apply to endpoints; IOAs apply to networks","D. IOAs are more accurate than IOCs for detecting known malware"],correct:1,explanation:"IOCs (hashes, domains, IPs) indicate a breach has occurred or malware is present. IOAs focus on attacker behavior and intent — unusual process trees, privilege escalation, reconnaissance — enabling earlier detection before IOCs are available for new threats."},
{id:786,domain:5,level:3,question:"What is 'adversary simulation' (red team exercise) and how does it differ from a penetration test?",options:["A. They are identical; the terms are interchangeable","B. Pen tests find specific vulnerabilities on defined scope; red team exercises simulate a full adversary campaign (multi-stage, objective-driven) to test detection and response","C. Red team exercises are less rigorous than penetration tests","D. Adversary simulation only tests network perimeter security"],correct:1,explanation:"Penetration tests enumerate vulnerabilities in a defined scope. Red team exercises simulate realistic adversary campaigns (initial access → lateral movement → objective) with minimal guidance, testing whether defenders detect and respond — not just whether vulnerabilities exist."},
{id:787,domain:6,level:1,question:"What is 'informed consent' in data privacy?",options:["A. Consent given by an employee after mandatory privacy training","B. Consent where the individual clearly understands what data is collected, how it will be used, who it will be shared with, and what their rights are","C. Consent obtained via a pre-ticked checkbox on a website form","D. Written consent required for all data processing activities"],correct:1,explanation:"Informed consent requires that data subjects genuinely understand the nature and implications of what they are consenting to. GDPR requires consent to be freely given, specific, informed, and unambiguous — pre-ticked boxes and bundled consent are not valid."},
{id:788,domain:6,level:2,question:"What is the role of a 'supervisory authority' under GDPR?",options:["A. A corporate data protection committee","B. An independent public authority in each EU member state responsible for monitoring and enforcing GDPR compliance","C. The European Data Protection Board","D. A third-party auditor approved by the European Commission"],correct:1,explanation:"Each EU member state has a supervisory authority (data protection authority / DPA) that monitors and enforces GDPR. They receive complaints from data subjects, conduct investigations, issue guidance, and can impose fines up to €20M or 4% of global turnover."},
{id:789,domain:6,level:3,question:"What is the 'EU AI Act' and what cloud security implications does it have?",options:["A. A regulation banning AI use in cloud security tools","B. An EU regulation classifying AI systems by risk level and imposing transparency, documentation, and human oversight requirements on high-risk AI","C. A standard for AI security testing developed by ENISA","D. A GDPR amendment covering AI-based data processing"],correct:1,explanation:"The EU AI Act creates a risk-based framework: prohibited uses (social scoring), high-risk AI (biometrics, critical infrastructure — requiring conformity assessments), limited risk (transparency obligations), and minimal risk. Cloud AI services must assess which tier applies to their use cases."},
{id:790,domain:1,level:2,question:"What is 'Infrastructure as a Service' (IaaS) provider responsibility in the shared responsibility model?",options:["A. Application security and data protection","B. Physical security, hypervisor, networking, and hardware — the foundational cloud infrastructure","C. Identity management and access control for customer applications","D. Patching customer guest operating systems"],correct:1,explanation:"In IaaS, the cloud provider is responsible for the physical facility, hardware, hypervisor, and network infrastructure. The customer manages everything above: OS, middleware, application, data, and identity."},
{id:791,domain:2,level:2,question:"What is 'pseudonymization' under GDPR?",options:["A. Replacing all personal data with anonymous data","B. Processing personal data so it can no longer be attributed to a specific individual without additional information held separately and securely","C. Using fake identities in test environments","D. Encrypting personal data fields in a database"],correct:1,explanation:"Pseudonymization replaces direct identifiers with artificial ones (pseudonyms). The link back to the individual is stored separately with access controls. GDPR recognizes it as a risk-reduction measure but pseudonymized data is still personal data (unlike anonymized data)."},
{id:792,domain:3,level:2,question:"What is the purpose of 'cloud security benchmark' standards like CIS Benchmarks?",options:["A. Benchmark cloud provider performance for procurement decisions","B. Provide prescriptive configuration guidelines for securing cloud services and infrastructure to a defined baseline","C. Compare security tool costs across cloud providers","D. Regulatory compliance checklists for specific industries"],correct:1,explanation:"CIS (Center for Internet Security) Benchmarks provide detailed, consensus-based configuration recommendations for AWS, Azure, GCP, and cloud services. They define secure baseline configurations, reducing misconfiguration risk and supporting compliance assessments."},
{id:793,domain:4,level:2,question:"What is 'fuzzing' in application security testing?",options:["A. Obfuscating code to make it harder to reverse engineer","B. Automated testing that sends unexpected, malformed, or random inputs to an application to discover crashes, exceptions, and vulnerabilities","C. Testing application behavior under high concurrent user load","D. Blurring sensitive data in application screenshots for documentation"],correct:1,explanation:"Fuzzing (fuzz testing) generates large volumes of unexpected inputs (random, malformed, boundary values) and monitors the application for crashes, errors, or security issues. It is highly effective at finding memory safety issues and unexpected code paths."},
{id:794,domain:5,level:2,question:"What is a 'security baseline' in cloud configuration management?",options:["A. The minimum acceptable performance level for security tools","B. A documented set of minimum-security configuration requirements that all systems must meet before deployment","C. Historical security metrics used as a reference for anomaly detection","D. The initial security assessment before deploying cloud services"],correct:1,explanation:"A security baseline defines the minimum required configuration for systems: specific OS hardening settings, required agents, disabled services, firewall rules. All new systems must meet the baseline before production use, enforced via IaC templates or configuration management."},
{id:795,domain:6,level:2,question:"What is 'SOX' (Sarbanes-Oxley) and what are its cloud security implications?",options:["A. A US law governing financial reporting integrity with requirements for IT controls over financial data systems","B. An international security standard for financial institutions","C. A GDPR equivalent for US financial data","D. A cloud compliance framework for banking"],correct:0,explanation:"SOX requires public companies to maintain and attest to internal controls over financial reporting (ICFR). IT general controls — access management, change management, backup and recovery, and audit logging of financial systems — are key cloud compliance requirements under SOX."},
{id:796,domain:1,level:3,question:"What is 'sovereignty by design' in cloud architecture?",options:["A. Designing cloud systems that are owned by governments","B. Building cloud architectures that inherently satisfy data sovereignty requirements through technical controls, not just contractual promises","C. Ensuring cloud provider headquarters are in the customer's country","D. Using sovereign cloud regions for all data"],correct:1,explanation:"Sovereignty by design uses technical controls — encryption with customer-controlled keys, data residency enforcement, audit logging, and access controls — to enforce sovereignty requirements regardless of contractual or jurisdictional uncertainty."},
{id:797,domain:2,level:3,question:"What is 'data lineage' and why is it important for cloud security and compliance?",options:["A. The genealogy of data schema versions over time","B. The documented path data takes from origin through transformations to its current state, supporting impact analysis, compliance, and breach investigation","C. Tracking data ownership succession in an organization","D. The chain of custody for data in legal proceedings"],correct:1,explanation:"Data lineage tracks where data originated, how it was transformed, where it moved, and who accessed it. For compliance, it demonstrates data flows for GDPR Article 30 records. For security, it supports breach impact analysis (what data was exposed, what processing occurred)."},
{id:798,domain:3,level:3,question:"What is a 'supply chain attack on cloud infrastructure' and how does it differ from a traditional supply chain attack?",options:["A. They are identical since cloud is just hosted infrastructure","B. Cloud supply chain attacks target cloud provider dependencies (container base images, IaC modules, cloud-native libraries) that, if compromised, affect all customers using them at scale","C. Cloud supply chain attacks focus on physical hardware supply","D. Cloud supply chain attacks are less impactful due to provider isolation"],correct:1,explanation:"Cloud supply chain attacks target shared components — public Terraform modules, container base images, cloud provider SDKs — that, if compromised, propagate malicious code to all consumers simultaneously. The scale of impact is vastly greater than traditional single-organization supply chain attacks."},
{id:799,domain:4,level:3,question:"What is 'API gateway security' and what controls should it enforce?",options:["A. Physical security of API server hardware","B. A centralized enforcement point for authentication, authorization, rate limiting, input validation, and logging for API traffic","C. Encrypting API traffic at the gateway level only","D. A firewall rule set for API endpoint IP addresses"],correct:1,explanation:"API gateways provide a centralized security enforcement layer: authenticating callers (API keys, OAuth tokens, mTLS), authorizing requests, rate limiting (preventing abuse and DDoS), validating input schemas, logging all traffic, and routing to backend services."},
{id:800,domain:5,level:3,question:"What is 'cloud-native application protection platform' (CNAPP)?",options:["A. A cloud provider's native firewall platform","B. An integrated platform combining CSPM, CWPP, CIEM, and container/serverless security to protect cloud-native applications throughout the lifecycle","C. A SaaS application security testing platform","D. A compliance management platform for cloud applications"],correct:1,explanation:"CNAPP (Gartner) consolidates cloud security tooling: CSPM (configuration posture), CWPP (workload runtime protection), CIEM (identity entitlement), container image scanning, and IaC scanning into a unified platform providing lifecycle-wide visibility and protection."},
{id:801,domain:6,level:3,question:"What is 'ITAR' (International Traffic in Arms Regulations) and how does it affect cloud use?",options:["A. A US tax regulation on international cloud service imports","B. US regulations controlling export of defense-related technology and data, requiring cloud environments handling ITAR data to restrict access to US persons only","C. International trade regulations for cloud provider equipment","D. A NATO standard for classified cloud environments"],correct:1,explanation:"ITAR controls the export of defense articles and services. Cloud environments storing or processing ITAR-controlled technical data must restrict access to US persons, maintain detailed access logs, use US-based infrastructure, and ensure foreign nationals cannot access the data."},
{id:802,domain:1,level:1,question:"What is 'auto-scaling' in cloud computing?",options:["A. Automatically updating software on cloud instances","B. Automatically increasing or decreasing the number of running instances based on demand metrics","C. Scaling data storage automatically as data grows","D. Automatically migrating workloads between cloud providers"],correct:1,explanation:"Auto-scaling monitors metrics (CPU, request rate, queue depth) and automatically adjusts the number of running instances up or down to match demand. This maintains performance during peaks and reduces cost during low demand."},
{id:803,domain:2,level:1,question:"What is the purpose of 'digital signatures' in cloud security?",options:["A. Electronic equivalent of a handwritten signature for documents","B. Cryptographic proof of the signer's identity and integrity of the signed data, using asymmetric cryptography","C. Marking digital files with a watermark for tracking","D. Encrypting email attachments"],correct:1,explanation:"Digital signatures use the sender's private key to create a signature over a hash of the data. The recipient verifies with the sender's public key, confirming both the signer's identity and that the data has not been altered since signing."},
{id:804,domain:3,level:1,question:"What is 'multi-availability zone deployment' in cloud resilience?",options:["A. Deploying applications across multiple cloud providers","B. Distributing workloads across physically separated data centers within a region to survive single facility failures","C. Deploying to multiple geographic regions for global performance","D. Using multiple internet service providers for redundancy"],correct:1,explanation:"Availability zones (AZs) are physically separated data centers within a region with independent power, cooling, and networking. Multi-AZ deployments survive single AZ failures (hardware, power, networking) without service interruption."},
{id:805,domain:4,level:1,question:"What is 'least privilege' in application design?",options:["A. Using the cheapest cloud services for applications","B. Granting applications only the permissions they need to function, nothing more","C. Running applications as the root user to simplify deployment","D. Applying minimal security controls to applications in development"],correct:1,explanation:"Least privilege in application design means service accounts, application roles, and API permissions are scoped to exactly what the application requires. Over-privileged applications amplify the impact of compromise — a breached app with broad permissions causes more damage."},
{id:806,domain:5,level:1,question:"What is 'security awareness training'?",options:["A. Technical training for security operations center analysts","B. Programs educating all staff about security risks, policies, and their role in protecting the organization","C. Awareness campaigns for cloud provider security features","D. Training specifically for managers on security governance"],correct:1,explanation:"Security awareness training educates employees about phishing, social engineering, password hygiene, data handling, and reporting procedures. Human error is a leading cause of breaches, making awareness training one of the highest-ROI security investments."},
{id:807,domain:6,level:1,question:"What is 'consent withdrawal' under GDPR and how must organizations respond?",options:["A. Organizations can ignore consent withdrawal if data processing is already underway","B. Data subjects can withdraw consent at any time; organizations must cease processing and delete data unless another legal basis applies","C. Consent withdrawal requires a formal legal notice from the data subject","D. Withdrawal only applies to marketing communications"],correct:1,explanation:"GDPR Article 7(3) requires that withdrawal of consent be as easy as giving it and that processing cease upon withdrawal. If no other legal basis exists, data must be deleted. This must be technically implemented — withdrawal is not merely a policy right."},
{id:808,domain:1,level:2,question:"What is 'multi-tenancy' and what security isolation does it require?",options:["A. Multiple teams sharing a single cloud account","B. Multiple customers sharing the same underlying infrastructure, requiring logical isolation to prevent data leakage and resource interference","C. Using multiple cloud tenants for redundancy","D. A billing arrangement for shared cloud accounts"],correct:1,explanation:"Multi-tenancy is the architectural model where multiple customers share cloud infrastructure. Strong logical isolation (hypervisor, container runtime, networking, IAM) must prevent one tenant from accessing another's data, resources, or affecting their performance."},
{id:809,domain:2,level:2,question:"What is a 'data catalog' in cloud data governance?",options:["A. A marketing catalog of cloud data services","B. A centralized inventory of data assets with metadata (location, classification, owner, lineage, quality) enabling discovery and governance","C. A database of all company contacts","D. A list of approved data sources for analytics"],correct:1,explanation:"A data catalog provides a unified, searchable inventory of all data assets across cloud environments. It associates metadata (sensitivity classification, owner, retention policy, lineage) with data assets, enabling governance, compliance, and self-service data discovery."},
{id:810,domain:3,level:2,question:"What is 'DDoS mitigation' in cloud and how do providers address it?",options:["A. Blocking all inbound traffic during an attack","B. Cloud providers offer always-on traffic scrubbing, rate limiting, and absorb DDoS through scale, with optional managed DDoS protection services","C. Geographically blocking source countries during attacks","D. Upgrading to larger instances to absorb DDoS traffic"],correct:1,explanation:"Cloud DDoS mitigation uses traffic scrubbing centers, rate limiting, blackholing, and provider scale to absorb volumetric attacks. Managed services (AWS Shield Advanced, Azure DDoS Protection) add automatic detection, real-time monitoring, and cost protection."},
{id:811,domain:4,level:2,question:"What is 'API versioning' and why does it matter for security?",options:["A. Versioning API documentation for internal use","B. Maintaining multiple API versions allows deprecation of insecure old versions while giving consumers time to migrate to more secure versions","C. Tracking API performance versions for SLA compliance","D. Versioning API keys for rotation purposes"],correct:1,explanation:"API versioning enables gradual migration from old versions with security issues to new ones. Unversioned or legacy API versions often linger in production long after known vulnerabilities are patched in newer versions, creating unnecessary attack surface."},
{id:812,domain:5,level:2,question:"What is 'cloud security incident response plan' and how does it differ from traditional IR?",options:["A. It is identical to traditional IR since cloud is just infrastructure","B. Cloud IR must address provider-specific evidence collection, API-driven containment, ephemeral resource challenges, and multi-jurisdiction considerations","C. Cloud IR is simpler because providers handle all incidents","D. Cloud IR only covers SaaS application incidents"],correct:1,explanation:"Cloud IR adapts traditional plans for cloud specifics: using provider APIs for evidence collection (CloudTrail, VPC flow logs), containment through IAM policy changes and security group updates, handling ephemeral/auto-scaled resources, and coordinating with providers across jurisdictions."},
{id:813,domain:6,level:2,question:"What is the 'CLOUD Act' (US) and why is it significant for cloud data?",options:["A. Legislation creating the FedRAMP program","B. US law allowing US authorities to compel US cloud providers to provide data stored overseas, with mechanisms for international conflicts","C. An act establishing cloud provider liability for data breaches","D. A US law requiring cloud providers to store data in the US"],correct:1,explanation:"The Clarifying Lawful Overseas Use of Data Act (2018) enables US law enforcement to require US cloud providers to disclose data regardless of where it is stored. It includes executive agreement mechanisms for resolving conflicts with foreign laws protecting the same data."},
{id:814,domain:1,level:3,question:"What is 'workload identity' in cloud-native security?",options:["A. The identity assigned to a cloud account for billing purposes","B. Cryptographic identity assigned to workloads (pods, functions, VMs) for service-to-service authentication without using static credentials","C. The name assigned to a cloud workload in the management console","D. A role used by cloud administrators to manage workloads"],correct:1,explanation:"Workload identity (e.g., Kubernetes service accounts with OIDC, AWS EC2 instance profiles) provides automatically-rotated cryptographic credentials to workloads. This enables service-to-service authentication and authorization without static API keys or passwords."},
{id:815,domain:2,level:3,question:"What is 'homomorphic encryption's primary limitation in practical cloud deployments?",options:["A. It does not support asymmetric key algorithms","B. Computational overhead is orders of magnitude higher than standard encryption, making it impractical for most production workloads today","C. It cannot protect data in transit","D. Cloud providers do not support homomorphic encryption libraries"],correct:1,explanation:"Fully homomorphic encryption (FHE) is computationally expensive — operations on encrypted data are 10,000x to 1,000,000x slower than on plaintext, depending on the scheme. While improving, this overhead limits current use to niche, high-sensitivity scenarios."},
{id:816,domain:3,level:3,question:"What is 'runtime security' in container environments and why is it needed?",options:["A. Security controls applied during the container build process","B. Monitoring and enforcing policy on container behavior at runtime to detect and prevent unexpected activity not caught by static scanning","C. Running security tools inside containers","D. Security reviews conducted at application runtime intervals"],correct:1,explanation:"Runtime security (tools like Falco, Sysdig) monitors container syscalls, network connections, and file access at runtime, detecting anomalies like shell spawning in a web container, unexpected outbound connections, or cryptomining processes that wouldn't appear in image scans."},
{id:817,domain:4,level:3,question:"What is 'OAuth token leakage' and how can it be prevented?",options:["A. OAuth tokens expiring too quickly causing user session issues","B. Access tokens being exposed through logs, URLs, browser history, or insecure storage — mitigated by short expiry, PKCE, secure storage, and avoiding token in URLs","C. Tokens leaking memory in OAuth server implementations","D. Sharing OAuth tokens between applications for convenience"],correct:1,explanation:"OAuth tokens in URLs can be logged by servers, proxies, and browser history. Tokens in logs expose API access. Mitigations: use Authorization headers not URL params; implement PKCE for public clients; keep expiry short; use secure, httpOnly cookies for token storage."},
{id:818,domain:5,level:3,question:"What is 'threat-informed defense' and how does MITRE ATT&CK enable it?",options:["A. Defense strategies based on threat actor declarations","B. Prioritizing defensive investments based on real-world adversary TTPs documented in ATT&CK to maximize effectiveness against likely attacks","C. Hiring former threat actors as security consultants","D. A defensive posture informed by threat intelligence subscriptions"],correct:1,explanation:"Threat-informed defense uses ATT&CK to understand which adversary techniques are used against organizations like yours, maps current detection/prevention coverage against those techniques, and prioritizes closing gaps most likely to be exploited by relevant threats."},
{id:819,domain:6,level:3,question:"What is 'contractual data protection' and when is it the only transfer mechanism available?",options:["A. Using encryption in contracts","B. Using Standard Contractual Clauses, BCRs, or bespoke contractual clauses as the legal basis for international data transfers when no adequacy decision exists","C. Protecting contracts themselves as personal data","D. Data protection clauses in employment contracts"],correct:1,explanation:"When no adequacy decision covers a destination country and BCRs are not in place, SCCs (or country-specific equivalents) are the primary contractual transfer mechanism. They impose GDPR-equivalent obligations on the data importer, providing legal basis for the transfer."},
{id:820,domain:1,level:1,question:"What is 'SLA' (Service Level Agreement) in cloud computing?",options:["A. A legal contract specifying the provider's privacy obligations","B. A commitment specifying the level of service (availability, performance) and remedies if not met","C. A technical document describing cloud architecture","D. A security certification issued by cloud providers"],correct:1,explanation:"An SLA is a contractual commitment between a cloud provider and customer specifying expected service quality (e.g., 99.9% uptime), measurement methods, and remedies (service credits) when the provider fails to meet the agreed levels."},
{id:821,domain:2,level:1,question:"What is 'role-based access control' (RBAC)?",options:["A. Controlling access based on the user's physical role in the office","B. Granting permissions to roles rather than individuals, then assigning users to roles based on their job function","C. Controlling access based on resource sensitivity ratings","D. A control limiting role definitions to senior management approval"],correct:1,explanation:"RBAC assigns permissions to roles (e.g., Admin, Read-Only, Developer) and then assigns users to roles. This simplifies management: changes to a role propagate to all users in that role. It enforces least privilege by aligning access with job functions."},
{id:822,domain:3,level:1,question:"What is 'availability zone' in cloud infrastructure?",options:["A. A geographic zone where cloud services are available","B. A physically isolated data center within a region with independent power, cooling, and networking","C. A time zone configuration for cloud resource scheduling","D. A zone where specific cloud services are available for purchase"],correct:1,explanation:"Availability zones are physically separated data centers within a cloud region. By distributing workloads across multiple AZs, applications can survive a single AZ failure. AZs are connected by low-latency, high-bandwidth private networks."},
{id:823,domain:4,level:1,question:"What is 'HTTP Strict Transport Security' (HSTS)?",options:["A. A firewall rule requiring HTTPS for web applications","B. An HTTP response header instructing browsers to only connect via HTTPS for a specified period, preventing protocol downgrade attacks","C. A server configuration requiring HTTP connections to be encrypted","D. A TLS certificate type for high-security web applications"],correct:1,explanation:"HSTS tells browsers that a site must only be accessed over HTTPS. After the first HTTPS visit, browsers refuse to connect over HTTP for the HSTS duration, preventing SSL stripping and downgrade attacks."},
{id:824,domain:5,level:1,question:"What is 'backup and recovery' in cloud security operations?",options:["A. Backing up security tools and configurations","B. Regularly copying data and systems to enable restoration after data loss, ransomware, or corruption","C. Recovery procedures for failed security controls","D. Backup internet connections for cloud management access"],correct:1,explanation:"Backup and recovery ensures data and system availability. Backups must be regular, tested (recovery validation), stored securely (encrypted, access-controlled), and geographically separated from production to survive regional failures or ransomware."},
{id:825,domain:6,level:1,question:"What is 'data portability' in GDPR and how does it differ from the right to access?",options:["A. They are the same right with different names","B. Data access provides a copy to the individual; data portability provides it in machine-readable format to enable transfer to another service provider","C. Data portability only applies to health data","D. Access provides all data; portability only covers recently created data"],correct:1,explanation:"The right to access (Article 15) gives individuals a copy of their data. The right to portability (Article 20) goes further: data must be in a structured, machine-readable format (e.g., CSV, JSON) that enables re-use with another provider, facilitating switching."},
{id:826,domain:1,level:2,question:"What is 'DevSecOps' and how does it change the security model?",options:["A. A security team that follows developers to review code","B. Integrating security practices and tooling throughout the development and operations lifecycle rather than treating it as a separate phase at the end","C. A DevOps team with a dedicated security person","D. Automating security audits after each deployment"],correct:1,explanation:"DevSecOps ('shift left') integrates security into every phase: threat modeling in design, SAST/SCA in development, security gates in CI/CD, runtime monitoring in production. It makes security everyone's responsibility and finds issues earlier when they are cheaper to fix."},
{id:827,domain:2,level:2,question:"What is 'sensitive data discovery' in cloud security?",options:["A. Identifying cloud regions storing sensitive data for cost optimization","B. Automated scanning of cloud storage, databases, and data streams to locate and classify sensitive data (PII, PHI, PCI)","C. Discovering new sensitive data regulations applicable to the organization","D. Finding sensitive data in backup archives"],correct:1,explanation:"Sensitive data discovery tools scan cloud environments (S3 buckets, databases, data lakes) using pattern matching and ML to identify and classify sensitive data. This drives remediation of improperly protected data and supports data governance."},
{id:828,domain:3,level:2,question:"What is 'privileged access management' (PAM) in cloud?",options:["A. Managing privileged cloud accounts in a spreadsheet","B. Solutions that control, monitor, and audit privileged access to cloud systems through vaulted credentials, session recording, and just-in-time access","C. Access management for premium cloud service tiers","D. Automated privilege escalation for authorized maintenance"],correct:1,explanation:"PAM solutions vault privileged credentials (root keys, admin passwords), inject them into sessions without revealing them, record all privileged sessions, enforce MFA, and provide just-in-time access (provisioned on-demand, revoked when done), dramatically reducing insider threat and credential theft risks."},
{id:829,domain:4,level:2,question:"What is 'software bill of materials' (SBOM) and why is it important for cloud application security?",options:["A. A bill for software licensing costs in cloud","B. A formal inventory of all software components in an application, enabling rapid identification of vulnerable dependencies when new CVEs are disclosed","C. A list of approved software for cloud deployments","D. A manifest of cloud services used by an application"],correct:1,explanation:"An SBOM is a machine-readable list of all open-source and proprietary components (with versions) in an application. When a new CVE is published, SBOMs enable instant identification of affected applications, dramatically accelerating vulnerability response."},
{id:830,domain:5,level:2,question:"What is 'network traffic analysis' (NTA) in cloud security monitoring?",options:["A. Analyzing cloud provider network performance metrics","B. Monitoring and analyzing network flow data and full packet captures to detect anomalies, lateral movement, and data exfiltration","C. Analyzing DNS traffic costs","D. Traffic analysis for cloud networking capacity planning"],correct:1,explanation:"NTA tools (using VPC flow logs, DNS logs, or mirrored traffic) apply behavioral analytics to detect anomalies: unusual volumes, new connections between previously isolated segments, DNS tunneling, or large outbound data transfers indicating exfiltration."},
{id:831,domain:6,level:2,question:"What is the purpose of 'incident notification' requirements in data protection regulations?",options:["A. Notifying the press about data breaches","B. Requiring organizations to notify regulators and affected individuals within defined timeframes to enable response and minimize harm","C. Notifying cloud providers about incidents affecting shared infrastructure","D. Internal escalation procedures for data security events"],correct:1,explanation:"Breach notification requirements (GDPR: 72 hours to supervisory authority, without undue delay to data subjects; HIPAA: 60 days to HHS and individuals) ensure regulators can coordinate responses and individuals can protect themselves from harm resulting from their exposed data."},
{id:832,domain:1,level:3,question:"What is 'cloud security maturity model' and how is it used?",options:["A. A model assessing cloud provider security certification level","B. A framework for assessing and improving an organization's cloud security practices across defined dimensions and capability levels","C. A maturity model for cloud provider selection","D. A scoring system for cloud application vulnerability management"],correct:1,explanation:"Cloud security maturity models (e.g., CSA CMM, C2M2) assess organizational capability across domains (governance, risk, identity, data, operations) on a maturity scale. They identify gaps, benchmark against peers, and guide a prioritized improvement roadmap."},
{id:833,domain:2,level:3,question:"What is 'quantum-resistant' (post-quantum) cryptography and why is it a cloud concern?",options:["A. Cryptography that runs on quantum computers","B. Algorithms designed to resist attacks by quantum computers that could break current RSA and ECC encryption, threatening long-term data confidentiality","C. Encryption using quantum key distribution","D. Cloud provider investments in quantum computing hardware"],correct:1,explanation:"Quantum computers running Shor's algorithm could break RSA and ECC. 'Harvest now, decrypt later' attacks already store encrypted data to decrypt when quantum computers mature. NIST has standardized post-quantum algorithms (ML-KEM, ML-DSA) for migration planning."},
{id:834,domain:3,level:3,question:"What is 'Kubernetes RBAC' and why is it critical for cluster security?",options:["A. Role-based access for managing Kubernetes billing","B. The Kubernetes authorization mechanism controlling which users and service accounts can perform which actions on which resources","C. A network policy for controlling pod-to-pod communication","D. RBAC for the container registry storing Kubernetes images"],correct:1,explanation:"Kubernetes RBAC defines Roles (namespaced) and ClusterRoles (cluster-wide) with allowed verbs (get, list, create, delete) on resources. Misconfigured RBAC — overly broad permissions or cluster-admin bindings — is a leading Kubernetes security risk enabling privilege escalation."},
{id:835,domain:4,level:3,question:"What is 'API rate limiting' and what attacks does it prevent?",options:["A. Limiting the number of API endpoints an application can expose","B. Controlling the rate of API requests per client to prevent credential stuffing, brute force, scraping, and denial of service via API abuse","C. Limiting API response payload size","D. Rate limiting API deployment frequency"],correct:1,explanation:"API rate limiting restricts how many requests a client can make in a time window. It prevents credential stuffing (thousands of login attempts), brute-force attacks on tokens, automated data scraping, and API-layer DoS attacks that exhaust backend resources."},
{id:836,domain:5,level:3,question:"What is 'cloud kill chain' and how does it extend the Cyber Kill Chain for cloud environments?",options:["A. A chain of cloud services that can be shut down during an incident","B. An adapted attack chain model for cloud-specific stages: initial access via APIs/credentials, cloud-native persistence (IAM roles, Lambda), and cloud-specific exfiltration paths","C. A chain of approvals for terminating cloud resources during incidents","D. The kill chain used by cloud providers to respond to attacks on their infrastructure"],correct:1,explanation:"The cloud kill chain adapts Lockheed Martin's Cyber Kill Chain for cloud-specific attack patterns: initial access via exposed APIs, stolen IAM credentials, or SSRF; lateral movement through IAM privilege escalation; persistence via new IAM roles; collection from cloud storage; and exfiltration to external buckets."},
{id:837,domain:6,level:3,question:"What is 'privacy engineering' and how does it differ from privacy compliance?",options:["A. Engineering privacy-focused products for consumers","B. Technical implementation of privacy principles (data minimization, purpose limitation, access control) into system design, not just documentation of compliance","C. Privacy compliance with an engineering background","D. A software engineering discipline for building privacy tools"],correct:1,explanation:"Privacy engineering translates privacy principles into technical design decisions: minimizing data collected, partitioning data stores, building deletion workflows, implementing access controls by default, and designing systems that cannot retain more data than needed. Compliance is the documentation; engineering is the implementation."},
{id:838,domain:1,level:1,question:"What is 'cloud region' in cloud infrastructure?",options:["A. A geographic area where cloud services are marketed","B. A specific geographic location containing multiple isolated availability zones where a cloud provider operates infrastructure","C. A regulatory jurisdiction governing cloud services","D. A content delivery network edge location"],correct:1,explanation:"A cloud region is a specific geographic location (e.g., us-east-1, eu-west-1) where a provider operates clusters of availability zones. Regions are isolated from each other, and data does not automatically cross region boundaries, supporting data residency requirements."},
{id:839,domain:2,level:1,question:"What is 'full disk encryption' (FDE) and how does it protect cloud data at rest?",options:["A. Encrypting the entire database including schema and metadata","B. Encrypting all data on a storage volume at the block level, protecting data if the physical media is accessed without the encryption key","C. Encrypting only sensitive files while leaving the OS unencrypted","D. Encrypting disks before they are physically shipped to customers"],correct:1,explanation:"FDE encrypts the entire storage volume (all data, system files, and metadata) at the block level. In cloud, provider-managed FDE protects against physical disk theft but does not protect against logical access using the cloud management plane."},
{id:840,domain:3,level:1,question:"What is a 'firewall' in cloud security?",options:["A. A physical wall protecting cloud data centers from fire","B. A network security device or service that monitors and controls incoming and outgoing network traffic based on predefined rules","C. Software preventing unauthorized software installations","D. A backup power system for cloud networking equipment"],correct:1,explanation:"A firewall filters network traffic based on rules (allow/deny) by source/destination IP, port, and protocol. In cloud, native firewalls (security groups, NACLs, cloud-native next-gen firewalls) protect VPC resources from unauthorized access."},
{id:841,domain:4,level:1,question:"What is 'SSL/TLS pinning' bypass and why is it a security concern?",options:["A. Attackers can bypass TLS by using older SSL versions","B. Mobile/native apps using certificate pinning can be reverse-engineered to remove pins, allowing MITM attacks during dynamic analysis or in production","C. TLS pinning can be bypassed by invalidating the CA certificate","D. Pinning bypass allows attackers to reuse expired certificates"],correct:1,explanation:"Certificate pinning in mobile apps can be bypassed using tools like Frida or by patching the app binary to remove pinning checks. This allows MITM attacks to intercept and modify traffic. Regular pinning updates and integrity checks help resist bypass."},
{id:842,domain:5,level:1,question:"What is 'patch Tuesday' and why is it relevant to cloud security?",options:["A. The day cloud providers release new services","B. Microsoft's monthly schedule for releasing security updates — relevant for patching Windows-based cloud workloads promptly","C. A weekly cloud security briefing","D. The deadline for cloud compliance reporting"],correct:1,explanation:"Microsoft releases security patches on the second Tuesday of each month. Cloud customers running Windows workloads must have processes to apply Patch Tuesday updates promptly, as vulnerabilities become public knowledge on release day, increasing exploitation attempts."},
{id:843,domain:6,level:1,question:"What is 'information security governance'?",options:["A. Technical management of information security tools","B. The system of oversight ensuring information security strategy aligns with business objectives through policies, accountability, and resource allocation","C. Government regulation of information security","D. A framework for auditing cloud security controls"],correct:1,explanation:"Information security governance establishes leadership accountability, strategic direction, policies, frameworks, and measurement for security. It ensures security investments are aligned with business risk and that accountability for security outcomes is clear."},
{id:844,domain:1,level:2,question:"What is 'hybrid cloud security' and what makes it more complex than pure public or private cloud?",options:["A. Security is easier because you can choose the most secure environment for each workload","B. Consistent policy enforcement across environments with different controls, managing connectivity security, and maintaining visibility across both environments","C. Hybrid cloud has identical security to on-premises","D. Security is simpler because data never leaves the private cloud"],correct:1,explanation:"Hybrid cloud complexity stems from: enforcing consistent security policies across environments with different native controls, securing the connectivity between them (VPN, Direct Connect), maintaining unified visibility and logging, and managing identity federation across both environments."},
{id:845,domain:2,level:2,question:"What is 'object storage security' and what misconfigurations commonly lead to breaches?",options:["A. Securing physical objects stored in data centers","B. Access control for cloud object storage (S3, GCS, Azure Blob), with public bucket exposure being the most common breach cause","C. Encrypting object metadata in storage buckets","D. Security for object-oriented programming language data storage"],correct:1,explanation:"Object storage (S3, GCS) misconfigurations — public bucket/object ACLs, overly permissive bucket policies, missing encryption, no access logging — have caused many major breaches. Key controls: block public access by default, enable versioning, enforce encryption, and log all access."},
{id:846,domain:3,level:2,question:"What is 'cloud identity federation' and how does it work?",options:["A. Federating multiple cloud providers under one bill","B. Establishing trust between an identity provider (IdP) and cloud services so users can authenticate once and access multiple cloud resources using their existing credentials","C. Combining multiple identities into a single cloud account","D. A federation of cloud providers sharing identity data"],correct:1,explanation:"Identity federation (using SAML, OIDC, or OAuth) allows users to authenticate via a trusted IdP (corporate directory, social login) and receive tokens granting access to cloud resources, enabling SSO without creating cloud-native accounts for each user."},
{id:847,domain:4,level:2,question:"What is 'container image scanning' and at what stages should it be performed?",options:["A. Scanning containers for regulatory compliance labels","B. Analyzing container images for known CVEs, malware, hardcoded secrets, and misconfigurations — in CI/CD, at registry push, and continuously in registries","C. Scanning container network traffic at runtime","D. Image quality verification for container documentation"],correct:1,explanation:"Container image scanning should occur in CI (blocking vulnerable builds), at registry ingestion (scanning pushed images), and continuously in registries (catching newly disclosed CVEs affecting images already stored). Tools include Trivy, Clair, Snyk, and provider-native scanners."},
{id:848,domain:5,level:2,question:"What is 'security orchestration' in SOAR platforms?",options:["A. Coordinating multiple security teams on a single incident","B. Automating the flow of security data and actions across integrated tools to coordinate detection, enrichment, and response without manual intervention","C. Orchestrating container deployments with security controls","D. Managing security tool procurement and licensing"],correct:1,explanation:"Security orchestration connects SIEM, threat intel, ticketing, and response tools into automated workflows. When an alert fires, orchestration automatically enriches it (WHOIS lookup, threat intel check), creates a ticket, and triggers response actions — reducing time and manual effort."},
{id:849,domain:6,level:2,question:"What is 'data transfer impact assessment' under SCHREMS II?",options:["A. A cost-benefit analysis for cloud data transfer pricing","B. A case-by-case assessment evaluating whether SCCs provide effective protection for data transferred to countries without adequacy decisions, especially the US","C. An assessment of cloud bandwidth for international data transfers","D. A GDPR requirement for all cross-border data flows regardless of destination"],correct:1,explanation:"Following Schrems II (invalidating Privacy Shield), organizations transferring data to non-adequate countries using SCCs must conduct a Transfer Impact Assessment (TIA) evaluating the destination country's surveillance laws and whether additional technical safeguards (e.g., encryption) are needed."},
{id:850,domain:1,level:3,question:"What is the difference between 'cloud security' and 'security in the cloud'?",options:["A. They are the same concept","B. Cloud security addresses securing cloud infrastructure and services themselves; security in the cloud uses cloud-delivered security tools to protect any environment","C. Security in the cloud only protects cloud workloads; cloud security protects on-premises","D. Cloud security is provider responsibility; security in the cloud is customer responsibility"],correct:1,explanation:"'Security of the cloud' (cloud security) is the provider's responsibility: securing physical infrastructure, hypervisors, and cloud services. 'Security in the cloud' uses cloud-hosted security services (SIEM-as-a-service, cloud WAF) to protect any environment — cloud or on-premises."},
{id:851,domain:2,level:3,question:"What is 'zero-knowledge proof' (ZKP) and what cloud use case does it enable?",options:["A. A cryptographic protocol proving knowledge of a secret without revealing it, enabling privacy-preserving authentication and verification","B. A proof that data was deleted with zero knowledge of its original content","C. Zero-knowledge architecture where the provider cannot access customer data","D. A proof-of-concept for zero-trust architectures"],correct:0,explanation:"ZKPs allow one party to prove to another that they know a value without revealing the value itself. Cloud use cases include privacy-preserving authentication (proving age/identity without revealing personal data) and compliance attestation (proving requirements are met without exposing sensitive data)."},
{id:852,domain:3,level:3,question:"What is 'pod security admission' in Kubernetes?",options:["A. Controlling who can connect to a Kubernetes cluster","B. An admission controller enforcing security standards on pods (e.g., preventing privileged containers, host namespace access, hostPath mounts)","C. Managing security certificates for Kubernetes API admission","D. A gating mechanism for deploying new pods to production"],correct:1,explanation:"Pod Security Admission (replacing PodSecurityPolicy) enforces security standards at admission time: Privileged (unrestricted), Baseline (minimal restrictions), and Restricted (hardened). It prevents dangerous configurations like privileged containers and host network access from being deployed."},
{id:853,domain:4,level:3,question:"What is 'GraphQL security' and what unique risks does GraphQL introduce?",options:["A. Security for graph database queries","B. GraphQL's flexible query model introduces risks including introspection exposure, deeply nested queries causing DoS, and over-fetching sensitive fields","C. Security for graph-based machine learning models","D. A security standard for API graph topology"],correct:1,explanation:"GraphQL allows clients to specify exactly what data they need, but this flexibility introduces risks: introspection (exposing full API schema), unbounded query depth/complexity causing DoS, batching attacks, and field-level authorization bypasses where nested objects expose unauthorized data."},
{id:854,domain:5,level:3,question:"What is 'insider threat detection' in cloud environments?",options:["A. Detecting external threats that have moved inside the network perimeter","B. Identifying malicious or negligent actions by employees, contractors, or privileged users through behavioral analytics, data access monitoring, and anomaly detection","C. Hiring insiders at cloud providers to detect threats","D. Detecting threats originating from inside containers"],correct:1,explanation:"Insider threat detection monitors privileged user behavior: unusual data downloads, accessing data outside job function, after-hours activity, mass deletions, or attempted privilege escalation. UEBA tools establish baselines and flag deviations for investigation."},
{id:855,domain:6,level:3,question:"What is 'legitimate interest' as a GDPR legal basis and when should it be used for cloud processing?",options:["A. Any business reason qualifies as legitimate interest","B. A balancing test where the controller's genuine interest must be weighed against the data subject's rights and freedoms — not a default fallback when consent is unavailable","C. Legitimate interest only applies to marketing use cases","D. Legitimate interest cannot be used for cloud-based processing"],correct:1,explanation:"Legitimate interest (Article 6(1)(f)) requires three conditions: a legitimate purpose; processing must be necessary; the interest must not be overridden by data subjects' rights. A legitimate interest assessment (LIA) must document this balance. It is not a weak fallback for processing that should be based on consent."},
{id:856,domain:1,level:1,question:"What is a 'cloud provider'?",options:["A. An organization that resells cloud services on behalf of hyperscalers","B. An organization that makes cloud computing resources available to customers as a service","C. A company that audits cloud deployments for compliance","D. A managed security service provider specializing in cloud"],correct:1,explanation:"A cloud service provider (CSP) is an organization that provides cloud computing services (IaaS, PaaS, SaaS) to consumers. Major providers include AWS, Microsoft Azure, and Google Cloud."},
{id:857,domain:2,level:1,question:"What is 'encryption key' in cryptography?",options:["A. A physical key for accessing cloud data centers","B. A piece of data used by an encryption algorithm to transform plaintext into ciphertext and vice versa","C. A unique identifier for cloud storage objects","D. A license key for encryption software"],correct:1,explanation:"An encryption key is the input to a cipher algorithm that determines the transformation of data. The security of encrypted data depends on key secrecy — the algorithm may be public, but the key must be protected."},
{id:858,domain:3,level:1,question:"What is 'egress traffic' in cloud networking?",options:["A. Traffic entering the cloud network from external sources","B. Traffic leaving the cloud network to external destinations","C. Internal traffic between cloud resources","D. Traffic between cloud provider data centers"],correct:1,explanation:"Egress traffic is data leaving a cloud environment to external networks (internet, on-premises). Monitoring and controlling egress is important for detecting data exfiltration and managing cloud costs (many providers charge for egress)."},
{id:859,domain:4,level:1,question:"What is 'code review' in the context of application security?",options:["A. Reviewing software licensing compliance","B. Manual or automated examination of source code to identify security vulnerabilities, logic flaws, and deviations from secure coding practices","C. Reviewing performance metrics from deployed code","D. Auditing cloud provider source code for backdoors"],correct:1,explanation:"Security-focused code review examines source code for vulnerabilities (injection flaws, hardcoded secrets, insecure cryptography, missing authorization checks). Peer review and automated SAST provide complementary coverage."},
{id:860,domain:5,level:1,question:"What is 'two-person rule' (dual control) in privileged access?",options:["A. Two passwords required to log in to any system","B. Requiring two authorized individuals to complete sensitive operations so no single person has unilateral control","C. Two-factor authentication requirement for all privileged accounts","D. Having two security analysts review every alert"],correct:1,explanation:"The two-person rule (dual control) requires two authorized persons to be present for sensitive operations (nuclear launch, HSM key ceremony, large financial transfers). It prevents insider abuse by ensuring no single individual can complete the action alone."},
{id:861,domain:6,level:1,question:"What is 'risk treatment' in information security risk management?",options:["A. Medical treatment for security professionals experiencing stress","B. Deciding how to handle identified risks: accept, avoid, transfer, or mitigate","C. Treating security findings as incidents requiring response","D. Applying automated security controls to reduce risk automatically"],correct:1,explanation:"Risk treatment options: Accept (acknowledge risk is within tolerance), Avoid (eliminate the activity creating risk), Transfer (shift to insurer or third party), Mitigate/Reduce (apply controls to lower likelihood or impact). The choice depends on cost vs. risk appetite."},
{id:862,domain:1,level:2,question:"What is 'observability' in cloud-native operations and why does it matter for security?",options:["A. The ability to observe cloud infrastructure from any location","B. Understanding internal system state from external outputs (logs, metrics, traces) — enabling rapid detection of anomalies and faster incident diagnosis","C. Compliance monitoring visibility for auditors","D. Cloud provider transparency about infrastructure operations"],correct:1,explanation:"Observability (logs, metrics, distributed traces) provides deep insight into system behavior. For security, it enables anomaly detection, performance-based attack identification (DDoS, resource exhaustion), forensic analysis, and faster mean time to detect/respond."},
{id:863,domain:2,level:2,question:"What is 'tokenization vs encryption' trade-off for protecting payment data?",options:["A. Encryption is always preferable for payment data","B. Tokenization removes card data from scope entirely (tokens have no value if stolen); encryption keeps data in scope requiring key management and protecting ciphertext","C. They provide identical security and compliance outcomes","D. Tokenization is only suitable for development/test environments"],correct:1,explanation:"Tokenization replaces card data with opaque tokens — if stolen, tokens are valueless without the vault. This removes data from PCI DSS scope. Encrypted card data remains in scope (the ciphertext must be protected). Tokenization simplifies compliance; encryption provides more flexibility."},
{id:864,domain:3,level:2,question:"What is 'ingress traffic' filtering in cloud security?",options:["A. Filtering mail delivery for cloud-related phishing","B. Controlling and inspecting traffic entering a cloud environment to block malicious requests before they reach internal resources","C. Filtering data entering cloud storage buckets","D. Controlling user ingress to cloud management consoles"],correct:1,explanation:"Ingress filtering (via security groups, NACLs, WAFs, network firewalls) inspects and controls inbound traffic at the network boundary, blocking malicious requests (known bad IPs, attack patterns, unauthorized ports) before they reach application workloads."},
{id:865,domain:4,level:2,question:"What is 'XML External Entity' (XXE) vulnerability?",options:["A. Malformed XML causing application crashes","B. An attack where XML parsers process external entity references in untrusted XML input, potentially reading local files, performing SSRF, or executing code","C. Cross-site scripting using XML content type","D. XML schema validation failures exposing error details"],correct:1,explanation:"XXE attacks exploit XML parsers that process external entity declarations in user-supplied XML. Attackers can use XXE to read server-side files (/etc/passwd, application configs), perform SSRF, or in some cases achieve RCE. Mitigation: disable external entity processing in parsers."},
{id:866,domain:5,level:2,question:"What is 'cloud access logging' and what events should be captured?",options:["A. Logging cloud resource costs for billing transparency","B. Recording all API calls and management plane activities including who made them, when, from where, and what changes were made","C. Logging only failed authentication attempts","D. Application-level access logging within cloud-hosted applications"],correct:1,explanation:"Cloud access logging (CloudTrail, Azure Activity Log, GCP Audit Logs) captures every API call: identity, timestamp, source IP, action, resource, and result. This is essential for detecting unauthorized changes, privilege abuse, and supporting forensic investigation."},
{id:867,domain:6,level:2,question:"What is 'records of processing activities' (RoPA) under GDPR Article 30?",options:["A. Records of all security incidents involving personal data","B. A required register documenting each processing activity: purposes, data categories, recipients, retention periods, and security measures","C. Financial records of data processing costs","D. Technical logs of all data processing operations"],correct:1,explanation:"RoPA (Article 30) requires controllers and processors to maintain a written register of processing activities. It documents what personal data is processed, why, who has access, where it flows, and how long it is kept — essential for demonstrating GDPR compliance."},
{id:868,domain:1,level:3,question:"What is 'cloud security posture' and how is it measured?",options:["A. The physical security posture of cloud data centers","B. The overall security state of cloud infrastructure based on configuration compliance, risk exposure, and adherence to security best practices across all cloud resources","C. Security rating assigned by cloud providers to customer accounts","D. The organization's defensive posture against cloud-specific threats"],correct:1,explanation:"Cloud security posture measures configuration compliance (misconfigurations, policy violations), identity risk (excessive permissions), network exposure (open ports, public resources), and vulnerability status across all cloud accounts and services. CSPM tools continuously measure and score posture."},
{id:869,domain:2,level:3,question:"What is 'key ceremony' in cryptographic key management?",options:["A. A ritual for decommissioning old encryption keys","B. A formal, witnessed procedure for generating or splitting master cryptographic keys in a secure environment with documented chain of custody","C. The initial ceremony when a new KMS is deployed","D. A compliance ritual for rotating encryption keys annually"],correct:1,explanation:"A key ceremony is a highly controlled process (often in a Faraday cage, with multiple witnesses) for generating, splitting, or loading master keys into HSMs. Every action is documented, witnessed, and audited to ensure the key material was never exposed and the process has integrity."},
{id:870,domain:3,level:3,question:"What is 'lateral movement' in cloud attacks and how does it differ from on-premises lateral movement?",options:["A. Moving physical servers between cloud regions","B. Attackers progressing from an initial foothold to additional resources via IAM privilege escalation, instance metadata abuse, or exploiting overpermissive service accounts — often without network scanning","C. Lateral movement requires network access in cloud just as on-premises","D. Cloud's network isolation makes lateral movement impossible"],correct:1,explanation:"Cloud lateral movement exploits IAM: using stolen credentials/tokens to assume roles, escalating privileges via misconfigured policies, abusing instance metadata for credentials, or using overprivileged service accounts. It often requires no network scanning, making it harder to detect with traditional network-based controls."},
{id:871,domain:4,level:3,question:"What is 'security-by-default' and how should it be implemented in cloud application deployment?",options:["A. All cloud security features are enabled by default by providers","B. Systems ship with the most secure settings enabled; less secure options require explicit opt-in rather than secure settings requiring explicit enablement","C. Security features default to the provider's security team","D. Default cloud configurations are inherently secure"],correct:1,explanation:"Security-by-default means deploying with maximum security out of the box: MFA required, public access blocked, encryption enabled, verbose logging on, minimal permissions. Deliberately less-secure configurations (public buckets, anonymous access) require explicit affirmative action."},
{id:872,domain:5,level:3,question:"What is 'cloud forensics framework' challenges compared to traditional digital forensics?",options:["A. Cloud forensics is easier because all evidence is digital","B. Challenges include shared tenancy (evidence isolation), ephemeral resources (destroyed evidence), provider dependency (access to logs/images), multi-jurisdiction, and chain of custody for cloud-held evidence","C. Cloud providers fully support forensic investigations at no cost","D. Traditional forensic tools work unchanged in cloud environments"],correct:1,explanation:"Cloud forensics faces unique challenges: ephemeral instances destroyed on termination (auto-scaling), multi-tenant environments requiring provider cooperation, data spanning multiple jurisdictions, difficulty establishing chain of custody for cloud-held evidence, and reliance on provider APIs rather than direct media access."},
{id:873,domain:6,level:3,question:"What is 'CCPA' (California Consumer Privacy Act) and how does it compare to GDPR?",options:["A. A US federal privacy law equivalent to GDPR","B. A California state privacy law providing similar rights (access, deletion, opt-out of sale) but with different scope, thresholds, and enforcement than GDPR","C. A federal US law preempting state privacy laws","D. A California law governing data center operations"],correct:1,explanation:"CCPA (effective 2020, amended by CPRA) grants California residents rights to know, delete, and opt-out of sale of personal information. Compared to GDPR: CCPA applies to businesses meeting revenue/data thresholds; GDPR is broader (any processing of EU residents); GDPR has stricter consent requirements; CCPA has a private right of action for breaches."},
{id:874,domain:1,level:1,question:"What is 'cloud bursting' primarily used for?",options:["A. Overloading a competitor's cloud infrastructure","B. Extending private cloud capacity into public cloud during peak demand periods","C. Rapidly deploying cloud resources after a disaster","D. Bursting network bandwidth for large file transfers"],correct:1,explanation:"Cloud bursting is a hybrid cloud pattern where an application normally runs on-premises or in a private cloud but automatically provisions additional capacity in a public cloud when demand exceeds private infrastructure capacity, then decommissions those resources when demand drops."},
{id:875,domain:2,level:1,question:"What is 'data integrity' in cloud security?",options:["A. Ensuring cloud data is legally compliant","B. The assurance that data has not been altered or corrupted without authorization","C. Keeping data integrated across multiple cloud regions","D. Maintaining data quality through automated cleansing"],correct:1,explanation:"Data integrity ensures data remains accurate and unaltered from its original or last authorized state. Cryptographic hashing, checksums, digital signatures, and access controls protect integrity. Detecting integrity violations is critical for detecting tampering or corruption."},
{id:876,domain:3,level:1,question:"What is 'ingress controller' in Kubernetes security?",options:["A. A physical device controlling server room access","B. A Kubernetes component managing external access to services, typically HTTP/S traffic, enforcing routing rules and TLS termination","C. A Kubernetes admission controller for security policy","D. A controller managing container image ingress from registries"],correct:1,explanation:"An ingress controller (e.g., NGINX Ingress, Traefik) manages inbound HTTP/S access to Kubernetes services based on Ingress resource rules. Security considerations include TLS termination, authentication offloading, rate limiting, and WAF integration."},
{id:877,domain:4,level:1,question:"What is 'penetration testing' (pen test)?",options:["A. Testing application performance under load","B. Authorized simulated attacks on systems to discover exploitable vulnerabilities before real attackers find them","C. Automated vulnerability scanning using tools","D. Testing network penetration speed and latency"],correct:1,explanation:"Penetration testing is authorized, simulated attacks by security professionals attempting to exploit vulnerabilities in systems, applications, or networks. Unlike automated scanning, pen testers chain vulnerabilities and think creatively like real attackers."},
{id:878,domain:5,level:1,question:"What is 'SIEM alert tuning' and why is it important?",options:["A. Adjusting SIEM hardware for optimal performance","B. Refining detection rules and thresholds to reduce false positives while maintaining sensitivity to real threats","C. Tuning SIEM storage settings for log retention","D. Adjusting SIEM licensing tiers based on log volume"],correct:1,explanation:"SIEM alert tuning balances sensitivity (catching real threats) against specificity (avoiding false positives). Excessive false positives cause alert fatigue, causing analysts to miss real threats. Continuous tuning based on environment-specific baselines is essential for effective SOC operations."},
{id:879,domain:6,level:1,question:"What is 'risk register' in information security management?",options:["A. A list of all security vendors and their risk ratings","B. A documented inventory of identified risks including their description, likelihood, impact, owner, and current treatment status","C. A register of all security incidents that have occurred","D. A legal register of compliance obligations"],correct:1,explanation:"A risk register is a central repository documenting all identified risks: description, threat source, likelihood, impact, risk level, current controls, treatment decisions, residual risk, and risk owner. It supports governance and prioritization of security investments."},
{id:880,domain:1,level:2,question:"What is the difference between 'RPO' and 'RTO' and how are they set in cloud disaster recovery?",options:["A. Both measure the same thing using different units","B. RPO is the maximum acceptable data loss (measured in time); RTO is the maximum acceptable downtime — both are set based on business impact analysis","C. RPO applies to databases; RTO applies to applications","D. These metrics are set by the cloud provider in the SLA"],correct:1,explanation:"RPO (Recovery Point Objective) defines the maximum data loss (e.g., 1-hour RPO means backups every hour). RTO (Recovery Time Objective) defines how quickly systems must be restored. Both are derived from Business Impact Analysis quantifying the cost of data loss and downtime."},
{id:881,domain:2,level:2,question:"What is 'transparent encryption' at the database layer?",options:["A. Encryption visible to all database users","B. Storage-level encryption of database files and backups that is transparent to applications and queries — data is decrypted automatically for authorized access","C. Database encryption that uses only open-source algorithms","D. Encryption with publicly visible keys for auditability"],correct:1,explanation:"Transparent Data Encryption (TDE) encrypts database files and backups at rest without application changes. It protects against physical media access but not against privileged database user access — the data is available in cleartext to any user with database permissions."},
{id:882,domain:3,level:2,question:"What is 'security group chaining' in cloud architecture?",options:["A. Linking multiple security groups to create cumulative allow rules","B. Using security groups as source/destination in other security group rules, enabling fine-grained workload-to-workload communication policies without IP dependency","C. Chaining security groups across VPCs for peered network access","D. A technique for bypassing security group restrictions"],correct:1,explanation:"Security group chaining references another security group as the source/destination instead of an IP range. This allows dynamic policies (e.g., allow traffic from 'web-tier' SG to 'app-tier' SG) that automatically apply to all members regardless of IP addresses."},
{id:883,domain:4,level:2,question:"What is 'access token vs refresh token' in OAuth 2.0 security?",options:["A. Access tokens last longer; refresh tokens are used for sensitive operations","B. Access tokens are short-lived credentials for resource access; refresh tokens are long-lived credentials for obtaining new access tokens without re-authentication","C. They are the same token with different names in different contexts","D. Refresh tokens replace access tokens when they expire without issuing new credentials"],correct:1,explanation:"Access tokens are short-lived (minutes to hours) bearer tokens for API calls. Refresh tokens are long-lived tokens (days to months) used to obtain new access tokens. Refresh token compromise is more severe as it enables long-term access. They must be stored more securely than access tokens."},
{id:884,domain:5,level:2,question:"What is 'security metrics' and why are they important in cloud security programs?",options:["A. Numeric ratings given to cloud security tools by analysts","B. Quantitative measures of security program effectiveness enabling data-driven decisions, investment justification, and progress tracking","C. Performance benchmarks for cloud security hardware","D. Compliance scores assigned by auditors"],correct:1,explanation:"Security metrics (MTTD, MTTR, vulnerability closure rate, patch compliance %, incident trend) provide objective data on security program health. They enable leadership communication, investment prioritization, and demonstrate improvement over time."},
{id:885,domain:6,level:2,question:"What is 'cross-border data transfer' risk and how is it managed?",options:["A. Performance risk from international network latency","B. Legal risk that data transferred to countries with inadequate privacy protections may be accessed without the safeguards required by the data's origin jurisdiction","C. Currency exchange risk for international cloud payments","D. Risk of data loss during international network transmission"],correct:1,explanation:"Cross-border data transfers risk creating obligations or violating restrictions in the data's home jurisdiction. Management: identify all cross-border flows, assess adequacy of destination protections, apply appropriate legal mechanisms (SCCs, BCRs, adequacy decisions), and implement technical controls."},
{id:886,domain:1,level:3,question:"What is 'cloud security reference architecture' and how is it used?",options:["A. A vendor's proprietary security architecture for their cloud platform","B. A documented pattern of security controls and their placement within a cloud architecture, serving as a starting point for organizations designing cloud security","C. A reference architecture for comparing cloud provider security features","D. An industry standard architecture mandated for regulated industries"],correct:1,explanation:"Cloud security reference architectures (CSA TCI, NIST SP 800-207, provider-specific) provide proven patterns: where to place controls (network, identity, data), how components interact, and which cloud-native services fulfill each security function. Organizations adapt them to their requirements."},
{id:887,domain:2,level:3,question:"What is 'data escrow' in cloud and when is it required?",options:["A. Storing encryption keys in a third-party escrow in case of lost keys","B. A contractual arrangement where a third party holds copies of customer data to ensure access if the cloud provider becomes insolvent or ceases operations","C. Escrowing data for legal discovery purposes","D. Backup copies of data held by the cloud provider"],correct:1,explanation:"Data escrow is contractual protection against cloud provider failure: a third party holds a current copy of data (and sometimes application code) that is released to the customer if the provider exits the market. Important for business continuity in critical system dependencies."},
{id:888,domain:3,level:3,question:"What is 'Falco' and how is it used in Kubernetes security?",options:["A. A Kubernetes network policy engine","B. An open-source runtime security tool that detects anomalous behavior in containers by monitoring Linux system calls using eBPF/kernel modules","C. A Kubernetes RBAC management tool","D. A container image vulnerability scanner"],correct:1,explanation:"Falco (CNCF) monitors container and host system calls in real time using eBPF, detecting anomalies like unexpected shell spawning in a container, reading sensitive files, network scanning, or process privilege escalation. Rules define expected behavior; violations trigger alerts."},
{id:889,domain:4,level:3,question:"What is 'API authentication' best practice for machine-to-machine (M2M) cloud API calls?",options:["A. Using shared API keys distributed to all consuming services","B. Short-lived signed tokens (JWT with narrow scope and expiry) issued by an authorization server, or mTLS with service certificates for stronger identity assurance","C. HTTP Basic authentication over HTTPS","D. IP allowlisting as the sole authentication mechanism"],correct:1,explanation:"M2M authentication best practices use short-lived JWT access tokens (OAuth 2.0 client credentials flow) with minimal scope, or mutual TLS for workload identity assurance. Long-lived shared API keys are a persistent risk if leaked; short-lived tokens limit the exposure window."},
{id:890,domain:5,level:3,question:"What is 'continuous threat exposure management' (CTEM) and why is it replacing point-in-time assessments?",options:["A. A replacement for SIEM based on continuous monitoring","B. A continuous program that discovers, scopes, prioritizes, validates, and mobilizes remediation of exposures — reflecting that the attack surface changes constantly","C. Continuous penetration testing replacing annual assessments","D. An automated patch management approach"],correct:1,explanation:"CTEM (Gartner) recognizes that the attack surface is dynamic — new cloud resources, code changes, and vulnerabilities emerge continuously. Unlike annual pen tests, CTEM continuously scans for exposures, validates exploitability, and prioritizes remediation based on real attacker impact."},
{id:891,domain:6,level:3,question:"What is 'DORA' (Digital Operational Resilience Act) and who does it affect?",options:["A. A data privacy regulation for digital companies in the EU","B. An EU regulation requiring financial sector entities to manage ICT risk, test resilience, manage third-party risk, and report ICT incidents","C. A resilience framework for cloud providers globally","D. A GDPR amendment covering digital operational data"],correct:1,explanation:"DORA (effective January 2025) applies to financial entities in the EU (banks, insurers, investment firms) and their critical ICT third-party providers (cloud providers). Requirements include ICT risk management, incident classification/reporting, resilience testing (TLPT), and third-party risk management."},
{id:892,domain:1,level:1,question:"What is 'platform as a service' (PaaS) in cloud computing?",options:["A. A platform for procuring cloud services","B. A cloud model providing a platform for customers to develop, run, and manage applications without managing the underlying infrastructure","C. A SaaS application for IT service management","D. A hardware platform hosted in a cloud data center"],correct:1,explanation:"PaaS provides a complete development and deployment environment (runtime, middleware, database, development tools) without customers managing servers, OS, or networking. Examples: AWS Elastic Beanstalk, Azure App Service, Google App Engine."},
{id:893,domain:2,level:1,question:"What is 'asymmetric encryption'?",options:["A. Encryption that is stronger in one direction than the other","B. Encryption using a mathematically linked key pair: a public key for encryption and a private key for decryption","C. Encryption using two different algorithms together","D. Encryption where ciphertext is longer than plaintext"],correct:1,explanation:"Asymmetric (public-key) encryption uses a key pair: the public key (shareable) encrypts data; only the corresponding private key can decrypt it. This eliminates the key distribution problem of symmetric encryption. Common algorithms: RSA, ECC."},
{id:894,domain:3,level:1,question:"What is a 'virtual private network' (VPN) used for in cloud access?",options:["A. Creating a private cloud network for each user","B. Encrypting network traffic through a tunnel to securely connect remote users or offices to cloud or corporate networks over the public internet","C. Providing dedicated private internet connections","D. Virtualizing network hardware to reduce costs"],correct:1,explanation:"VPNs create encrypted tunnels over public networks, securing remote user access to cloud or corporate resources. In cloud, site-to-site VPNs connect on-premises networks to VPCs; client VPNs provide remote user access."},
{id:895,domain:4,level:1,question:"What is 'authorization' in application security?",options:["A. Verifying the identity of a user","B. Determining what actions an authenticated user or system is permitted to perform","C. The process of approving security policy changes","D. Authorizing cloud resource deployments through change management"],correct:1,explanation:"Authorization determines what an authenticated identity is allowed to do. It is distinct from authentication (who are you?). Authorization checks (access control) verify the requester has permission for the specific resource and action."},
{id:896,domain:5,level:1,question:"What is 'configuration management database' (CMDB) in cloud security?",options:["A. A database of security configuration settings","B. A repository tracking all IT assets (hardware, software, cloud resources), their attributes, and relationships, supporting change management and incident response","C. A database for storing security scan configurations","D. A cloud provider database for managing customer configurations"],correct:1,explanation:"A CMDB provides a centralized inventory of configuration items (CIs) and their relationships. In cloud, it tracks instances, services, configurations, and owners. During incidents, the CMDB identifies affected systems and their dependencies, accelerating response."},
{id:897,domain:6,level:1,question:"What is the purpose of 'security policy' in an organization?",options:["A. Technical rules enforced by security tools","B. A high-level document stating management's intent and requirements for protecting information assets, providing a framework for specific standards and procedures","C. Legal contracts with cloud providers","D. A checklist for annual security audits"],correct:1,explanation:"A security policy expresses management's commitment and direction for information security, sets expectations, assigns responsibilities, and provides the authority for security controls. It is the foundation from which more specific standards, guidelines, and procedures flow."},
{id:898,domain:1,level:2,question:"What is 'cloud cost optimization' and why does it have security implications?",options:["A. Reducing security tools to lower cloud costs","B. Right-sizing resources, eliminating waste, and using reserved capacity — security implications include ensuring cost cuts don't remove critical monitoring or logging","C. Optimizing cloud costs by moving data to less secure, lower-cost storage tiers","D. Reducing cloud costs by sharing resources between clients"],correct:1,explanation:"Cost optimization identifies unused resources, right-sizes workloads, and uses cheaper storage tiers. Security implications: reduced logging retention, disabled monitoring services, or terminated security tools in the name of cost. Cost and security goals must be balanced with governance."},
{id:899,domain:2,level:2,question:"What is 'data tagging' in cloud security and governance?",options:["A. Adding watermarks to sensitive documents","B. Attaching metadata labels (owner, classification, environment, project) to cloud resources and data assets for governance, security control, and cost tracking","C. Tagging database records for deletion","D. Applying classification labels to email messages"],correct:1,explanation:"Resource and data tagging attaches standardized metadata (Owner, Classification, Environment, Compliance-Scope, Project) to cloud assets. Tags drive security automation (apply stricter controls to 'Confidential' tagged resources), cost allocation, and governance reporting."},
{id:900,domain:3,level:2,question:"What is 'host-based intrusion detection system' (HIDS) in cloud?",options:["A. Detecting intrusions into cloud management consoles","B. Security software on individual cloud instances monitoring OS activity, file integrity, and system calls for signs of compromise","C. Network-based intrusion detection at the cloud provider level","D. A SaaS-based intrusion detection service"],correct:1,explanation:"HIDS (e.g., OSSEC, Wazuh) runs on individual cloud instances, monitoring file integrity, log entries, process activity, and network connections for indicators of compromise. It complements network-level detection by providing visibility inside the instance."},
// ─── MIXED BATCH G (IDs 901–1000) ───────────────────────────────────────────
{id:901,domain:4,level:2,question:"What is 'API schema validation' and why is it a security control?",options:["A. Validating API server SSL certificates","B. Enforcing that API request and response bodies conform to a defined schema, rejecting malformed or unexpected inputs early","C. Validating API performance against a defined SLA","D. Schema migration validation in API versioning"],correct:1,explanation:"API schema validation (using OpenAPI/JSON Schema) enforces that requests match expected structure, types, and constraints before reaching business logic. It provides a defense-in-depth layer blocking malformed payloads, mass assignment attacks, and unexpected fields used in injection attempts."},
{id:902,domain:5,level:2,question:"What is 'security event correlation' in SIEM and why does it reduce false positives?",options:["A. Correlating security tool licensing costs","B. Linking related events from multiple sources over time to identify patterns that indicate real threats rather than isolated benign events","C. Correlating security events with business transactions","D. Matching security events to compliance requirements"],correct:1,explanation:"Correlation rules fire only when multiple conditions are met (e.g., failed logins + success + large data transfer). Individual events may be benign, but the combination indicates a real threat. This reduces false positives compared to alerting on single events."},
{id:903,domain:6,level:2,question:"What is 'cloud contract security review' and what provisions are critical?",options:["A. Reviewing cloud provider marketing contracts for security claims","B. Legal and security review of cloud agreements covering data ownership, breach notification, audit rights, sub-processors, data deletion, and liability","C. Contract review for cloud security tool vendors","D. Annual review of cloud SLA performance"],correct:1,explanation:"Cloud contract security review examines: who owns data; breach notification timelines; right to audit; sub-processor disclosure and approval; data deletion on termination; liability caps; and jurisdiction/governing law. Gaps in these provisions create unmanageable risk."},
{id:904,domain:1,level:3,question:"What is 'cloud security architecture review' and what does it evaluate?",options:["A. Annual review of cloud provider security certifications","B. Assessment of cloud deployment architecture against security principles: network segmentation, IAM design, encryption strategy, logging, and resilience","C. Technical review of cloud provider hardware security","D. Review of cloud costs from a security investment perspective"],correct:1,explanation:"A cloud security architecture review evaluates a deployment's design: Is the network properly segmented? Is IAM following least privilege? Is data encrypted at rest and in transit? Are logs centralized and protected? Does the design meet compliance requirements? It identifies security gaps before deployment."},
{id:905,domain:2,level:3,question:"What is 'secure multi-party computation' (SMPC) and what cloud scenario does it address?",options:["A. Securing computations spread across multiple cloud providers","B. A cryptographic technique allowing multiple parties to jointly compute a function over their inputs without revealing those inputs to each other","C. Multi-party authorization for cloud administrative actions","D. Secure computation using multiple redundant cloud instances"],correct:1,explanation:"SMPC allows parties to jointly compute results (e.g., statistical aggregations, ML model training) from private inputs without any party revealing their data to others. Cloud use cases include cross-organization analytics on sensitive data where raw data sharing is legally or competitively prohibited."},
{id:906,domain:3,level:3,question:"What is 'Terraform security scanning' and which tools provide it?",options:["A. Security scanning of Terraform provider endpoints","B. Static analysis of Terraform IaC files to detect misconfigurations before infrastructure is provisioned — tools include Checkov, tfsec, and Terrascan","C. Runtime scanning of Terraform-managed infrastructure","D. Scanning Terraform state files for leaked secrets"],correct:1,explanation:"IaC security scanners (Checkov, tfsec, Terrascan) analyze Terraform configurations for misconfigurations: open security groups, public S3 buckets, missing encryption, disabled logging. Running in CI/CD, they prevent misconfigured infrastructure from ever being deployed."},
{id:907,domain:4,level:3,question:"What is 'shift-left security testing' and what are its benefits?",options:["A. Moving security teams to the left side of the office","B. Integrating security testing earlier in the SDLC (design and development) rather than just before release, reducing cost and time to fix vulnerabilities","C. Shifting security responsibilities left to developers","D. Left-shifting the security review approval process"],correct:1,explanation:"Shift-left moves security testing to the earliest possible phase: threat modeling in design, SAST during coding, SCA in build, IaC scanning in commit. Vulnerabilities found early are 10-100x cheaper to fix than those found in production and prevent security debt accumulation."},
{id:908,domain:5,level:3,question:"What is 'cloud security incident classification' and why does it matter?",options:["A. Classifying incidents by cloud service type","B. Categorizing incidents by type (data breach, account compromise, malware, DDoS) and severity to trigger appropriate response procedures and notification requirements","C. Classification of all cloud events as potential incidents","D. Provider classification of incidents affecting shared infrastructure"],correct:1,explanation:"Incident classification determines response priority and procedures. A data breach triggers breach notification obligations (GDPR 72h, HIPAA 60d). Account compromise triggers credential rotation and forensics. Classification ensures the right playbook and stakeholders are activated immediately."},
{id:909,domain:6,level:3,question:"What is 'privacy-preserving analytics' and what techniques enable it?",options:["A. Analytics with access controls preventing unauthorized viewing","B. Analytical techniques (differential privacy, SMPC, federated learning, synthetic data) that derive insights from sensitive data without exposing individual records","C. Analytics performed only on anonymized data","D. Privacy settings controlling who can view analytics dashboards"],correct:1,explanation:"Privacy-preserving analytics enables valuable insights while protecting individuals: differential privacy adds noise to query results; federated learning trains models without centralizing data; SMPC allows joint computation; synthetic data replaces real data with statistically similar artificial data."},
{id:910,domain:1,level:1,question:"What is 'cloud management plane' and why is it security-critical?",options:["A. The physical plane of cloud server hardware management","B. The APIs and interfaces used to provision, configure, and manage cloud resources — compromise grants attacker control over all resources","C. A management dashboard for cloud cost tracking","D. The control plane network for cloud provider internal routing"],correct:1,explanation:"The cloud management plane (control plane) is the API layer used to provision infrastructure, manage IAM, configure networking, and read/write all resource configurations. Compromise of management plane credentials (cloud root account, admin IAM keys) gives an attacker complete control over the entire cloud environment."},
{id:911,domain:2,level:1,question:"What is 'data backup' in cloud security?",options:["A. Moving inactive data to lower-cost storage tiers","B. Creating copies of data in separate locations to enable recovery after accidental deletion, corruption, ransomware, or disaster","C. Backing up encryption keys for disaster recovery","D. Cloud provider's redundant storage of your data"],correct:1,explanation:"Data backup creates protected copies separate from production. For cloud: backups should be encrypted, access-controlled, versioned, geographically separated from production, regularly tested for recoverability, and protected from ransomware (immutable backup storage)."},
{id:912,domain:3,level:1,question:"What is 'private subnet' in cloud networking?",options:["A. A subnet reserved for cloud provider internal use","B. A subnet with no direct internet route, accessible only through internal routing or NAT, used for resources that should not be internet-reachable","C. A subnet with private IP addresses on the public internet","D. A subnet requiring VPN access for all traffic"],correct:1,explanation:"Private subnets have no internet gateway route, preventing direct inbound/outbound internet traffic. Resources (databases, application servers) in private subnets are protected from direct internet exposure. They access the internet via NAT gateway for outbound-only needs."},
{id:913,domain:4,level:1,question:"What is 'HTTP security headers' and name three important examples?",options:["A. Authentication headers for HTTP API requests","B. Response headers instructing browsers on security behavior — including Content-Security-Policy, X-Frame-Options, and Strict-Transport-Security","C. HTTP headers used for secure cookie transmission","D. Headers required for HTTPS connections"],correct:1,explanation:"HTTP security headers configure browser security behaviors: CSP (controls resource loading, prevents XSS), HSTS (forces HTTPS), X-Frame-Options (prevents clickjacking), X-Content-Type-Options (prevents MIME sniffing), Referrer-Policy, and Permissions-Policy."},
{id:914,domain:5,level:1,question:"What is 'antivirus' / 'anti-malware' in cloud workload security?",options:["A. A cloud provider service blocking all known malware at the network level","B. Software detecting, blocking, and removing malicious software on cloud instances using signature and behavioral detection","C. A SaaS service scanning email attachments","D. Container image scanning for malware signatures"],correct:1,explanation:"Anti-malware on cloud instances detects and removes malware using signature databases and behavioral analysis. In cloud, next-gen endpoint protection (EDR) provides deeper visibility than legacy AV. Customers must deploy it on IaaS instances; PaaS/SaaS workloads rely on provider controls."},
{id:915,domain:6,level:1,question:"What is 'due diligence' in cloud vendor selection?",options:["A. Negotiating the best price from cloud vendors","B. Thorough investigation of a cloud provider's security controls, compliance certifications, financial stability, and contractual terms before engagement","C. Legal review of cloud contracts by company lawyers","D. Technical testing of cloud services before purchase"],correct:1,explanation:"Due diligence in cloud vendor selection assesses: security certifications (SOC 2, ISO 27001), compliance scope (HIPAA BAA, PCI DSS), financial stability, incident history, contractual protections, data handling practices, and references — before committing to a provider."},
{id:916,domain:1,level:2,question:"What is 'cloud security assessment' and when should it be conducted?",options:["A. Periodic assessment of cloud provider pricing","B. A systematic evaluation of cloud environment security posture against standards and best practices — conducted before go-live, after major changes, and on a regular schedule","C. Self-assessment of cloud skills by the security team","D. Provider assessment of customer security maturity"],correct:1,explanation:"Cloud security assessments evaluate configurations, IAM, network security, encryption, logging, and compliance against frameworks (CIS Benchmarks, NIST CSF). They should be performed before production go-live, after significant architecture changes, and periodically (annually or more frequently for high-risk environments)."},
{id:917,domain:2,level:2,question:"What is 'data retention policy' and what should it specify?",options:["A. A policy specifying how much cloud storage to budget for data","B. A documented policy specifying how long different data categories must be retained, in what form, where, and how they must be securely deleted at expiry","C. A policy for retaining backup copies of security logs","D. A cloud provider policy governing data storage duration"],correct:1,explanation:"A data retention policy maps data categories to retention periods (driven by legal, regulatory, and business requirements), defines storage requirements (immutability, encryption), specifies secure deletion methods, and assigns responsibility for enforcement. It is the foundation of a compliant data lifecycle."},
{id:918,domain:3,level:2,question:"What is 'network peering' and what security controls are needed?",options:["A. Connecting cloud networks with equal priority routing","B. Connecting VPCs or cloud networks directly for private traffic exchange — requiring careful routing controls to prevent unintended transitive access","C. Network load balancing across peer servers","D. Peering agreements between cloud providers for bandwidth sharing"],correct:1,explanation:"VPC peering creates private connections between networks. Security controls: non-overlapping CIDR ranges, specific route table entries (avoid overly broad routes), security group rules permitting only necessary traffic, and preventing transitive peering (network A cannot reach network C through network B)."},
{id:919,domain:4,level:2,question:"What is 'clickjacking' and how is it prevented?",options:["A. Click fraud in digital advertising","B. Tricking users into clicking hidden elements on an attacker-controlled page overlaid on a legitimate site — prevented by X-Frame-Options or CSP frame-ancestors header","C. Hijacking user browser sessions through malicious clicks","D. Attack using automated click bots on web applications"],correct:1,explanation:"Clickjacking loads a target site in a hidden iframe and overlays it with deceptive content. The user clicks what appears to be harmless content but actually interacts with the hidden legitimate site (transferring money, changing settings). X-Frame-Options: DENY/SAMEORIGIN prevents framing."},
{id:920,domain:5,level:2,question:"What is 'threat feed' integration in cloud security monitoring?",options:["A. Feeding cloud resource metrics to threat detection tools","B. Consuming external threat intelligence (malicious IPs, domains, file hashes) and using it to automatically block or alert on matching activity in cloud environments","C. Monitoring social media feeds for cyber threat mentions","D. Cloud provider threat advisories subscription"],correct:1,explanation:"Threat feed integration automatically blocks or alerts when cloud traffic matches known-bad indicators (IP reputation, malicious domains, C2 endpoints). Integrated into WAFs, security groups, DNS resolvers, and SIEM, it provides automated protection against known threats without manual analysis."},
{id:921,domain:6,level:2,question:"What is 'proportionality' in GDPR data processing?",options:["A. Proportional financial penalties for GDPR violations","B. Processing must be proportionate to the purpose — not collecting more data, retaining it longer, or processing it more broadly than necessary to achieve the stated purpose","C. Proportional security controls based on data sensitivity","D. Proportional allocation of data protection responsibilities"],correct:1,explanation:"Proportionality in GDPR means data processing must be limited to what is adequate and relevant for the stated purpose. Over-collection (gathering unneeded fields), over-retention (keeping data beyond purpose), and scope creep (using data for undisclosed purposes) all violate this principle."},
{id:922,domain:1,level:3,question:"What is the 'cloud threat landscape' and how does it differ from on-premises threats?",options:["A. Cloud threats are a subset of on-premises threats","B. Cloud introduces unique threats: misconfigured APIs/storage, credential-based attacks via cloud APIs, IAM privilege escalation, metadata service abuse, and supply chain attacks on cloud-native components","C. Cloud threats are identical since attacks target data regardless of location","D. Cloud providers eliminate most traditional threats"],correct:1,explanation:"Cloud-specific threats include: exposed cloud storage (S3 bucket breaches), stolen IAM credentials granting API access, SSRF targeting metadata services (169.254.169.254), container/serverless escape, control plane compromise, and cloud-native supply chain attacks — often invisible to traditional network monitoring."},
{id:923,domain:2,level:3,question:"What is 'client-side encryption' and what protection does it provide over server-side encryption?",options:["A. Encryption implemented in browser JavaScript","B. Data is encrypted by the client before sending to the cloud — the provider never sees plaintext, protecting against provider-side threats including insiders and government requests","C. Encryption of client device storage","D. TLS encryption implemented on the client side"],correct:1,explanation:"Client-side encryption means data is encrypted with customer-controlled keys before transmission. The cloud provider stores only ciphertext. This protects against provider staff accessing data, provider security incidents, and government requests served on the provider — the provider cannot decrypt without the key."},
{id:924,domain:3,level:3,question:"What is 'service control policy' (SCP) in AWS Organizations and how does it enforce security?",options:["A. A policy controlling cloud services pricing in enterprise accounts","B. An organization-level policy that defines maximum permissions available to accounts, acting as guardrails that cannot be overridden even by account administrators","C. A service mesh policy for inter-service communication","D. A policy controlling which AWS services are available by region"],correct:1,explanation:"SCPs define the maximum permissions for member accounts in AWS Organizations. Even if an account administrator grants full permissions, SCPs limit what can actually be done. Used as guardrails: denying root account use, enforcing encryption, restricting regions — centrally enforced across all accounts."},
{id:925,domain:4,level:3,question:"What is 'DAST in CI/CD' and what is the primary challenge?",options:["A. Automating penetration tests in deployment pipelines","B. Integrating dynamic application testing into CI/CD pipelines — the challenge is that DAST requires a running application instance and takes longer than SAST, risking pipeline slowdown","C. Dynamic testing of CI/CD pipeline security controls","D. Continuous automated testing of production applications"],correct:1,explanation:"DAST in CI/CD requires deploying the application to a test environment before scanning, adding pipeline time. Challenges: managing test environments, false positives from incomplete test data, authentication, and scan duration. Solutions include targeted scanning, API scanning, and parallel execution."},
{id:926,domain:5,level:3,question:"What is 'attacker dwell time' and why is reducing it critical?",options:["A. Time attackers spend planning an attack","B. The period between initial compromise and detection — longer dwell time allows more reconnaissance, lateral movement, data theft, and persistence before defenders respond","C. Time attackers spend in the dark web before targeting an organization","D. Duration of a DDoS attack"],correct:1,explanation:"Attacker dwell time (median 16-21 days in recent studies) is the gap between compromise and detection. During this time attackers establish persistence, move laterally, exfiltrate data, and cause damage. Reducing dwell time (better detection) dramatically limits breach impact."},
{id:927,domain:6,level:3,question:"What is 'shadow IT' risk from a compliance perspective?",options:["A. IT systems operating in the shadow of larger systems","B. Unauthorized cloud services used by employees bypassing governance, potentially processing regulated data without compliance controls, DPAs, or risk assessment","C. IT services operated during night shifts","D. Undocumented legacy systems in the data center"],correct:1,explanation:"Shadow IT (unsanctioned cloud services) creates compliance risk: GDPR data processed in services without DPAs; HIPAA PHI in unsanctioned SaaS; PCI card data in non-compliant storage. Discovery via CASB and governance processes (approved service catalog) manage this risk."},
{id:928,domain:1,level:1,question:"What is 'cloud migration' in the context of IT strategy?",options:["A. Moving physical cloud servers to new locations","B. The process of moving applications, data, and workloads from on-premises or legacy systems to cloud infrastructure","C. Migrating between cloud providers","D. Updating cloud services to new versions"],correct:1,explanation:"Cloud migration moves IT assets (applications, data, infrastructure) to cloud environments. Strategies include the 6Rs: Retire, Retain, Rehost (lift and shift), Replatform, Repurchase, and Re-architect. Migration requires careful planning for security, compliance, and operational continuity."},
{id:929,domain:2,level:1,question:"What is 'data owner' responsibility in cloud governance?",options:["A. The cloud provider who owns the data storage infrastructure","B. The business stakeholder accountable for a data set, responsible for defining its classification, access controls, and authorized uses","C. The IT administrator managing cloud storage","D. The legal owner of intellectual property in cloud"],correct:1,explanation:"The data owner is the business executive or manager accountable for a specific data set. They define data classification, approve access requests, authorize data sharing, and are accountable for ensuring appropriate security controls are applied — not the IT team who implements them."},
{id:930,domain:3,level:1,question:"What is 'cloud provider shared responsibility' for SaaS?",options:["A. Provider and customer share 50/50 responsibility for all security","B. In SaaS, the provider manages all infrastructure, platform, and application security; the customer is responsible for data, access management, and end-user security","C. The customer is responsible for all security in SaaS","D. There is no shared responsibility in SaaS — the provider is fully responsible"],correct:1,explanation:"In SaaS the provider manages physical, hypervisor, OS, application, and runtime security. The customer manages: user access and IAM within the SaaS, data they upload, endpoint security for accessing the SaaS, and configuration of the SaaS security settings."},
{id:931,domain:4,level:1,question:"What is 'sensitive data in logs' risk in cloud applications?",options:["A. Log files consuming excessive cloud storage","B. Application logs inadvertently capturing passwords, tokens, PII, or payment data, creating a secondary exposure path for sensitive data","C. Log files being corrupted by sensitive operations","D. Sensitive data in cloud provider operational logs"],correct:1,explanation:"Applications often log more than intended: stack traces containing user data, debug logs with request bodies (including passwords or tokens), or audit logs capturing full objects with PII. Sensitive data in logs widens the breach surface and may violate privacy regulations requiring data minimization."},
{id:932,domain:5,level:1,question:"What is 'security dashboard' in cloud security operations?",options:["A. A cloud provider's billing and usage dashboard","B. A centralized visual interface showing real-time security posture, alert trends, compliance status, and key metrics for security operations","C. A physical display in the data center monitoring room","D. A compliance checklist dashboard for auditors"],correct:1,explanation:"Security dashboards provide consolidated visibility into the security posture: active alerts, recent incidents, compliance scores, vulnerability metrics, and trend data. They support both operational decisions (SOC analysts) and executive communication of security program health."},
{id:933,domain:6,level:1,question:"What is 'data processing' under GDPR?",options:["A. Technical processing of data by computer systems","B. Any operation performed on personal data — collection, storage, use, disclosure, combination, erasure — whether automated or manual","C. Processing of financial data for payment systems","D. Only automated operations on personal data in digital systems"],correct:1,explanation:"GDPR Article 4 defines processing broadly: any operation on personal data including collection, recording, organization, storage, adaptation, retrieval, use, disclosure, dissemination, combination, restriction, erasure, or destruction — covering virtually any handling of personal data."},
{id:934,domain:1,level:2,question:"What is 'cloud security governance' and what components does it include?",options:["A. Government regulation of cloud security","B. The framework of policies, accountability structures, processes, and metrics ensuring security decisions align with business objectives and risk tolerance","C. Cloud provider governance of customer security configurations","D. Governance of cloud security vendor contracts"],correct:1,explanation:"Cloud security governance includes: security policies and standards, risk management framework, compliance management, defined roles and accountability, security architecture review, metrics and reporting, and executive oversight. It ensures security is systematically managed rather than ad hoc."},
{id:935,domain:2,level:2,question:"What is 'cloud data governance' and what problems does it solve?",options:["A. Government oversight of cloud data practices","B. Policies, processes, and controls ensuring data quality, availability, integrity, and security across cloud environments — solving sprawl, inconsistent classification, and orphaned data","C. Governance of cloud provider data center operations","D. IT governance standards for cloud data architectures"],correct:1,explanation:"Cloud data governance addresses: who owns which data, how it's classified, where it can go, how long it's kept, and who can access it. Without it, cloud sprawl leads to unclassified, unprotected data scattered across accounts, creating compliance and security risks."},
{id:936,domain:3,level:2,question:"What is 'service account security' in cloud IAM?",options:["A. Security for cloud billing service accounts","B. Securing machine identities (service accounts) used by applications/services through least-privilege permissions, key rotation, and avoiding long-lived static credentials","C. Account security for cloud provider support staff","D. Security settings for cloud management console service accounts"],correct:1,explanation:"Service accounts are non-human identities for workloads. Common misconfigurations: over-privileged accounts (Editor/Owner roles), long-lived static keys in code or environment variables, and reusing accounts across multiple services. Best practices: dedicated minimal accounts, workload identity federation, regular key rotation."},
{id:937,domain:4,level:2,question:"What is 'API documentation security' risk?",options:["A. Attackers modifying API documentation to mislead developers","B. Publicly accessible API documentation (Swagger/OpenAPI) may expose endpoint structure, authentication methods, and data models, aiding attacker reconnaissance","C. Missing API documentation increasing security risk from developer errors","D. API documentation containing hardcoded test credentials"],correct:1,explanation:"Public API documentation (Swagger UI, developer portals) provides attackers a roadmap: all endpoints, parameters, authentication methods, and response schemas. While needed for legitimate developers, sensitive internal APIs should not have public documentation, and endpoints should enforce authorization regardless."},
{id:938,domain:5,level:2,question:"What is 'threat modeling for cloud workloads' and what methodology is most commonly used?",options:["A. Modeling cloud cost threats for budget planning","B. Systematically analyzing cloud workload designs to identify threats, attack vectors, and required mitigations — STRIDE is commonly used for cloud threat modeling","C. Modeling attacker behavior using machine learning","D. Cloud provider threat analysis for service design"],correct:1,explanation:"Cloud threat modeling uses STRIDE (Spoofing, Tampering, Repudiation, Information disclosure, Denial of service, Elevation of privilege) or PASTA/LINDDUN to systematically identify threats specific to the workload design: What can an attacker do to each component? What data flows need protection? What authorization checks are needed?"},
{id:939,domain:6,level:2,question:"What is the 'right to restriction of processing' under GDPR?",options:["A. Restricting cloud providers from processing EU data","B. A data subject right to request that processing of their data be halted while accuracy is contested, a complaint is pending, or they need data for legal claims despite requesting deletion","C. A regulatory right to restrict cloud provider operations","D. Restricting automated processing including profiling"],correct:1,explanation:"Restriction of processing (Article 18) allows data subjects to 'pause' processing in specific circumstances: disputing accuracy, unlawful processing where they prefer restriction to erasure, data needed for legal claims, or objection pending verification. The data is stored but not otherwise processed."},
{id:940,domain:1,level:3,question:"What is the 'Well-Architected Framework' security pillar?",options:["A. A cloud provider certification framework for well-designed architectures","B. A set of best practices for secure cloud design covering IAM, detective controls, infrastructure protection, data protection, and incident response","C. A security framework for evaluating cloud provider architecture","D. A framework for architecting security operations centers in cloud"],correct:1,explanation:"AWS Well-Architected, Azure Well-Architected, and GCP Architecture Framework all include security pillars with best practices: strong identity foundation, enable traceability, apply security at all layers, automate security best practices, protect data in transit and at rest, keep people away from data, and prepare for security events."},
{id:941,domain:2,level:3,question:"What is 'cloud data loss prevention' (Cloud DLP) and how does it differ from traditional DLP?",options:["A. Cloud DLP prevents accidental deletion of cloud data","B. Cloud DLP discovers, classifies, and protects sensitive data across cloud services (SaaS, IaaS storage) using APIs rather than network interception, covering data at rest and in motion","C. Cloud DLP is identical to traditional DLP deployed on cloud VMs","D. Cloud DLP only monitors data leaving cloud environments"],correct:1,explanation:"Traditional DLP monitors network traffic and endpoints via agents/proxies. Cloud DLP (Google Cloud DLP, CASB DLP) uses cloud service APIs to scan storage, databases, and SaaS data at rest, finding and classifying sensitive data across cloud environments without requiring network interception."},
{id:942,domain:3,level:3,question:"What is 'cloud workload identity' and how does it eliminate static credential risk?",options:["A. Identifying cloud workloads by their resource names","B. Dynamic, automatically-rotated credentials bound to cloud resources (EC2 instance profiles, pod service accounts) that workloads use instead of long-lived static API keys","C. A workload classification system for IAM policy targeting","D. Identity verification for cloud workload licensing"],correct:1,explanation:"Workload identity (EC2 IAM instance profiles, GKE Workload Identity, Azure Managed Identity) provides automatically-rotated, short-lived credentials to workloads via the instance metadata service. Workloads never handle long-lived secrets — eliminating the credential leak risk of static API keys embedded in code or config."},
{id:943,domain:4,level:3,question:"What is 'CI/CD pipeline security' and what are the key attack surfaces?",options:["A. Securing the CI/CD tool vendor's cloud infrastructure","B. Protecting the build and deployment pipeline from attacks: source code repositories, build systems, artifact registries, secrets in pipelines, and deployment credentials","C. Ensuring CI/CD deployments do not break security controls","D. Compliance validation in CI/CD pipelines"],correct:1,explanation:"CI/CD pipeline attacks target: source repos (code injection, branch protection bypass), build systems (dependency confusion, malicious build steps), artifact registries (image tampering), secrets stored in CI variables, and overprivileged deployment credentials. Compromise of a pipeline can poison every deployment."},
{id:944,domain:5,level:3,question:"What is 'proactive security' vs 'reactive security' in cloud operations?",options:["A. Proactive security uses AI; reactive security uses human analysts","B. Proactive security prevents and detects threats before impact (threat hunting, posture management, red teaming); reactive security responds after incidents occur","C. Proactive security is more expensive and less effective","D. They are identical approaches with different names"],correct:1,explanation:"Proactive security invests in finding and closing gaps before attackers exploit them: CSPM, threat modeling, red teaming, threat hunting, and continuous compliance. Reactive security responds after detection. Mature programs balance both — proactive reduces incident frequency; reactive limits impact when incidents occur."},
{id:945,domain:6,level:3,question:"What is 'privacy audit' and what does it examine in a cloud context?",options:["A. A financial audit of privacy tool costs","B. A systematic examination of data processing activities, privacy controls, legal bases, consent mechanisms, and data flows to assess compliance with privacy regulations","C. A technical security audit focused on data encryption","D. An audit conducted by supervisory authorities only"],correct:1,explanation:"A privacy audit examines: completeness and accuracy of RoPA; legal bases for all processing activities; consent collection and management; data subject rights implementation; data flows and cross-border transfers; retention schedules; vendor DPAs; breach notification procedures; and PIA/DPIA completion."},
{id:946,domain:1,level:1,question:"What is a 'content delivery network' (CDN) and what security benefit does it provide?",options:["A. A network for delivering content to cloud storage","B. A distributed network of proxy servers caching content near users, providing DDoS protection and reducing origin server exposure","C. A private cloud network for content companies","D. A network protocol for secure content transmission"],correct:1,explanation:"CDNs (Cloudflare, CloudFront, Akamai) cache content at edge locations near users, improving performance. Security benefits: absorbing DDoS attacks at the edge before reaching origin, hiding origin server IP, WAF capabilities at edge, and TLS offloading."},
{id:947,domain:2,level:1,question:"What is 'digital certificate' in cloud security?",options:["A. A digital document certifying cloud compliance","B. An electronic credential binding a public key to an identity, signed by a trusted certificate authority, used for authentication and encryption","C. A certificate of completion for cloud security training","D. A digital copy of a physical security certificate"],correct:1,explanation:"A digital certificate (X.509) binds a public key to an identity (domain, organization, person) with the signature of a trusted CA. It enables TLS (HTTPS), code signing, and mutual authentication. Certificate management (renewal, revocation) is critical in cloud environments."},
{id:948,domain:3,level:1,question:"What is 'intrusion detection system' (IDS) vs 'intrusion prevention system' (IPS)?",options:["A. IDS blocks attacks; IPS only detects them","B. IDS detects and alerts on suspicious activity; IPS detects and automatically blocks or drops malicious traffic","C. IDS is hardware-based; IPS is software-based","D. They are the same technology with different vendor names"],correct:1,explanation:"IDS monitors network traffic and generates alerts for suspicious patterns without blocking traffic. IPS sits inline and can automatically drop malicious packets or terminate connections. In cloud, both are typically software-defined or delivered as managed services."},
{id:949,domain:4,level:1,question:"What is 'cookie security' in web application development?",options:["A. Securing the web server's cookie storage","B. Configuring cookies with Secure (HTTPS-only), HttpOnly (no JS access), and SameSite (CSRF protection) flags to protect session tokens","C. Complying with cookie consent laws on websites","D. Encrypting all cookies before storing them in the browser"],correct:1,explanation:"Secure cookie flags: Secure (transmit only over HTTPS, preventing interception); HttpOnly (inaccessible to JavaScript, preventing XSS theft); SameSite=Strict/Lax (prevent CSRF by restricting cross-site sending). Together they harden session token protection significantly."},
{id:950,domain:5,level:1,question:"What is 'security operations maturity' and how is it measured?",options:["A. The number of security tools deployed by the SOC","B. The capability level of security operations across detection, response, threat intelligence, automation, and continuous improvement — measured using maturity models","C. Years of experience of SOC analysts","D. The SOC's budget as a percentage of IT spend"],correct:1,explanation:"SOC maturity models (SANS, SOC-CMM) assess capabilities: basic alerting → correlation → threat intelligence → hunting → predictive analytics → automated response. Maturity measurement identifies investment priorities to improve detection effectiveness and response speed."},
{id:951,domain:6,level:1,question:"What is 'ISO 27001' and what does certification demonstrate?",options:["A. An ISO standard for cloud service quality","B. An international standard specifying requirements for an Information Security Management System (ISMS) — certification demonstrates systematic management of information security risks","C. A certification for individual cloud security professionals","D. An ISO standard for software development security"],correct:1,explanation:"ISO 27001 specifies requirements for establishing, implementing, maintaining, and improving an ISMS. Certification (by accredited auditors) demonstrates that an organization systematically identifies security risks and implements controls to manage them — covering cloud and on-premises environments."},
{id:952,domain:1,level:2,question:"What is 'cloud-native application' and what security considerations are unique to it?",options:["A. Applications developed by cloud provider engineering teams","B. Applications designed to exploit cloud capabilities (microservices, containers, serverless) with security considerations around API security, container security, and ephemeral infrastructure","C. Applications that only run in cloud environments","D. Applications using all available cloud services from a single provider"],correct:1,explanation:"Cloud-native apps (microservices, containers, serverless, CI/CD) have unique security concerns: large API attack surface between services, container runtime security, secrets in environment variables, over-permissive service accounts, short-lived infrastructure complicating forensics, and supply chain risks in base images and dependencies."},
{id:953,domain:2,level:2,question:"What is 'data minimization' in cloud system design?",options:["A. Minimizing cloud storage costs through compression","B. Designing systems to collect and retain only the personal data strictly necessary for defined purposes, including limiting fields, purging data on schedule, and avoiding data collection by default","C. Reducing the amount of data sent across the network","D. Minimizing the number of data classification categories"],correct:1,explanation:"Data minimization by design means: define what data is needed before collection (not collect-all-filter-later); use form field controls; implement automatic purging; avoid logging sensitive request data; and review data models to remove fields no longer needed. GDPR Article 25 mandates this."},
{id:954,domain:3,level:2,question:"What is 'cloud network monitoring' and what tools are used?",options:["A. Monitoring cloud provider network infrastructure availability","B. Capturing and analyzing network traffic metadata (VPC flow logs, DNS logs, packet mirrors) to detect threats and support operations","C. Monitoring cloud network costs for budget management","D. Network performance monitoring for SLA compliance"],correct:1,explanation:"Cloud network monitoring uses VPC flow logs (traffic metadata), DNS query logs, network packet mirroring (full capture for inspection), and cloud-native threat detection (GuardDuty, Azure Sentinel) to detect malicious traffic, lateral movement, and data exfiltration."},
{id:955,domain:4,level:2,question:"What is 'API key security' best practice?",options:["A. Using the same API key for all services for simplicity","B. Generating unique keys per service, scoping permissions narrowly, rotating regularly, storing in secrets managers (not code), and monitoring usage for anomalies","C. Sharing API keys with partners for integration","D. Using long API keys for increased entropy"],correct:1,explanation:"API key best practices: unique key per client/integration; minimum required permissions; automatic rotation; stored in a secrets manager (never in code, git history, or environment variables); usage monitoring to detect unexpected patterns; revocation process for compromised keys."},
{id:956,domain:5,level:2,question:"What is 'SOC 2 vs SOC 1' in cloud compliance?",options:["A. SOC 1 is for large organizations; SOC 2 for small organizations","B. SOC 1 reports on controls relevant to financial reporting (ICFR); SOC 2 reports on controls relevant to security, availability, confidentiality, processing integrity, and privacy (Trust Services Criteria)","C. SOC 2 is more comprehensive than SOC 1 for all purposes","D. SOC 1 covers cloud; SOC 2 covers on-premises"],correct:1,explanation:"SOC 1 (SSAE 18/ISAE 3402) reports on controls at a service organization relevant to user entities' financial reporting — relevant for payroll processors, financial SaaS. SOC 2 reports on security controls (Trust Services Criteria) — more relevant for cloud IaaS/PaaS/SaaS security assessment."},
{id:957,domain:6,level:2,question:"What is 'privacy notice' requirement under GDPR and when must it be provided?",options:["A. Notice to regulators before starting data processing","B. Information provided to data subjects at the time of data collection or within a reasonable period (Article 13/14), covering identity of controller, purposes, legal basis, rights, and retention","C. Annual privacy report published on the company website","D. Notification of privacy policy changes to existing customers"],correct:1,explanation:"GDPR Articles 13 and 14 require data controllers to provide transparent information to data subjects when collecting data (Article 13 — directly from subject) or within 1 month if not directly (Article 14). Required content includes controller identity, processing purposes, legal basis, retention, rights, and any third-party recipients."},
{id:958,domain:1,level:3,question:"What is 'ENISA's Cloud Risk Assessment' and what is its value?",options:["A. A technical audit conducted by ENISA on cloud providers","B. A risk assessment framework published by the EU Agency for Cybersecurity identifying and assessing cloud-specific risks for customers choosing cloud services","C. ENISA's internal risk assessment for its own cloud infrastructure","D. A regulatory tool for EU member states to assess cloud providers"],correct:1,explanation:"ENISA's Cloud Computing Risk Assessment identifies cloud-specific risks (policy/organizational, technical, legal) and their likelihood and impact. It helps organizations understand what risks they take on when adopting cloud and guides due diligence and risk treatment decisions."},
{id:959,domain:2,level:3,question:"What is 'cryptographic agility' and why is it important for long-lived cloud systems?",options:["A. Quickly deploying new encryption keys when needed","B. Designing systems to easily swap cryptographic algorithms without major refactoring, enabling migration when algorithms are deprecated or broken","C. Agile development practices applied to cryptography implementation","D. Using multiple encryption algorithms simultaneously for redundancy"],correct:1,explanation:"Cryptographic agility anticipates that algorithms will eventually be deprecated (MD5, SHA1, DES, 3DES already have been; RSA/ECC face quantum threats). Systems with hardcoded algorithms require major rework for migration. Agile designs abstract the algorithm choice, allowing migration to post-quantum algorithms with minimal change."},
{id:960,domain:3,level:3,question:"What is 'Kubernetes network policy' and how does it improve security?",options:["A. Kubernetes cluster firewall rules for external traffic","B. Kubernetes objects defining allow/deny rules for pod-to-pod and pod-to-external network traffic, enabling micro-segmentation within the cluster","C. Network bandwidth policies for Kubernetes nodes","D. TLS certificate policies for Kubernetes services"],correct:1,explanation:"Kubernetes Network Policies define which pods can communicate with each other and with external endpoints. By default all pod communication is allowed; Network Policies implement a deny-by-default approach with explicit allow rules, preventing lateral movement within the cluster."},
{id:961,domain:4,level:3,question:"What is 'API abuse detection' and how does it differ from traditional WAF protection?",options:["A. Detecting misuse of internal APIs by developers","B. Identifying legitimate API calls used in abusive patterns (account takeover, scraping, fraud) that bypass WAF signature rules through behavioral analysis","C. Blocking all non-whitelisted API endpoints","D. Detecting API version mismatches in client requests"],correct:1,explanation:"API abuse uses valid, well-formed requests (bypassing WAF signatures) but in malicious patterns: credential stuffing (many logins), data scraping (exhaustive enumeration), fake account creation, or price manipulation. Detection requires behavioral analytics: rate anomalies, sequential enumeration, user-agent analysis."},
{id:962,domain:5,level:3,question:"What is 'zero-day vulnerability' management in cloud environments?",options:["A. Managing vulnerabilities discovered on day zero of deployment","B. Responding to unknown vulnerabilities with no available patch by applying compensating controls, monitoring for exploitation indicators, and accelerating vendor patch deployment when released","C. A vulnerability scoring system for newly discovered CVEs","D. Cloud provider responsibility to patch zero-days in managed services"],correct:1,explanation:"Zero-day vulnerabilities have no available patch. Response: apply compensating controls (WAF rules, network isolation, disable affected features), monitor closely for exploitation indicators, and deploy vendor patches as emergency changes when released. In cloud, provider-managed services may be patched transparently."},
{id:963,domain:6,level:3,question:"What is 'data protection by default' (Article 25(2) GDPR) and how is it implemented?",options:["A. All data is encrypted by default in cloud deployments","B. The highest privacy settings are the default; users must actively choose to share more data or reduce privacy protections rather than the reverse","C. Data protection controls are applied by default by cloud providers","D. Default data retention is set to minimum legal requirement"],correct:1,explanation:"Data protection by default (Article 25(2)) means that by default, only personal data necessary for each purpose is processed. Users should not have to take action to protect their privacy — privacy-invasive features (public profiles, location sharing, data for analytics) must require explicit opt-in."},
{id:964,domain:1,level:1,question:"What is 'total cost of ownership' (TCO) analysis in cloud migration?",options:["A. The purchase price of cloud services","B. A comprehensive cost comparison including hardware, software, operations, personnel, and hidden costs for on-premises vs cloud over a defined period","C. Cloud provider's total cost to run customer workloads","D. The total cost of security tools in a cloud environment"],correct:1,explanation:"TCO analysis compares all costs: on-premises hardware, data center, power/cooling, personnel, maintenance, and refresh cycles vs cloud subscription, data transfer, support, and engineering costs. Security and compliance costs should be included in both scenarios."},
{id:965,domain:2,level:1,question:"What is 'public key infrastructure' (PKI)?",options:["A. Physical infrastructure for cloud key management","B. The framework of policies, procedures, hardware, software, and standards for creating, distributing, managing, and revoking digital certificates","C. A public cloud key management service","D. Key generation infrastructure operated by cloud providers"],correct:1,explanation:"PKI is the complete ecosystem for managing digital certificates and public key cryptography: Certificate Authorities (CAs) that sign certificates, registration authorities, certificate revocation lists (CRLs), OCSP, and the policies governing the entire system."},
{id:966,domain:3,level:1,question:"What is 'cloud load balancer' and what security role does it play?",options:["A. A device balancing the cost of cloud services","B. A service distributing traffic across multiple backend instances, providing DDoS absorption, TLS termination, health filtering, and single point for security policy enforcement","C. A load balancer for cloud management traffic","D. Distributing security responsibilities between cloud and customer"],correct:1,explanation:"Load balancers distribute traffic, provide high availability, and offer security benefits: absorbing volumetric attacks, TLS termination (centralizing certificate management), health check filtering (routing around unhealthy instances), and WAF integration for application-layer protection."},
{id:967,domain:4,level:1,question:"What is 'open redirect vulnerability'?",options:["A. A web server misconfiguration allowing unrestricted file access","B. A web application flaw that allows attackers to redirect users to external malicious sites using a trusted site's URL as a vector","C. An HTTP redirect loop causing application errors","D. Open-source redirection framework vulnerabilities"],correct:1,explanation:"Open redirects allow attackers to craft URLs on a trusted domain that redirect to malicious sites (phishing, malware). Example: https://trusted.com/redirect?url=evil.com. Users trust the initial domain but are sent elsewhere. Fix: whitelist permitted redirect destinations."},
{id:968,domain:5,level:1,question:"What is 'cloud security training' for developers and why is it different from general security training?",options:["A. Training developers to use cloud security services","B. Specialized training on cloud-specific vulnerabilities, secure cloud architecture patterns, and cloud-native security tooling tailored to developers' daily work","C. Security awareness training delivered via cloud platforms","D. Training developers to pass cloud security certifications"],correct:1,explanation:"Developer security training in cloud context covers: cloud-specific OWASP risks, IaC security practices, secrets management (not hardcoding keys), secure use of cloud services (encryption, IAM), container security, and using security tools (SAST, SCA, image scanning) in their workflows."},
{id:969,domain:6,level:1,question:"What is 'personal data' under GDPR?",options:["A. Data about a person's personal life and interests","B. Any information relating to an identified or identifiable natural person — including name, email, IP address, cookie identifiers, location data, and pseudonymous data","C. Only sensitive categories like health or biometric data","D. Data collected with explicit consent only"],correct:1,explanation:"GDPR defines personal data broadly: any information that can directly or indirectly identify a living natural person. This includes obvious identifiers (name, ID number) and less obvious ones (IP addresses, device identifiers, behavioral data) if they can be linked to an individual."},
{id:970,domain:1,level:2,question:"What is 'cloud security strategy' and what should it address?",options:["A. A strategy for procuring cloud security tools","B. A plan aligning cloud security investments with business objectives, covering risk posture, architecture principles, governance, tooling, and team capabilities","C. The cloud provider's security strategy document","D. A strategy for achieving cloud security certifications"],correct:1,explanation:"A cloud security strategy defines: target security architecture and principles; risk appetite and treatment approach; governance framework; key security capabilities to build/buy; compliance roadmap; and metrics for measuring success. It aligns security investment with cloud adoption pace and business risk."},
{id:971,domain:2,level:2,question:"What is 'cloud-native key management service' (KMS) and when should a dedicated HSM be used instead?",options:["A. KMS and HSM are the same service in cloud","B. Cloud KMS provides software-based key management integrated with cloud services; dedicated HSMs provide hardware security for highest-assurance regulatory requirements like FIPS 140-2 Level 3","C. HSMs are always required for any key management in regulated industries","D. Cloud KMS provides stronger security than dedicated HSMs"],correct:1,explanation:"Cloud KMS (AWS KMS, Azure Key Vault, GCP Cloud KMS) provides convenient, integrated key management meeting most compliance needs. For highest assurance (FIPS 140-2 Level 3, single-tenant key storage, financial sector requirements), dedicated HSMs (AWS CloudHSM, Azure Dedicated HSM) provide hardware-level isolation."},
{id:972,domain:3,level:2,question:"What is 'cloud-native firewall' vs 'virtual firewall appliance' in cloud?",options:["A. Cloud-native firewalls are built by the cloud provider; virtual appliances are open source","B. Cloud-native firewalls (security groups, AWS Network Firewall) are fully managed and integrate with cloud APIs; virtual appliances (Palo Alto, Fortinet) offer richer features but require management overhead","C. Virtual appliances provide better security; cloud-native firewalls are less capable","D. Cloud-native firewalls are free; virtual appliances require licensing"],correct:1,explanation:"Cloud-native firewalls integrate seamlessly with the cloud platform, auto-scale, and require no management. Virtual network appliances offer advanced features (deep packet inspection, threat prevention, custom IPS signatures) but require patching, HA configuration, and careful sizing — adding operational complexity."},
{id:973,domain:4,level:2,question:"What is 'directory traversal' vulnerability?",options:["A. Traversing Active Directory to enumerate user accounts","B. An attack exploiting insufficient input validation on file path parameters to access files outside the intended directory, potentially exposing system files or configuration","C. Crawling web application directories for hidden endpoints","D. Traversal of network paths between cloud regions"],correct:1,explanation:"Directory (path) traversal uses sequences like '../' to navigate outside intended directories. Example: a file download endpoint with ?file=../../etc/passwd reads the system password file. Mitigation: canonicalize paths, reject sequences traversing above the allowed root, use whitelisting."},
{id:974,domain:5,level:2,question:"What is 'playbook automation' in SOAR and what are its benefits?",options:["A. Automating the writing of incident response documentation","B. Encoding incident response procedures as executable code that automatically performs enrichment, notification, containment, and remediation actions triggered by security alerts","C. Automating security training playbooks for analysts","D. Automated review and approval of security change playbooks"],correct:1,explanation:"SOAR playbooks automate routine incident response: on alert, automatically query threat intel, check asset owner, look up similar incidents, notify stakeholder, quarantine affected resource if confidence is high. Benefits: consistent execution, minutes instead of hours, reduced analyst fatigue, 24/7 response."},
{id:975,domain:6,level:2,question:"What is 'cloud compliance automation' and what tools enable it?",options:["A. Automated submission of compliance reports to regulators","B. Using policy-as-code, CSPM, and CI/CD gates to continuously detect and remediate compliance deviations rather than relying on periodic audits","C. Automating compliance training for cloud employees","D. Cloud provider automation of customer compliance requirements"],correct:1,explanation:"Compliance automation uses tools like AWS Config rules, Azure Policy, GCP Security Command Center, and Open Policy Agent to continuously evaluate configurations against compliance requirements (CIS, HIPAA, PCI) and automatically remediate deviations, generating machine-readable evidence for audits."},
{id:976,domain:1,level:3,question:"What is 'cloud security posture management' (CSPM) vs 'cloud-native application protection platform' (CNAPP)?",options:["A. CSPM is an older term for CNAPP","B. CSPM focuses on infrastructure configuration posture; CNAPP is a broader platform that includes CSPM, CWPP, CIEM, and application-layer security in an integrated lifecycle view","C. CSPM covers all cloud security; CNAPP only covers applications","D. CNAPP is a subset of CSPM"],correct:1,explanation:"CSPM continuously assesses cloud configuration posture (misconfigurations, compliance drift). CNAPP (Gartner) expands this to a comprehensive platform: CSPM + CWPP (runtime workload protection) + CIEM (identity entitlement) + container/serverless security + IaC scanning — covering the full application development and runtime lifecycle."},
{id:977,domain:2,level:3,question:"What is the 'crypto-shredding' technique and when is it used?",options:["A. Physically destroying storage media containing encrypted data","B. Deleting the encryption key for a data set, rendering the encrypted data permanently unreadable, as a fast and verifiable deletion method especially for distributed cloud storage","C. Overwriting encrypted data with random bytes","D. Shredding paper documents containing decryption keys"],correct:1,explanation:"Crypto-shredding destroys data by deleting its encryption key rather than finding and overwriting all copies. In cloud, where data may be spread across storage, backups, and replicas, deleting the unique key renders all copies permanently unreadable — verifiable and instantaneous."},
{id:978,domain:3,level:3,question:"What is 'privileged access workstation' (PAW) and how does it protect cloud administration?",options:["A. A workstation with root access to cloud systems","B. A dedicated, hardened device used exclusively for privileged administrative tasks, isolated from general internet browsing and email to prevent credential theft","C. A remote desktop for accessing cloud management consoles","D. A virtual machine used for cloud security scanning"],correct:1,explanation:"PAWs are purpose-built, hardened workstations with no internet browsing, email, or general applications — only the tools needed for privileged administration. This prevents credential theft via phishing or malware on the admin's device, which is a common attack vector for cloud account compromise."},
{id:979,domain:4,level:3,question:"What is 'mobile application security testing' (MAST) for cloud-connected apps?",options:["A. Testing mobile app performance over cellular networks","B. Security testing of mobile applications including binary analysis, traffic interception, data storage analysis, and API security testing for cloud backend interactions","C. Testing mobile device management integration with cloud services","D. Accessibility testing for mobile cloud applications"],correct:1,explanation:"MAST evaluates: insecure data storage on device (plaintext credentials, tokens in shared storage), certificate validation (MITM susceptibility), binary protections (obfuscation, anti-tampering), API authentication security, and backend cloud API authorization — using both static and dynamic analysis."},
{id:980,domain:5,level:3,question:"What is 'security information sharing' and what frameworks support it?",options:["A. Sharing security tool configurations between organizations","B. Exchanging threat intelligence (IOCs, TTPs, vulnerability data) between organizations and sectors using standards like STIX/TAXII to improve collective defense","C. Internal security knowledge sharing within the SOC","D. Cloud provider sharing of security data with customers"],correct:1,explanation:"Threat intelligence sharing (ISAC/ISAO communities, MISP, STIX/TAXII) allows organizations to share IOCs, TTPs, and vulnerability data. One organization's detection becomes another's prevention. Sharing frameworks standardize format (STIX) and transport (TAXII) for machine-readable exchange."},
{id:981,domain:6,level:3,question:"What is 'GDPR extraterritorial effect' and which organizations are subject to it?",options:["A. GDPR applies only to organizations with physical presence in the EU","B. GDPR applies to any organization worldwide that processes personal data of EU residents in connection with offering goods/services or monitoring behavior in the EU","C. GDPR only applies to EU-based organizations and their subsidiaries","D. GDPR extraterritoriality only applies when data is stored in the EU"],correct:1,explanation:"GDPR Article 3 has wide territorial scope: it applies to organizations outside the EU if they offer goods or services to EU residents (even free ones) or monitor the behavior of EU residents. This is why US and global cloud providers must comply with GDPR."},
{id:982,domain:1,level:1,question:"What is 'OpEx vs CapEx' in cloud financial modeling?",options:["A. Operating expenses are more expensive than capital expenses in cloud","B. CapEx requires upfront investment in owned assets (data centers, hardware); cloud OpEx is a pay-as-you-go operating cost that is more flexible and financially predictable","C. Cloud forces organizations to use both CapEx and OpEx equally","D. CapEx is only relevant for private cloud; OpEx for public cloud"],correct:1,explanation:"Traditional IT requires CapEx: buying servers, data centers, and infrastructure. Cloud converts this to OpEx: predictable subscription or consumption costs requiring no upfront capital. This improves financial flexibility, eliminates over-provisioning waste, and moves costs to variable expenses matching actual usage."},
{id:983,domain:2,level:1,question:"What is 'cryptographic hash' and give examples of secure vs insecure algorithms?",options:["A. A hash that uses cryptographic keys for additional security","B. A one-way function producing a fixed-size digest; SHA-256 and SHA-3 are secure; MD5 and SHA-1 are cryptographically broken for security uses","C. A hash stored in encrypted form for added protection","D. A hash used specifically for password storage"],correct:1,explanation:"Cryptographic hashes (SHA-256, SHA-3, BLAKE2) produce a fixed-size fingerprint that is computationally infeasible to reverse or find collisions in. MD5 and SHA-1 are collision-vulnerable and must not be used for security purposes (digital signatures, integrity verification). They persist in some legacy systems."},
{id:984,domain:3,level:1,question:"What is 'auto-remediation' in cloud security?",options:["A. Automatic repair of cloud hardware failures","B. Automated processes that detect and fix security misconfigurations or policy violations without human intervention, such as enabling encryption or revoking public access","C. Self-healing applications that recover from security incidents","D. Automated patching of cloud operating systems"],correct:1,explanation:"Auto-remediation uses Lambda functions, Azure Functions, or CSPM integrations to automatically correct security violations: making a public S3 bucket private, enabling encryption on an unencrypted volume, or removing an overly permissive security group rule — immediately upon detection."},
{id:985,domain:4,level:1,question:"What is 'secure development lifecycle' (SDL/SDLC)?",options:["A. A development methodology focused on speed","B. A framework integrating security activities (threat modeling, code review, testing, penetration testing) at each phase of software development","C. A lifecycle for decommissioning insecure applications","D. Microsoft's proprietary development framework"],correct:1,explanation:"SDL integrates security into every SDLC phase: requirements (security requirements), design (threat modeling), development (secure coding standards, SAST), testing (DAST, pen test), and deployment (security configuration review). It is the foundation of DevSecOps."},
{id:986,domain:5,level:1,question:"What is 'incident containment' in cloud environments?",options:["A. Physical containment of cloud hardware during incidents","B. Actions taken to stop an incident from spreading: isolating affected resources, revoking compromised credentials, blocking malicious IP addresses, or disabling affected services","C. Containing incident information within the security team","D. Cloud provider actions to contain incidents affecting shared infrastructure"],correct:1,explanation:"Cloud containment uses cloud-native capabilities: detaching instances from subnets, applying deny-all security group rules, disabling or revoking IAM credentials, blocking IPs at WAF/security groups, isolating storage buckets — all via API without physical access, enabling rapid response."},
{id:987,domain:6,level:1,question:"What is 'residual risk' in information security?",options:["A. Risk remaining after all possible controls have been applied regardless of cost","B. The risk remaining after security controls have been applied, which the organization accepts as within its risk tolerance","C. Risks not yet identified during the risk assessment","D. Risks transferred to third parties including cloud providers"],correct:1,explanation:"Residual risk is what remains after mitigation controls are applied. No control eliminates all risk. Residual risk must be reviewed against risk appetite: if within tolerance, it is accepted; if not, additional controls or risk transfer (insurance) are considered."},
{id:988,domain:1,level:2,question:"What is 'cloud architecture pattern' for high availability?",options:["A. Using the most expensive instance type for reliability","B. Deploying redundant components across multiple availability zones with health checks and automatic failover, ensuring no single component failure causes service downtime","C. Backing up the application to a separate region","D. High-availability architecture requires a dedicated cloud region"],correct:1,explanation:"High availability in cloud uses: multi-AZ deployment, load balancers with health checks, auto-scaling to replace failed instances, stateless application design (session state in external store), and regional failover for disaster recovery. Together these provide resilience against component and AZ failures."},
{id:989,domain:2,level:2,question:"What is 'data exfiltration prevention' in cloud environments?",options:["A. Preventing data from being exported to competitor cloud providers","B. Controls detecting and blocking unauthorized transfer of sensitive data outside the organization — including DLP, egress monitoring, cloud access controls, and network-level controls","C. Preventing cloud providers from accessing customer data","D. Data backup restrictions to prevent excessive copying"],correct:1,explanation:"Data exfiltration prevention combines: DLP policies blocking sensitive data in outbound channels, egress traffic monitoring (anomaly detection on large outbound transfers), cloud service controls (S3 block public access, prevent cross-account sharing), CASB for SaaS monitoring, and network controls restricting outbound destinations."},
{id:990,domain:3,level:2,question:"What is 'cloud infrastructure security testing' and what methods are used?",options:["A. Testing cloud provider physical security controls","B. Assessing cloud infrastructure for vulnerabilities and misconfigurations through CSPM, configuration audits, vulnerability scanning, and penetration testing with provider permission","C. Cloud cost security for infrastructure budgets","D. Testing cloud infrastructure performance under load"],correct:1,explanation:"Cloud infrastructure security testing: CSPM continuous assessment, CIS Benchmark audits, vulnerability scanning of exposed services, manual penetration testing (cloud API, IAM privilege escalation, SSRF). Cloud providers require permission and compliance with acceptable use policies for active testing."},
{id:991,domain:4,level:2,question:"What is 'TLS certificate management' best practice for cloud applications?",options:["A. Using the longest available certificate validity (3 years)","B. Automating certificate provisioning and renewal (Let's Encrypt, ACM), using short validity periods, monitoring for expiry, and implementing certificate transparency monitoring","C. Using wildcard certificates for all domains","D. Managing all certificates in a central spreadsheet"],correct:1,explanation:"Best practices: automate provisioning/renewal (ACM, Let's Encrypt with auto-renewal) to prevent expiry-caused outages; use 1-year or shorter validity; monitor expiry with alerts; check CT logs for unauthorized certificates; pin certificates in mobile apps; use CT monitoring to detect misissued certificates."},
{id:992,domain:5,level:2,question:"What is 'cloud workload protection' in the context of runtime security?",options:["A. Financial protection against cloud workload cost overruns","B. Real-time monitoring and protection of running cloud workloads against exploitation, malware, and anomalous behavior using agents, eBPF, or hypervisor-level controls","C. Workload backup protection during cloud operations","D. Network protection for cloud workload communication"],correct:1,explanation:"Cloud workload protection (CWPP) secures running workloads: vulnerability assessment, runtime behavioral monitoring (detecting unexpected processes, network connections, file modifications), anti-malware, application allowlisting, and network micro-segmentation — across VMs, containers, and serverless."},
{id:993,domain:6,level:2,question:"What is 'data subject access request' (DSAR) handling in cloud environments?",options:["A. Restricting data subject access to cloud systems","B. The process of identifying, collecting, reviewing, and fulfilling requests from individuals to access their personal data held across cloud services within regulatory timeframes","C. Automated cloud storage access for data subjects","D. A request for cloud access to personal data for analytics"],correct:1,explanation:"DSARs (GDPR: respond within 1 month) require finding all personal data about the requester across all cloud services, databases, logs, and backups. Cloud sprawl makes this complex. Organizations need data mapping, automated discovery tools, and processes to compile complete responses within deadlines."},
{id:994,domain:1,level:3,question:"What is 'cloud security program' and what are its core components?",options:["A. A cloud provider's internal security program","B. An organizational program governing all aspects of cloud security: strategy, governance, risk management, architecture, operations, compliance, and continuous improvement","C. A training program for cloud security certifications","D. A security certification program for cloud products"],correct:1,explanation:"A cloud security program encompasses: strategy and governance (policies, roles, metrics), risk management (assessment, treatment), architecture (secure-by-design patterns), operations (CSPM, SOC, IR), compliance management (framework mapping, audit evidence), and talent (training, hiring). It provides systematic management vs. ad hoc security."},
{id:995,domain:2,level:3,question:"What is 'anonymization' under GDPR and why is it difficult to achieve?",options:["A. Replacing names with pseudonyms in datasets","B. Irreversibly transforming data so individuals cannot be identified directly or indirectly — difficult because re-identification using auxiliary data or ML is often possible even from 'anonymized' data","C. Encrypting all personal identifiers in a dataset","D. Removing obvious identifiers like names and IDs from data"],correct:1,explanation:"GDPR does not apply to truly anonymized data. However, achieving real anonymization is hard: research shows k-anonymized datasets can be re-identified using auxiliary data; sparse datasets (location, viewing history) can uniquely identify individuals even without direct identifiers. 'Anonymized' datasets often aren't."},
{id:996,domain:3,level:3,question:"What is 'cloud security automation' and what processes benefit most?",options:["A. Automated procurement of cloud security tools","B. Using code and APIs to automate repeatable security tasks: remediation, compliance checks, access provisioning, patch management, and incident response steps that would otherwise require manual effort","C. Cloud AI replacing all security analysts","D. Automated security configuration by cloud providers"],correct:1,explanation:"Security automation delivers the most value for high-volume, repeatable tasks: misconfig remediation, compliance drift correction, user access provisioning/deprovisioning, patch deployment, alert triage playbooks, and evidence collection for audits. Automation reduces human error, response time, and operational burden."},
{id:997,domain:4,level:3,question:"What is 'principle of fail-safe defaults' in application security?",options:["A. Applications automatically recover from security failures","B. Access should be denied by default; explicit permission must be granted for access rather than explicit denial being required to block access","C. Security controls fail to a safe, locked state on error","D. Application defaults prevent the most common security failures"],correct:1,explanation:"Fail-safe defaults means the default access decision is 'deny.' Every resource is inaccessible unless explicitly permitted. This contrasts with fail-open systems where access is allowed unless explicitly denied. In cloud IAM, deny-by-default with explicit allow (e.g., AWS IAM) implements this principle."},
{id:998,domain:5,level:3,question:"What is 'post-incident review' (PIR / post-mortem) and what should it produce?",options:["A. A review of security tools after an incident to assess their performance","B. A blameless analysis of what happened, why, what worked, what failed, and concrete action items to prevent recurrence and improve response capability","C. A compliance report filed with regulators after a major incident","D. A management review determining disciplinary action after a breach"],correct:1,explanation:"Post-incident reviews (post-mortems) analyze root causes, detection gaps, response effectiveness, and communication. Blameless culture (blaming processes, not people) encourages honest analysis. Output: documented timeline, root cause analysis, and specific action items with owners and deadlines to prevent recurrence."},
{id:999,domain:6,level:3,question:"What is the 'principle of purpose limitation' under GDPR and how does it affect cloud analytics?",options:["A. Limiting the purposes for which cloud services can be used","B. Personal data collected for a specific purpose cannot be used for a different, incompatible purpose without obtaining a new legal basis or consent","C. Cloud analytics must be limited to anonymized data","D. Purpose limitation only applies to sensitive data categories"],correct:1,explanation:"Purpose limitation (Article 5(1)(b)) requires data collected for one purpose (e.g., order fulfilment) cannot be repurposed for incompatible uses (e.g., profiling, resale) without a new legal basis. For cloud analytics: repurposing customer data for ML model training or behavioral analytics requires separate justification."},
{id:1000,domain:1,level:3,question:"An organization is building a cloud security program from scratch. According to CSA and NIST guidance, what should be established FIRST to provide a foundation for all subsequent controls?",options:["A. Deploy a SIEM and start collecting logs","B. Establish governance: define roles and accountability, risk appetite, and security policies that will guide all security decisions and investments","C. Perform a full penetration test of the cloud environment","D. Deploy CSPM tooling to assess current posture"],correct:1,explanation:"Governance is the foundation of any security program. Without defined ownership, risk appetite, and policies, technical controls lack direction and prioritization. CSA CCM and NIST CSF both position governance and risk management as the starting point, from which all other domains derive their requirements and authority."},
// ─── MIXED BATCH D (IDs 606–705) ────────────────────────────────────────────
{id:606,domain:1,level:1,question:"What is 'resource pooling' in NIST's cloud computing definition?",options:["A. Combining network cables to increase bandwidth","B. Provider's computing resources serve multiple consumers using a multi-tenant model, dynamically assigned on demand","C. Pooling financial resources to share cloud costs","D. Aggregating backup storage across multiple customers"],correct:1,explanation:"Resource pooling means the provider's resources (compute, storage, network) are pooled to serve multiple consumers, with different physical and virtual resources dynamically assigned and reassigned according to demand."},
{id:607,domain:1,level:1,question:"Which of the following BEST describes a private cloud?",options:["A. Cloud services operated solely for a single organization","B. Cloud services shared among unrelated organizations","C. Cloud services offered to the general public","D. Cloud services hosted outside any data center"],correct:0,explanation:"A private cloud is provisioned for exclusive use by a single organization comprising multiple consumers (e.g., business units). It may be owned, managed, and operated by the organization, a third party, or some combination."},
{id:608,domain:1,level:1,question:"What does 'on-demand self-service' mean in cloud computing?",options:["A. The provider dispatches a technician when needed","B. A consumer can provision computing capabilities without requiring human interaction with the service provider","C. Cloud services are available only during business hours","D. Service tickets are resolved automatically"],correct:1,explanation:"On-demand self-service allows consumers to unilaterally provision computing capabilities (e.g., server time, storage) as needed automatically, without requiring human interaction with the provider."},
{id:609,domain:1,level:2,question:"What risk does 'noisy neighbor' describe in multi-tenant cloud environments?",options:["A. A security breach where one tenant overhears another tenant's communications","B. A tenant consuming excessive shared resources, degrading performance for co-located tenants","C. A denial-of-service attack from within the cloud","D. Unauthorized access to another tenant's network"],correct:1,explanation:"The noisy neighbor effect occurs when one tenant's workload consumes disproportionate shared resources (CPU, network I/O), causing performance degradation for other tenants on the same physical host."},
{id:610,domain:1,level:2,question:"What is the purpose of a Cloud Security Posture Management (CSPM) tool?",options:["A. Monitor end-user behavior inside SaaS applications","B. Continuously assess cloud infrastructure configurations against security best practices and compliance standards","C. Scan application source code for vulnerabilities","D. Provide network intrusion detection in cloud environments"],correct:1,explanation:"CSPM tools continuously monitor cloud environment configurations (IaaS/PaaS) for misconfigurations and compliance violations, providing remediation guidance across accounts and regions."},
{id:611,domain:1,level:2,question:"A company uses multiple public cloud providers for different workloads. This is called:",options:["A. Hybrid cloud","B. Community cloud","C. Multi-cloud","D. Federated cloud"],correct:2,explanation:"Multi-cloud is the use of cloud services from more than one cloud vendor. Unlike hybrid cloud, which connects private and public cloud, multi-cloud typically refers to using multiple public clouds."},
{id:612,domain:1,level:3,question:"Which standard provides audit and attestation criteria specifically for cloud service organizations?",options:["A. ISO 27001","B. SOC 2 Type II","C. PCI DSS","D. NIST CSF"],correct:1,explanation:"SOC 2 Type II is an attestation report (AICPA) evaluating a cloud service organization's controls over a period of time (typically 6–12 months) against the Trust Services Criteria (security, availability, confidentiality, processing integrity, privacy)."},
{id:613,domain:1,level:3,question:"Which cloud architecture pattern improves resilience by designing components to assume failures will occur?",options:["A. Lift and shift","B. Design for failure","C. Monolithic architecture","D. Scale-up design"],correct:1,explanation:"'Design for failure' is a cloud architecture principle where each component is built assuming it will fail. This drives use of redundancy, auto-healing, health checks, circuit breakers, and graceful degradation."},
{id:614,domain:2,level:1,question:"What is the primary security concern with data at rest in cloud storage?",options:["A. Latency during retrieval","B. Unauthorized access or disclosure if storage media is compromised","C. Encryption slowing write performance","D. Data loss due to hardware failure"],correct:1,explanation:"Data at rest faces the risk of unauthorized access if storage media is lost, stolen, or accessed by unauthorized parties including cloud provider insiders. Encryption at rest mitigates this risk."},
{id:615,domain:2,level:1,question:"What does 'data sovereignty' refer to in cloud computing?",options:["A. A cloud provider owning the data stored by customers","B. Laws governing data based on the country where it is stored or processed","C. Customer control over data encryption keys","D. Data replication across sovereign nation-states"],correct:1,explanation:"Data sovereignty is the concept that data is subject to the laws and governance structures of the nation in which it is stored. It is a key consideration when selecting cloud regions."},
{id:616,domain:2,level:1,question:"Which encryption approach uses the same key for both encryption and decryption?",options:["A. Asymmetric encryption","B. Public key encryption","C. Symmetric encryption","D. Hashing"],correct:2,explanation:"Symmetric encryption uses one shared key for both encryption and decryption. It is fast and efficient for bulk data but requires secure key distribution between parties."},
{id:617,domain:2,level:2,question:"What is 'data remanence' and why is it a cloud security concern?",options:["A. Data that was recently accessed remains cached in memory","B. Residual data remaining on storage media after deletion, which may be recoverable","C. Data that is replicated across multiple cloud regions","D. Metadata remaining in cloud logs after data is deleted"],correct:1,explanation:"Data remanence refers to the residual representation of data remaining after attempts to remove it. In cloud environments, customers may not be able to verify secure erasure when decommissioning storage, making remanence a significant risk."},
{id:618,domain:2,level:2,question:"What is the purpose of a Data Loss Prevention (DLP) solution in cloud?",options:["A. Prevent ransomware from encrypting cloud data","B. Detect and prevent unauthorized transfer or exposure of sensitive data","C. Back up data to prevent accidental deletion","D. Monitor cloud storage costs"],correct:1,explanation:"DLP solutions identify, monitor, and protect sensitive data (PII, financial data, IP) from unauthorized access, transfer, or exfiltration across cloud services, email, and endpoints."},
{id:619,domain:2,level:2,question:"Which key management practice provides the strongest customer control over cloud data encryption?",options:["A. Provider-managed keys (PMK)","B. Customer-managed keys (CMK) stored in a cloud KMS","C. Bring Your Own Key (BYOK) with keys generated and escrowed by the customer","D. Using a shared key for all cloud resources"],correct:2,explanation:"BYOK allows customers to generate encryption keys using their own hardware or HSM, import them into the cloud KMS, and maintain control including the ability to revoke access, providing the strongest customer control."},
{id:620,domain:2,level:3,question:"An organization needs to share a dataset with an analytics partner without exposing individual records. Which privacy-preserving technique adds statistical noise to query results?",options:["A. Tokenization","B. Data masking","C. Differential privacy","D. Format-preserving encryption"],correct:2,explanation:"Differential privacy adds calibrated statistical noise to query results, ensuring that the inclusion or exclusion of any single individual cannot be inferred from the output, enabling analysis without exposing individual records."},
{id:621,domain:2,level:3,question:"Which cryptographic technique allows computation on ciphertext, producing results that, when decrypted, match the result of operating on the plaintext?",options:["A. Elliptic curve cryptography","B. Homomorphic encryption","C. Format-preserving encryption","D. Envelope encryption"],correct:1,explanation:"Homomorphic encryption allows computations to be performed directly on encrypted data. The result of the computation, when decrypted, matches what would have been obtained by operating on the plaintext data."},
{id:622,domain:2,level:3,question:"A security team discovers a cloud storage bucket exposing 50,000 customer records. What is the MOST important immediate action?",options:["A. Notify customers immediately via email","B. Revoke public access and preserve forensic state before notifying","C. Delete the exposed data to prevent further exposure","D. Conduct a root cause analysis before taking any action"],correct:1,explanation:"The first priority is containment: revoke public access to stop the ongoing exposure. The forensic state (access logs, bucket policy at time of discovery) must be preserved for investigation and breach notification decisions before any data is altered or deleted."},
{id:623,domain:3,level:1,question:"What is a Virtual Private Cloud (VPC)?",options:["A. A VPN connecting multiple cloud providers","B. An isolated, logically partitioned network section within a public cloud","C. A private cloud hosted in the customer's data center","D. A cloud service for storing virtual machine images"],correct:1,explanation:"A VPC is an isolated section of a public cloud where customers can launch resources in a defined virtual network. It provides network isolation, custom IP address ranges, subnets, route tables, and gateway controls."},
{id:624,domain:3,level:1,question:"What is the purpose of a security group in cloud networking?",options:["A. Organize IAM users by department","B. Act as a virtual stateful firewall controlling inbound and outbound traffic to cloud resources","C. Group cloud resources for billing purposes","D. Provide dedicated hardware to a group of instances"],correct:1,explanation:"Security groups are virtual stateful firewalls that control inbound and outbound traffic at the instance level. Being stateful, response traffic is automatically allowed without explicit outbound rules."},
{id:625,domain:3,level:1,question:"What distinguishes a Network Access Control List (NACL) from a security group?",options:["A. NACLs apply to instances; security groups apply to subnets","B. NACLs are stateful; security groups are stateless","C. NACLs apply to subnets and are stateless; security groups apply to instances and are stateful","D. NACLs require VPN connectivity; security groups do not"],correct:2,explanation:"NACLs operate at the subnet level and are stateless (return traffic must be explicitly allowed). Security groups operate at the instance level and are stateful (return traffic is automatically permitted)."},
{id:626,domain:3,level:2,question:"What is the purpose of a bastion host in cloud infrastructure?",options:["A. A dedicated server for running batch jobs","B. A hardened jump server providing secure administrative access to resources in private subnets","C. A load balancer distributing traffic across regions","D. A server that stores encryption keys"],correct:1,explanation:"A bastion host is a specially hardened server that provides a secure entry point for SSH/RDP access to cloud resources in private subnets, reducing the attack surface by limiting which systems are exposed to the internet."},
{id:627,domain:3,level:2,question:"What is 'east-west traffic' in cloud security?",options:["A. Traffic flowing between cloud regions in east and west geographic areas","B. Lateral traffic moving between workloads within the same network, as opposed to north-south traffic","C. Traffic between on-premises data centers and cloud","D. Traffic from users in eastern and western time zones"],correct:1,explanation:"East-west traffic refers to lateral communication between servers, microservices, or containers within a data center or cloud environment. It contrasts with north-south traffic (user to server). East-west traffic is a key attack vector for lateral movement."},
{id:628,domain:3,level:2,question:"What is the purpose of a Web Application Firewall (WAF) in cloud architecture?",options:["A. Block all non-web traffic at the network perimeter","B. Filter, monitor, and block HTTP/S traffic targeting web applications based on rules and signatures","C. Encrypt web application traffic with TLS","D. Provide CDN caching for static web content"],correct:1,explanation:"A WAF operates at the application layer (Layer 7) to protect web applications by filtering and monitoring HTTP/S traffic. It can block OWASP Top 10 attacks such as SQL injection, XSS, and CSRF."},
{id:629,domain:3,level:3,question:"An organization wants to prevent lateral movement within its cloud environment. Which control is MOST effective?",options:["A. Enable MFA for all user accounts","B. Implement micro-segmentation with allow-list-based east-west traffic policies","C. Deploy a WAF at the internet boundary","D. Encrypt all storage volumes"],correct:1,explanation:"Micro-segmentation applies granular network policies at the workload level, creating secure zones that limit east-west communication to only what is explicitly permitted. This prevents attackers from moving laterally even after compromising one workload."},
{id:630,domain:3,level:3,question:"What is confidential computing and what security property does it address?",options:["A. Encrypting data at rest using HSMs","B. Processing data in a hardware-protected trusted execution environment (TEE) to protect data in use","C. Applying confidentiality labels to cloud documents","D. Securing the management plane of cloud services"],correct:1,explanation:"Confidential computing protects data in use by performing computation within a hardware-enforced TEE (e.g., Intel SGX, AMD SEV). This addresses the gap where data must be decrypted during processing, which traditional encryption does not protect."},
{id:631,domain:4,level:1,question:"What is the OWASP Top 10?",options:["A. A ranking of the ten most critical web application security risks","B. A list of ten cloud security misconfigurations","C. Ten required security controls for PCI DSS compliance","D. A scoring system for vulnerability severity"],correct:0,explanation:"The OWASP Top 10 is a standard awareness document for web application security representing broad consensus about the most critical web application security risks, updated periodically based on data from the security community."},
{id:632,domain:4,level:1,question:"What is 'injection' in application security?",options:["A. Inserting new cloud resources into an existing deployment","B. Untrusted data sent to an interpreter as part of a command or query, causing unintended execution","C. Installing malware by physically accessing a server","D. Injecting encryption keys into application memory"],correct:1,explanation:"Injection attacks (e.g., SQL, LDAP, OS injection) occur when untrusted user data is passed to an interpreter without proper validation, causing the interpreter to execute unintended commands or access unauthorized data."},
{id:633,domain:4,level:1,question:"What is cross-site scripting (XSS)?",options:["A. An attack where scripts from one website are run in the context of another trusted website in the victim's browser","B. Cross-domain resource sharing between different cloud providers","C. An attack targeting scripting engines in the cloud control plane","D. A technique for bypassing content delivery networks"],correct:0,explanation:"XSS attacks inject malicious scripts into content from a trusted website. When the victim's browser executes the script, it can steal cookies, session tokens, or redirect the user, since the script runs with the trust level of the target site."},
{id:634,domain:4,level:2,question:"What is the purpose of static application security testing (SAST)?",options:["A. Test application performance under static load","B. Analyze application source code or binaries for security vulnerabilities without executing the program","C. Penetration test a live production application","D. Validate application configuration against a static baseline"],correct:1,explanation:"SAST analyzes source code, bytecode, or binaries at rest for security vulnerabilities (e.g., hardcoded secrets, SQL injection, buffer overflows) without running the application. It is typically integrated into CI pipelines for early detection."},
{id:635,domain:4,level:2,question:"What is dynamic application security testing (DAST)?",options:["A. Testing application performance dynamically based on user traffic","B. Security testing of a running application by sending inputs and observing responses","C. Dynamically scaling the number of security tests based on risk","D. Analyzing memory dumps from a running application"],correct:1,explanation:"DAST tests a running application by sending crafted inputs (like a real attacker would) and analyzing the responses. It finds vulnerabilities visible at runtime (authentication, input validation, server configuration) without access to source code."},
{id:636,domain:4,level:2,question:"What does 'software composition analysis' (SCA) identify?",options:["A. The components and services making up a cloud architecture","B. Known vulnerabilities in open-source libraries and dependencies used in an application","C. The software used by cloud provider personnel","D. Security requirements for custom software development"],correct:1,explanation:"SCA tools inventory open-source components and third-party libraries in an application and compare them against vulnerability databases (NVD, OSV) to identify known CVEs in dependencies."},
{id:637,domain:4,level:3,question:"An application accepts file uploads and stores them in cloud storage. Which security controls are MOST important?",options:["A. Rate limiting and captcha on the upload form","B. Validate file type server-side, scan for malware, store uploads in isolated storage with no execute permission","C. Require user authentication before uploading","D. Limit file size and log all upload attempts"],correct:1,explanation:"File upload vulnerabilities can enable code execution if attackers upload malicious files. Server-side validation of content type (not just extension), antivirus scanning, and storing files in a location where execution is impossible are the key controls."},
{id:638,domain:4,level:3,question:"What is the concept of 'secrets management' in cloud-native applications?",options:["A. Managing classified government information in cloud","B. Securely storing, distributing, and rotating credentials, API keys, and tokens needed by applications at runtime","C. Encrypting all application logs","D. Hiding application logic from end users"],correct:1,explanation:"Secrets management ensures that sensitive credentials (database passwords, API keys, certificates) are stored securely (vault), injected into applications at runtime without hardcoding, and rotated automatically. Tools include HashiCorp Vault and cloud-native secret stores."},
{id:639,domain:4,level:3,question:"A security review finds an API that returns full user objects including fields the caller doesn't need. What vulnerability is this?",options:["A. Broken authentication","B. Security misconfiguration","C. Excessive data exposure (now OWASP API3)","D. Server-side request forgery"],correct:2,explanation:"Excessive data exposure (OWASP API Security Top 10) occurs when APIs return more data than clients need, relying on the client to filter. Attackers can access sensitive fields. The fix is to return only required fields per endpoint."},
{id:640,domain:5,level:1,question:"What is the purpose of a Security Information and Event Management (SIEM) system?",options:["A. Patch cloud virtual machines automatically","B. Collect, aggregate, correlate, and analyze security log data to detect threats and support incident response","C. Encrypt log data before storing","D. Replace human security analysts"],correct:1,explanation:"A SIEM aggregates logs from across the environment, applies correlation rules and analytics to detect threats, generates alerts, and provides dashboards for security operations and compliance reporting."},
{id:641,domain:5,level:1,question:"What is the FIRST step in the incident response process?",options:["A. Containment","B. Eradication","C. Preparation","D. Recovery"],correct:2,explanation:"The NIST incident response lifecycle begins with Preparation, which includes establishing policies, procedures, tools, and training before an incident occurs. The subsequent phases are Detection/Analysis, Containment/Eradication/Recovery, and Post-Incident Activity."},
{id:642,domain:5,level:1,question:"What is a Security Operations Center (SOC)?",options:["A. A physical room where network cables are terminated","B. A centralized team responsible for monitoring, detecting, and responding to security incidents","C. A cloud service providing automated threat remediation","D. A compliance certification for cloud operations"],correct:1,explanation:"A SOC is a centralized function (team and technology) that continuously monitors an organization's IT environment for security threats, investigates alerts, and responds to incidents."},
{id:643,domain:5,level:2,question:"What is 'threat hunting' in cloud security operations?",options:["A. Automated scanning for known malware signatures","B. Proactive searching for threats that have evaded automated detection tools","C. Hunting for misconfigurations in cloud accounts","D. Tracking threat actors across the dark web"],correct:1,explanation:"Threat hunting is the proactive, human-led search for adversaries or malicious activity that has bypassed automated security controls. Hunters form hypotheses based on threat intelligence and use tools to investigate the environment."},
{id:644,domain:5,level:2,question:"What is a cloud-specific challenge for digital forensics?",options:["A. Cloud environments have too few logs","B. Log data is too small to be meaningful","C. Limited ability to directly access physical media and potential for evidence spread across jurisdictions","D. Cloud providers do not support forensic investigation"],correct:2,explanation:"Cloud forensics is complicated by the inability to access physical hardware, shared infrastructure, ephemeral compute (auto-scaled instances may terminate), multi-jurisdictional data, and dependency on the provider's cooperation for evidence collection."},
{id:645,domain:5,level:2,question:"What is 'mean time to detect' (MTTD) in security operations?",options:["A. Average time to patch a detected vulnerability","B. Average time from the start of a security incident to its detection by the security team","C. Time to detect cloud service outages","D. Time for a threat to propagate through the network"],correct:1,explanation:"MTTD measures the average elapsed time between when an attack begins and when it is detected by the security team. Lower MTTD correlates with reduced breach impact and is a key SOC performance metric."},
{id:646,domain:5,level:3,question:"What does SOAR stand for and what is its primary benefit?",options:["A. Security Operations Automated Response; faster patching","B. Security Orchestration, Automation, and Response; reduces manual effort by automating repetitive tasks and orchestrating tool workflows","C. Security Operations Architecture Review; improves cloud design","D. Security Oversight and Risk; a governance framework"],correct:1,explanation:"SOAR platforms integrate security tools, automate repetitive analyst tasks (like enriching alerts with threat intel), and orchestrate incident response workflows (playbooks). This reduces MTTD, MTTR, and analyst fatigue."},
{id:647,domain:5,level:3,question:"A SOC analyst notices beaconing traffic from a cloud workload at regular 60-second intervals to an external IP. What is the MOST likely explanation?",options:["A. Normal DNS health check behavior","B. Command-and-control (C2) communication from malware on the compromised workload","C. NTP time synchronization","D. Auto-scaling heartbeat traffic"],correct:1,explanation:"Regular outbound traffic at precise intervals to an external IP is a classic indicator of C2 beaconing, where malware periodically checks in with attacker infrastructure. The regularity distinguishes it from legitimate traffic."},
{id:648,domain:5,level:3,question:"Which log source provides the MOST actionable data for detecting cryptojacking in a cloud environment?",options:["A. Application access logs","B. Cloud billing and resource usage monitoring alerts showing unexpected compute cost spikes","C. DNS query logs","D. User authentication logs"],correct:1,explanation:"Cryptojacking (unauthorized cryptocurrency mining) significantly increases compute usage and cost. Cloud billing anomaly alerts are often the first and clearest indicator. CPU utilization metrics and process-level monitoring are also valuable."},
{id:649,domain:6,level:1,question:"What is the General Data Protection Regulation (GDPR)?",options:["A. A US federal data protection law","B. A European Union regulation governing the processing of personal data of EU residents","C. An international standard for information security management","D. A self-regulatory framework for cloud providers"],correct:1,explanation:"GDPR is an EU regulation (effective May 2018) that governs how organizations collect, process, and store personal data of EU residents. It applies to any organization processing EU residents' data, regardless of where the organization is located."},
{id:650,domain:6,level:1,question:"Under GDPR, what is a 'data subject'?",options:["A. A database containing personal information","B. The organization that processes personal data","C. The identified or identifiable natural person to whom personal data relates","D. A data protection officer"],correct:2,explanation:"A data subject is the identified or identifiable natural person whose personal data is being processed. They have rights under GDPR including access, erasure, rectification, and portability."},
{id:651,domain:6,level:1,question:"What is the CCSP exam primarily focused on?",options:["A. Network engineering and routing protocols","B. Cloud security architecture, design, operations, and governance","C. Physical data center security and hardware","D. Software development and DevOps practices"],correct:1,explanation:"The CCSP (Certified Cloud Security Professional) credential focuses on cloud security architecture and design, cloud data security, cloud platform and infrastructure security, cloud application security, cloud security operations, and legal, risk, and compliance."},
{id:652,domain:6,level:2,question:"What is the role of a Data Protection Officer (DPO) under GDPR?",options:["A. Manage IT security operations for the organization","B. Advise on and monitor GDPR compliance, serve as a point of contact with supervisory authorities","C. Encrypt all personal data processed by the organization","D. Conduct annual penetration testing"],correct:1,explanation:"A DPO (required for certain organizations) monitors internal GDPR compliance, advises on data protection impact assessments, trains staff, and serves as the contact point for data subjects and supervisory authorities."},
{id:653,domain:6,level:2,question:"What is a Standard Contractual Clause (SCC) in the context of GDPR?",options:["A. A mandatory clause in all cloud service agreements","B. Pre-approved contractual clauses by the European Commission that provide appropriate safeguards for international data transfers","C. Standard security requirements that cloud providers must meet","D. A clause limiting liability for data breaches"],correct:1,explanation:"SCCs are standardized contractual clauses approved by the European Commission that, when included in contracts, allow the transfer of personal data from the EU to third countries without an adequacy decision."},
{id:654,domain:6,level:2,question:"What does PCI DSS protect?",options:["A. Personally identifiable information of EU residents","B. Protected health information in the US","C. Payment card data including cardholder data and authentication data","D. Federal government information systems"],correct:2,explanation:"The Payment Card Industry Data Security Standard (PCI DSS) was developed by the major card brands to protect cardholder data. It applies to any organization that stores, processes, or transmits payment card data."},
{id:655,domain:6,level:3,question:"An organization processes health data in US cloud services. Which regulation primarily governs this?",options:["A. GDPR","B. CCPA","C. HIPAA","D. FISMA"],correct:2,explanation:"HIPAA (Health Insurance Portability and Accountability Act) governs the privacy and security of protected health information (PHI) in the US. It applies to covered entities (healthcare providers, insurers) and their business associates (including cloud providers)."},
{id:656,domain:6,level:3,question:"What is a Business Associate Agreement (BAA) in cloud computing?",options:["A. A general cloud service contract","B. An SLA guaranteeing cloud uptime for healthcare applications","C. A contract required by HIPAA between a covered entity and a vendor who creates, receives, or transmits PHI on its behalf","D. A partnership agreement between cloud providers"],correct:2,explanation:"Under HIPAA, a BAA is a required contract between a covered entity and a business associate (such as a cloud provider) that specifies the permitted uses of PHI and the business associate's safeguarding obligations."},
{id:657,domain:1,level:2,question:"What is the CSA STAR certification program?",options:["A. A penetration testing certification for cloud providers","B. A security assurance program for cloud providers combining ISO 27001 with CSA Cloud Controls Matrix","C. A government certification for cloud services handling classified data","D. A performance benchmark for cloud networking"],correct:1,explanation:"CSA STAR (Security Trust, Assurance, and Risk) provides a registry and assurance program for cloud providers. STAR certification combines ISO 27001 with the CSA CCM for cloud-specific controls and provides three levels: self-assessment, third-party audit, and continuous monitoring."},
{id:658,domain:1,level:3,question:"What is 'immutable infrastructure' and why is it a security best practice?",options:["A. Infrastructure that cannot be changed by any user","B. A pattern where servers are never modified after deployment; changes are made by replacing instances with new ones","C. Infrastructure protected by immutable access controls","D. Cloud resources that are locked and cannot be deleted"],correct:1,explanation:"Immutable infrastructure treats servers as disposable: instead of patching in-place, a new image is built, tested, and deployed, and the old instance is terminated. This eliminates configuration drift, ensures known-good states, and simplifies forensics."},
{id:659,domain:2,level:2,question:"What is 'data classification' and why is it important in cloud security?",options:["A. Categorizing cloud services by provider and service type","B. Labeling data by sensitivity level to ensure appropriate security controls are applied throughout its lifecycle","C. Sorting data by creation date for archiving purposes","D. Organizing cloud storage buckets by department"],correct:1,explanation:"Data classification assigns labels (e.g., Public, Internal, Confidential, Restricted) based on sensitivity. These labels drive security controls: encryption requirements, access restrictions, handling procedures, and retention policies."},
{id:660,domain:2,level:3,question:"What is 'key wrapping' in cloud cryptography?",options:["A. Applying multiple layers of encryption to data","B. Encrypting a data encryption key (DEK) with a key encryption key (KEK) to securely store or transmit it","C. Rotating encryption keys on a schedule","D. Distributing a single key to multiple users"],correct:1,explanation:"Key wrapping uses a key encryption key (KEK, typically stored in an HSM or KMS) to encrypt a data encryption key (DEK). The wrapped DEK can be stored alongside encrypted data. This is the foundation of envelope encryption."},
{id:661,domain:3,level:2,question:"What is the purpose of a cloud access security broker (CASB) in shadow IT management?",options:["A. Prevent employees from using cloud services altogether","B. Discover and assess unauthorized cloud service usage and enforce policy controls","C. Provide a single sign-on portal for approved cloud services","D. Monitor cloud provider compliance certifications"],correct:1,explanation:"CASBs provide visibility into shadow IT by discovering what cloud services employees are using (often via proxy or API), assessing risk, and allowing security teams to block unapproved services or apply policy controls to approved ones."},
{id:662,domain:3,level:3,question:"An organization runs Kubernetes in the cloud. Which attack technique targets misconfigured service accounts?",options:["A. Container escape via kernel exploit","B. Privilege escalation through overprivileged Kubernetes service account tokens to access cloud provider APIs","C. Node-level network sniffing","D. Image repository poisoning"],correct:1,explanation:"Overprivileged Kubernetes service accounts can be exploited if an attacker gains access to a pod. The service account token can then be used to call Kubernetes or cloud provider APIs, escalating privileges far beyond the compromised pod."},
{id:663,domain:4,level:2,question:"What is 'broken object-level authorization' (BOLA/IDOR) in API security?",options:["A. Missing authentication on API endpoints","B. An API that allows users to access objects belonging to other users by manipulating object identifiers","C. Returning too much data in API responses","D. Failing to validate API request schemas"],correct:1,explanation:"BOLA (also called IDOR - Insecure Direct Object Reference) is the top OWASP API Security risk. It occurs when an API uses user-supplied identifiers to access objects without verifying the caller has permission, allowing attackers to access other users' data."},
{id:664,domain:4,level:3,question:"What is 'supply chain security' in the context of cloud application development?",options:["A. Securing the physical supply chain for cloud hardware","B. Ensuring the integrity and security of code, tools, dependencies, and pipelines used to build and deploy software","C. Managing vendor contracts for cloud services","D. Securing logistics for physical server replacement"],correct:1,explanation:"Software supply chain security addresses threats throughout the build pipeline: compromised build tools, malicious open-source packages (dependency confusion, typosquatting), poisoned container images, and tampered CI/CD pipelines. Notable incidents include SolarWinds and XZ Utils."},
{id:665,domain:5,level:2,question:"What is 'user and entity behavior analytics' (UEBA)?",options:["A. Analytics tracking user engagement on web applications","B. Security analytics that establish behavioral baselines and detect anomalous deviations indicating threats","C. Compliance reporting on user access activities","D. A user interface for the SIEM platform"],correct:1,explanation:"UEBA uses machine learning to establish normal behavioral baselines for users and entities, then detect deviations (e.g., unusual login times, abnormal data access volumes) that may indicate insider threats, compromised accounts, or APT activity."},
{id:666,domain:5,level:3,question:"What is the purpose of a 'runbook' in cloud incident response?",options:["A. A manual for onboarding new SOC analysts","B. A documented, step-by-step procedure for responding to a specific type of security incident or operational event","C. A log of all incidents that occurred","D. A planning document for disaster recovery exercises"],correct:1,explanation:"Runbooks (playbooks) codify the response steps for known incident types (e.g., account compromise, ransomware, DDoS). They ensure consistent, repeatable responses, reduce decision fatigue during high-pressure incidents, and can be automated in SOAR platforms."},
{id:667,domain:6,level:2,question:"What is the 'right to erasure' (right to be forgotten) under GDPR?",options:["A. The right to delete a cloud storage account","B. A data subject's right to have their personal data deleted when it is no longer necessary or when they withdraw consent","C. A regulator's right to erase non-compliant data","D. The right to erase backup copies only"],correct:1,explanation:"GDPR Article 17 grants data subjects the right to request erasure of their personal data when it is no longer needed for its original purpose, consent is withdrawn, or data was unlawfully processed. This must be technically implemented in cloud architectures."},
{id:668,domain:6,level:3,question:"What is FedRAMP and who must comply with it?",options:["A. A financial regulation for cloud providers in the US","B. A US government risk management framework that cloud providers must use to authorize cloud services for federal agency use","C. A NIST standard applicable to all US organizations","D. An international cloud security framework"],correct:1,explanation:"FedRAMP (Federal Risk and Authorization Management Program) standardizes security assessment, authorization, and monitoring for cloud products and services used by US federal agencies. Providers must achieve FedRAMP authorization to sell cloud services to federal agencies."},
{id:669,domain:1,level:1,question:"What is 'broad network access' as defined by NIST for cloud computing?",options:["A. Cloud services use broadband internet connections","B. Capabilities are available over the network and accessed through standard mechanisms (mobile phones, tablets, laptops, workstations)","C. Cloud services are accessible from any country without restriction","D. Cloud providers must offer high-bandwidth connections"],correct:1,explanation:"Broad network access means cloud capabilities are available over the network and accessed through standard client platforms (thin or thick clients), enabling ubiquitous access from diverse devices."},
{id:670,domain:2,level:1,question:"What is 'tokenization' in data security?",options:["A. Converting data into tokens for authentication","B. Replacing sensitive data with a non-sensitive surrogate (token) that maps back to the original in a secure vault","C. A method of encrypting data using tokens","D. Dividing a dataset into tokens for parallel processing"],correct:1,explanation:"Tokenization replaces sensitive data (e.g., credit card numbers) with a non-sensitive placeholder (token). The original data is stored in a secure token vault. Unlike encryption, tokens cannot be reversed without accessing the vault, and the algorithm is not mathematical."},
{id:671,domain:3,level:1,question:"What is 'infrastructure as code' (IaC)?",options:["A. Writing documentation for cloud infrastructure","B. Managing and provisioning infrastructure through machine-readable configuration files rather than manual processes","C. Developing cloud-native applications using infrastructure APIs","D. Converting physical infrastructure to virtual code"],correct:1,explanation:"IaC uses configuration files (Terraform, CloudFormation, Pulumi) to define, provision, and manage infrastructure. It enables version control, repeatability, automated testing, and consistent deployments, eliminating manual configuration drift."},
{id:672,domain:4,level:1,question:"What is 'input validation' and why is it a security control?",options:["A. Verifying that user inputs meet expected format, type, length, and range before processing to prevent injection attacks","B. Validating that configuration inputs match infrastructure requirements","C. Checking that API keys are valid before allowing access","D. Validating SSL certificates on input connections"],correct:0,explanation:"Input validation verifies that data received by an application conforms to expected constraints. It is a primary defense against injection attacks (SQL, OS, LDAP), XSS, and buffer overflows by rejecting or sanitizing malicious input before processing."},
{id:673,domain:5,level:1,question:"What is 'log management' in cloud security?",options:["A. Managing cloud service logs to reduce storage costs","B. Collecting, storing, protecting, and analyzing log data from cloud resources to support security monitoring and compliance","C. Logging API calls for billing purposes","D. Rotating log files to prevent disk overflow"],correct:1,explanation:"Log management encompasses collection, aggregation, storage, analysis, and retention of log data from cloud services, applications, and infrastructure. Logs are essential for threat detection, forensic investigation, and compliance auditing."},
{id:674,domain:6,level:1,question:"What is 'risk appetite' in organizational risk management?",options:["A. The maximum financial loss an organization can sustain","B. The amount and type of risk an organization is willing to accept in pursuit of its objectives","C. The speed at which the organization responds to risks","D. The number of risks identified in an annual assessment"],correct:1,explanation:"Risk appetite is the level and type of risk the organization is willing to accept to achieve its strategic objectives. It guides risk treatment decisions: risks within appetite are accepted; risks exceeding appetite require mitigation."},
{id:675,domain:1,level:2,question:"What is the difference between availability and reliability in cloud services?",options:["A. They are the same concept measured differently","B. Availability is the percentage of time a service is operational; reliability is the probability of performing correctly when needed","C. Availability applies to storage; reliability applies to compute","D. Reliability includes disaster recovery; availability does not"],correct:1,explanation:"Availability is the percentage of time a service is up and accessible (e.g., 99.9% SLA). Reliability is the probability that a system performs its intended function without failure over a given period. High availability requires redundancy; high reliability requires quality engineering."},
{id:676,domain:2,level:2,question:"What is a 'data steward' and how does this role differ from a 'data owner'?",options:["A. Data stewards own the data; data owners manage it operationally","B. Data owners have business accountability for data; data stewards manage data quality and governance operationally on the owner's behalf","C. Both roles are identical in most organizations","D. Data stewards are IT staff; data owners are executives who never interact with data"],correct:1,explanation:"Data owners (typically business executives) are accountable for data and define classification and policy. Data stewards implement those policies operationally: maintaining data quality, managing metadata, and enforcing governance procedures on the owner's behalf."},
{id:677,domain:3,level:2,question:"What is a 'golden image' or 'hardened base image' in cloud security?",options:["A. A premium VM instance type with dedicated hardware","B. A pre-configured, security-hardened VM or container image used as the approved baseline for deploying new instances","C. The original OS image before any patching","D. A backup image stored in a separate cloud region"],correct:1,explanation:"A golden image is a pre-hardened, tested, and approved VM or container template used as the baseline for all deployments. It incorporates security baselines (CIS benchmarks), required agents, and approved software, ensuring consistent security posture across instances."},
{id:678,domain:4,level:2,question:"What is the purpose of a Content Security Policy (CSP) HTTP header?",options:["A. Authenticate content between the server and CDN","B. Restrict what resources (scripts, styles, images) a browser will load, mitigating XSS attacks","C. Encrypt HTTP responses in transit","D. Set cache control for web content"],correct:1,explanation:"Content Security Policy is an HTTP header that tells browsers which sources are trusted for loading scripts, styles, images, and other resources. By preventing loading of unauthorized scripts, CSP significantly reduces the attack surface for XSS."},
{id:679,domain:5,level:2,question:"What is the purpose of a 'tabletop exercise' in incident response preparation?",options:["A. Test network failover by simulating traffic","B. A discussion-based simulation where stakeholders walk through an incident scenario to test plans and identify gaps","C. Train security analysts on SIEM use through live exercises","D. A physical exercise rehearsing data center evacuation"],correct:1,explanation:"Tabletop exercises bring together key stakeholders to discuss roles, responsibilities, and actions in a simulated incident scenario. They identify gaps in plans, communication, and escalation without the cost of a full simulation."},
{id:680,domain:6,level:2,question:"What is the 'right of audit' clause in cloud contracts?",options:["A. A cloud provider's right to audit customer usage","B. A contractual right allowing the customer to audit the provider's security controls, compliance certifications, or both","C. A regulator's right to audit cloud providers","D. A right to audit cloud billing statements"],correct:1,explanation:"Right of audit clauses grant customers the right to inspect a provider's security controls. In large-scale cloud, this is often satisfied through third-party certifications (SOC 2, ISO 27001) rather than direct customer audits, which providers may limit."},
{id:681,domain:1,level:3,question:"What is 'chaos engineering' and how does it relate to cloud resilience?",options:["A. Intentionally introducing failures into a production system to discover weaknesses before they cause outages","B. Randomly deploying cloud resources to test automation","C. Security testing by injecting malicious code","D. Unplanned cloud migrations to test portability"],correct:0,explanation:"Chaos engineering (popularized by Netflix's Chaos Monkey) deliberately injects failures (terminating instances, blocking network paths, degrading services) into production to discover system weaknesses and verify that redundancy mechanisms work as expected."},
{id:682,domain:2,level:3,question:"What is 'privacy by design' (PbD)?",options:["A. Designing user interfaces that are visually privacy-focused","B. Embedding privacy protections into technology, business practices, and physical design from the outset rather than as an afterthought","C. A design pattern for secure login flows","D. An architectural pattern for encrypting data at rest"],correct:1,explanation:"Privacy by Design (Ann Cavoukian, embedded in GDPR Article 25) requires that privacy is considered at the design stage: data minimization, purpose limitation, access controls, and default privacy settings built in from the start rather than added later."},
{id:683,domain:3,level:3,question:"What is the principle of 'ephemeral credentials' and why are they preferred in cloud?",options:["A. Credentials that expire after a short time, reducing the window of opportunity if compromised","B. Credentials stored temporarily in browser memory","C. Credentials generated for each cloud region separately","D. Credentials that are never stored, requiring re-authentication every time"],correct:0,explanation:"Ephemeral (short-lived) credentials (e.g., STS tokens, OIDC tokens) expire automatically, limiting the damage from credential theft. Long-lived static credentials (IAM access keys) are a persistent risk if leaked; ephemeral credentials significantly reduce that window."},
{id:684,domain:4,level:3,question:"What is 'server-side request forgery' (SSRF) and why is it dangerous in cloud environments?",options:["A. An attack where the server is forced to make unauthorized requests to internal resources on behalf of the attacker","B. A technique for bypassing server-side rate limiting","C. Cross-origin requests from untrusted servers","D. Forging server certificates to intercept traffic"],correct:0,explanation:"SSRF tricks a server into making HTTP requests to internal resources (metadata API, internal services) that the attacker cannot reach directly. In cloud, SSRF can expose the instance metadata endpoint (169.254.169.254), allowing attackers to steal IAM credentials."},
{id:685,domain:5,level:3,question:"What is 'threat intelligence' and how is it operationalized in a SOC?",options:["A. Security training for the intelligence community","B. Evidence-based knowledge about threats (indicators, TTPs, adversary profiles) used to inform defensive decisions","C. A database of all known vulnerabilities","D. Intelligence gathered from penetration tests"],correct:1,explanation:"Threat intelligence is curated knowledge about adversaries: indicators of compromise (IOCs), tactics, techniques, and procedures (TTPs), and adversary profiles. SOCs operationalize it by ingesting threat feeds into SIEM/SOAR for automated indicator matching and informing hunting hypotheses."},
{id:686,domain:6,level:3,question:"What is the 'right to data portability' under GDPR?",options:["A. The right to move cloud services to a different provider","B. A data subject's right to receive their personal data in a structured, machine-readable format and transmit it to another controller","C. The right to access data from any geographic location","D. The right to portable storage devices for backup"],correct:1,explanation:"GDPR Article 20 grants data subjects the right to receive personal data they provided in a commonly used, machine-readable format and to transmit it to another data controller. This applies when processing is based on consent or contract and is automated."},
{id:687,domain:1,level:1,question:"Which of the following is a characteristic of public cloud?",options:["A. Dedicated resources for a single organization","B. Shared infrastructure managed by a provider, accessible to the general public","C. Cloud services within a private network","D. On-premises infrastructure managed as cloud"],correct:1,explanation:"Public cloud infrastructure is provisioned for open use by the general public. It is owned and operated by a third-party cloud provider and shared among multiple tenants."},
{id:688,domain:2,level:1,question:"What is a 'hash function' used for in data security?",options:["A. Encrypting data so it can be decrypted later","B. Producing a fixed-size digest from input data for integrity verification","C. Generating encryption keys from passwords","D. Compressing data to reduce storage requirements"],correct:1,explanation:"Hash functions produce a fixed-size digest (fingerprint) from input data. They are one-way: the original data cannot be derived from the hash. Used for integrity verification (detecting tampering), digital signatures, and password storage."},
{id:689,domain:3,level:1,question:"What is a 'denial of service' (DoS) attack?",options:["A. An attack denying an attacker access to stolen data","B. Overwhelming a service with traffic or requests to make it unavailable to legitimate users","C. Deleting data to deny users access","D. Blocking a user's account to deny login"],correct:1,explanation:"A DoS attack floods a target with traffic or requests, exhausting resources and making the service unavailable to legitimate users. Distributed DoS (DDoS) uses multiple sources, making it harder to filter."},
{id:690,domain:4,level:1,question:"What is 'authentication' in application security?",options:["A. Determining what actions an authenticated user may perform","B. Verifying the identity of a user, system, or service","C. Encrypting communications between user and application","D. Logging user activity for audit purposes"],correct:1,explanation:"Authentication is the process of verifying that an entity (user, system, service) is who it claims to be. This typically involves credentials (password, certificate, token). It is distinct from authorization, which determines what the authenticated entity may do."},
{id:691,domain:5,level:1,question:"What is 'vulnerability management'?",options:["A. Managing the organization's risk tolerance for accepting vulnerabilities","B. The ongoing process of identifying, evaluating, prioritizing, and remediating security vulnerabilities","C. A vulnerability database maintained by cloud providers","D. Automated patching of all cloud virtual machines"],correct:1,explanation:"Vulnerability management is the cyclical process of discovering vulnerabilities (scanning), assessing their risk (CVSS scoring, business context), prioritizing remediation, applying fixes, and verifying remediation."},
{id:692,domain:6,level:1,question:"What is 'compliance' in the context of cloud security?",options:["A. Agreement between cloud provider and customer on service levels","B. Adherence to laws, regulations, standards, and contractual requirements applicable to the organization's cloud operations","C. Technical security controls implemented in cloud environments","D. Customer satisfaction with cloud services"],correct:1,explanation:"Compliance means meeting the requirements of applicable laws (GDPR, HIPAA), regulations, industry standards (PCI DSS, ISO 27001), and contractual obligations. In cloud, shared responsibility means compliance obligations may be split between provider and customer."},
{id:693,domain:1,level:2,question:"What is 'cloud sprawl' and why is it a security concern?",options:["A. Cloud resources growing faster than available bandwidth","B. The uncontrolled proliferation of cloud accounts, services, and resources outside governance and visibility","C. Data growing faster than cloud storage capacity","D. Cloud providers expanding into new geographic markets"],correct:1,explanation:"Cloud sprawl occurs when cloud accounts, services, and resources proliferate beyond the IT team's visibility and governance. Unmanaged resources may have misconfigurations, missing security controls, or contain sensitive data, creating an expanded and unmonitored attack surface."},
{id:694,domain:2,level:2,question:"What is a 'data processing agreement' (DPA) in cloud services?",options:["A. A performance agreement for data processing speed","B. A contract required when a data controller uses a processor to handle personal data, specifying obligations and rights","C. An agreement on data backup and recovery procedures","D. A technical specification for API data formats"],correct:1,explanation:"A DPA (required under GDPR Article 28) is a contract between a data controller and data processor specifying processing instructions, security measures, breach notification obligations, sub-processor requirements, and rights to audit."},
{id:695,domain:3,level:2,question:"What is 'certificate pinning' and what attack does it prevent?",options:["A. Pinning certificates to specific cloud regions to prevent data crossing borders","B. Hardcoding expected certificates or public keys in an application to prevent MITM attacks using fraudulent certificates","C. Automatically renewing TLS certificates before expiry","D. Pinning IP addresses to TLS certificates"],correct:1,explanation:"Certificate pinning embeds expected TLS certificates or public keys in client code. Even if an attacker presents a fraudulently issued certificate (from a compromised CA), the application rejects it because it doesn't match the pinned value."},
{id:696,domain:4,level:2,question:"What is 'security as code' (SaC)?",options:["A. Writing security policies in natural language","B. Expressing security requirements and controls in code that can be versioned, tested, and enforced automatically in CI/CD pipelines","C. Coding security training modules","D. Converting security audit findings to code fixes"],correct:1,explanation:"Security as code treats security policies and controls as code: IaC security scanning, policy-as-code (OPA), automated compliance checks, and security tests in CI/CD. This enables consistent, auditable, automated security enforcement."},
{id:697,domain:5,level:2,question:"What is 'mean time to respond' (MTTR) in security operations?",options:["A. The time for a customer to respond to a security questionnaire","B. The average time from incident detection to full resolution","C. The average time to respond to a DDoS attack","D. Time to restore service after a disaster"],correct:1,explanation:"MTTR measures the average time between incident detection and resolution (containment, eradication, and recovery). Along with MTTD, it is a primary metric for SOC effectiveness. Lower MTTR reduces breach impact."},
{id:698,domain:6,level:2,question:"What is a 'privacy impact assessment' (PIA/DPIA)?",options:["A. An assessment of cloud privacy settings","B. A process to identify and minimize privacy risks of new systems or processes involving personal data","C. A post-breach privacy impact evaluation","D. A regulatory audit of an organization's privacy practices"],correct:1,explanation:"A Data Protection Impact Assessment (DPIA, required by GDPR Article 35 for high-risk processing) systematically analyzes privacy risks introduced by a new project or system and identifies measures to mitigate those risks before deployment."},
{id:699,domain:1,level:3,question:"What is the 'shared fate' model proposed by some cloud providers as an evolution of shared responsibility?",options:["A. Cloud providers and customers share financial losses from security incidents","B. Cloud providers take on greater responsibility and invest in customer security outcomes, aligning provider incentives with customer success","C. Customers and providers share credentials to simplify access management","D. All cloud tenants share the consequences of any single tenant's security failure"],correct:1,explanation:"'Shared fate' is a philosophy where the cloud provider goes beyond defining responsibility boundaries to actively investing in tools, guidance, and controls that help customers succeed. The provider's reputation is tied to customer security outcomes, aligning incentives."},
{id:700,domain:2,level:3,question:"What is the 'CIA triad' and how does it apply to cloud data security?",options:["A. Cloud Infrastructure Audit triad for compliance","B. Confidentiality, Integrity, and Availability — the three core properties of information security applied to cloud data protection","C. Cloud Integration Architecture framework","D. Certified Information Assurance program"],correct:1,explanation:"The CIA triad (Confidentiality, Integrity, Availability) is the foundation of information security. In cloud: Confidentiality is protected by encryption and access controls; Integrity by hashing and checksums; Availability by redundancy, replication, and DDoS protection."},
{id:701,domain:3,level:3,question:"What is 'network segmentation' and why is it critical in cloud security?",options:["A. Dividing network traffic by protocol type","B. Partitioning cloud networks into isolated segments to contain breaches and limit lateral movement","C. Throttling network bandwidth by segment","D. Separating network infrastructure between cloud providers"],correct:1,explanation:"Network segmentation divides a network into zones with different trust levels and traffic rules. In cloud, this limits an attacker's ability to move laterally after compromising one segment. Micro-segmentation extends this to the workload level."},
{id:702,domain:4,level:3,question:"What is 'OAuth 2.0' and how does it relate to cloud application security?",options:["A. An encryption protocol for cloud API traffic","B. An authorization framework allowing applications to access resources on behalf of users without sharing credentials","C. An authentication protocol replacing username/password","D. A cloud API rate limiting standard"],correct:1,explanation:"OAuth 2.0 enables third-party applications to obtain limited access to user accounts without exposing credentials. It issues access tokens scoped to specific permissions. Misconfigurations (open redirects, overly broad scopes) are common vulnerabilities."},
{id:703,domain:5,level:3,question:"What is 'cloud detection and response' (CDR)?",options:["A. A cloud provider service for automatically detecting and responding to hardware failures","B. Security tools and practices focused on detecting and responding to threats specific to cloud environments","C. A framework for responding to cloud service outages","D. CDR = Cloud Disaster Recovery, another term for cloud backup"],correct:1,explanation:"CDR tools are designed for cloud-specific threat detection: monitoring cloud APIs, control plane activity, identity behavior, network flows, and workloads for indicators of compromise, and supporting incident response in dynamic, ephemeral cloud environments."},
{id:704,domain:6,level:3,question:"What is 'ISO 27701' and how does it relate to privacy management?",options:["A. An extension to ISO 27001 providing requirements for a Privacy Information Management System (PIMS)","B. An international standard for cloud security controls","C. A GDPR compliance checklist published by ISO","D. An ISO standard for data breach notification timelines"],correct:0,explanation:"ISO 27701 extends ISO 27001/27002 to include privacy management requirements. It specifies requirements and guidance for establishing, implementing, maintaining, and continually improving a PIMS, and can be used to demonstrate GDPR compliance."},
{id:705,domain:1,level:2,question:"What is the purpose of a 'cloud exit strategy'?",options:["A. Procedures for offboarding employees from cloud access","B. A plan for migrating data and workloads away from a cloud provider if needed, avoiding lock-in","C. Emergency shutdown procedures for cloud resources","D. A strategy for exiting unprofitable cloud service lines"],correct:1,explanation:"A cloud exit strategy defines how an organization would migrate away from a cloud provider (data portability, workload migration, contract termination). It mitigates vendor lock-in risk and is important for business continuity planning."},
];

